window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-048.json"] = [{"name":"东非麻雀","english_name":"Swahili Sparrow","scientific_name":"Passer suahelicus","appearance":"东非麻雀体长约15至16厘米，体重20至30克。头部、颈部至背部和下体呈灰褐色，臀部鲜红。上翼和尾巴为棕色，肩部红色，中覆羽尖端白色（形成较小的翼斑）。有时喉部有较淡的灰色区域。虹膜棕色，喙黑色或角质色，腿为淡棕色或淡肉色。雌雄相似，幼鸟与成鸟非常相似，但中覆羽缺少白色。","call":"鸣唱被描述为一系列柔和的叫声组合，如“chup chu-weew chop wor chu-weet chip choy chaw-chip chaw wor-chip chwoop”。","habits":"栖息于散落树木的草地和轻型林地，尤其靠近水源，也会出现在耕作地和人类居住区。海拔可达2000米。雨季期间有局部移动。主要以种子为食，也会在村庄附近捡食残渣，以及在游戏公园的旅馆周围觅食。","breeding":"繁殖期为1月至5月，与雨季同步。巢为不规则的穹顶状结构，侧面有隧道入口，建在树洞或房屋中，有时利用旧燕子巢。","identification":"与灰头麻雀相比，东非麻雀有更深的下体颜色，喉咙对比不明显，背部更灰。与鹦嘴麻雀相比，体型略小，喙更细，下体颜色更浅。","protection":"IUCN：LC（无危）","distribution":"分布在非洲东部的稀树草原和人造生境：从肯尼亚西南部、中部到坦桑尼亚南部。","other":"东非麻雀与灰头麻雀在生态习性上有差异，如筑巢偏好、巢的构建方式和繁殖后的行为模式。"},{"name":"南非灰头麻雀","english_name":"Southern Grey-headed Sparrow","scientific_name":"Passer diffusus","overview":"南非灰头麻雀（英文名：Southern Grey-headed Sparrow，学名：Passer diffusus），是雀形目雀科雀属的鸟类。头部和颈背呈淡灰褐色，有时带棕色调，下体颜色较浅，腹部和臀部近白色。喉部可能比胸部略淡，但通常并无明显差异。背部及翅膀上方为棕色，肩部和翅膀覆羽带有红褐色，形成显著的白色翼斑。黑色喙在繁殖季节变黑，其余时间呈角质色。该物种广泛分布于非洲南部的开阔灌木林地带，常靠近人类居住区。","appearance":"成鸟全长约15至16厘米，体重20至29.6克。头部和颈背颜色为淡灰褐色，下体颜色较浅，腹部和臀部近白色。喉部有时比胸部略淡，但很少形成明显的斑块。上体包括翅膀上方为棕色，肩部和翅膀覆羽带有红褐色，形成明显的白色翼斑。尾巴呈深棕色，虹膜为深棕色，喙在繁殖季节变黑，其余时间为暗棕色，腿为淡粉棕色。雌雄外观相似，幼鸟颜色更偏棕色，上体有轻微的条纹，翼斑可能减小或缺失。","call":"鸣叫为反复的'chirp'或'chirrup'声，比家麻雀的声音更为柔和悦耳。歌声是一系列类似鸣叫音符的连续组合，例如'chyup chet chyew chyurp chip chyit chooy'。威胁声为持续的'churrrrrdididit'，伴随翅膀展开、尾巴扇开稍抬高、臀部羽毛蓬松。","habits":"主要栖息于开阔的金合欢树（Acacia）灌木林地带，经常接近人类居住区，甚至进入建筑密集区。在北部分布区域，偏好干燥环境，几乎完全与莫帕尼树（Colophospermum mopane）林地相关联，较少出现在农田和居住地附近。以杂草种子和昆虫为主食，也吃花蕾、浆果和花蜜，还捡食人类丢弃的食物残渣。幼鸟主要以昆虫喂养，如白蚁。大部分食物从地面收集，但大部分时间在树上度过。以步行和跳跃的方式觅食，成对或小群活动。","breeding":"全年均可繁殖，与当地雨季同步，通常育两窝。巢由双亲共同建造，主要用干草制成，内衬羽毛，通常建在树洞或建筑物中的小洞穴里，材料会填满整个洞穴。经常利用其他物种的旧巢。与家麻雀竞争巢址。每窝产卵2至5枚，多为3至4枚，双亲共同孵卵，具体孵化期未知；雏鸟由双亲共同喂养，离巢期为16至25天；离巢后仍由双亲喂养一段时间。","identification":"与灰头麻雀极为相似，但后者头部颜色更深，喉咙白色对比更鲜明，喙部更大且全年保持深色。不同亚种间存在细微差异，如luangwae亚种体型较小，背部颜色更暖，mosambicus亚种冠部灰色更浓，背部稍微温暖，而stygiceps亚种上体颜色更偏棕色，下体颜色更深。","protection":"IUCN：LC（无危）；在斯威士兰的密度为51只/100公顷。自1950年代以来，其分布范围有所扩大；在南非，向西显著扩展到西开普省，但在更干旱的卡鲁地区仍未出现。","distribution":"分布于非洲南部的开阔灌木林地带和人类影响的生境：东部安哥拉向东至北部赞比亚和南部坦桑尼亚，南部穿过南非。","other":"自1950年代以来，南非灰头麻雀的分布范围有所扩大，尤其在南非，它已显著向西延伸至西开普省，但至今尚未进入更干旱的卡鲁地区。"},{"name":"荒漠麻雀","english_name":"Desert Sparrow","scientific_name":"Passer simplex","overview":"荒漠麻雀（英文名：Desert Sparrow，学名：Passer simplex），是雀形目雀科雀属的鸟类。在北非撒哈拉沙漠的绿洲、干河床和城镇中生活。体型娇小，颜色淡雅，以不畏惧人类著称，有时甚至会在泥墙中筑巢。在某些文化中，被视为带来好消息的吉祥鸟。","appearance":"荒漠麻雀体长约13.5至15厘米，体重约18至21克，外观呈现出一种细腻的灰白色调。雄鸟上体呈淡灰色，胸前有一块明显的黑色斑点，眼睛前方有黑色线条，腹部沙色，翅膀上有显著的白色斑块。雌鸟整体呈现柔和的沙色，腹部颜色较浅，缺乏鲜明特征。幼鸟与雌鸟相似。","call":"鸣叫时发出深沉的'churp'声，叫声略显粗哑。","habits":"生活在干燥的沙质环境中，如沙漠灌木丛、绿洲和种植园等。以沙漠灌木和地面植被的种子为主食，包括Panicum turgidum等草籽和栽培谷物的种子。巢穴中的雏鸟可能以无脊椎动物为食。获取水分主要来自食物，但也会访问水源。大部分时间在树上度过，觅食时则在地上收集食物，通常成对或小群体活动。","breeding":"繁殖季节从二月至八月，主要集中在三月中旬到十月下旬（摩洛哥南部）。通常独居或形成小型群体繁殖，每棵树中可能有四到五个巢。巢由双方共同建造，呈圆顶状，入口向上倾斜，由干草和小枝条构成，内部铺垫柔软的植物材料和羽毛。巢一般位于树冠中，如刺槐或废弃建筑中。每次产卵2至5枚（罕见六枚），蛋壳呈白色，带有棕色和灰色的斑点，平均尺寸为19.2毫米×13.5毫米。孵化期约为12至13天，雏鸟由双亲喂养，育雏期大约为12至14天。","identification":"与灰麻雀相比，荒漠麻雀在颜色、体型和分布上有所不同，后者主要分布在中亚。","protection":"IUCN：LC（无危）","distribution":"分布于北非的撒哈拉沙漠绿洲、干河床和城镇，从摩洛哥东南部向东延伸至利比亚东南部，向南穿过毛里塔尼亚直至苏丹中部。","other":"由于栖息地破坏，荒漠麻雀的数量在当地变得越来越稀少，但在全球范围内仍被评估为无危物种。"},{"name":"灰麻雀","english_name":"Zarudny's Sparrow","scientific_name":"Passer zarudnyi","overview":"灰麻雀（英文名：Zarudny's Sparrow，学名：Passer zarudnyi），是雀形目雀科雀属的鸟类。属于小型鸟类，体长13.5-15厘米，嘴短粗呈圆锥状，上下嘴闭合无缝隙。雌雄羽毛颜色有区别，上体棕黑斑杂。主要分布于乌兹别克斯坦和土库曼斯坦的干旱灌木丛地带，历史上曾记录于伊朗，但现在可能已在那里绝迹。","appearance":"灰麻雀体长13.5-15厘米，拥有短粗且强壮的圆锥状嘴，闭合时上下嘴间无缝隙。雌雄羽毛颜色有明显区别，上体呈现棕、黑色斑杂状。雄鸟有明显的黑色面罩，延伸至眼后，背部和肩部灰色，翼上有显著白色斑块；雌鸟类似雄鸟，但黑色部分减少，更偏棕色。初级飞羽共9枚，外侧飞羽的淡色边缘在羽基和近端处形成略显横斑状，尤其在飞行时可见。","call":"灰麻雀的鸣叫声特征未详细记载，据报告其声音与欧红额金翅雀的叫声相似，也有说法其颤音丰富，某些声音类似于家麻雀的啾啾声。","habits":"灰麻雀栖息于裸露、岩石或沙平原地带，偏好稀疏树木和灌木丛，尤其是沙枣树（Ammodendron conellyi）和白梭梭树（Holoxylon ammodendron）。以沙漠灌木和地面植被的种子为主食，尤其是Aristida pennata的种子。也会食用甲虫、蚱蜢、鳞翅目幼虫和蜘蛛。大部分时间在树上度过，但在地面觅食。成对或小群体活动，非繁殖季节形成小群。","breeding":"繁殖期为4月至8月，每年繁殖两次。独居或小群繁殖，每棵树可能有4到5个巢。巢由双方共同建造，形状为穹顶，入口向上倾斜至巢杯，主要由干草和小枝构成，内部铺垫柔软的植物纤维和羽毛，位于离地1.5-4米的树枝上。每窝产2-6枚（极少数7-8枚）蛋，双亲轮流孵卵，孵化期12-13天。雏鸟异步孵化，由双亲喂养，巢期12-14天。","identification":"灰麻雀与荒漠麻雀相比，翼和喙较短，尾较长，雄鸟面部面罩更明显，黑色更深，上体更灰，尤其是臀部几乎同色，背和肩部较棕色直到晚冬。翼覆羽图案不同，大覆羽面板更白，前翼黑色（覆盖物的前缘）在荒漠麻雀中明显，而在灰麻雀中不明显。雌鸟羽毛通常略带棕色，头部和胸脯黑色减少且更棕色。","protection":"IUCN：LC（无危）。灰麻雀并非全球受威胁物种，但在土库曼斯坦被列入红名单，有证据表明其数量近期有所下降。","distribution":"灰麻雀主要分布在土库曼斯坦和乌兹别克斯坦的干旱灌木丛地带。历史上曾在伊朗东部霍拉桑省被记录，但目前似乎已在该地区灭绝。","other":"尽管灰麻雀与荒漠麻雀在分类学上曾被视为同一物种的不同亚种，但由于存在明显的形态差异，现在被普遍认为是独立的物种。"},{"name":"麻雀","english_name":"Eurasian Tree Sparrow","scientific_name":"Passer montanus","overview":"麻雀（英文名：Eurasian Tree Sparrow，学名：Passer montanus），是雀形目雀科雀属的鸟类。俗名: 霍雀、瓦雀、琉雀、家雀、老家贼、只只、嘉宾、照夜、麻谷、南麻雀、禾雀、宾雀、北国鸟、户巴拉，广泛分布于欧亚大陆，具有栗色头冠和黑色面颊上的白色斑点，性别颜色相同。在中国全境均有分布，为常见的留鸟。","appearance":"麻雀体型略小于家麻雀，雄雌相似。头顶红褐色，幼鸟偏暗褐色；脸颊黑白色，喉部有少量黑色。成鸟头部丰满，背部暖棕色，带黑色条纹，翼上有两道白色翼纹，尾羽灰棕色，边缘淡黄色。嘴部黑色，基部常有淡黄色斑点。幼鸟色彩较暗淡，头顶有灰色斑点，耳斑不明显。","call":"鸣叫声尖锐，比家麻雀音调更高，带有较大的音高变化；飞行时发出更硬、更突然的音符；休息时发出干燥的“tecking”声；叫声鼻音重，双音节。","habits":"偏好轻度森林化开放地带，包括农田、公园、乡村和有树木的区域。以种子为主食，也摄取昆虫，尤其在繁殖季节。成群活动，春季和秋季时雄鸟会展示求偶行为，如同家麻雀，通过鸣叫和蓬松羽毛吸引雌鸟。","breeding":"繁殖期在春季至夏季，巢建在树洞、岩石裂缝或人造结构中，如屋檐和墙壁空洞。一窝产卵5到6枚，孵化期12-13天，雏鸟15-18天后离巢。每年可繁殖2-3窝。","identification":"与家麻雀相比，树麻雀体型更苗条，脸部有明显的黑色耳斑，而家麻雀无此特征，且头部较大，上体灰色而非棕色。此外，树麻雀的叫声更为尖锐。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布在帕拉尔地区和东方地区的农场、公园和城市，包括英国群岛、斯堪的纳维亚半岛南部、俄罗斯北部至南部楚科特卡、勘察加半岛、指挥官群岛，以及伊比利亚半岛南部等地。","other":"尽管麻雀繁殖能力强，但由于农业集约化和农药的使用，某些地区种群数量正在下降。"},{"name":"金麻雀","english_name":"Sudan Golden Sparrow","scientific_name":"Passer luteus","overview":"金麻雀（英文名：Sudan Golden Sparrow，学名：Passer luteus），是雀形目雀科雀属的鸟类。亦被称为金色歌雀，小型雀科鸟类，广泛分布在非洲撒哈拉以南的干燥地带。其最显著的特征是雄鸟的金黄色头部和下体，以及栗色的背部。雌鸟颜色较为朴素，上体沙棕色，下面淡黄带灰，略显黄色调。此物种有时与阿拉伯金麻雀合并为一，统称为\"金麻雀\"。","appearance":"金麻雀体型小，长约12-13厘米，重11-16克。雄鸟拥有金色的头部和下体，耳羽顶端常有灰色，背部栗色，臀部灰黄色。翅膀上的中覆羽和外覆羽黑色，尖端白色形成明显的双翼条纹。雌鸟上体沙棕色，脸部和下体淡黄色，具淡黄色眉纹，翅膀似雄鸟但更偏褐色。幼鸟与雌鸟相似，但背部有灰色斑点，下体更浅。雄鸟幼鸟在孵化后约10周开始显现肩部的黄色。","call":"金麻雀的基本叫声为啾啾声或类似其他麻雀的唧唧声。叫声变化多样，包括类似歌曲的叫声和快速节奏的\"che-che-che\"。","habits":"金麻雀栖息于干燥开阔的稀树草原、半沙漠、干旱灌木丛和谷物种植地。它们高度群居且游牧，常与其他种子食用鸟类如红嘴奎利亚雀和其他麻雀混合成群。傍晚在城市如喀土穆的栖息地可能聚集数十万只鸟。以种子为主食，也会摄取昆虫，特别是在喂养幼鸟时。","breeding":"金麻雀在大型殖民地中繁殖，巢穴由树枝搭建，呈大而杂乱的穹顶状，位于树梢，巢室内衬羽毛。每年产一到两窝，每窝通常有三至四枚蛋，蛋壳白色带暗斑。","identification":"雄性金麻雀通过其栗色背部与阿拉伯金麻雀相区别，而雌鸟则因颜色较暗和黄色调较少而易于识别。金麻雀与阿拉伯金麻雀虽相似，但分布范围几乎不重叠。","protection":"IUCN：LC（无危）","distribution":"繁殖于撒哈拉以南的萨赫勒地带，从毛里塔尼亚南部和塞内加尔北部向东延伸至苏丹东部、厄立特里亚北部和埃塞俄比亚远北地区。游牧性，分布范围随季节变化。","other":"金麻雀在鸟类学中曾被认为是极其原始的Passer属成员，与家麻雀关系较远。"},{"name":"阿拉伯金麻雀","english_name":"Arabian Golden Sparrow","scientific_name":"Passer euchlorus","overview":"阿拉伯金麻雀（英文名：Arabian Golden Sparrow，学名：Passer euchlorus），是雀形目雀科雀属的鸟类。有时被视为金麻雀的亚种。","appearance":"雄性阿拉伯金麻雀大部分体羽呈金黄色，翅膀和尾巴为黑白相间，非繁殖季节背部略显灰色，头部带有锈色。雌鸟则更朴素，背部为淡褐色，腹部偏白，全身泛着淡淡的黄色光泽。幼鸟与雌鸟相似，但上体有轻微斑点。雄鸟的虹膜深棕色，喙在繁殖季变为黑色，腿呈浅粉棕色。","call":"阿拉伯金麻雀的常见叫声是一系列清脆的颤音，类似于的双音节高音鸣叫。群鸟时持续发出柔和的叽叽声。","habits":"阿拉伯金麻雀主要栖息于干旱的荆棘灌木草原及附近的耕作地。它们基本定居，但在非繁殖季节有小规模的局部移动。它们以草籽和农作物种子为食，尤其偏好小米，常成小群觅食，非繁殖季节时可能形成数千只的大群。","breeding":"繁殖通常与雨季相关，已知在也门的3月至7月及吉布提的3月至5月。高度集群繁殖，单棵树上可筑20至30个巢。巢为紧凑的卵形结构，顶部呈穹顶状，侧面有入口，由细长的金合欢树枝编织而成，内部铺垫植物纤维和羽毛，筑于树上约2至3米处，常见于金合欢树上。","identification":"与金麻雀相比，雄性阿拉伯金麻雀背羽黄色而非栗色，雌鸟更亮黄，背部条纹不明显。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于西南阿拉伯半岛（沙特阿拉伯西南部、也门西部）、吉布提和索马里西北沿海地区。非繁殖期间有局部移动。","other":"阿拉伯金麻雀依赖于农作物生存，人类并未直接控制其数量，但其栖息地可能因人类活动而改变。非洲的分布可能是近期范围扩张的结果，可能是由于笼养鸟逃脱导致的。"},{"name":"栗麻雀","english_name":"Chestnut Sparrow","scientific_name":"Passer eminibey","overview":"栗麻雀（英文名：Chestnut Sparrow，学名：Passer eminibey），是雀形目雀科雀属的鸟类。最小的麻雀之一，身长仅约11厘米，以深栗色羽毛著称。常见于非洲东部的干燥草原和沼泽地带，包括苏丹南部至坦桑尼亚北部。其独特外观和群居习性使其易于识别。","appearance":"雄性栗麻雀全身呈深栗色，头部颜色更深，翅膀和尾巴为黑褐色，翼基部有淡色斑点。雌鸟和幼鸟背部为灰棕色，头顶、眉纹、喉部和胸部中央为栗色，下体淡色，腹部和两胁为淡栗色。雌鸟的嘴较雄鸟更淡，幼鸟与雌鸟相似但色调更淡，胸栗色减少。","call":"栗麻雀的基本叫声为低沉的啾啾声，变体包括斥责威胁声“chrrrrit”或“chrrrrreeeerrrrrrrr”和飞行叫声“chew chew”。展示中的雄鸟会发出高音颤鸣声“tchiweeza tchiweeza tchi-tchi-tchi-tchi see-see-see-seeichi”。","habits":"栗麻雀栖息于干燥的金合欢树（Acacia）草原，靠近沼泽或人类居住区，海拔可达2200米。非繁殖季节时，它们会游荡，形成大群，有时与其它鸟类混群。主要以草籽和杂草种子为食，也吃家庭残余食物。巢中雏鸟以昆虫为主食。","breeding":"繁殖期与雨季同步，全年均可繁殖，受织布鸟（Ploceidae）繁殖活动刺激。群居繁殖，巢穴为球形结构，侧入口，由干草筑成，内部铺有羽毛。有时会侵占织布鸟的旧巢，甚至驱赶巢主。每窝产3-4枚卵，孵化期在人工饲养条件下为18-19天，雏鸟可能仅由雌鸟喂养。","identification":"雄性栗麻雀与繁殖期的栗织雀相似，但体型更小，喙较小。雌鸟与家麻雀和索马里麻雀相似，但色彩更丰富。幼鸟与雌鸟相似，但更淡，胸栗色减少。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部的金合欢草原，从乍得中部（状态不明）、苏丹南部和埃塞俄比亚东北部至坦桑尼亚南部。在繁殖季节外，可能游荡至达累斯萨拉姆等远离繁殖地的区域。","other":"栗麻雀的命名来源于探险家Emin Pasha，由Gustav Hartlaub于1880年首次描述。曾被认为是Sorella属的唯一成员，但现在通常归类于雀属。"},{"name":"淡色石雀","english_name":"Pale Rockfinch","scientific_name":"Carpospiza brachydactyla","overview":"淡色石雀（英文名：Pale Rockfinch，学名：Carpospiza brachydactyla），是雀形目雀科淡色石雀属的鸟类。形似麻雀、雀科或百灵鸟，体长13.5至14.5厘米，体重21至25克。其分布于中东及中亚的半干旱地区，包括从土耳其东部至阿富汗，南至阿拉伯半岛和北非直至埃塞俄比亚。该物种在特定降雨条件下繁殖，与温度、昆虫丰度及栖息地条件密切相关。","appearance":"淡色石雀外表朴素，全身呈淡沙灰色，头部顶部颜色较浅，有不明显的浅色眉纹和眼下的区域。侧面头部呈灰褐色，颊纹较浅，与较暗的颊纹形成对比。背部淡沙灰色，上覆羽稍深，翅膀主要为深棕色，中覆羽和大覆羽有宽阔的米色尖端，形成双色翼条。二级飞羽有淡沙色边缘和尖端，形成淡色翼斑。尾巴较暗的灰棕色，羽毛边缘较浅，除中央一对外，其余尾羽尖端白色。下巴和喉咙为白色至淡黄色，胸部和上腹部颜色较深，呈淡灰色，其余下体部位为白色，带有可变的淡黄色色调。虹膜深棕色，喙为淡棕色，腿橙棕色。幼鸟与成鸟相似，但色泽更淡。","call":"淡色石雀的叫声为尖锐的鼻音“twee”、“zweee”或“twee-oo”。其歌曲单调，类似昆虫的嗡嗡声“tss tss tss tsseeeeeee”，通常在岩石顶或灌木丛中发出。飞行时发出柔和的颤音或咕噜声；在筑巢和孵化期间，伴侣会在巢附近发出二重唱叫声。","habits":"栖息于植被稀疏的干旱地区，常见于草皮覆盖的丘陵和山区，以及岩石峡谷，海拔可达3000米。非繁殖季节出现在开阔的农田。迁徙性鸟类，主要在西沙特阿拉伯和东北非洲（苏丹东部和东北部、厄立特里亚、吉布提和埃塞俄比亚北部）度过非繁殖季，偶尔出现在以色列南部、埃及和阿曼。离开繁殖地的时间为7月中旬至8月中旬；从2月中旬开始离开非繁殖地，3月中旬至4月中旬在阿拉伯大部分地区达到迁徙高峰，有时记录到大群（例如在阿拉伯联合酋长国3月中旬记录到1200只）。主要以植物为食，特别是种子，包括谷物和植物的绿色部分；繁殖季节也吃昆虫。在地面和低矮植被中觅食。成对或小群活动，非繁殖季节形成较大群体。","breeding":"被认为是在特殊降雨条件下繁殖的机会主义者，繁殖期从范围南部的3月持续至北部的7月，一般只繁殖一次。在松散的群落中筑巢，巢为开放的、庞大而不整洁的半球形，由带刺的枝条、植物茎和草构成，内部铺垫植物绒毛和动物毛发，位于灌木中，有时在岩石裂缝或建筑物的洞穴中。一窝产卵3至6枚，通常4至5枚；仅雌鸟孵卵，孵化期13至14天；雏鸟由双方喂养，巢期11至16天。","identification":"淡色石雀与其它鸟类的区别在于其独特的外观和声音。其与同属的物种区分较为明显，尤其是在头颈部的颜色和翼条上。叫声和歌曲也有助于与其他相似物种的辨识。","protection":"IUCN：LC（无危）","distribution":"繁殖于西亚，包括土耳其东南部、亚美尼亚、阿塞拜疆西部和南部、伊朗、土库曼斯坦南部和阿富汗西部，叙利亚南部至以色列南部，沙特阿拉伯北部、中部和东部，科威特和穆桑德姆半岛。非繁殖区主要在阿拉伯半岛南部、埃及东部、苏丹、厄立特里亚、吉布提和埃塞俄比亚东北部。","other":"在非繁殖季节，几百只的大群可能对谷物（小米）种植构成威胁，被视为害虫。"},{"name":"石雀","english_name":"Rock Sparrow","scientific_name":"Petronia petronia","overview":"石雀（英文名：Rock Sparrow，学名：Petronia petronia），是雀形目雀科石雀属的鸟类。中型雀类，共分为6个亚种。具有明显的黄色喉部斑点，与周围环境色调形成鲜明对比，这一特征对于繁殖季节内的吸引力和社交地位有重要意义。广泛分布于古北界的南部至中东、中亚和中国北方及蒙古，尤其偏好岩石裸露的地带和开阔的林地。","appearance":"石雀体型与家麻雀相似，长约14厘米，拥有粗壮的锥形喙。其头部有显著的白色眉纹和较弱的冠纹，背部和翅膀有斑驳的棕色图案，腹部有条纹，最独特的是一块黄色的喉部斑点，但这一特征在野外不易观察到。性别之间无明显差异，幼鸟比成鸟颜色更暗淡，缺乏黄色的喉部斑点。","call":"石雀发出响亮而略带嘶哑的叫声，种类繁多，主要为双音节，较为鼻音，如“pee-yee”或“jee-wee”。威胁声类似家麻雀的“terrettettet”。","habits":"石雀栖息于荒芜山丘及多岩的沟壑深谷，最高可达海拔3000米。它们常在开阔的耕地上觅食，如葡萄园、橄榄园，甚至接近旧建筑或进入人类居住区。主要以低矮植物的种子和草籽为食，秋季食用小浆果，繁殖季节则增加动物性食物如白蚁和甲虫，也捕食较大的猎物。","breeding":"繁殖季节通常在3月至8月，可繁殖两窝。巢建在岩石裂缝、树洞或孤立的废墟建筑中，偶尔也在有人居住的建筑物内。巢由草制成，内衬羽毛、动物毛发和羊毛，每次产卵4至7枚，孵化期11至14天，仅由雌鸟负责孵化，雄鸟偶尔参与喂养，幼鸟在巢中的时间为18至19天。","identification":"石雀与家麻雀相比，拥有更强壮的喙和更明显的黄色喉部斑点，这是辨识两者的关键特征。不同亚种间存在颜色深浅和条纹明显程度的差异。","protection":"IUCN：LC（无危）","distribution":"石雀在繁殖季节分布于马德拉群岛、加那利群岛、伊比利亚半岛、法国南部至土耳其、高加索、哈萨克斯坦西北和东南、俄罗斯南部、蒙古直至中国内蒙古；南部分布自摩洛哥至利比亚西北部，还包括以色列、约旦西部、伊拉克北部、伊朗南部、阿富汗西部，通过塔吉克斯坦和吉尔吉斯斯坦至中国新疆西北部，青海、甘肃南部至四川西北部。","other":"石雀在西班牙的种群密度估计为每10公顷土地上有1.6只鸟，但在耕地上的密度仅为每10公顷0.02只鸟。"},{"name":"黄喉石雀","english_name":"Yellow-throated Bush Sparrow","scientific_name":"Gymnoris superciliaris","overview":"黄喉石雀（英文名：Yellow-throated Bush Sparrow，学名：Gymnoris superciliaris），是雀形目雀科细嘴石雀属的鸟类。亦被称为黄喉petronia，主要分布在非洲南部至中部，包括从加蓬东南部至坦桑尼亚东北部，南至纳米比亚东北部和南非东南部的树林、灌木丛和农耕地带。","appearance":"黄喉石雀体长15-16厘米，体重22-30克。成鸟上体呈灰褐色，具显著的宽白色眉纹，眉纹自眼前方开始向后延伸至颈背处增宽，下缘由黑褐色眼纹衬托。背部有灰褐色条纹，飞羽覆羽尖端淡黄褐色；尾羽深褐色，边缘淡黄或暖黄褐色；喉部有一不显眼的黄色斑点；下体棕色，腹部中央偏白；虹膜深褐色，喙强壮，褐色，下颚较浅色；腿暗灰色。雌雄相似，幼鸟颜色更温暖的褐色，缺少黄色喉斑。不同亚种在上体颜色上有差异。","call":"鸣叫包括双音节的\"chlee-chlee\"或\"chew-chew\"，以及单音\"pick\"或\"peek\"；其歌为一系列杂乱的啾啾声，最多7个连续的音符，如\"tyee-tyee-tyee\"或\"tyoo-tyoo-tyoo-tyoo\"，有时更快，\"chichichichichichichew\"。低沉的叽叽喳喳声可能用于威胁。","habits":"栖息于树林、灌木丛、河流附近的灌木和耕地上，尤其在丘陵地带，海拔可达1500米，偶尔更高。季节性迁徙不明显，但在非繁殖季节会有局部游荡。以种子、花蜜和昆虫为食，通常在树的高枝上觅食，也常在地面活动。繁殖季外常见小群活动。","breeding":"繁殖期在刚果民主共和国、赞比亚、津巴布韦和南非林波波省为8月至11月，在莫桑比克为10月至11月，在南非东部为10月至1月，在纳米比亚为1月至2月，与雨季相吻合。巢为松散的草球，内衬厚羽毛，置于树洞中。每窝产卵3-4枚，仅雌鸟孵卵，孵化期17天；雏鸟由双亲共同喂养，巢中养育期18-19天。","identification":"与纹头丝雀相比，黄喉石雀具有更宽的眉纹和明显的翼带。与雌鸟sparrows的区别在于更明显的淡色眉纹和背部缺乏锈色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲南部至中部的树林、灌木丛和耕地上，从加蓬东南部至坦桑尼亚东北部，南至纳米比亚东北部和南非东南部。"},{"name":"小石雀","english_name":"Sahel Bush Sparrow","scientific_name":"Gymnoris dentata","overview":"小石雀（英文名：Sahel Bush Sparrow，学名：Gymnoris dentata），是雀形目雀科细嘴石雀属的鸟类。广泛分布于非洲的萨赫勒地带，自毛里塔尼亚至几内亚，东至厄立特里亚，及西南阿拉伯半岛干旱草原和干燥灌木丛中。","appearance":"小石雀长约13厘米，具长锥形喙和短尾。雄鸟头部主要灰色，有红褐色眉纹，耳羽和脸颊灰色，喉部奶油白色，胸部和两胁灰白色。雌鸟类似，但冠部更棕色，有较宽的白色眉纹，喙全年角质色，翼上有两条白色条纹。幼鸟似雌鸟，上体更棕褐色，眉纹为棕黄色。","call":"发出连续清脆的“chru-chru-chru”叫声，略带滚动感，音调低沉而干燥。","habits":"小石雀栖息于半干旱草原，带有零星树木和农田，常在村庄附近的开阔地。主要以小种子和昆虫为食，既在地上觅食也在树上搜寻。常单独、成对或小群活动，有时在食物丰富处形成较大群体。","breeding":"繁殖季节为11月至翌年3月。筑杯状巢于树洞、柱子裂缝或树干裂隙中，偶尔在树枝间构建松散的草堆巢。巢由双亲共同维护，孵化期14-17天，雏鸟由双亲喂养，巢中育雏期约13天。","identification":"与黄喉石雀区别在于眉纹标记和较小体型。雌鸟与家麻雀相似，但具有更长的喙和更宽的淡色眉纹。","protection":"IUCN：LC（无危）","distribution":"分布于非洲萨赫勒地带，从南部毛里塔尼亚到几内亚，向东至北部厄立特里亚，西部和中部埃塞俄比亚，南苏丹；也见于西南也门。"},{"name":"黄斑石雀","english_name":"Yellow-spotted Bush Sparrow","scientific_name":"Gymnoris pyrgita","overview":"黄斑石雀（英文名：Yellow-spotted Bush Sparrow，学名：Gymnoris pyrgita），是雀形目雀科细嘴石雀属的鸟类。其自然栖息地为干燥的草原和亚热带或热带的干草原低地。","appearance":"体长约15至16厘米，体重约21至28.5克。头部灰褐色，上部无条纹，具微弱的淡黄色眉纹，眼周白色，脸颊呈暗褐色；尾羽深棕色，外侧边缘灰黄褐色；喉部白色，下喉有黄色斑点（野外观察时较难见）；胸部灰色，腹部及以下部分为脏白色，腹部颜色更浅。虹膜深棕色，喙粉角色，腿蓝或蓝灰色。雌雄相似，雌鸟的喉部黄斑可能比雄鸟模糊。幼鸟与成鸟类似，但颜色更深，眉纹更明显，背部有条纹。pallida亚种比指名亚种更淡，上方沙色，下方清晰白色。","call":"叫声包括尖锐的“tyit”、“tyeet”和“chillip”，以及更低音调的、啾啾声“tlooey-tlooey”或“cherp-cherp”。歌唱声简单，为“chiew-chiew-chiew-chiew-tcheep”的重复。","habits":"在地面和树上觅食，主要食物为牙刷树（Salvadora persica）的浆果和种子，也会捕食昆虫，包括甲虫（Coleoptera）。以类似山雀（Paridae）的方式在树上寻找昆虫。通常成对或小群活动，常与小型织布鸟（Ploceidae）结伴。","identification":"与小石雀相似，但缺乏明显的眉纹标记。也与淡色石雀相似，但翅膀上的图案较少，喉咙处的白色定义更清晰。","distribution":"分布于非洲的萨赫勒地带和东北非干旱森林及花园中，从毛里塔尼亚南部和塞内加尔北部到厄立特里亚北部和索马里，再向南穿过埃塞俄比亚（除西部）到达乌干达东北部和坦桑尼亚中部。"},{"name":"栗肩石雀","english_name":"Yellow-throated Sparrow","scientific_name":"Gymnoris xanthocollis","overview":"栗肩石雀（英文名：Yellow-throated Sparrow，学名：Gymnoris xanthocollis），是雀形目雀科细嘴石雀属的鸟类。小型、色彩较为暗淡的雀科鸟类，无条纹，拥有独特的白色翼带。雄鸟在新鲜羽毛时有淡黄色喉斑和肩部的栗色斑块，雌鸟和幼鸟外观相似，但颜色较淡，缺乏明显的喉部黄色斑点和肩部栗色。广泛分布于亚洲南部，包括土耳其至伊朗、阿富汗、巴基斯坦、印度、孟加拉国等地。","appearance":"体长约12.5至14厘米，体重14至20克。头部细长，喙相对长而尖。雄鸟上体橄榄灰棕色，下体浅棕色至近白色，具淡黄色喉斑和肩部的栗色斑块，双翼上有明显白翼带。雌鸟和幼鸟类似雄鸟但色泽更淡，喉部黄色斑点和肩部栗色斑块不明显或缺失。","call":"发出特有的‘chilp’叫声，通常在高处栖息时发出，声音柔和且悦耳。","habits":"栖息于轻森林、灌木丛、村庄、农田地带，高度可达1500米。夏季访问土耳其东部至巴基斯坦和北印度，南方部分迁徙，冬季部分个体向南迁移。以植物种子为主食，辅以小浆果、花蜜及昆虫，尤其是鞘翅目、毛虫、蚱蜢和蚂蚁。群居，繁殖季节外形成较大群体。","breeding":"繁殖期在阿富汗为4月至7月，在印度主要为2月至5月，每年繁殖两窝。巢由雌鸟建造，常位于树洞、墙洞或建筑物孔隙中，或利用其他鸟类旧巢。每窝产卵3至4枚，偶尔5枚，仅雌鸟孵卵，双亲共同喂养雏鸟。","identification":"与其他雀科鸟类相比，具有较细长的喙，无条纹，双翼上的白色翼带是其显著特征。雄鸟与雌鸟的主要区别在于喉部和肩部的色彩差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖土耳其东南部至伊朗中部、阿富汗南部、喜马拉雅山脉下的巴基斯坦、印度西北平原、尼泊尔南部至印度东部比哈尔邦西部；非繁殖季节分布至叙利亚东部、伊拉克东部、科威特、阿拉伯半岛东南部至印度半岛南端。","other":"曾与非洲的黄斑石雀归为同一物种。"},{"name":"白斑翅雪雀","english_name":"White-winged Snowfinch","scientific_name":"Montifringilla nivalis","appearance":"身长16.5至19厘米，体型丰满，翅膀和尾巴相对较长。雄鸟头部蓝灰色至冬季转淡，上体巧克力棕色，翼上有大量白色斑块，尾羽大部分白色，仅中央一对黑色。下体白色，胸部微带浅棕色。雌鸟类似雄鸟，但色调更暗淡。幼鸟比雌鸟更暗淡，翼和尾的白色较少，喙明亮橙黄色。","call":"鸣唱复杂，含多种颤音和啾啾声，伴有重复的个别元素如'sitticher sitticher'。飞行时发出尖锐鼻音'pschieu'或'pchie'，以及'tsee'和柔和的'pruuk'或'kiek'声。","habits":"栖息于岩石裸露的高山地带，海拔2000至5300米之间，冬季会下降到较低高度。不畏惧人类，常在滑雪度假村附近觅食。食物以种子为主，夏季会吃昆虫。","breeding":"繁殖季节为5月至7月/8月，通常产两窝。在小松散群体或单独繁殖，每窝4-5枚蛋，由雌鸟孵化，孵化期12-14天，双亲共同喂养雏鸟，离巢前哺育18-22天。","identification":"与同属其他雪雀相比，白斑翅雪雀体型更大，翼部白色面积显著，尾羽黑白相间。雌雄鸟在非繁殖季颜色差异明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于南欧至中亚，包括西班牙、法国南部至奥地利、科西嘉岛、巴尔干半岛、希腊、土耳其南部、伊朗北部、阿富汗中部和东部、塔吉克斯坦、吉尔吉斯斯坦和哈萨克斯坦东南部，以及中国新疆西北部，远至俄罗斯南部和蒙古西部。","other":"历史上曾被错误分类为雀科，后归入雪雀属。"},{"name":"藏雪雀","english_name":"Tibetan Snowfinch","scientific_name":"Montifringilla henrici","overview":"藏雪雀（英文名：Tibetan Snowfinch，学名：Montifringilla henrici），是雀形目雀科雪雀属的鸟类。原作为白斑翅雪雀的亚种。藏雪雀小型棕色雀鸟，常见于青藏高原开阔的高山草原地带。雄鸟具有独特的黑色髭纹和深色喙，而雌鸟则缺少髭纹，拥有橙色喙，以及淡白色的眉纹，这在某种程度上与雌鸟和幼年家麻雀相似。飞行时白色翼斑尤为显眼。有时在旧版野外指南中，褐翅雪雀被错误地标记为藏雪雀。","appearance":"藏雪雀长约17厘米，体重约40克。雄鸟头部和颈背呈土褐色，披肩、背部及肩羽为深棕色，翼上有显著的白色斑块（飞行时尤其明显），胸前有一小块黑色饰羽，腹部灰色，两胁略带锈褐色。雌鸟整体颜色比雄鸟稍暗淡，胸前饰羽较小。幼鸟的描述尚未见报道。","habits":"藏雪雀栖息于高海拔的草原地带，从树线以上至雪线，海拔高度在2500至4500米之间。它们以种子和植物物质为食，育雏期间则以昆虫为主，包括甲虫（Coleoptera）和苍蝇（Diptera）的幼虫和成虫，以及蛛形纲动物。藏雪雀通常在小群体或大群中活动。","breeding":"藏雪雀在4月至5月间占据繁殖领地，繁殖季节为6月至8月。关于其繁殖行为的详细信息尚缺。","identification":"藏雪雀与非常相似的白斑翅雪雀主要区别在于体型较大，整体羽毛颜色较暗且较不鲜艳。雌雄鸟在髭纹和胸前饰羽上有明显差异。","protection":"IUCN：LC（无危）","distribution":"藏雪雀分布于帕拉尔区的高山草原地带，具体范围从青海东北部向南延伸至西藏南部，宽度约为100至250公里的地带。"},{"name":"褐翅雪雀","english_name":"Black-winged Snowfinch","scientific_name":"Montifringilla adamsi","overview":"褐翅雪雀（英文名：Black-winged Snowfinch，学名：Montifringilla adamsi），是雀形目雀科雪雀属的鸟类。这种壮实而形长的雪雀在克什米尔、喜马拉雅山脉、青藏高原及中国西北部均有分布。以高海拔草地和牧场上的短暂一瞥而闻名，其灰褐色的外观使其与环境融为一体。","appearance":"体长约17厘米。成年雄鸟头部灰棕色，具淡色眉纹和次嘴角纹，下颏和喉部黑色，有小白尖羽；上体灰棕色带深色条纹，臀部和上尾覆羽黑褐色；翼上覆羽暗棕色带宽白缘，大覆羽白色（有时内侧羽片有少许棕色），翼指暗棕色，翼端白色，主翼羽黑褐色带窄淡边，次级飞羽黑褐色带白色远端半部；尾白色，中央尾羽黑，所有尾羽具黑尖；下体乳白色，胸部微染黄褐色。雌鸟相似，但喉斑更淡，翅膀的黑色略带棕色。幼鸟与成鸟类似，但颜色更暖的棕色，翼上的白色较少，喉部灰褐色，喙基黄色。","habits":"褐翅雪雀占据岩石高海拔草原地带，接近高山村落，通常在溪流边缘和融化的雪地附近活动。它们的海拔活动范围在3500至5200米之间，但在夏季通常比白斑翅雪雀处于较低的高度。以高山植物种子和昆虫为食，在地面觅食，常在雪地边缘搜索，也会捕捉空中飞行的昆虫。繁殖季节外，它们会组成中等到非常大的群体。","breeding":"繁殖季为5月至7月。在松散的群体或孤立的对中繁殖。雄鸟有发达的降落展示飞行，悬停并展开翅膀和尾巴下落。巢由草、羊毛等材料构成，内衬毛发、羽毛和羊毛碎片，通常置于岩石裂缝或巨石下的洞穴中，较少见于鼠兔（Ochotona）的洞穴中。每窝产4枚卵；可能由双亲共同孵化；雏鸟由双亲喂养。无其他信息。","identification":"与白斑翅雪雀相比，褐翅雪雀的羽毛颜色对比度较低，翼上的白色部分较少。雌鸟的喉部斑点更淡，翅膀上的黑色略显棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于帕米尔高原、西藏高原的高山草原，靠近水源和村落，从印度拉达克至尼泊尔北部和锡金北部，青海东北部，甘肃西部至西藏东部和四川南部。非繁殖期保持在高海拔游荡。"},{"name":"白腰雪雀","english_name":"White-rumped Snowfinch","scientific_name":"Onychostruthus taczanowskii","overview":"白腰雪雀（英文名：White-rumped Snowfinch，学名：Onychostruthus taczanowskii），是雀形目雀科白腰雪雀属的唯一物种。小型鸟类，以其眼周的黑色斑块和明亮的白色翼斑与尾缘为显著特征。广泛分布于西藏、青海、甘肃、四川等地的高山地带，是常见的留鸟。","appearance":"白腰雪雀体长约15至17厘米，体重29至36克。具有结实且略尖的喙与长腿。头顶和颈背为灰棕色，前额和眉纹白色，眼周有黑色斑块；背部灰棕色，肩部和上背部有暗棕色条纹，臀部纯白；尾巴暗棕色，外侧羽毛逐渐变白至末端；翅膀的中覆羽黑色，端部白色，大覆羽暗棕色，边缘浅黄褐色（内侧大覆羽更白），飞羽黑色，基部有宽白色条纹，初级飞羽边缘白色，次级飞羽边缘浅黄褐色；下颚和喉咙白色，下体灰白色，胸部和两胁带灰黄褐色；虹膜棕色；喙呈淡角质色，顶端深色；腿黑色。雌雄相似，幼鸟颜色较温暖的棕色。","call":"其叫声为尖锐响亮的“duid duid”。鸣唱基于这一叫声，表现为短暂而响亮的“duid-ai-duid duid duid ai”，在类似云雀的展示飞行中发出。","habits":"白腰雪雀栖息于海拔3500至5100米的高山草地、草原和有稀疏植被的荒漠地带，常与鼠兔群落相伴，使用鼠兔的洞穴作为栖息和繁殖之所。冬季会接近人类居住区。主要食物为小种子和昆虫，尤其在繁殖季节偏好昆虫。善于地面觅食，快速奔跑，成对或小群活动，非繁殖季节形成较大群体。","breeding":"繁殖期为5月至8月，白腰雪雀在繁殖期间非常活跃，雄鸟围绕雌鸟鸣叫并相互追逐。营巢于岩石洞穴、废弃房屋墙洞或鼠兔的废弃洞穴中，巢由根和草制成，内衬兽毛和鸟羽。每窝产卵3至5枚，卵呈椭圆形，纯白色，平均大小约为25.7毫米x16.9毫米，新鲜状态下重约3.6克。孵化期9至15天，由雌鸟单独承担，雏鸟孵化时裸露，头部有灰色绒毛，眼睛在约7天后睁开。双亲共同喂养巢鸟和幼鸟，平均一窝能至少成功育成一只幼鸟。","identification":"白腰雪雀通过其独特的黑白配色、体型和栖息习性与同类区分开来，尤其是在使用鼠兔洞穴方面。","protection":"IUCN：LC（无危）。在整个分布区内普遍常见，但在南部地区如拉达克和尼泊尔较为罕见。","distribution":"繁殖区域：位于帕米尔高原的高山草原，包括远西北印度的拉达克东南部，向东延伸至西藏、青海东北部和甘肃南部，南至四川西北部（中国中部），并向南延伸至尼泊尔西北部和锡金北部。非繁殖季节，会迁至较低海拔和定居点。"},{"name":"黑喉雪雀","english_name":"Pere David's Snowfinch","scientific_name":"Pyrgilauda davidiana","overview":"黑喉雪雀（英文名：Pere David's Snowfinch，学名：Pyrgilauda davidiana），是雀形目雀科黑喉雪雀属的鸟类。小型的、外观较为暗淡的类似雀类的鸟类，雄鸟特征显著，脸部有大片黑色斑块，从头顶延伸到喉咙；雌鸟具有明亮的橙色喙。广泛分布于俄罗斯南部阿尔泰山脉至蒙古及中国北方的多石山区和半荒漠地带，通常靠近水源活动。","appearance":"黑喉雪雀体长12至15厘米，体重约20至25克。雄鸟具有黑色的额头、眉纹、下巴和喉咙，上部体羽呈土褐色，背部有深色条纹，耳羽呈浅棕色；雌鸟喙色较亮，呈灰色至稻草色。两性皆为上部体羽淡棕色，下部体羽污白色。幼鸟比成鸟颜色更浅，脸部无黑色斑块。","call":"黑喉雪雀相对沉默，但群体中会持续发出轻柔的叽叽声作为联系。","habits":"黑喉雪雀栖息于半干旱环境，如石质平原、岩石高原和沙漠边缘，海拔1000至3000米，有时可达4500米。它们主要以小种子和昆虫为食，常在地面快速移动，也会在牲畜粪便中寻找食物。繁殖季节外，它们以对或小群体的形式出现，非繁殖季节则形成较大规模的群体。","breeding":"繁殖季节为5月至7月早期或8月初。它们以孤对或松散的群体形式繁殖，领地性强。巢由干草、羊毛和软植物材料构建，位于小型哺乳动物洞穴入口0.5至2.3米处，如土拨鼠、鼠兔和仓鼠的洞穴，或自挖洞穴。每窝产卵5至6枚，由雌鸟孵化，孵化期为11至13天。幼鸟孵化后19至22天离巢。","identification":"与同属物种相比，黑喉雪雀的黑色面部斑块和雌鸟的橙色喙是其显著的识别特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在帕拉尔区的蒙古山地多石草原：俄罗斯南部、蒙古以及中国青海东北部至内蒙古（中国北部和东北部）。","other":"黑喉雪雀在部分地区分布稀少，但在某些地方却相当常见乃至丰富。"},{"name":"棕颈雪雀","english_name":"Rufous-necked Snowfinch","scientific_name":"Pyrgilauda ruficollis","overview":"棕颈雪雀（英文名：Rufous-necked Snowfinch，学名：Pyrgilauda ruficollis），是雀形目雀科黑喉雪雀属的鸟类。这色彩鲜明的雪雀，拥有独特的橙色颊后新月状标记，容易与棕背雪雀混淆，但其脸部两条相等长度的黑色条纹形成直角，构成显著特征。广泛分布于开阔的高原草地、牧场及人类居住地附近。","appearance":"棕颈雪雀体型介于13至15厘米，体重23至28克。头部图案独特，包括灰色顶冠、白色眉线、眼通过的黑色线条以及黑色髭纹，脸颊后部由红色带环绕延伸至颈部侧面；上体有深褐色条纹，下背至尾羽覆羽为均匀的棕色；翅膀棕色，中覆羽和大覆羽有宽白尖；飞行羽黑色边缘较浅，二级飞羽和内侧初级飞羽基部有白色斑块；尾羽中央对深棕色，外侧羽毛主要为白色尖端；下体奶油白色，胸部侧面带有姜黄色色调；虹膜红棕色；喙暗灰色，繁殖季节变为黑色；腿黑色。雌雄相似，雌鸟头部有时更棕色，翼上的白色较少。幼鸟比成鸟更平淡、更棕色。","call":"发出柔和的“duuid”或“doooid”叫声，报警时会发出类似Common Magpie的叽叽喳喳声。展示飞行时伴有嗡嗡声。","habits":"栖息于高海拔的贫瘠石质草原和草甸，尤其偏好靠近小水道的边缘和人类居住区附近的垃圾堆；与鼠兔（Ochotona）和田鼠（Microtus）的群体有关联。以种子和昆虫为食，在地面觅食，能挖掘并利用双腿和喙寻找食物。成对或小群活动，非繁殖季节形成较大群落。","breeding":"5月初开始筑巢，巢通常建在墙洞、土岩或鼠兔废弃的洞穴内，由雌雄共同建造，巢外层为干草，内层有羊毛、羽毛。卵重约2.5克，大小约为21×16毫米，纯白色，比白斑翅雪雀的卵小。","identification":"与棕背雪雀相比，本种脸部具有两条黑色条纹，形成直角，且颜色更加鲜艳。种族isabellina比指名亚种更淡。","protection":"IUCN：LC（无危）","distribution":"主要分布于西藏和中国中部、西部相邻地区，包括新疆西南部至青海和甘肃西部，南部从拉达克东部、尼泊尔北部、锡金北部到四川西部。冬季向南迁移至印度Uttarakhand、尼泊尔、锡金和不丹，有时降至较低海拔。"},{"name":"棕背雪雀","english_name":"Blanford's Snowfinch","scientific_name":"Pyrgilauda blanfordi","appearance":"该鸟具有色彩鲜明的特征，头前部白色被黑色条纹分割，眼周有黑色线条，颊部呈奶油色，颈背和上背部为红栗色，胸侧有一小块黑色斑点。上体沙棕色，具深棕色条纹；翅膀覆羽与背部相似，初级覆羽较暗，飞羽深棕色边缘略白，形成明显的白色翼斑。尾中央羽毛棕灰，其余部分白色带暗色斑点及黑白相间或纯黑色的尖端。下体乳白色，胸部带有暖色淡黄褐色。雌雄相似，但雌鸟头部标记可能较为灰暗，黑色较少。幼鸟头部图案类似淡化版成鸟，下巴深灰色，喉咙和下体灰色偏黄，喙黄色。","call":"棕背雪雀发出快速的啾啾歌声，既能在地面也能在展示飞行中发出。","habits":"栖息于海拔3000至5500米的高寒地带，包括青藏高原上的多石草原和半荒漠地区。它们常成对活动，冬季会聚集于低洼避风的山谷、凹地、牛羊圈及居民点附近。以昆虫和种子为主食，冬季完全依赖植物。飞行距离短且不高，耐高寒。","breeding":"繁殖期记录自五月到六月初，筑巢于小型哺乳动物（如鼠兔）的洞穴中，具体繁殖细节信息有限。","identification":"与棕颈雪雀相似，但可通过脸部的特征性图案进行区分：白色前额被黑色条纹分割，黑色眼线，奶油色脸颊，以及红栗色的颈背和上背部。","protection":"IUCN：LC（无危）","distribution":"分布于青藏高原的阿尔卑斯式多石和草地高原：从新疆东南部向东穿过青海，向南至拉达克东部、尼泊尔北部、锡金北部直至四川西北部。","other":"物种命名纪念了英国动物学家威廉·托马斯·布拉福德（William Thomas Blanford）。"},{"name":"阿富汗雪雀","english_name":"Afghan Snowfinch","scientific_name":"Pyrgilauda theresae","overview":"阿富汗雪雀（英文名：Afghan Snowfinch，学名：Pyrgilauda theresae），是雀形目雀科黑喉雪雀属的鸟类，仅见于阿富汗北部兴都库什山脉的高山地带。物种面临威胁较小，故被IUCN评估为无危状态。其主要以种子为食，辅以昆虫。","appearance":"阿富汗雪雀体长13.5至15厘米，体重23至35克。雄鸟呈灰褐色，翅膀带有白色，面部有黑色面罩，喉部有双叉斑块。雌鸟颜色较淡，翼上白色较少，面罩灰色且较弱。幼鸟羽色细节未知，但推测与雌鸟相似。雄鸟眼睛呈砖红色。","call":"阿富汗雪雀的警戒声为尖锐的'tsi'声，飞行时发出柔和的'quaak'声，以及类似'zig-zig'的颤音。","habits":"阿富汗雪雀栖息于石质山坡、高原及山口开阔地带，海拔高度2575至3000米。冬季大雪后会向低海拔和北方向的巴德吉斯省迁移，形成大群，有时与其他雪雀、岩雀及多种鹨混群。","breeding":"筑巢于鼠类（如土拨鼠、旱獭和威廉姆斯跳鼠）挖掘的洞穴中，巢内铺垫鼠毛、羊毛、骆驼毛和羽毛。幼鸟孵化时盲而无助，全身裸露，仅有少许浅色绒毛。","identification":"与白翅雪雀相比，阿富汗雪雀翼上的白色斑点更小，体羽更偏褐色。与沙漠雀在外观上有相似之处，但阿富汗雪雀条纹更明显，面部标记更强烈，喙较小。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于欧亚大陆的帕米尔高原，具体在阿富汗中部的高山地带。非繁殖季节会迁至土库曼斯坦南部（罕见记录）。","other":"1937年首次由Richard Meinertzhagen科学记录，以他的表妹Theresa Clay命名，她是鸟类寄生虫专家。"},{"name":"白嘴牛文鸟","english_name":"White-billed Buffalo Weaver","scientific_name":"Bubalornis albirostris","overview":"白嘴牛文鸟（英文名：White-billed Buffalo Weaver，学名：Bubalornis albirostris），是雀形目织雀科牛文鸟属的鸟类。主要分布在非洲中南部地区，从毛里塔尼亚和塞内加尔到苏丹、厄立特里亚、埃塞俄比亚和肯尼亚西部。这种鸟体型大而健壮，以黑色为主，背部和翅膀带有白色斑点，雄鸟的喙呈白色，而雌鸟为黑色。","appearance":"白嘴牛文鸟体长约23厘米，体重约70克。雄鸟具有黑色羽衣，翅膀基部边缘为白色，肩部前方有一块明显的白色斑块，飞行时翼上有一淡色斑块较为显眼。雌鸟喙为黑色，幼鸟为深棕色，下部有重条纹。雄鸟特有的羽毛杆状结构（phalloid organ）从腹部突出，长度约15毫米。","call":"常见叫声为刺耳的‘sjet’声，通常由一群鸟连续合唱。雄鸟鸣唱开始为‘tschutchutchutchu’的颤音，随后是一串尖锐的‘skwee-skwee-skwee-kereekerilli-kerilli-keree’的叫声，形式多样。求偶时，雄鸟发出独特的双音节叫声，雌鸟则回应以嘶嘶声。","habits":"栖息于干燥的灌木草原和林地，常成群活动。以种子（包括作物如小米）、水果、昆虫（如蚱蜢、白蚁、甲虫及其幼虫）、小型动物（如青蛙）为食。在地面觅食，亦在牛粪中寻找昆虫，帮助牛只去除体外寄生虫如蜱虫。","breeding":"繁殖季节通常为7月至9月，有时在西非国家延长至10月至11月，埃塞俄比亚和厄立特里亚则为2月至3月。一夫多妻制，群体筑巢，巢直径超过1米，由干刺枝构成，高至10米的树上。每巢有多个独立的巢室，内部铺垫草、绿叶、根须和羊毛。每次产卵2至4枚，颜色从白色到浅绿色或蓝色，表面有灰色和灰褐色的斑点。仅雌鸟孵卵和喂养雏鸟，孵化时间和育雏期未知。平均每个巢有2.5只幼鸟存活。","identification":"与红嘴牛文鸟的区别在于后者不会出现红色喙。白嘴牛文鸟雄鸟有明显的白色肩斑和喙，雌鸟和幼鸟的外观显著不同。","protection":"IUCN：LC（无危）","distribution":"分布于撒哈拉沙漠以南的非洲大部分地区，具体从毛里塔尼亚、塞内加尔、冈比亚、几内亚比绍东部、几内亚南部至乍得中部、苏丹南部、埃塞俄比亚西南部、厄立特里亚西部、乌干达东北部和肯尼亚西北部。最近在坦桑尼亚北部确认其分布，但缺乏繁殖证据。","other":"在坦桑尼亚塞伦盖蒂国家公园记录到了可能的分布范围扩展。"},{"name":"红嘴牛文鸟","english_name":"Red-billed Buffalo Weaver","scientific_name":"Bubalornis niger","overview":"红嘴牛文鸟（英文名：Red-billed Buffalo Weaver，学名：Bubalornis niger），是雀形目织雀科牛文鸟属的鸟类。体型较大的编织鸟。其显著特征是巧克力棕色的羽毛和鲜红的喙及腿。分布于非洲东部、东南部和南部的干草原和稀树草原。","appearance":"红嘴牛文鸟体长22厘米，雄鸟重65至98克，雌鸟59至90克。雄鸟全身呈深巧克力色，具红色腿脚和厚实的朱红色喙。雌鸟和幼鸟颜色较淡，腹部有条纹，喙色较浅。飞行时，白色翼斑十分醒目。雄鸟具有独特的未穿孔羽毛棒（‘phalloid organ’），长约16毫米，而雌鸟的相应器官较小，平均长度约6毫米。雏鸟为淡褐色，下体有白色斑点。","call":"它们的叫声独特，带有电子音效，常吸引人注意。","habits":"偏好干燥灌木丛，如mopane和混合金合欢-猴面包树林，通常在大型哺乳动物践踏过的草地栖息。以昆虫为主食，包括甲虫、蝗虫、毛虫、蝽象、蚂蚁、黄蜂和苍蝇，也会食用蜘蛛、蝎子、种子和果实。群居，地面觅食，有时与其他鸟类如椋鸟、卷尾、雀鸟和伯劳共同活动。","breeding":"繁殖季节主要在3月至6月，也可能双窝繁殖。采取一雄多雌制或合作多配偶制。巢由雄鸟建造，位于高大树木中，如猴面包树、铅木、金合欢、马拉拉树，甚至黄嘴鹮鹳巢基部。巢穴长达数年，由荆棘枝条构成，每巢含有多间孵化室。雌鸟单独孵卵，孵化期11至14天，雏鸟喂养主要由雌鸟承担，巢期20至23天。","identification":"与白嘴牛文鸟的区别在于后者没有红色或橙色的喙。雄鸟的'phalloid organ'比雌鸟的大，且雄鸟的喙和腿更红。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部、东南部和南部，包括肯尼亚、坦桑尼亚、南非等地的干草原和稀树草原。","other":"红嘴牛文鸟的巢穴有时会成为其他物种如非洲侏隼、栗头丽椋鸟、红头环喉雀和蓝顶蓝饰雀的栖身之所。"},{"name":"白头牛文鸟","english_name":"White-headed Buffalo Weaver","scientific_name":"Dinemellia dinemelli","overview":"白头牛文鸟（英文名：White-headed Buffalo Weaver，学名：Dinemellia dinemelli），是雀形目织雀科白头牛文鸟属的大型、粗壮而美丽的鸟类，自成一属。头部和下体白色，上体和尾部褐色，臀部和腰部呈红棕色，肩羽有醒目的红棕色小斑。分布于非洲东部和中东部，常见于干燥灌木丛和稀树草原，偏好低于1400米的地带。","appearance":"体型较大，长度约18厘米，体重57至85克。主要特征为白色头部，额头、顶冠和颈背白色，眼周有黑色裸露皮肤，背部暗棕色，臀部和尾上覆羽橙红色。翅膀和尾巴深棕色，初级飞羽黑色，翼上的大覆羽、次级飞羽、三级飞羽和最外侧尾羽边缘有窄白色边。喉部和下体白色，大腿深棕色，下尾覆羽橙红色。虹膜棕色，喙黑色，腿色深灰。性别相似，幼鸟具明显口角肉垂，尾覆羽起初呈淡橙色而非红棕色。","call":"发出尖锐鼻音的缓慢歌曲，包含刺耳的哨声和颤音，如“tsu-weely-weely-wair”、“tsu-weely-weely-tsair-tsu”。还有尖锐叫声“skwieeeer”、“errrrrrh”或“kiiyerr”，以及连续间隔的清脆‘tew’声。","habits":"主要以昆虫为食，也吃种子和果实，如鞘翅目和鳞翅目幼虫。通常在地面觅食，常成群活动，由3至6只组成，经常与其他鸟类混群，如Plocepasser和椋鸟科（Sturnidae），在索马里与栗头丽椋鸟和白冠丽椋鸟特别相关联。肯尼亚地区，常加入混合物种群在开阔林地中活动。","breeding":"繁殖季节随当地降雨而变，一般在8月至9月（苏丹）、4月至8月（埃塞俄比亚）、2月至6月和9月（索马里）、5月（乌干达）、2月至3月、5月、7月和11月（肯尼亚）、12月（坦桑尼亚）。一夫一妻制。巢由两性共同建造，为大型椭圆形结构，长约0.5米，外壳由带刺树枝构成，入口向下开的小通道，内部以干草茎、叶子和羽毛铺垫。巢高2至4米，通常位于树枝上或悬挂在枝端或枝下。每窝产卵3至4枚，卵灰色或浅蓝色，密布橄榄褐色和灰褐色斑点，平均尺寸24.6×18毫米（肯尼亚数据）。孵化期未知，两性共同喂养幼鸟，巢中养育期至少14天（圈养数据）。","identification":"与其他牛文鸟区别在于头部和下体白色，臀部和腰部红棕色，翼上有明显的白色带。与 dinemelli相比， boehmi的背部、翅膀和尾巴主要为黑色，白色边缘减少。","protection":"IUCN：LC（无危）。在其分布范围内普遍常见，主要栖息在人口稀少的干旱地区，并存在于其分布范围内的保护区。","distribution":"分布于非洲东部和中东部，包括埃塞俄比亚、肯尼亚、索马里、苏丹、坦桑尼亚和乌干达。在海拔低于1400米的干燥灌木丛和稀树草原栖息。","other":"两个亚种被确认。有时会利用白眉织雀旧巢，其巢穴可能被非洲侏隼占用，也被环喉雀使用。"},{"name":"白眉织雀","english_name":"White-browed Sparrow-Weaver","scientific_name":"Plocepasser mahali","overview":"白眉织雀（英文名：White-browed Sparrow-Weaver，学名：Plocepasser mahali），是雀形目织雀科雀织雀属的鸟类。中等体型的褐色小鸟，常见于非洲中部和北部的南部地区。这种鸟通常以家庭群体的形式居住在干燥的灌木丛和较干旱的阔叶林地带。","appearance":"白眉织雀长约17至19厘米，最显著的特征是宽阔的白色眉纹和飞行时可见的白色臀部。雄鸟拥有黑色的喙，而雌鸟的喙呈角色(淡灰色)，幼鸟喙色为粉棕色。在津巴布韦，白眉织雀的胸部带有淡淡的褐色斑点。","call":"白眉织雀的鸣叫包括短暂的'chik-chick'声或响亮流畅的'cheoop-preeoo-chop'口哨声。","habits":"白眉织雀主要栖息于年降雨量超过600毫米的开阔莫潘尼(Mopane)和金合欢(Acacia)草原，海拔通常低于1400米。它们的饮食包括昆虫和种子，昆虫部分占比可达50%，如白蚁、甲虫、毛虫和蚂蚁等。白眉织雀主要在地面觅食，也会翻滚石头或挖掘土壤寻找食物。","breeding":"白眉织雀全年繁殖，但在温暖季节更为集中。它们在树上建造倒U形的干草巢，每巢只有一个入口用于繁殖，而两头开口的巢用于栖息。雌鸟独自孵卵，孵化期约为14至16天。幼鸟出生后最初几天仅由雌鸟喂养，之后雄鸟和其他辅助者也参与喂养。","identification":"白眉织雀与黄喉Petronia的区别在于后者具有粉色棕色而非黑色的喙，黄色而非白色的眉纹，黑色而非粉色的脚，以及喉咙底部的黄色色调。白眉织雀比黄喉Petronia体型更大。","protection":"IUCN：LC（无危）","distribution":"白眉织雀广泛分布于非洲中部和北中部的南部地区，包括博茨瓦纳、纳米比亚北部和中部、津巴布韦西部、南非北部、赞比亚南卢安瓜国家公园和马拉维南部。部分地区如莫桑比克的赞比西河谷估计个体数量超过100万。","other":"白眉织雀的巢穴有时会被其他鸟类如红头雀和灰顶雀使用。"},{"name":"栗顶织雀","english_name":"Chestnut-crowned Sparrow-Weaver","scientific_name":"Plocepasser superciliosus","overview":"栗顶织雀（英文名：Chestnut-crowned Sparrow-Weaver，学名：Plocepasser superciliosus），是雀形目织雀科雀织雀属的鸟类。大型的具有鲜明图案的织雀。其显著特征为头部大部分呈栗色，拥有白色喉部和眉纹，以及黑色髭纹。两道白色的翼带在飞行时尤为显眼。广泛分布于非洲南部撒哈拉沙漠以南地区，从塞内加尔和冈比亚至厄立特里亚、埃塞俄比亚和肯尼亚西部。","appearance":"栗顶织雀体型较大，最引人注目的是其栗色的头部，搭配白色的喉部和眉纹，以及黑色的髭纹。双翼上两道白色翼带在飞行时尤为突出。雌雄和幼鸟的羽毛颜色和大小在此描述中未提供具体差异。","call":"栗顶织雀的叫声是一段长而连续的颤音，其歌声则是一连串高音速射的音乐性音符，有时可以持续很长。","habits":"生活在多种林地和草原生境中，常以小群出现，但通常较为隐蔽。在繁殖季节以外，它们可能在更广阔的范围内移动。","breeding":"繁殖时间在不同地区有所不同，例如在冈比亚为9月至11月，在尼日利亚为4月至8月，在苏丹为5月至6月。巢由干草茎构成的水平管状结构，位于离地面高达6米的树枝上，一树上可能有多个巢。每窝产2枚蛋，蛋壳颜色为奶油色或红色，布满灰色和淡紫色斑点，平均尺寸为22.6 x 15.3毫米。","identification":"与白眉织雀相似，但通过头部和背部的栗色以及更加复杂的面部图案容易区分开来。","protection":"IUCN状态未知。","distribution":"主要分布在非洲南部撒哈拉沙漠以南地区，具体包括从冈比亚和塞内加尔向东延伸到中非共和国北部、苏丹西南部，然后向东到达厄立特里亚、埃塞俄比亚和肯尼亚西部。"},{"name":"肯尼亚织雀","english_name":"Donaldson Smith's Sparrow-Weaver","scientific_name":"Plocepasser donaldsoni","overview":"肯尼亚织雀（英文名：Donaldson Smith's Sparrow-Weaver，学名：Plocepasser donaldsoni），是雀形目织雀科雀织雀属的鸟类。体型较大，具有独特的外观特征。分布于非洲南部，从埃塞俄比亚南部至肯尼亚中部和索马里南部。","appearance":"成年鸟长约17厘米，体重35至45克，外观类似大型麻雀，头部顶部有鳞状斑纹，额头和头顶为暗褐色，边缘略显淡色，形成鳞片效果；颈背和上身呈棕色，臀部白色；上翼和尾巴深棕色，飞羽覆羽有明显的白色边缘；下巴和喉咙白色，有一条狭窄的黑色颊纹延伸至翅膀水平位置；胸部白色，羽毛中央有浅棕色条纹，有时在下体形成宽条带，两胁淡棕色，腹部、大腿和尾下覆羽白色；虹膜红褐色；喙黑色；腿淡棕色。雄雌相似。幼鸟头部无鳞状斑纹，颊纹不明显，胸部标记较淡，两胁淡黄色，虹膜棕色，喙角质色，腿灰色。","call":"其鸣唱为一段杂乱的音符组合，包括刺耳声、哨音和颤音，语句开始和结束时最为响亮；频率低于肯尼亚境内共栖的白眉织雀。通常在筑巢时鸣唱。接触叫声为响亮的“chink-chink”和柔和的“cluk cluk”。","habits":"主要以草籽和昆虫为食，常在地上觅食。小群活动，偶尔与白头牛文鸟一同出现。","breeding":"在肯尼亚的1月、6月、7月、9月和12月繁殖。繁殖系统信息不明，可能为合作性繁殖者。巢穴由干草茎构成的管状结构，类似于其他雀织雀的巢，位于离地面1.5到3米高的低矮荆棘树或灌木丛中，一棵树上最多可有20个巢。关于蛋的颜色和数量的记录不详；已知蛋壳呈粉红色或灰色，带有细小分散的紫罗兰色和红棕色斑点。","identification":"与白眉雀织雀相比，可通过不同的头部图案和斑驳而非纯白的下体来区分。","protection":"IUCN状态未提及。","distribution":"分布于非洲，具体范围从埃塞俄比亚南部至肯尼亚中部和索马里南部。"},{"name":"栗背织雀","english_name":"Chestnut-backed Sparrow-Weaver","scientific_name":"Plocepasser rufoscapulatus","overview":"栗背织雀（英文名：Chestnut-backed Sparrow-Weaver，学名：Plocepasser rufoscapulatus），是雀形目织雀科雀织雀属的独特鸟类，以淡色喙、鲜明的头部花纹、栗色背部和白色翼纹为显著特征。广泛分布于非洲南部，自安哥拉和刚果民主共和国南部至赞比亚和马拉维一带的米奥诺阔叶林地带。","appearance":"体长约18厘米，体重约39至49克。外观类似大型麻雀，头上有厚重的黑白条纹，背部呈栗色。额头黑色，头顶有一条宽大的中央白纹被黑色带环绕，眉线从喙附近延伸至颈背，眼周和脸颊黑色；上体呈深红棕色，臀部灰色，尾巴灰褐色；翅膀上部暗棕色，三级飞羽和翼覆羽边缘呈浅黄色，上翼覆羽尖端白色形成翼纹；下巴和喉咙白色，脸颊黑色条纹；胸部、侧腹、腹部、大腿和下尾覆羽呈灰白色；虹膜红棕色；喙白色或黑色，不同季节可能变色；腿粉色。雌雄外观相似。幼鸟似成鸟，但背部颜色较淡，脸颊条纹不明显，虹膜深棕色，喙黑褐色。","call":"最常听到的叫声是一种松散、金属般的颤音。","habits":"这种鸟在地面上觅食，但在树上也很显眼。它栖息于米奥诺阔叶林中，通常保持安静，不易察觉。","identification":"与白眉织雀相似，但通过淡色喙、头部条纹和栗色背部容易区分。","protection":"IUCN状态未知。","distribution":"非洲南部，分布于安哥拉和刚果民主共和国南部至赞比亚和马拉维。","other":"无"},{"name":"棕尾织雀","english_name":"Rufous-tailed Weaver","scientific_name":"Histurgops ruficauda","overview":"棕尾织雀（英文名：Rufous-tailed Weaver，学名：Histurgops ruficauda），是雀形目织雀科棕尾织雀属的鸟类。自成一属。其独特之处在于鳞状羽毛、棕红色尾羽和翼部，肩部镶白边，眼睛颜色较淡。在中海拔的湿润灌木丛和林地中活动，常见于小群结队。在坦桑尼亚繁殖，偶尔在肯尼亚也有迷鸟记录。","appearance":"体长约21厘米，体重60至70克。拥有斑驳的羽毛，头部、披肩和背部呈深棕色，边缘有浅色羽缘，臀部和上尾覆羽棕红色带暗色条纹；尾羽棕红色，中间两根较暗；翅膀棕色，飞羽带有粉红至棕红色边缘和内侧网膜；下体白色，下颌、喉咙、腹部、大腿和下尾覆羽有深色条纹，胸部和侧羽上有深棕色的滴状图案；虹膜蓝白色；上喙黑色，下喙棕色基部泛白；腿灰色。雌雄相似，幼鸟比成鸟更暗，下体有鳞状斑点，虹膜褐色，喙黄绿色。","call":"发出尖锐的鼻音“skeeya”和“krrrra”音符，有时连串成一系列声音。","habits":"栖息于中等湿度的草原和林地，以种子、昆虫和果实为食，胃中常含较多昆虫而非种子。通常在地面觅食，进食时做短距离低空飞行。群体可达25只，常与栗头丽椋鸟或红嘴牛文鸟相伴。","breeding":"繁殖期记录于5月至6月、8月及10月至次年2月。实行单配偶制，集群筑巢，每棵树最多可有30个巢。巢由草类编织成圆柱形，初期有两个入口，产卵后封闭一个，留下约10厘米长的宽管状出口，置于1.5至4米高的金合欢树（如Acacia drepanolobium或Acacia tortilis）上。巢被非洲鬣鹰掠夺。","identification":"与红嘴牛文鸟形状和大小相似，但细节上明显不同，如无红色喙，且虹膜颜色、尾羽颜色等特征明显区分。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲的坦桑尼亚，偶尔有记录在肯尼亚。"},{"name":"灰头群织雀","english_name":"Grey-capped Social Weaver","scientific_name":"Pseudonigrita arnaudi","overview":"灰头群织雀（英文名：Grey-capped Social Weaver，学名：Pseudonigrita arnaudi），是雀形目织雀科伪群织雀属的鸟类。具有独特的浅灰色头冠、暗灰色喙、白色眼环和角质腿。以群居形式在刺槐树上建造草制屋顶巢穴，主要在非洲中东部的干燥草原和耕作地带活动，以草籽和昆虫为食。雌雄羽色相似，DNA分析证实其属于织雀科。","appearance":"灰头群织雀体型小巧，长度约11至12厘米，体重介于15至26克之间。其特征为淡灰色的头冠、深灰色的喙、白色的环眼圈和角质的腿。翅膀和尾巴带有黑色，尾巴末端有一条明显的浅色带，飞行时尤为明显。成年雄鸟的头冠几乎纯白，而雌鸟的头冠更偏淡灰色。幼鸟羽毛较暗淡，喙呈棕色，头冠为浅褐色。","call":"发出一系列尖锐的高音叫声，通常由7至10个元素组成，包括滚动和颤音的飞行叫声以及接触叫声；领地展示时会发出响亮的\"cheep\"声，警戒时也会发出单个\"cheep\"声。","habits":"栖息于干燥的草原和耕作区，常以群体形式活动。饮食上，它们以混合的草籽和昆虫为食，包括蚱蜢、甲虫、白蚁和毛虫。取食主要在地面进行，定期饮水。","breeding":"繁殖活动全年皆有记录，高峰出现在苏丹的8月至12月和东非的3月至5月。它们通常是单配偶制，有时会形成合作繁殖系统，如在肯尼亚的一个群体中，25%-30%的巢穴有帮手参与。巢穴建于刺槐树上，由成对的鸟儿共同搭建，巢穴结构复杂，附着于细枝，常用抗蚁刺槐（Acacia drepanolobium）等树种。巢穴可被其他鸟类如环喉雀和栗麻雀再利用。一窝产3-4枚蛋，颜色从绿色到蓝白色不等，平均尺寸为19x14毫米。孵化期13-14天，由双亲轮流孵卵，幼鸟在20天左右离巢，之后的2-3周内仍由成鸟喂养。","identification":"灰头群织雀的辨识要点在于其独特的浅灰色头冠和白色的环眼圈，以及沙褐色的体羽。与之最接近的物种是环喉雀和栗麻雀，但可通过头冠颜色和栖息环境区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲中东部，包括埃塞俄比亚、肯尼亚、索马里、南苏丹、苏丹、坦桑尼亚和乌干达。在繁殖区域和非繁殖区域均有所见，尤其偏好干燥的草原和耕作地带。","other":"灰头群织雀的巢穴不仅用于繁殖，也是成鸟夜间休息的地方。"},{"name":"黑头群织雀","english_name":"Black-capped Social Weaver","scientific_name":"Pseudonigrita cabanisi","overview":"黑头群织雀（英文名：Black-capped Social Weaver，学名：Pseudonigrita cabanisi），是雀形目织雀科伪群织雀属的鸟类。类似雀类的鸟类，属于织雀科。原由Fisher和Reichenow命名，后归入Pseudonigrita属。其显著特征为黑色大帽状头部、象牙色喙、红色眼睛、棕色背部与翅膀、黑褐色尾巴、白色喉部和下体，以及黑色中线。在东北非的半干旱灌木草原上成群活动，筑巢于刺树中。","appearance":"体长约13厘米，体重18-24克，具有黑色的额头、冠部和后颈，形成明显的界限。背部、翅膀、臀部呈均匀的棕色，尾部黑褐。喉咙、颈侧、胸部、腹部和肛周为白色，腹部中央有一条清晰可见的细长黑色条纹。幼鸟缺少黑色标记，全身呈淡褐色。喙象牙白，腿暗角质色，眼红亮。","call":"发出混合了啾啾声和尖叫声的鸣叫，类似于麻雀的声音，群体中常有集体合唱的金属质感的尖叫。","habits":"栖息于半干旱的荆棘草原，通常成群活动，以种子为主食，也会摄取少量昆虫。地面觅食，群居生活，筑巢于树上。","breeding":"繁殖期为2月至5月，有时在12月至1月及8月至9月。一夫一妻制，可能为合作性繁殖。在树上建造屋顶式巢穴，每巢可容纳2-4枚蛋，蛋白色或粉红色，有棕色和紫色斑点，大小约为19x14毫米。幼鸟由繁殖对和额外的成鸟共同喂养。","identification":"与灰头群织雀有相似的生活习性，但可通过黑色冠和白色的下体进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于埃塞俄比亚南部、肯尼亚北部和中部、索马里部分地区以及坦桑尼亚东北部。","other":"有时被爱好者在笼中饲养和繁殖，偏好较大的群体环境，需提供充足的筑巢材料和适宜的食物搭配。"},{"name":"群织雀","english_name":"Sociable Weaver","scientific_name":"Philetairus socius","appearance":"群织雀体长约14厘米，重24至32克，两性相似，具黑喉、条纹侧翼和鳞状背部。幼鸟较暗淡，缺乏成鸟的特征标记。成鸟的头部为沙棕色，后颈至背部为深棕色，带有淡色边缘形成鳞片状效果；臀部为淡沙棕色；翅膀和尾巴为暗棕色，翅覆羽有宽阔的淡色边缘；脸颊呈奶油色，带有棕褐色调；从眼窝到下巴和喉咙有黑色斑块；胸部、腹部、大腿和尾下覆羽呈奶油色，带有棕褐色调，侧翼有白色边缘的黑色斑块；虹膜深棕色；喙蓝灰色，基部颜色更深；腿为深棕色。","call":"高阶雄鸟的歌唱为约10个初始音符的叽叽声，随后是几个成对的元素。威胁叫声是一系列至少15个快速音符；进入巢穴的叫声是一个超过15个元素的长语句。飞行时，每秒7至8个叫声；接触叫声通常是一个单音符；警报是一个刺耳的单音符。","habits":"群织雀栖息于开放的干旱地区，年降雨量在80至600毫米之间，依赖于散落的树木或人造结构作为巢址。小至大群在地面觅食，追逐昆虫和种子。食物包括草蜢、甲虫幼虫、毛虫、蛾类、白蚁，尤其是收获白蚁和白蚁有翅成虫；偶尔食用软果和Rhigozum trichotomum花的卵巢。大多数食物在地面收集，也追逐飞行中的昆虫。","breeding":"繁殖期在北纳米比亚为12月至8月，在东南部为11月至1月；在其他地方繁殖不受季节限制，取决于不规律的降雨，持续9个月。单配制，但连续的筑巢尝试常与不同的伴侣。合作繁殖，最多九个帮手（成鸟和幼鸟），通常是与巢中幼鸟相关的个体。殖民地繁殖，单个巢穴可达几百个个体。巢穴巨大，深度可达4米，长度7.2米，重达1吨，由干燥的草茎构成，覆盖独立的巢室，入口在底部，材料全年添加，巢室用柔软的植物材料、动物皮毛有时还有羽毛衬垫，雨后特别添加新巢室。","identification":"群织雀与较小的Scaly Weaver区别在于，后者更不群居，具有粉红色的喙。成年群织雀的特征是蓝色灰喙、黑喉和背部的鳞状图案。幼鸟较为暗淡，缺乏黑喉和鳞片状背部。","protection":"IUCN：LC（无危）","distribution":"群织雀分布在纳米比亚中北部，南至博茨瓦纳西南部和南非西北部。具体而言，其分布从纳米比亚北部至博茨瓦纳南部，延伸至南非西北部。","other":"群织雀的种群数量在2010年代有所增加，这可能归因于电力塔和其他人造结构作为筑巢地点的增多。"},{"name":"鳞额编织雀","english_name":"Scaly-feathered Weaver","scientific_name":"Sporopipes squamifrons","overview":"鳞额编织雀（英文名：Scaly-feathered Weaver，学名：Sporopipes squamifrons），是雀形目织雀科编织雀属的雀形目鸟类。其特征是拥有沙色的羽毛、粉红色的喙以及黑白相间的喉部条纹，赋予它独特的外观。主要分布在非洲南部，包括安哥拉西南部、纳米比亚（除沿海沙漠）、赞比亚南部、博茨瓦纳、津巴布韦西部和中部以及南非北部和南部。","appearance":"鳞额编织雀体长约11厘米，体重介于10至14克之间。它的头部和冠部羽毛呈黑色，边缘有箭头状的白色斑点；头部侧面、颈背和背部颜色为暗灰褐色；尾巴深棕色，羽毛边缘带有白色；上翼棕色，而上翼覆羽和三级飞羽为黑褐色，边缘宽阔且白色。下颌黑色，喉部白色，有两条延伸至喉部的黑色颊纹；腹部白色，胸部略带淡棕色；虹膜红棕色；喙粉色至玫瑰色，下颌基部呈浅蓝色；跗跖呈角质棕色。雌雄相似，幼鸟的冠部和前额较暗，颊纹不明显，喙色角质色。","call":"雄鸟发出重复的双音节'kreep krop'的鸣叫声。雌鸟在求偶时发出高音调的'zi-zi-zi'叫声。两性都有滚动的'sirrip'接触叫声。","habits":"这种鸟类居住在干燥的金合欢（Acacia）草原、灌木丛和沿干涸水道的植被中，以及靠近住宅区的灌木地带。它们在食物短缺期间会局部游荡。主要以小型种子为食，如Aristida和Schmidtia的种子，也会捕食昆虫，包括白蚁（Isoptera）。它们主要在地上觅食，跳跃而非行走，同时在地面收集昆虫和种子。野生个体在没有饮用水的情况下能存活长达62天。","breeding":"繁殖季节根据环境条件而定，通常在赞比亚的2月至3月、博茨瓦纳的12月至4月、津巴布韦的1月至3月以及南非的1月至6月达到高峰。它们是单配性的，至少在一个繁殖季节内如此。雄鸟保卫一小块领地。在圈养条件下，雌鸟筑巢，雄鸟提供材料。巢穴是一个杂乱的椭圆形草堆，由刚硬的草茎和Androgopon、Aristida、Digitaria、Eragrostis、Sporobolus和Urochloa等植物的花序组成，有时还会有芳香的Pentzia茎，内部铺垫植物绒毛、来自Rhynchelytrum的芒刺和羽毛，通常位于树上，距离地面1至4米，最高可达6米。有时会利用旧的鵙鸟（Laniidae）或鶲鸟（Muscicapidae）的杯状巢，或再利用其他编织雀的旧巢，例如黑额织雀。巢穴全年用于栖息，最多可容纳十二个个体。每窝产3至5枚蛋，蛋壳颜色为绿色、蓝色或淡奶油色，密集地布满灰色至棕色的斑点，平均尺寸为15.7 x 11.3毫米（基于南非的106枚蛋的测量值）。孵化仅由雌鸟完成，周期为10至12天。幼鸟由两性喂养，巢居期为14至18天。在30个巢穴中，有九个因捕食而失败。","identification":"与群织雀相比，鳞额编织雀体型更小，具有粉红色的喙。群织雀的喙为蓝灰色，体型显著更大。","protection":"IUCN：LC（无危）","distribution":"鳞额编织雀的分布范围包括西南安哥拉、纳米比亚（除了沿海沙漠）、赞比亚最南部、博茨瓦纳、津巴布韦西部和中部以及南非北部和南部，包括卡拉哈迪跨国公园边境地区的博茨瓦纳和南非。近年来，其分布范围已向北扩展，并在赞比亚南部建立了稳定的种群。"},{"name":"点额织雀","english_name":"Speckle-fronted Weaver","scientific_name":"Sporopipes frontalis","overview":"点额织雀（英文名：Speckle-fronted Weaver，学名：Sporopipes frontalis），是雀形目织雀科编织雀属的鸟类。分布于非洲西部至东部，包括毛里塔尼亚、冈比亚到埃塞俄比亚和坦桑尼亚等地。","appearance":"体型小，约11厘米，重14至22克。头部特征明显，前额与冠部羽毛黑色，尖端白色形成斑点效果；脸颊和耳羽淡灰色，颈背栗棕色，延伸至耳羽后方形成窄弯月形；黑色颊纹，边缘白色；上体淡灰褐色，翼和尾棕褐色带淡色边缘；喉部和下体白色，胸部略带灰色；虹膜棕色；喙淡角灰色；腿棕色。两性相似。幼鸟似成鸟，但整体更淡，尤其是颈背呈浅黄色，而非栗色。","call":"常见叫声为短暂的颤音，歌声类似鹨鸟，是一系列快速的响亮哨声。","habits":"栖息于干燥或适度湿润的灌木丛和树林，常以小群活动。食谱主要为种子，也吃小型昆虫，包括飞翔的白蚁。觅食活动主要在地面进行，通常在开放的砾石区域，常与蜡嘴雀科鸟伴生。","breeding":"繁殖季节从9月至12月，有时持续至2/3月；在埃塞俄比亚记录4至5月繁殖，在肯尼亚为5至7月，在坦桑尼亚为5至8月。一夫一妻制，巢穴为大而不整的草球，侧面有入口隧道，内部铺垫细软材料和少量草籽，偶尔含羽毛，置于2至6米高的灌木或树上。雌鸟单独孵化，孵化期未知，雏鸟由双亲喂养，通过反刍种子喂食。巢穴可能被绿木 hoopoe 和红颊蓝饰雀侵占。","identification":"与本属其他物种的区别在于其独特的头部斑纹，以及较淡的颈背部颜色。","protection":"IUCN状态未提供。","distribution":"广泛分布于非洲西部、中部和东部，具体包括毛里塔尼亚、冈比亚、埃塞俄比亚、坦桑尼亚等地，海拔从400米至2000米，常见于村庄附近。"},{"name":"厚嘴织雀","english_name":"Thick-billed Weaver","scientific_name":"Amblyospiza albifrons","overview":"厚嘴织雀（英文名：Thick-billed Weaver，学名：Amblyospiza albifrons），是雀形目织雀科厚嘴织雀属的鸟类，拥有独特而粗壮的喙。分布于非洲的西、东及南部地区，常出没于湿地、森林边缘及近水地带。该鸟种以其强健的喙部著称，用于剥开坚果和浆果种子。","appearance":"厚嘴织雀体型较大，羽毛呈深色，喙部异常粗大。雄鸟具有巧克力棕色头部和上体，翼上可见白色斑点，额头和翅膀带有白色标记，喉部至腹部亦为深巧克力棕色，有时下胸至臀部有较淡的羽毛边缘。雌鸟呈暗棕色，胸部至腹部有重褐色条纹，喙部颜色偏黄至橙黄色。幼鸟外观类似雌鸟，但喙部为黄色，雄鸟幼鸟需两年以上才能达到成鸟的羽色。","call":"厚嘴织雀的鸣声包含快速的高音颤音，夹杂多个喷溅般的颤鸣，例如“pit-pit-pit-pit chweeer-kuuuurrrr”。此外，其叫声中还包含颤音和咔哒声的组合，如'jee teee click-click-click clee-clee-clee wer-pee krrrr'，以及响亮的'chuck'联系叫声。","habits":"厚嘴织雀栖息于靠近水源的地带和茂密林区，繁殖季节选择湿地区域，非繁殖季节则在常绿森林边缘和树冠层活动，经常远离水源。以种子、软果、昆虫和其他小型动物为食，包括Acacia robusta、Albizia adianthifolia、Pennisetum等植物的种子，以及Celtis africana等植物的绿色果实。在地面和森林树冠层觅食，非繁殖季节以小群形式活动。","breeding":"繁殖期在不同地区有所差异，通常为5月至11月间。雄鸟可与多达六位雌鸟配对，最多同时有三位雌鸟在其领地筑巢。巢穴呈卵圆形，由雄鸟编织，材料为细长的草条，悬挂于芦苇、香蒲或水边的草丛中。每巢平均产卵3枚，卵壳白色至粉红色，带红、紫、棕色斑点，大小约为23.6 x 16.2毫米。雌鸟负责孵化，持续14至16天，雏鸟由雌鸟通过反刍喂养，偶尔雄鸟也会参与，孵化期约18至20天。","identification":"厚嘴织雀与其他织雀的区别在于其粗大的喙部，以及巢穴的构造和位置。雄鸟额头的白色标记和深色体羽也是辨识特征。不同亚种之间在头部颜色、胸部条纹和体型上有细微差别。","protection":"IUCN：LC（无危）","distribution":"厚嘴织雀广泛分布于非洲的西、东及南部地区，包括肯尼亚、刚果东部、坦桑尼亚、喀麦隆、南非等国家。在肯尼亚和刚果东部可达海拔3000米，坦桑尼亚基里曼贾罗山高达1300米，南非南部至1500米。在喀麦隆库佩山低于850米。","other":"厚嘴织雀的巢穴在使用后可能被攀树鼠占据，或是被橙胸蜡嘴雀或褐背火雀用于繁殖。"},{"name":"黄腹织雀","english_name":"Baglafecht Weaver","scientific_name":"Ploceus baglafecht","overview":"黄腹织雀（英文名：Baglafecht Weaver，学名：Ploceus baglafecht），是雀形目织雀科织雀属的鸟类。此鸟以独特的黄色腹部和面部黑色标记著称，分布于东非和中非的森林边缘、林地、花园及城市环境。其头部颜色和体型在地理上具有显著变异性。","appearance":"成年黄腹织雀雄鸟头额至眼水平线呈金黄色，脸颊和耳羽黑色，后冠和颈绿褐色；背部橄榄绿，披覆有窄中央条纹；尾部橄榄绿；翅膀深褐，翼羽具黄色边缘，翼盖有宽绿边；下体金色至尾下覆羽；眼睛黄色；喙黑色；腿棕色。非繁殖期雄鸟灰白上体，头部侧面泛黄，无面具，背部有暗色条纹；尾巴和翅膀同繁殖期；下颚、喉和胸泛黄，腹部、胁、大腿和尾下覆羽白色；雌鸟类似繁殖期雄鸟，但头部颜色较淡，面具周围眼区黑而带绿。幼鸟头部和颈灰色至褐色，面部黑色，上体褐色，披覆有中央条纹，喉和下体统一淡白色，虹膜棕色，喙和腿棕色。","call":"鸣叫声为典型的‘chet’音符和类似无线电杂音的嘶嘶声。","habits":"黄腹织雀栖息于海拔较高的森林边缘、林地、湿润灌木丛、花园、农耕地和森林边缘。主要以昆虫为食，也吃水果、种子和花蜜。它们在树和灌木中活动，高度随季节变化，旱季较低（约4.5米），雨季较高（约6.5米）。通常单独或成对觅食，繁殖后形成小群（8-10只），偶尔加入混合物种群。对其他鸟类有侵略性。","breeding":"繁殖期在不同地区有所不同，一般在8月至11月间。单配偶制，有时两对共栖一地。雄鸟在远离巢穴处进行求偶，展示竖翅拍打动作。巢由雄鸟用绿色草茎或草叶宽条编织，内部由雄雌共同填充植物绒毛和羽毛。巢悬挂在树枝上，常位于金合欢树中，偶尔在棕榈树或外来松树和桉树中。雌鸟独孵，雄鸟常在附近守候，孵化期11-12天。雏鸟初期由母鸟喂养，第4天起雄鸟参与，离巢期15-17天。","identification":"黄腹织雀通过黑色面部、黄色喉咙和较大体型与其他织雀种类相区分。各亚种在头部和上体颜色、是否存在季节性换羽上有差异。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲中东部和东南部，包括喀麦隆、埃塞俄比亚、肯尼亚、乌干达、赞比亚和马拉维等地。在喀麦隆山区海拔1400-2300米，埃塞俄比亚海拔1200米以上，肯尼亚和乌干达海拔800-3000米，赞比亚和马拉维海拔1800米以上。","other":"黄腹织雀在一些地区相当常见，适应性强，能在受干扰的生境如花园中频繁出现。"},{"name":"黑脸黄腹织雀","english_name":"Bannerman's Weaver","scientific_name":"Ploceus bannermani","overview":"黑脸黄腹织雀（英文名：Bannerman's Weaver，学名：Ploceus bannermani），是雀形目织雀科织雀属的鸟类。以鸟类学家David Armitage Bannerman的名字命名。主要分布于非洲西部的喀麦隆和尼日利亚山区，栖息在海拔1100至2900米的森林和林缘地带。其显著特征是明亮的黄色羽毛、黑色面部和喉咙，以及橄榄绿色的背部和尾巴。","appearance":"成年黑脸黄腹织雀体长12至14厘米，体重29至33克。头部前额和冠部呈金色黄色，颈背略显绿意，上体和尾巴橄榄绿色。翼上覆羽暗褐色，带有橄榄绿边缘。面部黑色，形成面罩，覆盖眼上方和喉咙。胸部金色黄色，腹部和大腿黄色，带有一抹绿意。下尾覆羽金色黄色。眼睛奶油色，喙黑色，腿粉色至深棕色。雌雄相似，幼鸟未详述。","call":"雄鸟的鸣唱高亢，以拉长的口哨声结束，比许多织雀更悦耳，'chi-chi-chi-chirr-chirr'。领土歌曲由独立音符开始，随后加速进入多音节元素，'chop kik kik ko ko chokwydo kwideekwo chip'。联系叫声尖锐，'prit'。","habits":"在喀麦隆和尼日利亚的山地森林中成对或小群出现，偏好海拔1100至2900米的森林和森林边缘环境。","identification":"与Baglafecht织雀类似，但后者喉部黄色，腹部白色。","protection":"IUCN：VU（易危）","distribution":"在喀麦隆的Bamenda高地和Adamawa高原以及尼日利亚的Obudu和Mambilla高原发现，特别是在喀麦隆的Mt Oku和尼日利亚的Gashaka-Gumti国家公园。"},{"name":"白喉黄腹织雀","english_name":"Bates's Weaver","scientific_name":"Ploceus batesi","overview":"白喉黄腹织雀（英文名：Bates's Weaver，学名：Ploceus batesi），是雀形目织雀科织雀属的鸟类。分布于喀麦隆的西南部和南部，从林姆贝东至摩隆杜。其分布狭窄，全球数量估计不足1000只。","appearance":"体型和形态上与同属其他种类相似。雄鸟具有黄色的下体，明亮的栗色头部，有限的黑色喉咙，以及橄榄绿色的背部。","habits":"栖息于亚热带或热带湿润的低地森林中，因生境丧失而受到威胁。","protection":"IUCN：EN（濒危）","distribution":"非洲：喀麦隆，具体分布在从林姆贝（位于喀麦隆山脚下）向东至摩隆杜（靠近刚果边境）的一条狭窄地带。"},{"name":"黑颏织雀","english_name":"Black-chinned Weaver","scientific_name":"Ploceus nigrimentus","overview":"黑颏织雀（英文名：Black-chinned Weaver，学名：Ploceus nigrimentus），是雀形目织雀科织雀属的鸟类。这种织雀具有明显的雌雄异型，分布于非洲的特定区域，包括加蓬东部、刚果共和国和安哥拉中部。主要栖息在海拔500至1500米的开放灌木丛生的草原和孤立的森林斑块中。","appearance":"黑颏织雀的背部呈黑色，臀部为黄色，雌雄外观差异明显。雌鸟拥有黑色的头罩和喉部，而雄鸟则有黄橙色的前额、冠、颈背，脸部和喉部为黑色。体型适中，羽毛色彩鲜明。","call":"其鸣叫特征包括尖锐的“chittick”叫声和一段简短的歌曲，据说听起来像“whit-pu pui trrr pui”。","habits":"这种鸟类通常生活在开放的灌木草原中，偏好海拔500至1500米的高度，常见于孤立的森林斑块。其生活习性与同属的其他织雀类似，但在具体行为上可能有所区别。","breeding":"繁殖模式被描述为“半群居”，具体季节未记录。其巢类似于其他Ploceus属的织雀，相对较大，入口朝向顶部。关于繁殖的其他信息目前尚不清楚。","identification":"与Baglefecht织雀外观相似，但后者喉部总是黄色，有助于区分两者。","protection":"IUCN状态未知。","distribution":"主要分布在加蓬东部、刚果共和国南部（Batéké高原）、安哥拉中部（Cuanza Sul、Huambo旧记录；最近在Lunda Norte发现繁殖）。"},{"name":"伯氏织雀","english_name":"Bertram's Weaver","scientific_name":"Ploceus bertrandi","overview":"伯氏织雀（英文名：Bertram's Weaver，学名：Ploceus bertrandi），是雀形目织雀科织雀属的鸟类。此鸟以Bertram Lutley Sclater命名，他是著名鸟类学家Philip Lutley Sclater之子，同时也是在马拉维发现此物种时的当地警察委员。伯氏织雀体型较大，体态丰满，常见于非洲东部和南部的山区林地、灌木丛及森林边缘。","appearance":"伯氏织雀两性皆具淡色眼，背部橄榄绿，腹部黄色。雄鸟面部有黑色面罩，头顶橙黄，头后部有一黑色斑点。雌鸟头部全黑。鸟体尺寸适中，色彩鲜明。","call":"鸣声典型，包含\"chet\"音节和类似电台静电的嘶嘶歌曲。","habits":"伯氏织雀在山地森林、灌木丛及森林边缘较为常见，偏好特定的生境。其分布区为海拔较高的地区。","breeding":"。","identification":"与Baglafecht织雀相似，但可通过黑色而非黄色喉咙加以区分。","protection":"IUCN状态未知。","distribution":"主要分布在非洲的赞比亚北部、坦桑尼亚中部、马拉维及莫桑比克北部，具体包括SW和E Tanzania、NE Zambia、Malawi和NW Mozambique。"},{"name":"细嘴织雀","english_name":"Slender-billed Weaver","scientific_name":"Ploceus pelzelni","overview":"细嘴织雀（英文名：Slender-billed Weaver，学名：Ploceus pelzelni），是雀形目织雀科织雀属的鸟类。以异常细长的喙而著称。分布于非洲中部和西部的湿地区域，包括沼泽、红树林和相邻的草原或灌木丛。其黑色面罩和黄色下体是成年雄鸟的显著特征。","appearance":"细嘴织雀体长11厘米，体重约10至16克。成年雄鸟具有黑色头部面具和黄色下体；雌鸟头部呈淡黄色，不同于其他织雀。幼鸟似雌鸟，但上部颜色更暗，下体颜色较淡，腹部白色。喙色随年龄变化，从角质色到黄色。","call":"鸣唱包含连续的颤音和吱吱声，其间穿插着吹哨般的'si-si-si'声，同时记录到了'buzzzt'的嗡嗡声。","habits":"栖息于湖泊附近、湿地、稻田和红树林，也会出现在城市花园和树篱中，海拔高度通常低于1700米。以昆虫为主食，包括毛虫和蚂蚁。活动敏捷，常单独、成对或成群觅食。","breeding":"繁殖季节在不同地区有所差异，通常在雨季。一夫一妻制，巢由雄鸟建造，偶尔雌鸟协助，球状巢挂在芦苇、棕榈叶或悬垂的带刺枝条上。每窝产2-3枚纯白或略带粉色的蛋，孵化期约15天，幼鸟由双亲共同喂养。","identification":"与小织雀相似，但生境不同，且喙更为细长。在体型和喙形上与其他织雀有明显区别。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部和西部，包括喀麦隆、刚果民主共和国、加蓬、加纳、尼日利亚、乌干达、安哥拉和赞比亚等地。","other":"在某些地区非常常见，记录显示其在塞拉利昂和可能的利比里亚也有分布。"},{"name":"西非金织雀","english_name":"Loango Weaver","scientific_name":"Ploceus subpersonatus","overview":"西非金织雀（英文名：Loango Weaver，学名：Ploceus subpersonatus），是雀形目织雀科织雀属的鸟类。生活在非洲加蓬沿海至刚果（布）、刚果（金）和安哥拉（卡宾达）地区的湿地区域的织雀科鸟类。具有狭长的喙，上体呈暗橄榄色，下体黄色带橙色。该物种为局部性居民，常见于棕榈沼泽、红树林和海岸附近的草原边缘。","appearance":"雄性西非金织雀头部有黑色的兜帽，向下逐渐变细形成“V”形，周围环绕着橙色的色调。雌鸟则无黑色兜帽，前额黄色，头顶橄榄色。两性均具有独特的色彩组合，使其在同类中易于识别。","call":"其鸣唱为典型的杂乱无章的织雀歌曲，通常以“chuka-chuka-chak”的结尾。","habits":"西非金织雀成对或小群体出现，偏好栖息在棕榈沼泽、红树林和靠近海岸的草原边缘。它们的栖息地选择非常具体，且可能因生境丧失导致分布碎片化和数量下降。","breeding":"繁殖季节不规律，可能全年都有繁殖行为。筑巢行为在7月有记录，8月和10月观察到幼鸟乞食，12月有巢穴访问记录。巢穴形状似倒置的壶，类似黑颈织雀的巢，但入口管较短，由草、干叶和一些细而柔韧的茎构成。","identification":"与之相似的细嘴织雀体型更小，下体颜色更鲜亮。","protection":"IUCN：VU（易危）","distribution":"分布于加蓬南部沿海地带，北至刚果（布），南至安哥拉（卡宾达）及相邻的刚果民主共和国。"},{"name":"小织雀","english_name":"Little Weaver","scientific_name":"Ploceus luteolus","overview":"小织雀（英文名：Little Weaver，学名：Ploceus luteolus），是雀形目织雀科织雀属的鸟类。以其独特的黄色外观和小巧体型著称。分布于非洲西部、中部至东部，常见于萨瓦纳和耕作区。","appearance":"小织雀体长约12厘米，体重介于11至15克之间。繁殖季节的雄鸟具有黑色面部面具，覆盖额头、头顶至眼后，脸颊、耳羽、下巴和喉部，延伸至胸部形成领结状。头部后冠和颈背亮黄色，背部淡黄带暗色羽轴条纹，臀部黄色；尾巴和上翅深橄榄棕色，初级飞羽边缘淡黄，翼覆羽边缘较宽。非繁殖季雄鸟及雌鸟上半身黄绿色，带有暗色羽轴条纹，下半身浅黄色至白色。幼鸟上半身灰棕色，下半身黄色，下颌骨浅色。","call":"小织雀的鸣唱由哀婉的音乐声调引入，如'sweetiswiswi'或'chip-wop-weep-wop-wop-weep-wip-wop-cheep'，随后是一系列叽叽喳喳的音符，比黑头织雀的歌声更安静、更多变。叫声为柔和的'tsip'声，以及尖锐、吱吱的警报声。","habits":"小织雀通常成对或小群活动，偏好在金合欢树和其他小树的叶丛中觅食，类似莺类的觅食方式，会利用喙的撬动动作。在西非，它们也会在地面觅食，与蜡嘴雀等种子食性鸟类一起活动。主要以种子和昆虫为食，食物中包含甲虫和毛虫。","breeding":"小织雀繁殖期在不同地区有所差异，一般从六月至十月，单配制。通常单独筑巢，偶尔群居。雄鸟编织球形巢，悬挂于刺枝上，离地3至5.5米高。巢由细草茎、草叶、藤蔓须构成，内衬草籽头等细软材料。孵化期约12天，雏鸟期18至20天，双亲共同参与喂养。","identification":"与细嘴织雀最相似，但栖息环境不同，且嘴部更短。通过其体形大小和独特黑黄相间的繁殖季雄鸟颜色，可以与其他织雀区分。","protection":"IUCN：LC（无危）","distribution":"分布于毛里塔尼亚南部、塞内加尔、冈比亚、马里中部和南部、布基纳法索、科特迪瓦北部，东至喀麦隆北部、乍得南部、中非共和国、苏丹、南苏丹、埃塞俄比亚西部、厄立特里亚、刚果民主共和国东北部、乌干达、肯尼亚西部和坦桑尼亚西北部。"},{"name":"眼斑织雀","english_name":"Spectacled Weaver","scientific_name":"Ploceus ocularis","overview":"眼斑织雀（英文名：Spectacled Weaver，学名：Ploceus ocularis），是雀形目织雀科织雀属的鸟类。分布于非洲中部、东部和东南部的织雀科鸟类。广泛存在于稀树草原、森林边缘以及花园中，但不会出现在极端干燥的地区（如卡鲁盆地）或茂密的原始雨林。眼斑织雀具有明亮的黄色羽毛，橄榄绿的背部，黑色的眼罩和淡色的眼睛，雄鸟的喉咙呈黑色。","appearance":"眼斑织雀体型约15至17厘米，体重介于22至32克之间。成年雄鸟具有黄褐色的前额和头顶，黄色颈背渐变为金色橄榄色，背部、臀部和尾巴橄榄绿色，翅膀暗棕色，虹膜奶油黄色，喙黑色，腿灰色。雌鸟和雄鸟相似，但缺乏黑色的喉部斑块。幼鸟类似雌鸟，但喉部没有栗色痕迹，眼睛线条呈暗绿色，虹膜深棕色；喙黄色，约3个月后变成棕色。","call":"其鸣叫特征为独特的向下‘tee-tee-tee-tee-tee…’声。","habits":"眼斑织雀栖息于从稀疏树木的稀树草原到灌木丛和树林地带，也可见于森林边缘和植被丰富的花园。它们主要以昆虫为食，包括蚱蜢、蟋蟀、毛虫、甲虫、蚂蚁、飞蚁等，偶尔也吃小型脊椎动物和植物果实。眼斑织雀非常敏捷，常在树上寻找食物，也会倒挂捕食，有时会在地面觅食。","breeding":"繁殖季节在非洲各地有所不同，一般在12月至次年4月间。眼斑织雀是单配偶制，雄鸟会向雌鸟展示求偶姿势。巢由雄鸟建造，雌鸟加入衬垫工作。巢通常悬挂于摇曳的植被末端，离地1至7米高。每窝产卵1至4枚，平均孵化期为13至14天，雏鸟的喂养期约为15至19天。","identification":"眼斑织雀与黑颈织雀的区别在于，后者背部明显较暗，但在西非橄榄背亚种中，通过较厚的喙和头部及胸部更多的栗色来区分。眼斑织雀的雄鸟有黑色的喉部斑块，而雌鸟没有。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部、东部和东南部，包括喀麦隆、埃塞俄比亚、刚果民主共和国、卢旺达、乌干达、肯尼亚、坦桑尼亚、安哥拉、赞比亚、马拉维、莫桑比克、南非等地。","other":"眼斑织雀在人类改变的生境中广泛且常见，但其在西北部的分布较为稀少。"},{"name":"黑颈织雀","english_name":"Black-necked Weaver","scientific_name":"Ploceus nigricollis","overview":"黑颈织雀（英文名：Black-necked Weaver，学名：Ploceus nigricollis），是雀形目织雀科织雀属的鸟类。具有明显的雌雄异型性，雄鸟上体橄榄色，头部金黄色并带有黑色眼罩和颈环，而雌鸟上体橄榄色，头部黄色，具黑色眼纹。分布于非洲中部至东部，包括肯尼亚、南部索马里等地。","appearance":"黑颈织雀是一种中等体型、深眼色的织雀，雄雌两性外观明显不同，但均色彩鲜艳。雄鸟的上体颜色在东非为黑色，而在中非为棕黑色。雌鸟上体橄榄色，头部黄色，有突出的黄色眉纹和较长的眼纹，没有喉部斑块。雄鸟头部深金黄色，眼周有黑色线条，颈背和颈围黑色，雌鸟前额、头顶和颈背黑色，突出的黄色眉纹，黑色眼线延伸到后方与黑色颈背相连。幼鸟上体暗橄榄色或灰橄榄色，尾羽边缘黄色，喙色较浅。","call":"鸣叫包括\"chet\"音符和类似无线电静电的嘶嘶声。","habits":"黑颈织雀栖息于林地，包括灌木丛、湿润草原、画廊森林、森林边缘、沿海灌丛、树木茂盛的花园、油棕榈和椰子树种植园、可可和咖啡森林。它们主要生活在海拔1600米以下的地区，如肯尼亚、埃塞俄比亚西南部和乌干达的Ruwenzoris山区。在肯尼亚，指名亚种出现在高地灌丛和湿润森林，而melanoxanthus亚种则通常位于较低海拔和较干燥的生境。物种快速占领适宜的生境，如再造林导致树密度增加时。","breeding":"黑颈织雀建造大型粗编织的巢，由草和藤蔓构成，带有15厘米面向下方的入口隧道，悬挂于球状的蛋室下方。巢悬挂在树上的枝条上，产卵2-3枚。繁殖时成对筑巢，但在非繁殖季节形成小群。","identification":"与眼斑织雀相区别，后者在东非相对广泛分布，而黑颈织雀主要限于林地和灌木丛。此外，黑颈织雀的雄鸟上体颜色和雌鸟的头部图案与眼斑织雀有所不同。","protection":"IUCN：LC（无危）","distribution":"黑颈织雀的分布区域包括非洲的中部和东部，从西非的喀麦隆到东非的肯尼亚和南部索马里。在肯尼亚，指名亚种出现在高海拔的灌丛和湿润森林，而melanoxanthus亚种则位于较低海拔和较为干燥的生境。","other":"该物种曾被认为是绿枕织雀的同种，但分子研究表明两者遗传差异显著，现已分类为独立物种。"},{"name":"黑头栗斑织雀","english_name":"Strange Weaver","scientific_name":"Ploceus alienus","overview":"黑头栗斑织雀（英文名：Strange Weaver，学名：Ploceus alienus），是雀形目织雀科织雀属的鸟类，主要分布在非洲的乌干达西南部、刚果民主共和国东部、卢旺达和布隆迪的阿尔伯丁裂谷山区森林。","appearance":"雄性黑头栗斑织雀具有黑色头部和颈部至喉部，胸部有一泪滴状黑色斑块，边缘下部为栗褐色；上体为均匀的橄榄绿色，臀部略带黄色调，尾巴橄榄绿色；上翼呈暗褐色，飞羽边缘绿色，翼覆羽橄榄绿；侧腹、腹部和尾下覆羽金黄色，大腿橄榄绿色；虹膜红色，喙黑色，腿灰色。雌鸟相似，但黑色仅限于喉部，胸上部为栗褐色斑块；侧腹橄榄绿色，而非黄色。幼鸟上体橄榄绿色，颏至胸黄橄榄绿色，颏和喉部染有金色棕色，腹部黄色到白色，虹膜棕色，喙角棕色。","call":"其鸣唱为有节奏的'wee chow-chow-chow'声。叫声包括一系列下降的哨音，类似于眼斑织雀的叫声，以及单音节的接触叫声。","habits":"通常成对出现在山地森林的下层和中层，它们在茂密的植被中穿行。其活动范围主要在海拔较高的地带。","breeding":"繁殖期在刚果民主共和国为1月至5月，可能全年都有繁殖活动，在乌干达为1月至2月、6月和10月。一夫一妻制，可能形成长期配偶关系。单独筑巢，但一对鸟有时会在附近建造两个巢穴。巢由两性共同建造，呈倒置的花瓶形状，带有指向外部的短入口管（约6厘米），并非垂直向下。巢主要由短而交织的藤蔓细枝和一些草条构成，内部衬以细草尖，悬挂在3至10米高的树枝尖端；靠近巢的树枝被筑巢对剥离了叶子。每窝产2枚蛋，蛋壳奶油色，有灰色阴影，不规则地散布着红褐色斑点，平均大小为22.3 x 15毫米。","identification":"与林织雀相似，但通过橄榄绿色而非黑色的背部和胸部的栗褐色斑块容易区分。","distribution":"分布于东刚果民主共和国、西南乌干达、卢旺达和布隆迪。"},{"name":"黑腹山织雀","english_name":"Black-billed Weaver","scientific_name":"Ploceus melanogaster","overview":"黑腹山织雀（英文名：Black-billed Weaver，学名：Ploceus melanogaster），是雀形目织雀科织雀属的鸟类。显著特征为黑色主体与黄色脸部的鲜明对比，以及细长的喙。广泛分布于非洲的中部地区，自西非东部至东非的部分区域。","appearance":"雄鸟具有黑色喉部，而雌鸟的头部几乎全黄，仅眼周带有黑色标记。西部地区的雄鸟胸前有一条黄色横带，而在东部地区，胸前则全部为黑色。它们的身体大小适中，羽毛质地细腻，颜色对比强烈。","call":"鸣唱时发出独特的“chyet”音符，以及类似无线电杂音的嘶嘶声。","habits":"栖息于山地森林的下层和中层，通常成对活动，穿梭于茂密植被中。它们偏好温暖湿润的环境，活动范围广泛。","breeding":"具体繁殖细节尚待研究，但织雀科的鸟类通常在繁殖季节会建造复杂的巢穴。","identification":"与同属其他种类相比，黑腹山织雀的黑色与黄色对比明显，且长而细的喙是其辨识关键。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，包括西非东部、中非部分地区直至东非。","other":"此物种在分类学上属于织雀科，具有独特的系统发育历史。"},{"name":"南非织雀","english_name":"Cape Weaver","scientific_name":"Ploceus capensis","overview":"南非织雀（英文名：Cape Weaver，学名：Ploceus capensis），是雀形目织雀科织雀属的鸟类。广泛分布在南非（除沙漠内部及亚热带东部低地）及斯威士兰和莱索托低地。体型较大的织雀，具有独特的黄色头部和橙色面部。","appearance":"南非织雀是一种体长约17厘米的结实鸟类，上部橄榄褐色带条纹，拥有长而尖锐的锥形喙。繁殖期的雄鸟头部和下体呈黄色，脸部橙色，虹膜白色。雌鸟头部和胸部橄榄黄色，逐渐变淡至腹部浅黄色。雌鸟的眼睛为棕色，但夏季有19%的个体眼睛颜色较浅，因此仅凭眼色无法确定性别。幼鸟外观与雌鸟相似。","call":"其鸣叫特征为刺耳且略显歇斯底里的嘶嘶声。警报叫声为尖锐的双音节‘chip’，接触叫声为粗哑的‘azwit’。","habits":"南非织雀栖息于开阔的草地、低地芬布斯、沿海灌木丛和农田，只要存在永久水源和树木即可。它们在更干燥、炎热的地区限于高海拔地带，从不在森林中出现。全年形成大群休息，有时与其它鸟类共栖。在非繁殖季节，它们会离开繁殖群落，直到下一个繁殖季节开始时返回。","breeding":"繁殖期在6月至翌年2月，高峰期在夏季降雨区的10月至翌年1月，在冬季降雨区的8月至10月。每窝产卵2-5枚，由雌鸟孵化约两周。雏鸟在孵化后最初的几晚由雌鸟照料，之后雌鸟会在邻近的空巢过夜。雌鸟起初喂养雏鸟，随着雏鸟长大，雄鸟承担更多喂食任务。雏鸟约在17天后离巢。","identification":"与较小的褐喉金织雀相比，南非织雀的喙更为细长；褐喉金织雀的雄鸟喉部界定更清晰的棕色，雌鸟腹部白色。东非织巢鸟有红色的眼睛，而大金织雀背部无条纹，呈淡黄色。","protection":"IUCN：LC（无危）","distribution":"主要分布在南非（除Kalahari沙漠）、莱索托和斯威士兰，向北至北方省，南至好望角，东至夸祖鲁纳塔尔北部，内陆接近自由州的布隆方丹。","other":"在非繁殖季节，南非织雀会形成大群，且全年聚集在大型栖息地。在某些地区，它们在繁殖季节结束后会离开繁殖地，直至下一繁殖季开始时返回。"},{"name":"安哥拉织雀","english_name":"Bocage's Weaver","scientific_name":"Ploceus temporalis","overview":"安哥拉织雀（英文名：Bocage's Weaver，学名：Ploceus temporalis），是雀形目织雀科织雀属的鸟类。以葡萄牙自然学家José Vicente Barbosa du Bocage命名，他在1880年首次描述了这一物种。安哥拉织雀具有显著的外部特征，繁殖季节时雄鸟头部带有棕色色调，非繁殖季节则整体颜色较为暗淡。","appearance":"这是一种体型相对较大的织雀，拥有细长而尖锐的喙。繁殖季节中的雄鸟具有一双浅色的眼睛和耳朵周围的棕色调。非繁殖期的雄鸟和雌鸟外表较为朴素，上体呈橄榄绿色，下体颜色较浅。","call":"它会发出典型的织雀类嘈杂而沙哑的鸣唱，以及\"chek\"的叫声。","habits":"安哥拉织雀栖息于混有树木、灌木丛及茂密草地的环境，通常靠近水源。其活动范围广泛，包括非洲的安哥拉、刚果民主共和国南部以及赞比亚北部。","breeding":"繁殖期具体细节未知，但织雀科鸟类一般会在繁殖季进行求偶、筑巢等活动。","identification":"繁殖期的雄鸟具有独特的外观，其他时期的个体可以通过结合其体型、长而细的喙以及雄鸟的浅色眼睛来识别。","protection":"IUCN状态未提及。","distribution":"主要分布于非洲的安哥拉，刚果民主共和国南部和赞比亚北部。"},{"name":"东非织巢鸟","english_name":"Eastern Golden Weaver","scientific_name":"Ploceus subaureus","overview":"东非织巢鸟（英文名：Eastern Golden Weaver，学名：Ploceus subaureus），是雀形目织雀科织雀属的鸟类。繁殖季节雄鸟呈鲜艳黄色，雌鸟颜色较淡，非繁殖季节羽毛更暗淡。该鸟种红眼为其显著特征，常见于非洲东部和东南部的沼泽地带。","appearance":"雄鸟在繁殖季节额头、头顶、脸颊和耳羽为黄色，颈背和上体绿色带黄，尾羽绿黄色，翼上覆羽绿色带黄，下体金色至黄色。雌鸟及非繁殖季节雄鸟上体橄榄绿色，下体黄色或灰白色。虹膜颜色因性别和季节而异，腿粉红色。幼鸟类似非繁殖雌鸟，但颜色更淡。","call":"发出连续滚动的嘶嘶声，伴有短促的‘tsip tsip tsweeezzzeerrr’音节，警报时发出尖锐的‘tzit’声。","habits":"栖息于沿海平原、低洼河谷和河流泛滥区，高度低于1300米。主要以种子为食，包括稻谷，亦食昆虫，尤其喜食飞蚁。成群活动，与多种鸟类混群觅食，地面觅食时与其它织雀和南黄弯嘴犀鸟共处。","breeding":"繁殖期为10月至翌年2月，可能为一雄多雌制。群居繁殖，巢由草茎或芦苇条精心编织而成，入口位于下方，高悬于地面或水面之上。每窝产卵2-3枚，仅雌鸟孵卵，孵化期未知，雏鸟期19-22天。在南非偶尔成为白眉金鹃的寄主。","identification":"与其它金织雀相似，但唯一具有红眼特征，易于区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部和东南部，主要在海岸平原和河流附近，向内陆延伸可达100公里。"},{"name":"大金织雀","english_name":"Holub's Golden Weaver","scientific_name":"Ploceus xanthops","overview":"大金织雀（英文名：Holub's Golden Weaver，学名：Ploceus xanthops），是雀形目织雀科织雀属的鸟类。其名称纪念捷克自然学家Emil Holub。该鸟以金黄色头部和黑色厚喙为显著特征，眼睛颜色浅淡，分布于从加蓬到乌干达、肯尼亚，南至纳米比亚北部、博茨瓦纳北部以及南非东部。","appearance":"成年雄性大金织雀体长约17-18厘米，体重40-50克；头部呈金色，上体绿色至金橄榄色，尾羽边缘黄色，翅膀暗褐色带淡黄色边缘；下体金黄色，颌部至胸上部可能带有橘色调；虹膜淡黄色，喙黑色，腿粉色。雌鸟与雄鸟相似，但额头黄色，下体颜色较淡，颌部和喉咙缺乏栗色。幼鸟上体橄榄绿，尾羽边缘黄，翅膀深褐色带绿黄边缘，颌部和喉咙黄，胸部淡褐色，腹部更淡，虹膜深棕色，喙浅棕色基部较暗。","call":"其叫声典型于织雀，包含‘chek’音节和类似无线电静电的嘶嘶声，音调较低。","habits":"栖息于高草丛生地带、森林边缘和溪流旁，常见于1200-2300米海拔，但在东南非沿海和安哥拉、刚果西部为低地。通常筑巢近水。可能为留鸟，至少在南非移动距离最远可达10公里。食物包括昆虫、果实、种子和花蜜，如甲虫幼虫、白蚁、番石榴、无花果、Rhus pyroides果实、草籽、外来松树种子、Ruttya和Erythrina花蜜以及花瓣。巢中雏鸟喂养蚱蜢、螳螂、马蝇和蜘蛛。","breeding":"繁殖期一般在1月至4月，最早在9月开始，东非大部分月份均可记录，高峰期在乌干达为8月至10月。可能双窝产卵。一夫一妻制。雄鸟筑巢，雌鸟提供内部衬垫，巢为肾形，由宽叶草编织，悬挂于高灌木或芦苇上，常在水面之上。一窝产1-3枚蛋，多为2枚，蛋壳颜色为蓝、白或粉红，平均尺寸24.1 x 16.2毫米。孵化期14-15天，幼鸟由两性共同喂养，离巢期19-22天。已知被白眉金鹃寄生。在南非的环志研究中，曾有鸟儿被重捕长达6年后。","identification":"与其他金织雀相比，大金织雀体型更大，且具有浅色眼睛。幼鸟通过整体结构和倾向于与成年鸟群居而可识别。","protection":"IUCN：LC（无危）","distribution":"分布于加蓬南部至刚果西南部、安哥拉西部，以及乌干达南部、肯尼亚西南部、刚果民主共和国东部和南部、卢旺达、布隆迪和坦桑尼亚西部，南至纳米比亚东北部（卡普里维地带）、博茨瓦纳北部（奥卡万戈盆地）、津巴布韦、莫桑比克西部、南非北部和东部（林波波至夸祖鲁-纳塔尔局部地区）以及斯威士兰西部。"},{"name":"橙色织雀","english_name":"Orange Weaver","scientific_name":"Ploceus aurantius","overview":"橙色织雀（英文名：Orange Weaver，学名：Ploceus aurantius），是雀形目织雀科织雀属的鸟类。雄鸟具有亮丽的橙色喉部与黄色羽毛，雌鸟外观较暗淡，呈绿黄色。广泛分布于非洲热带雨林区域。","appearance":"成年雄鸟在繁殖季节头部至颈背为橙色，喉部橙亮，具黑色眼线，背部橄榄绿色，臀部橙黄色，尾部橄榄棕色，上翼深棕色，边缘橄榄黄色，下体橙黄色至橙红色。雌鸟前额、冠部和颈背黄绿色，背部橄榄绿，臀部黄色，尾部橄榄棕色，脸颊和耳羽暗黄色，下体白色带黄色，腹部和尾下覆羽淡白色，两胁和大腿灰色。幼鸟上体橄榄绿，具显著黄色眉纹，翅膀暗棕色，内网黄色，下体白色，仅喉区黄色。","call":"鸣唱为一系列悠扬的音符，带有音乐质感，缺乏许多其他织雀歌声中的粗糙感。叫声为响亮的'kew-kewp'。","habits":"栖息于湿地环境，包括湖泊、河流和沼泽，通常在水边的芦苇丛或树木中筑巢。它们是群居性筑巢者，有时与黑顶织雀和灰头织雀一同筑巢。","breeding":"繁殖期在不同地区有所不同，一般在雨季。雄鸟筑巢，巢由草或棕榈条紧密编织而成，通常位于水面以上1.5至3米处的芦苇中，或陆地上方高达5米的树或灌木丛中。雌鸟孵卵，平均孵化期为13至14天，雏鸟期约13至16天。","identification":"雄性橙色织雀与红巧织雀相似，但后者具有黑色腹部。雌鸟与非繁殖期雄鸟相似。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部和中部，包括利比里亚、加纳、多哥、尼日利亚、加蓬、刚果共和国、刚果民主共和国、乌干达等地。"},{"name":"绿腰织雀","english_name":"Heuglin's Masked Weaver","scientific_name":"Ploceus heuglini","overview":"绿腰织雀（英文名：Heuglin's Masked Weaver，学名：Ploceus heuglini），是雀形目织雀科织雀属的鸟类。主要特征为小体型，拥有黄色的眼睛和绿色的背部。分布于非洲的塞内加尔、冈比亚、马里至科特迪瓦，向东延伸至乌干达和肯尼亚西部。","appearance":"绿腰织雀具有独特的外观特征。成年雄鸟拥有黑色的面部面罩，延伸到上胸部形成尖点，面罩周围没有栗色的斑纹。雌鸟和幼鸟较为暗淡，胸部带有淡黄色的斑纹，背部轻轻条纹。整体呈现绿色的背部是其显著的标志。","habits":"绿腰织雀常居住在开阔的草原和半干旱地区，是一种较为常见的留鸟。它们倾向于群体筑巢，靠近蚂蚁和黄蜂巢穴附近。","identification":"在相似的种类中，绿腰织雀可以通过其黄色眼睛和特定的面部面罩加以区分。较大的黑头织雀和赤道黑额织雀具有红色眼睛，而黑脸织雀则有黑色而非黄色的前额。","distribution":"绿腰织雀主要分布在非洲，具体包括塞内加尔、冈比亚、马里至科特迪瓦，向东延伸至乌干达和肯尼亚西部。"},{"name":"橙头织巢鸟","english_name":"Golden Palm Weaver","scientific_name":"Ploceus bojeri","overview":"橙头织巢鸟（英文名：Golden Palm Weaver，学名：Ploceus bojeri），是雀形目织雀科织雀属的鸟类。繁殖季节的雄鸟拥有鲜亮的黄色羽毛，头部大多呈橙色，而雌鸟颜色较暗淡，但仍保持鲜艳的黄色。广泛分布于东非沿海的灌木草原和棕榈树丛生地带，内陆沿河的干燥地区亦可见其踪迹。","appearance":"雄性橙头织巢鸟的头部至喉部为橙色，胸脯边缘有一圈栗褐色的新月形斑纹，颈项橄榄黄至背部逐渐变为绿色，臀部泛黄；尾羽绿色，尾羽中央带黄色边缘；上翅橄榄绿，飞羽边缘黄色，翼覆羽边缘宽黄，中覆羽尖端黄色；全身下部金黄色，除胸脯新月形栗褐色斑纹；虹膜深棕色，喙黑色，腿粉红肉色。雌鸟额头、头顶、颈背、脸颊及耳羽绿色，黄色眉纹；背部绿色，略带条纹，臀部泛黄；尾羽绿色，尾羽边缘黄色，翅膀橄榄绿，边缘黄色如同雄鸟；全身下部均匀黄色；上喙深棕色，下喙浅棕色。幼鸟类似雌鸟，但下部颜色更淡，背部条纹更多。","call":"鸣叫声包括典型的‘chet’音符和嘶嘶的‘无线电静电’般的歌声。","habits":"通常群居，以种子和昆虫为食。栖息于沿海的灌木草原和棕榈树丛，以及内陆沿河的干燥地区。","breeding":"繁殖期在肯尼亚全年都有记录，高峰出现在十月和一月，但在蒙巴萨为五月至十月；索马里为五月至七月，坦桑尼亚为六月和十二月至四月。可能为多配偶制。群居繁殖，常与黑头织雀和东非织巢鸟共存于混合繁殖群。巢穴呈球状，无入口隧道，由雄鸟用草条或棕榈叶编织，雌鸟用树叶碎片和细草头做内部衬垫，悬挂于低处水面之上，或高1.5-4米固定于地面的高草或灌木上，有时位于棕榈叶下侧，高度可达十米以上；也在香蒲、竹子和芦苇中筑巢。每窝产卵2枚，颜色为海绿色带有灰色或红色斑点，或白色覆盖着浅棕色，平均尺寸为21.1 x 14.3毫米（肯尼亚数据）。外来物种家鸦是巢穴的主要掠食者；蒙巴萨一处繁殖群因反复袭击而被放弃。","identification":"与大金织雀相似，分布区域重叠，但可通过黑色而非红色的眼睛来区分。","protection":"IUCN状态未知。","distribution":"分布于东非，具体包括肯尼亚、索马里和坦桑尼亚。"},{"name":"栗头金织雀","english_name":"Taveta Weaver","scientific_name":"Ploceus castaneiceps","overview":"栗头金织雀（英文名：Taveta Weaver，学名：Ploceus castaneiceps），是雀形目织雀科织雀属的鸟类。显著特征为雄鸟头部至胸部的鲜艳橙黄与金黄色调，活跃于非洲东部的肯尼亚与坦桑尼亚的草原地带。","appearance":"雄性栗头金织雀呈现明亮的黄色，胸腹部位及冠部后方带有深橙色斑块，颈背呈金色，上体橄榄黄，臀部黄色，尾巴绿黄色，翼部橄榄绿，覆羽具黄色边缘。雌鸟背部暗色，腹部淡黄色，喙浅色基部，双眼深色。雌雄均具有黑眼。幼鸟外观类似雌鸟，但上体偏褐色，下体偏淡黄色，喙部下颌带黄色。","call":"鸣唱包含低沉的颤音，被描述为单调而不悦耳，接触叫声为刺耳的'jet'或'jick'。","habits":"栖息于芦苇丛及其周边的灌木林和草原地带，群居，以种子（包括草籽和玉米）、蚂蚁等昆虫为食。","breeding":"繁殖季节在肯尼亚为10月至翌年5月，坦桑尼亚为9月至翌年1月及4月至5月。聚居型，巢呈球形或卵圆形，由芦苇叶片编织，悬挂于水面上的芦苇或悬垂树上。一窝通常产3枚橄榄绿色蛋，孵化期约13天，雏鸟期16天。","identification":"与橙头织巢鸟、大金织雀和东非织巢鸟相似，但分布范围无重叠，可通过黑色眼睛加以区分。雌鸟通常与雄鸟共处，辨识相对容易。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于非洲的肯尼亚和坦桑尼亚，具体包括沿海东非从坦桑尼亚东部到肯尼亚东南部。","other":"此鸟以其独特的巢编织技能著称，巢穴有时可占据整棵树，体现了其生存智慧。"},{"name":"普岛金织雀","english_name":"Principe Weaver","scientific_name":"Ploceus princeps","appearance":"成年雄鸟拥有橙色的额部、头顶和颈背，背部呈黄绿色，尾羽橄榄绿，翅膀暗褐色，翼羽边缘黄色，颊部和耳羽为胸褐色，喉部至腹部黄色，两胁带橙色，腹白。雌鸟头部和颈背黄绿色，背部橄榄绿，具微弱的中央条纹，颊部黄色，耳羽略带胸褐色，腹白。幼鸟外观类似雌鸟，但上体和下体更黄，虹膜棕色。","call":"其鸣唱由一系列前奏音符后接拉长的呼哧声组成，'pzeep-pzeep-pzzzzzzzzrrrr'，另有一三部分组成的鸣声，以响亮的哨音开始，随后是柔和的哨音和刮擦音结尾，'wee-wee-wee-wee werdi-werdi chuckju-jerji-chickwajjer'。接触叫声为响亮的'zeet'，还有'ksuit'和'ksuip'叫声。","habits":"普林西比金织雀常成群活动，多达30只，觅食时会加入混合物种群，与多氏仙鹟、丽辉椋鸟、太阳鸟（Nectariniidae）和Speirops白眼鸟共同觅食。饮食包括种子、果实（如香蕉、辣椒和油棕果）、Erythrina树的花蜜和昆虫。","breeding":"繁殖期在5月至6月和8月至9月，一夫一妻制。有时成群筑巢，但巢间距大。雄鸟在巢下挂唱，翅膀猛烈拍打。巢由雄鸟编织，呈球形或椭圆形，入口位于下方，材料来自棕榈叶或香蕉叶，内部衬有细草和绒毛草头，通常悬挂在离地面10米以上的树枝或棕榈叶尖。每窝产卵1-2枚，蓝色，雄鸟参与喂养雏鸟。","identification":"普林西比金织雀是普林西比岛上唯一的金织雀，雄鸟头部橙色，雌鸟头部黄绿色，腹部白色，通过这些特征可与其他种类区分开来。","protection":"IUCN：LC（无危）","distribution":"普林西比金织雀仅分布于几内亚湾中的普林西比岛（Príncipe Island）。"},{"name":"北非褐喉织雀","english_name":"Northern Brown-throated Weaver","scientific_name":"Ploceus castanops","overview":"北非褐喉织雀（英文名：Northern Brown-throated Weaver，学名：Ploceus castanops），是雀形目织雀科织雀属的鸟类。小型织雀科鸟类，以明亮的黄色羽毛和栗色脸部在繁殖季节特别显眼。分布于乌干达、卢旺达、邻近的布隆迪北部、刚果民主共和国东部、肯尼亚西部及坦桑尼亚西北部。","appearance":"雄鸟繁殖季节羽毛鲜亮，全身黄色，脸部栗色。非繁殖季节和雌鸟、幼鸟羽毛较暗淡，背部有条纹，整体颜色较浅。雄鸟额头栗色，头顶及颈背金色，上体橄榄绿带深色羽缘，下体金黄色。雌鸟及幼鸟上体橄榄棕色，下体淡白色带微黄。","call":"发出一系列高音的叽喳声和吱吱声，长歌在领地防御时及雌鸟进入巢穴时，短歌用于求偶和巢穴展示。","habits":"常在湿地边的植被中活动，如湖泊和河流旁的纸莎草和ambatch植物群落。非繁殖季节会进入森林和林地。以种子和昆虫为食，通常小群觅食，地面、植被中或水上漂浮植物上均可发现其踪迹。","breeding":"全年繁殖，高峰期在3-5月和9月（乌干达），刚果民主共和国在2-5月和7月。一夫一妻制，集群繁殖，每棵树上有5-6个巢，有时与其它织雀共巢。巢由雄鸟建造，圆形紧致，入口下垂，有小前庭，巢内铺细草和羽毛，位于高草或灌木中。","identification":"可通过淡色眼睛、湿地生境及体型和形状与其它织雀区分开来。","protection":"IUCN：LC（无危）；在当地常见。","distribution":"分布于东北刚果民主共和国、卢旺达、北布隆迪、乌干达（除东部）、肯尼亚西部和坦桑尼亚西北部。","other":"北非褐喉织雀与黑头黄背织雀的杂交种曾被认为是 Ploceus victoriae。"},{"name":"褐喉金织雀","english_name":"Southern Brown-throated Weaver","scientific_name":"Ploceus xanthopterus","overview":"褐喉金织雀（英文名：Southern Brown-throated Weaver，学名：Ploceus xanthopterus），是雀形目织雀科织雀属的鸟类。体型较小，羽色鲜明，以金色和栗色为主要特征。广泛分布于南部非洲的湿地环境中。","appearance":"繁殖期雄鸟拥有亮黄色体羽，搭配独特的栗色颈围。雌鸟、非繁殖期雄鸟和幼鸟色泽较暗淡，背部有条纹，喙基部通常呈浅色。雄鸟体重约22至31克，雌鸟约16至24克。雄鸟繁殖期头部、冠部和耳羽呈金黄色，逐渐变为绿黄色背部，臀部鲜黄，尾羽绿色带宽黄缘。雌鸟繁殖期类似非繁殖期雄鸟，但翼羽内侧有明显黄色，喉部至腹部有黄色调。喙黑色，腿粉色。","call":"鸣唱为杂乱序列的鼻音、嗡嗡声、颤音和嘶嘶声的组合。叫声包括嘶嘶声和尖锐的“jick”声。","habits":"栖息于湿地中的芦苇床和高大的水生植被，如纸莎草。冬季则出现在河流边的植被和森林中。食物主要包括草籽、浆果、花蜜和昆虫，如蛾类、甲虫和蚱蜢。也会在喂鸟器处取食面包。","breeding":"繁殖期从十月到四月不等，视地区而异。多配偶制，一雄多雌。巢群聚居，由雄鸟编织，每群可达300个巢。巢为椭圆形，用芦苇和草条编织，由雌鸟衬垫内部。每窝产2至3枚蛋，孵化期14至17天，仅雌鸟孵卵。雏鸟由雌鸟独自喂养，离巢期14至19天。对干扰敏感，巢常因检查而被弃。","identification":"通过喙基部的浅色、湿地栖息环境和整体大小形状可谨慎识别。与其他金织雀种类区分较为困难。","protection":"IUCN：LC（无危）","distribution":"主要分布在南部非洲，包括坦桑尼亚、赞比亚、马拉维、博茨瓦纳、津巴布韦、莫桑比克和南非的部分地区。","other":"在莫桑比克估计有超过10,000个体，在博茨瓦纳和南莫桑比克的数量近年来似乎有所下降。"},{"name":"凯隆织雀","english_name":"Kilombero Weaver","scientific_name":"Ploceus burnieri","overview":"凯隆织雀（英文名：Kilombero Weaver，学名：Ploceus burnieri），是雀形目织雀科织雀属的鸟类。主要以鲜明的黄色羽毛和黑色胸带为其显著特征。仅分布于坦桑尼亚中部的特定湿地环境中。","appearance":"繁殖期雄性凯隆织雀拥有亮丽的黄色羽毛，额部和头部带有橘橙色，脸颊、喉部黑色并带有橙色边缘形成独特的胸带。背部橄榄绿色，臀部黄色，翅膀灰棕色，覆羽具黄色尖端，形成闭合翅膀上的条纹。颈部和腹部均为黄色，胸部带有橙色调。雌鸟繁殖期头部、颈背橄榄褐色，有深色羽干，背部暗橄榄色，重条纹，臀部淡褐色带绿，尾巴橄榄绿，翼灰色，翼覆羽有较浅边缘，颊、耳羽、喉部黄白色，胸部黄褐色，腹部、胁部、尾下覆羽淡黄白，大腿部黄褐色。嘴深灰色，腿灰褐色至暗粉红色。非繁殖期雄鸟和雌鸟的描述未详，幼鸟描述亦未提供。","call":"凯隆织雀的叫声包括典型的‘chek’音节和类似静电噪声的歌唱声。","habits":"凯隆织雀生活在坦桑尼亚中部河流沿岸的芦苇丛中，常成群活动，筑巢集体化。","breeding":"繁殖生态细节未详细描述。","identification":"凯隆织雀与维特林面罩织雀等其他织雀的区别在于其暗色背部、相对较少的黄色色调和分布范围。","protection":"IUCN：VU（易危）","distribution":"凯隆织雀的分布局限于坦桑尼亚西部基洛姆贝罗河泛滥平原的季节性淹没草地。","other":"凯隆织雀的生存受到农业扩张、放牧增加、耕作面积扩大以及为了清除田地和促进新生草生长而进行的燃烧活动的威胁。"},{"name":"栗脸织雀","english_name":"Rüppell's Weaver","scientific_name":"Ploceus galbula","overview":"栗脸织雀（英文名：Rüppell's Weaver，学名：Ploceus galbula），是雀形目织雀科织雀属的鸟类。脸部带有红褐色斑块和红色眼睛。分布于非洲北部和阿拉伯半岛西南部。","appearance":"成年雄鸟繁殖期间头部至眼水平线及脸颊、耳羽为栗色，头顶金黄色渐变为绿黄色颈背；背部绿黄色，中央有细暗纹，臀部淡黄色；翅膀和尾巴橄榄绿，飞羽和尾羽边缘黄；下颚栗色，喉部棕色，逐渐过渡至金色胸部和余下腹部；虹膜橙红色，喙黑色，腿棕色至粉红色。非繁殖期雄鸟和雌鸟整体绿色橄榄色，具暗色眼和粉色喙，雌鸟头部、颈部至背部灰棕至橄榄灰，有深色纵纹，腹部、侧腹、大腿和尾下覆羽淡白色；幼鸟似雌鸟，胸脯更黄。","call":"鸣叫声包括‘chik’音节和类似无线电静电的嘶嘶声。","habits":"栖息于干燥的荆棘草原和耕作区，通常以小群或大群出现。食性以种子为主，包括谷物作物的种子。活动范围广泛，曾报道在苏丹、索马里和埃塞俄比亚形成巨大的繁殖后群体。","breeding":"繁殖季节在苏丹为5月至8月，在埃塞俄比亚除3月至4月外全年均可繁殖，索马里为2月至3月、5月至6月和11月，也门主要为3月至8月，沙特阿拉伯为12月至3月，阿曼为3月至9月。多配偶制，单个雄鸟有时可拥有至多三雌和八个巢。巢呈几乎球形或扁球形，由雄鸟用草或长条棕榈叶编织，内部衬有植物绒毛、小羽毛和树叶，悬挂于地面2至6米高处，可能位于水面上方。","identification":"与维泰琳面罩织雀非常相似，但通过暗色眼和整体大小、形状可区分。","protection":"IUCN状态未知。","distribution":"分布于苏丹至索马里和肯尼亚极北部，以及阿拉伯半岛西南部，包括沙特阿拉伯南部、也门、阿曼西部。"},{"name":"北非黑脸织雀","english_name":"Northern Masked Weaver","scientific_name":"Ploceus taeniopterus","overview":"北非黑脸织雀（英文名：Northern Masked Weaver，学名：Ploceus taeniopterus），是雀形目织雀科织雀属的鸟类。小型、修长的织雀，拥有粗壮的喙。繁殖季节的雄鸟具有鲜明的黄色羽毛，脸部黑色面具逐渐过渡到边缘的栗色，使其外观独特。该鸟种常见于湿地环境，也会进入周边干燥的草原地带，通常以群居形式活动。","appearance":"繁殖期雄性北非黑脸织雀呈现明亮的黄色体羽，脸部有黑色面罩，边缘渐变为栗色。雌鸟、非繁殖期雄鸟和幼鸟颜色较暗淡，背部有条纹，腹部颜色较浅。整体上，除了繁殖期雄鸟，其他个体较为朴素。","call":"鸣叫特征包括典型的‘chek’音符和类似无线电静电的歌唱声。","habits":"北非黑脸织雀栖息于湿地，偶尔会进入周围的干草原。它们几乎总是成群结队活动，展现出群居行为。","breeding":"繁殖期发生在苏丹的8月至10月，在刚果民主共和国为7月至11月，肯尼亚则为5月至9月。雄鸟构建巢穴，巢呈椭圆形，入口位于下方，由草条编织，内部有草茎支撑。雌鸟单独孵卵和喂养幼鸟。一窝产卵2至3枚，颜色从黄绿色到棕色不等，有时带有红棕色斑点。","identification":"除了繁殖期雄鸟的显著特征外，其他时期的个体可通过深色的喙和眼，以及相对苍白的整体色调与体型来识别。","protection":"IUCN：LC（无危）","distribution":"分布于苏丹西部、南部和东部，南苏丹，埃塞俄比亚西部和西南部，刚果民主共和国东北部，以及肯尼亚西部（巴林戈湖和博戈里亚湖）。在肯尼亚的巴林戈湖沿岸有近期的目击记录。","other":"2014年首次在乌干达被记录。"},{"name":"黑脸织雀","english_name":"Lesser Masked Weaver","scientific_name":"Ploceus intermedius","appearance":"黑脸织雀体长约13厘米，体重介于17至27克。繁殖期雄鸟头部前额、前冠、颊、耳羽、下颏及喉部呈黑色，后冠橙栗色，颈背和颈侧黄色；背部绿黄色，有狭窄的中央条纹；上翼和尾橄榄棕色，飞羽和尾羽边缘泛黄；胸部上部带有橙栗色，下胸、腹部、腹侧、大腿和尾下覆羽黄色。雌鸟繁殖期前额、冠、颈背橄榄绿色，带轻微条纹，背部橄榄绿色且重条纹，臀部黄绿色；翅膀和尾巴暗橄榄棕色，有较浅的羽缘，尤其是翼覆羽；脸颊和耳羽橄榄色，泛黄，下颏、喉、胸淡绿黄色，渐变为下腹白色，腹侧、大腿和尾下覆羽泛黄。非繁殖期雌鸟和雄鸟外观相似，但雌鸟下部颜色更淡。幼鸟类似非繁殖期雌鸟，但上部更棕，下部更白，虹膜深棕色，喙角质色。","call":"黑脸织雀的鸣唱为长而尖锐的叫声，间杂着喋喋不休的音符和其他元素，'swizzzzzz jubjub swizzzurrrrrrrr'。呼叫音为'pew-pew-pew'和'tsop-tsop'。","habits":"黑脸织雀主要以昆虫为食，包括毛虫、蚱蜢、白蚁，也吃种子、桑葚、紫荆花，甚至花蜜，尤其是在龙舌兰属植物上。偶尔在花园里啄食玉米粥。它们常在河流林木的树冠层觅食，探查叶片和花朵中的昆虫。面部可能因吸食花蜜而沾满花粉。","breeding":"繁殖季节在刚果民主共和国为1月至5月，卢旺达为10月至11月和3月至5月，埃塞俄比亚为3月、5月至7月和9月，在索马里为6月，在乌干达为3月至6月；除肯尼亚8月至11月外全年繁殖，高峰在4月；坦桑尼亚2月至4月，安哥拉12月和3月，赞比亚9月至2月，马拉维11月至3月，莫桑比克11月至2月，津巴布韦和博茨瓦纳及南非9月至2月。雄鸟一夫多妻制，每只雄鸟有两到三只雌鸟。群居繁殖，每处最多60个巢，有时与其它种类共栖，如红眉苇莺、金顶织雀、红顶织雀等。雄鸟在巢边展示，快速扇动翅膀，展开尾羽，同时摇晃头部并歌唱。巢呈肾形，有约5厘米长的入口管，由雄鸟用草条建造，放置在芦苇丛中或水边树上，离地面1至3米，由雌鸟用草穗内衬。平均产卵2至3枚，白色或淡蓝白色，平均大小21.4×14.7毫米；孵化仅由雌鸟承担，孵化期13天；雏鸟由双亲喂养，雄鸟喂食频率仅为雌鸟的一半，巢期15天。在南部非洲地区，有2.6%的巢被迪德里克杜鹃寄生，东非也有报道。在肯尼亚的一个群落中，超过30%的巢穴中发现弃卵，多数单卵不育。非洲鱼鹰和绿猴在某些群落中会袭击巢穴；非洲扁头蛇是赞比亚和其他地方常见的蛋和雏鸟捕食者。","identification":"黑脸织雀与其它淡色眼圈的织雀的区别在于其灰石色而非粉红色的腿，以及繁殖期雄鸟的黑色面罩和黄色王冠。在非繁殖季节，可通过其淡色眼圈和白色腹部来识别。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部、东南部和南部，包括刚果民主共和国、卢旺达、埃塞俄比亚、索马里、乌干达、肯尼亚、坦桑尼亚、安哥拉、赞比亚、马拉维、莫桑比克、津巴布韦、博茨瓦纳和南非。","other":"黑脸织雀在其分布范围内常与村织雀和红嘴牛织雀共同筑巢，是迪德里克杜鹃常见的寄主。"},{"name":"黑额织雀","english_name":"Southern Masked Weaver","scientific_name":"Ploceus velatus","overview":"黑额织雀（英文名：Southern Masked Weaver，学名：Ploceus velatus），是雀形目织雀科织雀属的鸟类。以织巢技巧著称。这种红眼、绿背、粉棕色腿的鸟常见于南部非洲的开阔草原和半干旱地带。","appearance":"雄鸟繁殖期具窄黑前额和黑面罩，覆盖眼上方、脸颊、耳羽、下巴和喉部，延伸至胸上部；头部鲜黄，颈后至背部呈绿橄榄色，有微弱中央条纹；臀部绿黄色；尾橄榄绿色，尾羽尖端淡黄；翅膀棕色，翼羽边缘黄色；腹部、两胁、大腿和尾下覆羽鲜黄。雌鸟和非繁殖期雄鸟较暗淡，虹膜红色到红棕色，喙黑色，腿棕色至粉棕色。雌鸟非繁殖期上体更橄榄色，喉部和胸部较非繁殖期雄鸟更苍白。","call":"发出尖锐的swizzling叫声，类似于其他种类的织雀。","habits":"栖息于多种生境，包括灌木地、草原、开放林地、内陆湿地和半沙漠地区。城市花园和公园中亦可见其身影。","breeding":"繁殖期主要在9月至翌年1月，雄鸟可拥有多位雌鸟伴侣，一季建巢多达25个。巢由草、芦苇或棕榈叶编织而成，雌鸟会用软草和羽毛装饰选定的巢穴。巢建于树上，常在水面上方，有时在郊区。一窝蛋颜色多样，帮助躲避寄生鸟的寄生。孵化和育雏主要由雌鸟承担。","identification":"与黑头织雀区别在于背部斑驳程度和雌鸟的喙型及眼色。黑头织雀雄鸟背部更斑驳，雌鸟喙更粗壮，眼色更暗。","protection":"IUCN：LC（无危）","distribution":"分布自安哥拉南部至莫桑比克，南至南非东部；亦见于圣多美岛（几内亚湾群岛）。"},{"name":"赞比亚黑额织雀","english_name":"Katanga Masked Weaver","scientific_name":"Ploceus katangae","overview":"赞比亚黑额织雀（英文名：Katanga Masked Weaver，学名：Ploceus katangae），是雀形目织雀科织雀属的鸟类。小型鸟类，最显著的特征是红眼和黑色面部面具，尤其是繁殖季节的雄鸟，额头上的黑色带纹宽窄随地理位置而异。分布于中南部非洲，主要在赞比亚北部和刚果民主共和国东南部的特定湿地及周边林地。","appearance":"雄鸟繁殖期间具有鲜明的黑色面罩，眼圈红色，背部橄榄绿，腿部呈粉棕色。雌鸟和幼鸟外观较为暗淡，与同类中的其他织雀难以区分。雄鸟的体型较小，面罩周围带有橙黄色，背部及臀部颜色较深。","habits":"居住在芦苇丛、湿地及相邻的树林地带，形成局部化的群体或成对居住。活动范围狭窄，仅限于东北赞比亚至东南刚果民主共和国的一条狭长地带。","breeding":"繁殖期在刚果民主共和国为1月至3月，在赞比亚则为9月至10月及3月。繁殖行为推测为一雄多雌制。巢穴呈肾脏形状，入口位于下方，筑于芦苇、纸莎草或靠近水源的树丛中，每窝产1-2枚蛋，蛋色为浅绿色至蓝绿色，带有细小的棕色或浅栗色斑点。","identification":"与褐喉金织雀相似，但体型更小，面罩周围有橙黄色，背部和臀部颜色更深。与坦噶尼喀和卢菲拉湖黑额织雀相比，后者面部和下体有更多的橘橙色，且分布范围不重叠。","protection":"IUCN：LC（无危）。分布范围有限，主要在Upemba国家公园内，但该公园管理状况堪忧，缺乏监控和保护措施。全球种群规模和趋势不明，急需进行详细的野外调查以评估其状态。","distribution":"主要分布在刚果民主共和国东南部和赞比亚北部的Upemba平原，具体地点包括Bukama、Mabwe和Kadia等地的Upemba沼泽地。"},{"name":"刚果黑额织雀","english_name":"Lufira Masked Weaver","scientific_name":"Ploceus ruweti","overview":"刚果黑额织雀（英文名：Lufira Masked Weaver，学名：Ploceus ruweti），是雀形目织雀科织雀属的特有种鸟类，主要分布在刚果民主共和国东南部的沼泽地带，如Lake Tshangalele和Kiubo Falls附近。","appearance":"红眼的刚果黑额织雀拥有橄榄黄的背部和粉棕色的腿脚。繁殖季节的雄鸟具有黑色的面部遮盖，延伸至后冠部，几乎覆盖整个头部，胸部和两侧呈强烈的栗色（中部腹部为淡黄色）。雌鸟和幼鸟上部暗绿，翼上有条纹，下部淡黄。","habits":"成对或群居于河流附近的植被中，偏好树而非芦苇床作为繁殖地点。活动范围局限，常见于刚果民主共和国东南部特定水域。","breeding":"刚果黑额织雀在一月至四月繁殖，报道显示可能有二次繁殖。雄鸟可能为多配偶制，每只雄鸟拥有数个巢穴，但并非群居形式，巢穴数量在3到20个之间，通常为4到6个一起。巢为椭圆形，由雄鸟编织，悬挂在距离水面0.5到2米的树枝上，材料为织物条。","identification":"与其他类似种类的差异在于黑色面部遮盖的范围和色彩饱和度。例如，Tanganyika Masked-Weaver的黑色遮盖面积较小；Katanga和Southern Masked-Weavers则更显黄色。","protection":"IUCN：LC（无危）","distribution":"仅在刚果民主共和国的东南部繁殖，具体地点包括Lake Tshangalele和Kiubo Falls沿岸的R Lufira河。","other":"直到2009年再次被发现前，仅知于1960年采集的雄鸟标本。2009年的观察显示其并不罕见。"},{"name":"坦桑黑脸织雀","english_name":"Tanzanian Masked Weaver","scientific_name":"Ploceus reichardi","overview":"坦桑黑脸织雀（英文名：Tanzanian Masked Weaver，学名：Ploceus reichardi），是雀形目织雀科织雀属的鸟类。亦被称为坦噶尼喀黑脸织雀。该鸟以红眼和橄榄绿背部为显著特征，繁殖期雄鸟具有黑色面部面具，橙色胸部，而雌鸟和幼鸟则较为暗淡，但胸前略带橙黄色，腹部白色。","appearance":"繁殖期雄性坦桑黑脸织雀的前额、眼圈、脸颊、耳羽、下巴和喉咙为黑色，面具延伸至胸部中部；头顶为深栗棕色至眼后，后冠和颈背为金黄色，肩部和背部为黄绿色，臀部金黄色，尾巴绿褐色；上翼为褐色，飞羽有狭窄的黄色边缘，翼羽有宽广的黄色边和尖端；胸腹和两侧为栗棕色，大腿、腹部中央和尾下覆羽为金黄色。雌鸟和幼鸟上体黄绿色，头部和肩部有浅色条纹；下方为黄色，胸有橙色晕染；虹膜棕色，喙和腿为棕色。","call":"其鸣唱被描述为无旋律的混合声，包括叽喳声和啾啾声，偶尔带有颤音。还发出“咔嗒”、“咕噜”和快速的“啾啾”叫声。","habits":"栖息于含有纸莎草(Cyperus papyrus)、香蒲(Typha)和芦苇的沼泽地带，有时远离干燥陆地；夜间栖息于沼泽。推测为留鸟。主要食物为草籽，曾在白蚁丘附近的林地中觅食，可能捕食白蚁。","breeding":"繁殖期在坦桑尼亚为四月，可能在赞比亚为十二月。可能为一雄多雌制。雄鸟在有高达150个巢的殖民地中建立领地。巢呈药壶状，无入口隧道，由雄鸟用窄条草叶紧密编织，顶部有草条构成的明显天花板，碗状巢室铺有细小的草穗和羽毛；悬挂于水面上方的灌木丛中，或附着于单株草或芦苇茎的一侧，距地面或水面高度1.5-3米。每窝产卵2-3枚，颜色为蓝色带深棕色斑点或灰橄榄色带模糊的深色标记，七枚卵平均大小为20.4×13.8毫米（坦桑尼亚）；关于孵化期和育雏期的信息未知。部分巢穴因大象觅食而被破坏。","identification":"与其他类似的黑脸织雀相比，如卡坦加和黑额织雀，繁殖期雄鸟的坦桑黑脸织雀更显黄色，缺乏栗色调，而刚果黑额织雀的面具延伸过顶冠，下体呈强烈栗色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西南部的坦桑尼亚和东北部的赞比亚，具体范围包括南卢夸湖周边的沼泽地带。","other":"此物种在卢库瓦（坦桑尼亚）的当前状况不确定，大部分栖息地现在位于划定的狩猎保护区。当地人曾收集巢中的雏鸟作为食物，但不清楚这一做法是否仍在继续。"},{"name":"赤道黑额织雀","english_name":"Vitelline Masked Weaver","scientific_name":"Ploceus vitellinus","overview":"赤道黑额织雀（英文名：Vitelline Masked Weaver，学名：Ploceus vitellinus），是雀形目织雀科织雀属的鸟类。雄鸟会展现出鲜艳的黄色羽毛，黑色面具覆盖眼周至喉咙，以及红眼和黑色喙。广泛存在于草原生境。","appearance":"赤道黑额织雀体长约14厘米，体重18-22克。繁殖季雄鸟具有鲜明特征，额头有窄黑带，面罩黑，冠部呈栗褐色，颈金色黄，背部绿黄有淡暗条纹，臀部黄，尾橄榄绿，翼上部暗棕，羽缘黄。非繁殖季雄鸟和雌鸟较暗淡，背部橄榄棕，翼和尾有黄边，腹部淡色，虹膜红色，喙黑，腿棕色。雌鸟相似，但色彩更柔和。幼鸟似非繁殖季雌鸟，上部更橄榄绿，虹膜棕，喙角棕。","call":"赤道黑额织雀的鸣唱为一系列嘶嘶声，间杂着粗糙音、哨声和啾啾声，短形式为“chick-chikleewer-chi”。接触叫声为尖锐的“pink”声。","habits":"赤道黑额织雀常以群居形式出现在多种草原生境中，活跃于地面和低树丛中，主要以种子和昆虫为食。迁徙模式依地理位置而异，部分地区为留鸟，其他地区则随季节迁移。","breeding":"繁殖期多在雨季前后，雄鸟会独力编织巢穴，形状为椭圆或梨形，结构紧密，入口短或无隧道，悬挂于单点，常见于离水源不远处。巢由雄鸟编织，吸引雌鸟前来产卵。每窝产卵2-4枚，蛋色蓝白至绿色，平均尺寸19.5x13.2mm。雌鸟孵卵，孵化期12-13天，雏鸟期14-16天。巢可能被其他鸟类如环喉雀和红颊蓝饰雀侵占。","identification":"赤道黑额织雀与其他织雀的区别在于其繁殖季雄鸟的栗色冠而非黑色，以及红色的眼睛。非繁殖季的个体通过体型、颜色和红色眼睛谨慎识别。","protection":"IUCN：LC（无危）","distribution":"分布于毛里塔尼亚西南部、塞内加尔、冈比亚、几内亚比绍、马里南部、布基纳法索、加纳东至乍得南部、中非共和国北部、苏丹南部、南苏丹、刚果民主共和国东北部、埃塞俄比亚中部和南部、索马里西北部和南部、乌干达西北部、肯尼亚东北部，向南至坦桑尼亚中部。"},{"name":"斯氏织雀","english_name":"Speke's Weaver","scientific_name":"Ploceus spekei","overview":"斯氏织雀（英文名：Speke's Weaver，学名：Ploceus spekei），是雀形目织雀科织雀属的鸟类。常见的东非鸣禽，以黄色为主色调，具有黑色脸罩，眼色淡，喙部较大，全年保持相同的羽色。分布于埃塞俄比亚、索马里至坦桑尼亚北部，常见于人烟稠密地区如肯尼亚的中央高地，乃至城市环境。","appearance":"雄性斯氏织雀额头、头顶至颈背呈金色黄色，逐渐过渡为橄榄绿色；背部黑色，边缘黄色，形成斑驳外观；翼上覆羽有宽阔的黄色边框，形成翼纹；颊部、耳羽、下颌和喉部黑色，延伸至胸上部，边缘狭窄的栗褐色；其余胸部、侧腹、腹部、大腿和下尾羽覆羽金黄色；雌鸟及非繁殖期雄鸟整体橄榄色，具暗色纵纹，腹部较白，繁殖季节下方更显黄色；幼鸟相似但色泽较暗淡。","call":"鸣唱变化多样，有版本被转录为“pew…pew…tew, chinkichi-chewchew-skerinkitsitew”。叫声包括巢边的尖锐‘tseep!’声和粗糙的叽喳声。","habits":"栖息于草原、灌木丛、农田及城镇，偏好干燥地带。常以小群出现，活动于开阔的稀树草原。","breeding":"营巢于群体或偶尔单独，巢编织于金合欢树上，呈球形，带有短入口管，开口朝侧或向下，巢内草茎杂乱，有时遮掩其形状。繁殖期涵盖短雨季和长雨季中期，一窝通常产四枚深蓝色无斑点的卵，卵形两端略尖，长约24至26毫米，宽约15至17毫米。","identification":"与黑脸织雀相似，但体型更壮实，喙更大，背部条纹更明显。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的埃塞俄比亚和索马里至坦桑尼亚北部，具体包括北至东北索马里，埃塞俄比亚中部至南部，肯尼亚（主要为中央高原），以及坦桑尼亚东北部。"},{"name":"乌干达织雀","english_name":"Fox's Weaver","scientific_name":"Ploceus spekeoides","overview":"乌干达织雀（英文名：Fox's Weaver，学名：Ploceus spekeoides），是雀形目织雀科织雀属的鸟类。体型短胖，尾巴较短，喙长。繁殖期雄鸟主要呈黄色，面部有黑色面罩，眼睛淡色，背部大部分黑色并带有黄色条纹。雌鸟颜色较为暗淡，整体呈橄榄褐色，腹部偏黄。该鸟种仅在乌干达特定地区发现，主要栖息于草原中的沼泽地带。","appearance":"乌干达织雀具有短胖的体型，尾部较短，长喙。雄鸟在繁殖季节呈现出鲜艳的黄色体羽，脸部覆盖着黑色面罩，双眼淡色，背部黑色为主并点缀着黄色条纹。雌鸟的色彩远不如雄鸟鲜艳，全身呈现橄榄褐色，腹部色调偏黄。与绿腰织雀相似，但体形更大，雄鸟的背部颜色更深。","call":"其鸣叫特征包括典型的‘chek’音符和类似无线电杂音的‘squealing’声，这是一种嘶嘶作响的‘radio static’歌曲。","habits":"乌干达织雀栖息于乌干达的沼泽环境内，偏好湿润的草原地带。它们的生存环境包括潮湿的草原、季节性湿润或被水淹没的低地草地以及沼泽。它们的生活习性和迁徙模式尚未详细记载。","breeding":"关于乌干达织雀的繁殖细节信息有限，但一般织雀科鸟类的繁殖习性包括营巢、求偶和育雏过程。","identification":"与绿腰织雀相比，乌干达织雀体型更大，雄鸟背部颜色更暗，这成为区分两者的重要特征。","protection":"IUCN：NT（近危）","distribution":"乌干达织雀的分布范围局限于乌干达中部的特定区域，包括沼泽环境内的草原。","other":"1913年，从乌干达中部Teso地区采集到了乌干达织雀的标本，该标本于1923年赠予英国自然历史博物馆。1947年，C.H.B. Grant和Mackworth-Praed将其鉴定为与斯氏织雀关系密切的独特物种。"},{"name":"黑头织雀","english_name":"Village Weaver","scientific_name":"Ploceus cucullatus","overview":"黑头织雀（英文名：Village Weaver，学名：Ploceus cucullatus），是雀形目织雀科织雀属的鸟类。广泛分布在非洲次撒哈拉地区，已引入葡萄牙、委内瑞拉及Hispaniola、Martinique、Puerto Rico、Mauritius和Réunion等岛屿。常见于多种开放或半开放生境，包括林地和人类居住区，形成大型嘈杂的城镇群体。善于建造大型粗糙的草叶条编织巢，巢口向下，悬挂于树上。以种子和谷物为主食，偶尔损害农作物。","appearance":"体长约15-17厘米，具强壮锥形喙与深红色眼睛。雄鸟繁殖季节头部黑色，边缘有栗褐色，北部和背部黄色带黑色V字标记；雌鸟橄榄绿上部，黄色和黑色翅膀，淡黄色下部。非繁殖季雄鸟头部黄色，冠橄榄绿，上部灰色，下部白色。雌鸟上部条纹橄榄绿，翅膀黄黑，下部浅黄。幼鸟似雌鸟，背部较棕色。","call":"发出延长的下降式鸣叫，终声似喘气声。另有20余种叫声，包括指向雏鸟的呼唤、巢邀请与交配叫声，以及短促的'chik'声和对捕食者的尖锐警报。","habits":"栖息于灌木草原、河岸林地、湿地、农田、乡村、城市与郊区花园。群居，大型群落，与人类居住区紧密相关。以种子、谷物、昆虫为食，造成农业损害。","breeding":"繁殖期随地区而异，群居繁殖，每巢2-4枚蛋，雌鸟独自孵卵约12天，雏鸟孵化后由雌鸟喂养，离巢前需17-21天。巢常遭蛇、猴、多种鸟类掠夺。","identification":"雄鸟繁殖羽与其他织雀通过体型、喙大小、眼色区分；雌鸟与橙巧织雀通过体型、喙、眼色区分。不同亚种间有颜色差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲次撒哈拉地区，但在西南和东北干旱地带缺失。已引入印度洋与加勒比海岛屿。","other":"被视为害鸟，特别是在稻田与农作物种植区。"},{"name":"大织雀","english_name":"Giant Weaver","scientific_name":"Ploceus grandis","overview":"大织雀（英文名：Giant Weaver，学名：Ploceus grandis），是雀形目织雀科织雀属的鸟类。仅见于圣多美岛（São Tomé），以其粗壮的喙和硕大的头部著称，酷似啄木鸟。成年雄鸟头黑胸栗，雌鸟色泽较淡，幼鸟上部棕色更深。","appearance":"大织雀体型庞大，雄鸟头部至喉部黑色，与后颈的栗褐色相连，背部黄绿色带暗色条纹，翼及尾橄榄绿，翼羽具黄色边缘形成翼斑。雌鸟前额至背部橄榄灰，腹部白色，脸颊和耳羽橄榄灰，下体淡黄色。幼鸟上部棕色，翼覆羽具宽淡色边缘，下体和头部侧面淡黄色。","call":"其鸣唱为一系列咔嚓声后接以嘶鸣，'pche pche pche pche pche pche gzzzuinuiuinuinuinuin'，类似黑头织雀的叫声，飞行时会发出重复的'prrric'叫声。","habits":"常见于森林、林缘和种植园中，成对或小群体活动。其习性类似树栖鸟，能灵活攀爬树木和枝条。","identification":"圣多美岛上其他种类的织雀体型较小，雄鸟不具备栗色特征。","protection":"IUCN：NT（近危）","distribution":"仅分布于圣多美岛（São Tomé），位于几内亚湾。"},{"name":"大黑织雀","english_name":"Vieillot's Black Weaver","scientific_name":"Ploceus nigerrimus","overview":"大黑织雀（英文名：Vieillot's Black Weaver，学名：Ploceus nigerrimus），是雀形目织雀科织雀属的鸟类。以法国鸟类学家Louis Pierre Vieillot命名。其分布广泛，自尼日利亚东南部至苏丹南部，乌干达，肯尼亚西部，坦桑尼亚西部，刚果民主共和国南部和安哥拉。过去曾被认为是与栗黑织雀同种，但基于显著的羽色差异而被区分为独立物种。","appearance":"成年雄性大黑织雀通体黑色，具黄色虹膜，喙黑色，腿灰至棕褐色。雌鸟上体暗绿色，顶冠及颈背有微弱的暗色条纹，背部条纹较宽，臀部无条纹；尾及上翅深棕灰色，翼羽有橄榄绿边缘，覆羽具淡黄边；脸侧和喉部淡黄，胸带宽阔，腹面黄至橄榄色；虹膜浅棕色，喙暗灰色，腿棕色。雌鸟和幼鸟相似，但额及顶冠无条纹，覆羽有黄边，下体更黄；虹膜最初暗灰，后转棕色，最终变为黄色。","call":"鸣唱为沙哑的喋喋不休的短语；短歌为chrrr-szee-zuit声，在领地争执和求偶时远离巢穴发出，雌鸟入巢时也会鸣叫。防御时发出尖锐的chak声，报警时发出类似叫声；叫声可组成不规则的短语，例如tsuk-way-tsik、way-tsik-tsuk-tsik，也能发出哨音sweet、上滑音way-yee和重复的tyo-tyo-tyo-tyeew。","habits":"栖息于森林空地，常出现在村庄、林木区域和高草草原；与森林带紧密相关，但不在完整的森林中。海拔可达喀麦隆的1300米和刚果民主共和国的2000米。通常居住在混合物种昆虫食群中，特别是在咖啡种植园中与灰背织雀相伴。食谱主要是昆虫，也可能包括种子、浆果和开花树的花蜜。","breeding":"繁殖期在尼日利亚为2月，喀麦隆全年除8月，加蓬为12月至2月、4月和7月，中非共和国为7月至8月，刚果民主共和国南部为11月、中部草原为4月和8月至9月、卢科尔拉为7月至2月、伊托姆贝可能全年繁殖(确认于2月、7月至8月和11月)；苏丹为8月和11月，乌干达全年(高峰为2月至5月和9月至10月)，肯尼亚为7月至9月，安哥拉为10月至3月。一夫多妻制，每只雄鸟领土内有多达五只雌鸟。筑巢于芦苇、高象草、棕榈、竹子或树木(如Musanga、Mangifera indica、Pachylobus edulis)中，高达25米。巢由雄鸟用棕榈叶条或草编织，内部由雌鸟铺垫草籽头。卵为两枚，淡蓝色，偶尔厚端有少许紫色斑点，大小为21.1-25.4mm×15-17.4mm(喀麦隆)或22-26.2mm×15.4-17mm(刚果民主共和国)。","identification":"雄鸟与栗黑织雀非常相似，但体型更大，偏好更开阔的栖息地，且具有明亮的黄色而非灰色的眼睛。雌鸟具有更丰富的赤褐色侧面和尾巴。","protection":"IUCN：LC(无危)","distribution":"分布于非洲东南部尼日利亚至苏丹南部，乌干达，肯尼亚西部，坦桑尼亚西部，刚果民主共和国南部和安哥拉。","other":"与黑头织雀形成混合殖民地，有时在人类住区附近。"},{"name":"韦氏织雀","english_name":"Weyns's Weaver","scientific_name":"Ploceus weynsi","overview":"韦氏织雀（英文名：Weyns's Weaver，学名：Ploceus weynsi），是雀形目织雀科织雀属的鸟类。体型较为壮实，拥有较长而相对细薄的喙。雄鸟外观独特而美丽，上体呈黑色，两侧锈色，腹部黄色。雌鸟外表较为暗淡，上体橄榄灰色，胸部有一条深色带。两性均有浅色眼睛。主要分布于非洲中南部的森林、种植园和沼泽地带，常见于群体中。雌鸟与Vieillot's Weaver雌鸟相似，但喙略细，胸部颜色更深，通常与特征明显的雄鸟相伴。","appearance":"雄性韦氏织雀具有鲜明的黑色上体，两侧锈色，腹部鲜黄至橙黄色，头部黑色。雌鸟和年轻个体大多为黄色，带有黑色痕迹，外观上更接近雌鸟。雄鸟的体重在24-36克之间，雌鸟体重在23-34克左右。","call":"鸣叫包括典型的织雀‘chek’音符和类似‘无线电杂音’的歌曲。","habits":"栖息于森林、种植园和沼泽地带，偏好靠近内陆淡水湖泊。在非繁殖季节，可能广泛游荡。以果实为主食，包括野无花果，常在森林树冠层觅食，通常成对或成群活动，有时群体可达200只以上。","breeding":"在刚果民主共和国，成年韦氏织雀的生殖腺在4月至6月期间增大。在乌干达，生殖腺的变化发生在6月和7月，幼鸟则出现在11月。繁殖后，9月至11月期间会换羽。","identification":"与Vieillot's Weaver雌鸟的区别在于，韦氏织雀雌鸟的喙略细，胸部颜色更深。","protection":"IUCN：LC（无危）。韦氏织雀在当地数量稳定，全球范围内并不受威胁，其种群趋势稳定。","distribution":"主要分布于非洲中南部，包括刚果民主共和国东北部、乌干达南部、坦桑尼亚西北部，以及肯尼亚有零星记录。"},{"name":"克氏织雀","english_name":"Clarke's Weaver","scientific_name":"Ploceus golandi","overview":"克氏织雀（英文名：Kilifi Weaver，学名：Ploceus golandi），是雀形目织雀科织雀属的鸟类。体型小巧、形态独特的森林型织雀，雄鸟具黑色头罩与亮黄色腹部，雌鸟色泽暗淡。该种仅分布于肯尼亚东南沿海狭窄地带，常在密林与潮湿林冠中结群活动。","appearance":"体长13厘米，雄鸟23–27克，雌鸟21–25克。雄鸟自头至胸黑色，背部及尾暗橄榄绿，腰亮橄榄绿并具黄色羽缘；翼黑褐，覆羽具宽阔黄边，折叠时形成两道显著翼斑；胸黑与黄腹界限分明，下腹、侧腹及尾下覆羽渐染白色；虹膜深褐，嘴黑色，脚淡褐。雌鸟额、头顶及后颈亮橄榄绿，具狭窄黄色眉纹；背、腰同色系但具黑色中央羽干纹；翼黑褐，覆羽具黄色边；脸及耳羽淡黄，喉至胸亮黄并带橄榄绿侧斑；腹、胁白色具黄色条纹，腿灰色带黄纹；虹膜褐色，嘴角灰色。幼鸟似雌鸟，但上体淡绿、条纹稀少，下体近白带黄洗，嘴褐色。两性及幼鸟均具黄色翼缘，飞行时尤为显眼。","call":"觅食群体会发出急促的“chek”声及持续的“sss sss”嘶嘶声，飞行时发出尖锐“chip chip”。合唱时呈“电台静电”般的尖细嘶嘶声。其鸣唱尚未被详细描述。","habits":"仅分布于肯尼亚东南沿海，主要栖息于沿海森林及以短盖豆属（Brachystegia）为主的湿润林地。多在林冠层活动，常结成活跃小群，有时多达30只，偶见百只以上混群。常与弯嘴林戴胜、东非黑头黄鹂、黑鹃鵙、灰背织雀、雷氏盔鵙及栗额盔鵙混群觅食。推测为留鸟，但8月至翌年3月记录较多，12–2月记录稀少，暗示可能有局部迁移。","breeding":"繁殖信息直至2013年才首次确认。当年在距马林迪西北的Dakatcha林地发现约400–500巢的繁殖群，巢密集建于一片仅80×30米的湿地中，巢体粗糙编织、侧口低置，筑于挺水高莎草（Cyperus exaltatus）顶端。从筑巢到离巢仅约24–30天（3月23日仍见求偶筑巢，4月7日已喂雏，4月19日群体弃巢）。巢内食物几乎全部为昆虫，其中约60%为不同大小的幼虫，其余包括蚱蜢、蟋蟀等。卵及雏鸟特征尚未描述。幼鸟记录见于1–2月、4月及7–8月，9月亦见雄鸟具繁殖状态，暗示该种可能在3–6月及11–12月两个雨季均有机会繁殖，具一定机会性。","identification":"与灰背织雀外形相近，但克氏织雀具明显的黄色翼缘、更细长的嘴及雄鸟黑色头罩与黄腹的鲜明对比，可据此区分。","protection":"IUCN: EN（濒危）。分布极为狭窄，属于“东非沿海森林”特有鸟区（EBA）。20世纪80年代初估计全球种群不足4000只，此后无再评估，推测仍在下降。主要威胁为林地开垦、选择性伐木及薪柴、雕刻材砍伐。核心栖息地Arabuko-Sokoke森林保护区约350平方千米被其占据，Dakatcha地区亦有记录，但部分山丘正被大规模清林改种水果。","distribution":"仅见于肯尼亚东南沿海：马林迪附近的Malindi区域、Arabuko-Sokoke森林保护区、Dakatcha林地（Sabaki河以北）以及Galana牧场东部至Marafa、Hadu一带。繁殖记录目前仅确认于Dakatcha的Arbamukenge湿地，Arabuko-Sokoke森林内4–7月几乎未见，8月起携幼鸟返回，可能非该森林的主要繁殖地。","other":"克氏织雀为单型种，无亚种分化。"},{"name":"萨氏织雀","english_name":"Juba Weaver","scientific_name":"Ploceus dichrocephalus","overview":"萨氏织雀（英文名：Juba Weaver，学名：Ploceus dichrocephalus），是雀形目织雀科织雀属的鸟类。这种织雀主要分布在非洲的埃塞俄比亚中部、肯尼亚极北部以及索马里南部，是该地区特有种。","appearance":"萨氏织雀是一种体型较为小巧紧凑的织雀，体长约13厘米，体重约18至20克。繁殖季节的雄鸟具有鲜艳的色彩，头部为黑色，颈背转为亮红褐色，背部绿色泛黄，腹部和背部呈黄色，翼上橄榄棕色，尾部橄榄绿色，尾羽边缘带有黄色。非繁殖季节的雄鸟和雌鸟则呈现暗淡的橄榄灰色，胸部淡黄，喙基部有一块浅色斑，喙整体黑色，腿为棕粉色。幼鸟外观类似雌鸟，但上体颜色更深，下体带有更多黄褐色。","call":"其鸣唱被描述为漫游且不悦耳，包含尖锐、打鼾和嗡嗡声的音符，发出典型的‘chik’声和粗糙的‘无线电噪音’般的歌声。","habits":"栖息于河流沿岸灌木丛，偏好干燥环境，常在小群中活动，海拔低于1500米。饮食以种子为主，可能也摄入昆虫。通常成对或小群体行动。","breeding":"繁殖季节在埃塞俄比亚为3月，可能采取一雄多雌制。筑巢于树上或芦苇中，巢为椭圆形，几乎无入口隧道，由草编织，内部衬有细草，悬挂于枝梢或单根芦苇侧边。每窝产卵2枚，蛋壳呈淡绿蓝或灰绿色，带褐色和淡紫色斑点，尺寸约为20.5 x 14.5毫米。","identification":"与其他织雀如黑头黄背织雀和苏丹金背织雀通过分布区域进行区分，非繁殖季的雄鸟和雌鸟可通过喙基部的浅色斑和整体大小形状识别。","protection":"IUCN：LC（无危）。萨氏织雀在当地常见，但在索马里罕见。已知存在于埃塞俄比亚的Babelle Elephant Sanctuary和索马里的Balcad Nature Reserve。","distribution":"分布于非洲的埃塞俄比亚中部、肯尼亚极北部以及索马里南部，主要栖息在河流沿岸的灌木丛中，甚至出现在半沙漠地区的Acacia-Commiphora荆棘灌木丛。"},{"name":"黑头黄背织雀","english_name":"Black-headed Weaver","scientific_name":"Ploceus melanocephalus","overview":"黑头黄背织雀（英文名：Black-headed Weaver，学名：Ploceus melanocephalus），是雀形目织雀科织雀属的鸟类。以其独特的黑色头部和黄色背部著称。分布于非洲的西部、中部和中东部地区，已引入伊比利亚半岛。","appearance":"成年雄鸟在繁殖季节具有醒目的外观，面部、颈部为黑色，身体其余部分为黄色，与之形成鲜明对比。雌鸟和非繁殖季节的雄鸟相似，胸部呈黄色，腹部白色。雄鸟体重约20.1-36.3克，雌鸟17.9-27.5克。幼鸟外观类似于雌鸟，但下体颜色较浅，翼羽边缘更宽，背部条纹较少。","call":"鸣唱混合了嘶哑、粗糙和嘎吱声，短形式的叫声“squeee-ki-kee”，用于领土防御和求偶。警戒时发出尖锐的“chak”声。","habits":"栖息于河流或静水附近的湿润地带，如芦苇丛和纸莎草丛。在较干燥地区可能出现在树丛草原。通常活动于海拔1500米以下。非繁殖季节形成群落。以种子和昆虫为食，使用喙的撬动动作觅食。","breeding":"繁殖期在不同地区有所不同，一般在5月至10月之间。一夫多妻制，有时单配偶。独居筑巢或群体筑巢，巢由雄鸟用草编织，内部由雌鸟铺设。每窝产卵2-3枚，孵化和喂养由雌雄共同承担。","identification":"与金背织雀和村织雀的区别在于其纯绿色的背羽和黑色头部。雌鸟和非繁殖季节的雄鸟与面具织雀相似，但有暗色眼睛和喙。下体羽毛颜色因个体而异。","protection":"IUCN：LC（无危）","distribution":"分布在非洲的西部、中部和中东部，包括毛里塔尼亚、塞内加尔、冈比亚等地。在伊比利亚半岛有自持的引进种群。","other":"北非褐喉织雀与黑头黄背织雀的杂交种曾被认为是 Ploceus victoriae。"},{"name":"苏丹金背织雀","english_name":"Golden-backed Weaver","scientific_name":"Ploceus jacksoni","overview":"苏丹金背织雀（英文名：Golden-backed Weaver，学名：Ploceus jacksoni），是雀形目织雀科织雀属的鸟类。也被称为杰克逊织雀。成年雄鸟色彩鲜艳，呈现明亮的黄色，头部光泽黑亮，腹部呈锈橙色。雌鸟整体颜色较暗淡，主要为黄色，与其它雌鸟织雀难以区分。其分布范围从非洲苏丹南部至坦桑尼亚，是东部非洲的本土物种。","appearance":"成年雄鸟的苏丹金背织雀拥有醒目的外观，全身大部分区域呈明亮的黄色，头部具有金属光泽的黑色，腹部则为锈橙色。雌鸟整体颜色较为暗淡，通体黄色，这使得它在野外与其他雌鸟织雀种类的辨识上存在一定的挑战。","habits":"苏丹金背织雀栖息于湿地环境，它们的活动范围集中在东部非洲的湿地区域。该物种已知在新加坡和阿联酋建立稳定种群，显示出对引入环境的适应能力。","breeding":"这种鸟类在繁殖季节会建造椭圆形的巢穴，这一行为是其生态习性的重要组成部分。","identification":"在辨识上，需留意与韦氏织雀的区别，后者雄鸟背部为黑色，两性眼睛颜色较浅，有助于区分。","protection":"IUCN：LC（无危）","distribution":"苏丹金背织雀的自然分布范围涵盖南苏丹南部、乌干达、肯尼亚西部与南部、坦桑尼亚北部、中部和东部以及布隆迪。此外，该物种已被引入阿联酋。"},{"name":"桂红织雀","english_name":"Cinnamon Weaver","scientific_name":"Ploceus badius","overview":"桂红织雀（英文名：Cinnamon Weaver，学名：Ploceus badius），是雀形目织雀科织雀属的鸟类。仅分布在苏丹和南苏丹，具有明显的季节性迁徙习性，通常在九月至十月返回繁殖地。以社群形式生活，偏好拥有浓密树冠的高大树木。","appearance":"成年雄鸟繁殖期间，额头、头顶、脸颊、耳羽、下颚和喉咙呈黑色，延伸至胸部形成黑领；颈背和背部为深栗褐色，尾巴暗橄榄绿；上翼深棕色，飞羽边缘有窄黄边，内部有宽黄斑；胸腹部深栗褐色环绕黑领，侧面较淡，两侧栗褐色，腹部金黄色带有栗色条纹，大腿和尾下覆羽黄色。雌鸟和非繁殖期雄鸟头部、颈背橄榄绿，背部淡褐色有中央条纹，臀部淡黄色，尾巴橄榄绿；翅膀深棕色，飞羽边缘和内侧有黄色；脸颊和耳羽淡褐色；下颚和喉咙白色，胸腹淡褐色，腹部中心白色；大腿和尾下覆羽白色。幼鸟类似雌鸟，但头和背部颜色更淡，臀部更绿，下颚和喉咙带黄色，下体淡白色，喙角棕，虹膜通常灰色但有变化。个体间黄色量在栗色部位差异明显。","call":"雄鸟的叫声包括鼻音的'err'声，持续约0.12秒，比北非黑脸织雀的叫声更长且不那么突然，有时重复长时间。有时发出双音节的'err-err'声，第一个音符可能高于或低于第二个，且经常重复；还有长达2到3秒的'errrrrrr'声，音调下降，比北非黑脸织雀的类似叫声更频繁。其他叫声包括尖锐的'chip'、'chup'或'tyoo'声，以及嗡嗡的'chup'声，有时在飞行中发出。两性都会发出'see-yoooo'的叫声，第二音符比第一音符略低且拖长。雌鸟访问群落时有时会发出'chuck'声，比大多数雄鸟叫声短且柔和。当雌鸟接近群落时，常听到一系列吱吱声和鼻音的喋喋不休。","habits":"桂红织雀生活在苏丹和南苏丹，它们在繁殖季节返回特定区域，可能采取一夫一妻制，以社群形式居住，选择密集树冠的高大树木作为栖息地。","breeding":"繁殖季节为每年的九月至十月，期间桂红织雀返回其繁殖地进行繁殖活动，具体繁殖细节尚需进一步研究。","identification":"桂红织雀与北非黑脸织雀相似，但桂红织雀的头部显得更加均匀，由于颊部和头顶更黄，而北非黑脸织雀的头顶和颊部较暗，形成更鲜明的超眉纹。在繁殖期，桂红织雀的雌鸟整体更偏黄色，而北非黑脸织雀的雌鸟胸部黄色，腹部更白。","protection":"IUCN：LC（无危）","distribution":"桂红织雀主要分布于苏丹和南苏丹，没有明确区分繁殖区与非繁殖区。","other":"在班丁吉洛国家公园报道存在重大的狩猎压力，尽管该物种在当地常见甚至丰富，且出现在一些保护区。"},{"name":"栗织雀","english_name":"Chestnut Weaver","scientific_name":"Ploceus rubiginosus","overview":"栗织雀（英文名：Chestnut Weaver，学名：Ploceus rubiginosus），是雀形目织雀科织雀属的鸟类，广泛分布于非洲东部及西南部。其显著特征为繁殖期雄鸟的不寻常色彩组合：黑色头部与栗色身躯形成鲜明对比。","appearance":"成年雄鸟在繁殖期展现独特的外观，额头、头顶、耳羽和脸颊为黑色，与颈部和背部的栗色形成明显界限。上翼和尾巴呈深棕色，胸腹部、两胁及臀部为栗褐色。非繁殖期雄鸟及雌鸟则呈现灰褐色，胸部有淡色斑带，腹部白色，两胁可能带有淡栗色。雌鸟外观类似非繁殖期雄鸟，但无栗色痕迹，整体色调较浅。幼鸟似雌鸟，但胸部有条纹。","habits":"栗织雀是一种高度游牧的物种，常见于干燥的草原环境。雨季后常以大群出现，开始在大型聚居区筑巢。它们的活动范围广泛，善于飞行，以种子为主要食物。","breeding":"繁殖期雄鸟会建立大型巢穴群落，吸引雌鸟。","identification":"繁殖期雄鸟与栗麻雀相似，但可通过较大的体型和黑色头部轻易区分。非繁殖期雄鸟和雌鸟颜色较为单一，缺乏类似种类的绿色和黄色调。","distribution":"非洲东部和西南部，包括但不限于埃塞俄比亚、肯尼亚、坦桑尼亚、赞比亚、安哥拉、纳米比亚等地。"},{"name":"金枕织雀","english_name":"Golden-naped Weaver","scientific_name":"Ploceus aureonucha","overview":"金枕织雀（英文名：Golden-naped Weaver，学名：Ploceus aureonucha），是雀形目织雀科织雀属的鸟类。最显著的外部特征是拥有暗红色的额头和头顶，以及颈部后方的金色橙色项圈。该物种分布于非洲的刚果民主共和国东北部低地森林，主要栖息在伊图里和塞姆利基森林的原始和次生森林及其边缘。","appearance":"雄性金枕织雀的胸部和喉部呈红棕色，背部带有金色条纹，而雌鸟则缺乏这些特征。头部的色彩和颈后独特的金色橙色项圈是该物种的标志性特征。","call":"其声音被描述为微弱的叽叽喳喳声。","habits":"金枕织雀主要栖息于伊图里和塞姆利基森林的低地森林及其边缘地带。对于它们的生活习性和生态偏好，由于记录稀少，了解甚少。","breeding":"关于其繁殖行为的信息极为有限，仅有的一次记录是在1993年，观察到一对金枕织雀正在喂养两只离巢的幼鸟。","identification":"金枕织雀通过其独特的头部颜色和颈后的金色橙色项圈与其他织雀属物种区分开来。","protection":"IUCN：EN（濒危）","distribution":"金枕织雀的分布局限于刚果民主共和国的伊图里和塞姆利基森林，以及乌干达西部的塞姆利基国家公园。","other":"金枕织雀自1926年后60年间未曾被记录，直到1986年才再次发现，显示出其极度稀有和难以追踪的特点。"},{"name":"黄肩织雀","english_name":"Yellow-mantled Weaver","scientific_name":"Ploceus tricolor","overview":"黄肩织雀（英文名：Yellow-mantled Weaver，学名：Ploceus tricolor），是雀形目织雀科织雀属的鸟类。广泛分布在非洲热带雨林区域，主要在西部和中部。其最显著的特征是背部有一块明亮的金黄色三角斑块。","appearance":"该鸟拥有黑色头部和腹部，与深灰色或红褐色的腹部形成鲜明对比。上体大部分为黑色，除了一块醒目的金黄色三角斑块位于背部，这是其最显著的外部特征。黄肩织雀的体型适中，雌雄及幼鸟的羽毛颜色和大小可能会有所不同。","call":"其鸣叫包括机械般的哨声和刺耳的叫声，以及干燥的嘁嘁喳喳声，有时会组合成复杂的歌曲。","habits":"黄肩织雀通常栖息在森林高处或旧农田中，靠近水体或洪水区域，以小群体或混杂种群的形式活动。它们的觅食行为多样，包括在地面拾取食物、空中捕食昆虫以及像啄木鸟一样攀爬较大的树枝和树干。","identification":"与其他几种织雀相比，黄肩织雀具有独特的上体特征，以及黑喉与较淡腹部之间的明显对比。","protection":"IUCN状态未提供。","distribution":"主要分布于非洲西部和中部的热带雨林区域。","other":"无"},{"name":"白枕黑织雀","english_name":"Maxwell's Black Weaver","scientific_name":"Ploceus albinucha","overview":"白枕黑织雀（英文名：Maxwell's Black Weaver，学名：Ploceus albinucha），是雀形目织雀科织雀属的鸟类。分布于非洲西部和中部热带雨林区，具有独特的黑色羽毛和醒目的白色眼睛。","appearance":"体长约13至15厘米，体重25至30克。成鸟全身黑色，上体光泽，颈背羽毛基部白色，形成淡色斑块，尤其在羽毛磨损时更为明显。虹膜白色到绿白色，喙黑色，腿棕色。雄雌相似。幼鸟上体暗褐色至黑褐色，缺乏光泽，下体灰暗，虹膜和喙均为棕色。西部种群的颈背羽毛完全黑色，幼鸟下体带有黄色调。东部种群则全身黑色。","call":"发出柔和的摩擦声，可能代表其歌声。在群体中接触时发出'chick chick'的叫声。","habits":"栖息于低地常绿森林，靠近被次生林环绕的村庄，常出现在河流和溪流附近，海拔高度可达850米。主要以昆虫为食，包括蚱蜢和毛虫，也会吃浆果和开花树的花蜜。白天在不同层次觅食，高处单独捕食昆虫，低处则小群体活动，通常不超过十二只，但在刚果共和国有时可达二十只。加入混合物种群。","breeding":"在西非，筑巢活动最早见于二月的塞拉利昂，十一月至十二月在利比里亚和加纳可见幼鸟，三月在喀麦隆发现性腺增大的个体。可能实行一夫多妻制。群体筑巢，每群20至500个巢，有时与黑头织雀和黄头织雀混群筑巢，较少与橙头织雀混群。巢呈粗糙球状，入口位于下方，几乎没有隧道，由细藤蔓或香蕉叶条编织而成，通常置于树冠高处的垂枝尖端，高于地面10米以上。在塞拉利昂的一个20巢的群体直接位于王鹰的巢下。","identification":"与维约氏织雀相比，拥有更薄更尖的喙，偏好森林环境。","protection":"IUCN：LC（无危）。分布区域内数量稀少至局部较为常见，乌干达罕见。可能因森林栖息地破坏而脆弱。在村落，巢穴中的幼鸟有时会被采集食用。","distribution":"主要分布在非洲西部和中部的热带雨林区，包括喀麦隆、刚果民主共和国、利比里亚、塞拉利昂等地。"},{"name":"纳利织雀","english_name":"Nelicourvi Weaver","scientific_name":"Ploceus nelicourvi","appearance":"雄性纳利织雀拥有黑色的前额、头顶至耳羽，形成鲜明的盔状结构；上体和上翼为均匀的橄榄绿色，尾部呈褐绿色；下颏黑色，喉咙到胸部黄色，环绕颈背形成锐利界定的黄色带，有时泛橙色光泽；胸上部有狭窄的橄榄色领环，下胸、腹部、胁部和大腿灰色，尾下覆羽红栗色；虹膜棕色至暗红棕色；喙黑色；腿灰色。雌鸟外观相似，但头部黑色部分主要由黄色替代，仅眼上方暗灰色，冠部橄榄色延伸至眼后和较暗的耳羽；腿灰色至肉粉色。幼鸟头部绿褐色，眼上方和喉部有黄色斑块，总体比雌鸟更暗淡，喙黄褐色，常有黑色斑点（最年轻的鸟喙可能均匀浅色）。","call":"其鸣声为尖锐的嘶嘶声；叫声则是沙哑的、重复的“chey”。","habits":"通常单独或成对出现，有时加入混合觅食群。偏好在低海拔至中海拔的湿润山地和低地森林中生活，但也可见于硬叶山地森林、灌木丛和茂密地带。以昆虫为主食，通过独自或小群体的方式觅食，经常与长嘴伯尼里亚鸟混群。巢穴悬挂在开阔地带，显眼而独特。","breeding":"繁殖期在9月至12月，表现为一夫一妻制，可能建立长期伴侣关系。巢独建，相距甚远；偶尔两巢相隔不远，但仅一巢被占用，可能由同一个体建造。巢室由雄鸟用草和棕榈纤维编织，形似药瓶，有一个长达20厘米的入口通道，悬挂于树、藤或竹茎之上，离地2至7米，常见于溪流上空或路径上方的空旷处。巢基部由15至30厘米长的“茎”固定。雌鸟可能提供内衬材料。每窝产卵2至4枚，多为3枚，蛋壳呈淡蓝绿色，平均尺寸21×15.5毫米。孵化由雌鸟单独承担，孵化期约15天，双亲共同喂养雏鸟。","identification":"与近缘种萨卡织雀相比，纳利织雀的羽毛较为光滑，无条纹。与林织雀和红织雀相比，上体颜色更加均匀，缺乏明显的红色特征。","protection":"IUCN：LC（无危）","distribution":"分布于马达加斯加北部（包括安布雷山）和东部（从塔拉塔纳纳山脉向东至萨姆巴瓦，南至托拉加纳罗）。","other":"其巢穴构造独特，由雄鸟精心编织，为研究鸟类筑巢行为提供了宝贵资料。"},{"name":"萨卡织雀","english_name":"Sakalava Weaver","scientific_name":"Ploceus sakalava","overview":"萨卡织雀（英文名：Sakalava Weaver，学名：Ploceus sakalava），是雀形目织雀科织雀属的鸟类。体型粗壮，喙大，为马达加斯加特有种，分布于北部、西部及南部低地至中海拔区域。繁殖季节时，雄鸟头部呈黄色，非常独特，雌雄两性眼周均有粉红色裸露皮肤。","appearance":"雄鸟繁殖期有鲜明的黄色头至胸上部，背部灰色至棕色，翼及尾深棕色，翼下覆羽及大覆羽具淡色边缘形成翼斑。腹部及臀部灰色，尾下覆羽淡白色。虹膜深棕色，眼周裸露皮肤呈红色，喙蓝灰色，腿暗粉色。非繁殖期雄鸟和雌鸟相似，但头部灰暗，眼周皮肤浅粉色，喙浅灰色。雌鸟头部灰色，脸颊及眉纹锈色，具双条纹，喉部灰白，下体较淡，喉部及尾下覆羽白色，侧身带些锈色。幼鸟似雌鸟，但整体更淡，头部尤其明显，喙角质色。","call":"雄鸟的歌声是一系列复杂、高音调的责备声和嘶嘶声。叫声为沙哑的“chert”。飞行叫声为“treeyoo”。","habits":"生活在开阔森林、灌木丛、种植园、草原及村庄。群居，常以群体形式活动，有时与其他鸟类混群。筑巢于繁忙的群体中，巢为凌乱的悬挂球状。","breeding":"繁殖时间受当地降雨影响，北部在9月至10月，西部在11月至翌年4月，更干旱的西南部则不规律，可能从8月开始到12月结束。主要为一夫一妻制，部分雄鸟可能为多妻制。巢由两性共建，呈药瓶状，入口延长成17至40厘米长的隧道，由草、叶茎和棕榈叶条编织而成，内衬柔软的植物纤维，离地面2至25米，通常位于树上，如猴面包树（Adansonia）和外来物种Gyrocarpus americanus。每窝产卵2至4枚，卵呈绿色，平均大小为20.5 x 15.1毫米。","identification":"与fodies相比，萨卡织雀体型更大，喙更粗，面部皮肤粉红色，面部图案不同。","protection":"IUCN：LC（无危）","distribution":"非洲：马达加斯加西北部，西部，南部。"},{"name":"亚洲金织雀","english_name":"Asian Golden Weaver","scientific_name":"Ploceus hypoxanthus","overview":"亚洲金织雀（英文名：Asian Golden Weaver，学名：Ploceus hypoxanthus），是雀形目织雀科织雀属的中型鸟类。特征为亮黄色的外表和厚实有力的喙，雄鸟面部具黑色面具，背部有鳞状斑点。雌鸟颜色较淡，喙部呈浅粉色。主要分布于东南亚大陆和苏门答腊，新加坡有人工引入种群。","appearance":"雄性亚洲金织雀长约15厘米，体重约19克，黄色为主，面部有黑色面具，背部黑色带绿黄色边缘，翼和尾暗棕色，腹部橙黄色。雌鸟额头和冠部暗棕色，背部中央有深色条纹，腹部淡褐色，腹中心和尾下覆羽淡白色。喙部上侧角质粉红，下侧浅粉。幼鸟似雌鸟，但常有黄色洗染和更明显的头部条纹。","call":"叫声为一系列嘈杂音符，结尾带有长颤音，伴有尖锐的“chit”声。声音与黄胸织雀相似。","habits":"栖息于低地湿地附近，如沼泽、稻田和泛滥草甸。群居性，以草籽为主要食物，如Echinochloa colona和Eriochloa procera的种子，繁殖期间昆虫占饮食比例小。在水边或非常潮湿的地面，靠近植被处筑巢。","breeding":"繁殖期在7月至9月，可能为一夫一妻制，偶尔多妻。在小群体中繁殖，雄鸟先建巢，后由雌鸟协助完成。巢呈圆形，侧面入口，由细草或棕榈叶编织，通常位于水面或沼泽地上方不足1米，常见于芦苇或香蒲中。每窝产2枚蛋，罕至3枚，灰白底色，平均尺寸18x13.5毫米。仅雌鸟孵卵，雏鸟主要由雌鸟喂养，偶尔雄鸟参与。","identification":"与黄胸织雀相比，亚洲金织雀雌鸟背部和翅膀的暗色图案较少，雄鸟黄色覆盖范围更广。雄鸟的黑色面具和黄色上体是辨识关键。","protection":"IUCN：NT（近危）；在苏门答腊和爪哇曾经广泛分布，现局部且稀少。因湿地转为农田导致种群持续减少，且面临非法捕捉和鸟市贸易威胁。","distribution":"繁殖于缅甸至爪哇，包括柬埔寨、印度尼西亚、老挝、缅甸、泰国和越南。在苏门答腊和爪哇曾广泛分布，现局部且稀少。","other":"历史记录显示，亚洲金织雀最早由瑞典自然学家Anders Erikson Sparrman命名，曾在19世纪尝试引入Cocos Islands（苏门答腊以南），但未成功。"},{"name":"褐翅织雀","english_name":"Compact Weaver","scientific_name":"Ploceus superciliosus","overview":"褐翅织雀（英文名：Compact Weaver，学名：Ploceus superciliosus），是雀形目织雀科织雀属的鸟类。从塞内加尔到利比里亚，东至埃塞俄比亚，南至安哥拉和刚果民主共和国南部。","appearance":"繁殖季节的雄鸟和雌鸟都具有黑色面罩，雄鸟的头顶呈黄色，而雌鸟的头顶则是黑色。非繁殖季节的个体外观更为独特，下体呈淡褐色，头部和眼纹深色。体型上，它们与典型的织雀有所不同，更显丰满。","call":"除了典型的织雀‘chit’声和类似无线电杂音的歌曲外，还会发出‘cheep’叫声。","habits":"偏好湿润和草丛微生境，如草原、森林边缘、灌木丛和耕作区。常以小型群体活动。","identification":"虽然外表上与其他织雀相似，但其独特的体型和色彩模式使其易于区分。","distribution":"分布区域高度不连续，覆盖了西南塞内加尔、几内亚比绍沿海、东南几内亚、塞拉利昂北部、利比里亚北部、科特迪瓦西部和东部、加纳南部至尼日利亚西南部（内陆至扎里亚）、喀麦隆中部和东南部、加蓬、刚果、中非共和国西南部、苏丹东南部、南苏丹南部和东部、埃塞俄比亚西南部、乌干达、刚果民主共和国、安哥拉北部和东北部、卢旺达西部、布隆迪西部、坦桑尼亚西北部（维多利亚湖边境）和肯尼亚西部。"},{"name":"黑胸织雀","english_name":"Black-breasted Weaver","scientific_name":"Ploceus benghalensis","overview":"黑胸织雀（英文名：Black-breasted Weaver，学名：Ploceus benghalensis），是雀形目织雀科织雀属的鸟类。生活在印度次大陆北部河流平原上的织雀。以独特的编织技巧著称，雄鸟会构建封闭式的巢穴，吸引雌鸟的注意力。该鸟种的命名源自于1758年瑞典自然学家卡尔·林奈的描述，最初被归入十字雀科，后归入由法国自然学家乔治·居维叶在1816年建立的Ploceus属中。黑胸织雀在南亚地区广泛分布，常见于印度次大陆北部，少量存在于半岛地区。","appearance":"黑胸织雀的体型类似麻雀，全长约15厘米。繁殖期雄鸟拥有亮丽的金黄色顶冠，头部和胸部有变化的黑色斑纹，一些个体的头部几乎全黑（除顶冠外），胸部也是黑色，而另一些个体则有白色喉咙或全白脸庞，仅有一条黑色带状图案与淡黄色下体相隔。非繁殖期雄鸟和雌鸟的顶冠为棕色，与背部羽毛一致，黑色胸带不那么明显。它们具有明显的眉纹，耳后斑点，以及窄窄的颊纹，颜色为淡黄色。群体常出现在耕作区、水塘边的芦苇丛或广阔的高草地带。","call":"黑胸织雀的鸣声为柔和的蟋蟀般的唧唧声，当群鸟返回栖息地时会发出轻柔的chit-chit声。","habits":"黑胸织雀栖息于芦苇沼泽、多草平原和稻田中。它们倾向于在高草或芦苇中建立庞大的巢群，通常每个巢群由2至3个巢组成。巢穴有中等长度的垂直入口通道，而非悬垂形状。黑胸织雀以种子为主食，包括Echinochloa colonum、Phalaris minor、Perotis、水稻（Oryza）、小麦（Triticum）、小米和高粱等作物的种子。在喂养幼鸟时，主要提供动物性食物，如昆虫，尤其是蚱蜢（Orthoptera），还有毛虫（Lepidoptera）、甲虫（Coleoptera）、蜘蛛（Araneae）和小型蜗牛（Gastropoda）。它们经常与其它种类的织雀、蜡嘴雀（Estrildidae）、椋鸟（Sturnidae）等混群觅食。","breeding":"繁殖期发生在6月至10月间，黑胸织雀实行一雄多雌制。雄鸟单独构建巢穴，巢穴呈葫芦形，入口通道长度在6至30厘米之间（很少超过20厘米），由草条或芦苇叶片编织而成，通常悬挂在距地面1至2米高的Pennisetum或Saccharum草丛中，或固定在芦苇或灯芯草（Typha）上。巢穴的上部穹顶直接连接到草丛上，或在‘头盔’阶段，巢穴边缘会被涂上一层厚厚的湿泥或牛粪，有时还装饰有鲜艳的红色或橙色花朵或花瓣（如Lantana、Lagerstroemia）。一旦雌鸟接受了巢穴结构，雄鸟会迅速完成剩余部分，雌鸟随后在巢穴内产卵。每窝通常产3枚白色无斑点的卵，平均尺寸为20.3×15毫米，孵化期由雌鸟负责，大约持续13至15天。雏鸟主要由雌鸟喂食昆虫，雄鸟在最后五天参与喂养，整个巢期为15天。","identification":"繁殖期雄鸟与黄胸织雀的区别在于胸带的颜色为黑褐色或褐色，边缘呈黄褐色；与纹胸织雀的区别在于腹部无纵纹。雌鸟及非繁殖期雄鸟的顶冠为褐色，但仍可见黑色胸带或黄褐色边缘。雌鸟与黄胸织雀的区别在于头部侧面的褐色及黄色图案。","protection":"IUCN：LC（无危）","distribution":"黑胸织雀主要分布在巴基斯坦至中国中南部的东洋界区域。具体而言，它们见于巴基斯坦东北部和东南部（在印度河泛滥平原）、印度北部（主要在恒河泛滥平原，从旁遮普向东至西孟加拉邦和阿萨姆邦）、尼泊尔南部和孟加拉国。关于缅甸南部和中国南部（云南）的旧记录存疑，而在卡塔尔有人工引入的记录。","other":"黑胸织雀被视为某些地区谷物作物的害虫，特别是在旁遮普地区的粮库造成损害。"},{"name":"纹胸织雀","english_name":"Streaked Weaver","scientific_name":"Ploceus manyar","overview":"纹胸织雀（英文名：Streaked Weaver，学名：Ploceus manyar），是雀形目织雀科织雀属的鸟类。常见于南亚和东南亚国家，如孟加拉国、不丹、柬埔寨、中国、埃及、印度尼西亚、尼泊尔、巴基斯坦、新加坡、斯里兰卡、泰国、越南等地，以及在卡塔尔和阿联酋引入。不如黄胸织雀普遍，但外观相似，下体有条纹。","appearance":"繁殖季节的雄鸟具有金黄色的顶冠，黑色面部和喉咙，背部暗棕色，羽缘锈色，腹部中央奶油白色，两侧和胸侧锈色，有深褐色条纹。非繁殖季节的雄鸟、雌鸟和幼鸟更接近其他燕雀，具黄色眉纹，沿脸后部延伸，背部暗棕色，条纹侧面，尾巴和上翼深棕色。雌鸟繁殖季节与非繁殖季节差异较小，上部暗棕色，有深灰色条纹，脸颊和耳羽灰色轻微条纹，下巴和喉咙淡黄白色。","call":"雄鸟发出连续的‘cheer’或‘teaur’叫声，不如黄胸织雀响亮，当雌鸟接近巢穴时，会发出不同的歌曲，由一系列高音口哨组成，以嘶哑的音符结束。","habits":"偏好水域附近的芦苇地，形成嘈杂的繁殖群体。主要以种子为食，包括Echinochloa colonum和Phalaris minor等草籽，以及稻米、小麦、小米和高粱。幼鸟主要以动物性食物喂养，如昆虫，尤其是蚱蜢、毛虫、甲虫、蜘蛛和小蜗牛。在炎热月份形成日间栖息地，靠近觅食地。非繁殖季节，会在芦苇地和甘蔗地中形成公共栖息地。","breeding":"繁殖期在巴基斯坦和印度为6月至9月，斯里兰卡为2月至4月和7月至10月，缅甸为6月至10月，爪哇为3月至5月。巢呈壶状，由雄鸟用芦苇或棕榈叶条编织，有时带有长达30厘米的入口隧道，面向下方。巢置于水面以上至2米的芦苇、香蒲、象草中，有时在棕榈树上或红树林中靠近人类居住区。每窝产2-3枚白色蛋，平均尺寸为20.3x14.3毫米。孵化期为14-17天，由雌雄共同承担，孵化后约17-18天雏鸟离巢。","identification":"与黄胸织雀相比，纹胸织雀的下体有明显的条纹，雄鸟繁殖季节的顶冠颜色为金黄色，而非黑色。","protection":"IUCN：LC（无危）","distribution":"在印度次大陆及中国西南地区广泛分布，具体包括南亚和东南亚各国，以及中东的卡塔尔和阿联酋。在中国，分布于西南地区。"},{"name":"黄胸织雀","english_name":"Baya Weaver","scientific_name":"Ploceus philippinus","overview":"黄胸织雀（英文名：Baya Weaver，学名：Ploceus philippinus），是雀形目织雀科织雀属的鸟类。以其独特的悬垂巢而知名。这种织雀遍布印度次大陆和东南亚，常见于开阔地带，如草场、农田和灌木丛中。其最显著的特征是繁殖季节中雄鸟的黄色前额和冠部，与深色喉部形成鲜明对比。","appearance":"雄鸟在繁殖季节头部呈明亮的黄色，喉部深色，与黄色的下体形成强烈对比。非繁殖季节雄鸟和雌鸟外观相似，主要为淡褐色，背部有暗色条纹，雌鸟有宽阔的淡色眉纹。幼鸟似雌鸟，但缺乏明显的眉纹。不同地区的亚种在黄色和黑色的数量上存在差异。","call":"雄鸟的广告鸣叫是一系列沙哑的叽喳声，随后是一串嗡嗡的哨音，穿插着长时间的叽喳声，通常由一群雄鸟同时发出，形成嘈杂的合唱。","habits":"栖息于草地、有散生树木的灌木丛、红树林和耕作区。常在水源附近的开阔地带活动，高度可达1400米。迁徙模式受海拔和食物可用性影响，有时会进行局部迁移。群居，以种子、花蜜、昆虫和其他小型无脊椎动物为食，偶尔捕食小青蛙、壁虎和软体动物。","breeding":"繁殖季为5月至9月（巴基斯坦）、4月至10月（印度）、3月至4月和8月至9月（斯里兰卡），在东南亚主要是12月至6月。雄鸟建造复杂、倒挂的巢穴吸引雌鸟，每只雄鸟可吸引3至5只雌鸟。巢由长条状的棕榈叶、草或稻叶编织而成，入口隧道长达40至65厘米。雌鸟负责孵卵，雄鸟偶尔协助喂养雏鸟。","identification":"黄胸织雀与纹胸织雀的区别在于前者缺乏强烈的条纹外观，尤其是繁殖季节雄鸟的黄色和深色对比明显。","protection":"IUCN：LC（无危）","distribution":"广泛分布于印度次大陆、东南亚地区，包括中国大陆的西南部。在苏门答腊、爪哇等地数量较多。","other":"在某些地区被视为害鸟，因为它们会损害农作物。人类的活动对其巢穴造成破坏可能是最大的威胁之一。"},{"name":"巨嘴织雀","english_name":"Finn's Weaver","scientific_name":"Ploceus megarhynchus","overview":"巨嘴织雀（英文名：Finn's Weaver，学名：Ploceus megarhynchus），是雀形目织雀科织雀属的鸟类。分布于印度北部、尼泊尔和不丹南部的特莱地区。这种鸟因拥有强大的暗色喙而著称，雄鸟主要呈黄色，颊部有深色斑块；雌鸟上身有条纹，下身颜色较淡，缺乏强烈条纹和面部图案。曾在笼鸟贸易中受到追捧。","appearance":"雄性巨嘴织雀主要为黄色，具有显著的暗色颊斑。雌鸟则上部条纹呈褐色，下部颜色更浅，无强烈条纹和面部图案。其喙强壮，呈暗色，比其他相似种类更为粗大和尖锐。两性均具有深褐色虹膜，黑色喙和深褐色脚。","call":"其叫声为轻柔的噗声，间杂以颤音、卷舌音及叫声，相比赤胸朱顶雀，声音更加嘶哑且带有鼻音。常见叫声为唇音r-r-r-r-r-ee或哑声turr，飞行时也会发出尖锐的shreep声。","habits":"巨嘴织雀偏好开放地带，散落有树木的环境，尤其青睐湿润地区。它们群居筑巢，雄鸟会在树顶或芦苇丛中建造球状巢穴，通常选择棉树作为筑巢地点。","breeding":"繁殖期从五月持续至九月。它们的巢结构独特，由薄叶片和芦苇编织而成，整个内部都铺有材料，不同于仅在巢底铺设材料的其他织雀种类。","identification":"与黑胸织雀和条纹织雀相比，巨嘴织雀雌鸟的色彩更深，没有明显的眉纹，喙更粗大且形状更锐利。","protection":"IUCN：EN（濒危），过去20年中快速下降，主要受人类活动压力和农业变化的影响，导致特莱草原的丧失和退化。在尼泊尔极西南部的苏克拉潘塔皇家野生动物保护区发现的种群估计不足50只，出现频率不稳定。","distribution":"繁殖区域主要位于印度北部、尼泊尔和不丹南部的特莱地区。在沙克拉潘塔国家公园有规律的夏季访客记录。","other":"曾被定期捕捉用于笼鸟贸易，由于稀少，价格较高。"},{"name":"灰背织雀","english_name":"Dark-backed Weaver","scientific_name":"Ploceus bicolor","overview":"灰背织雀（英文名：Dark-backed Weaver，学名：Ploceus bicolor），是雀形目织雀科织雀属的鸟类。具有独特暗色背部、黄色腹部和浅色喙的织雀。其分布广泛，见于非洲的森林和茂密林地，包括miombo林区。","appearance":"体长约14至15厘米，体重28至47克。成鸟的前额、头顶至颈部及背部呈深紫褐色，臀部为深棕色，部分羽毛边缘黄色；上翼和尾部为深紫褐色，初级飞羽边缘狭窄灰色；颊部和耳羽黑褐色；喉部羽毛基部棕色，尖端黄白色，形成斑点状效果；胸部、侧腹、腹部、大腿和尾下覆羽金黄色，胸部带有橙色调；虹膜深棕色；喙黑色至蓝灰色，边缘淡色（远观可能显得苍白）；腿粉红至灰粉色。雌雄相似；幼鸟似成鸟，但上体较暗淡，下体黄色较淡，喉部灰色，点缀黄色，喙角质色至黄色。不同亚种在颜色上有细微差异。","call":"其独特的歌声由不同类型的叫声交织而成，节奏错落有致，通常以二重唱形式呈现。","habits":"常成对出现，偶尔成群。主要以节肢动物为食，包括蜘蛛、蚱蜢、蟑螂、甲虫、毛虫、蝽象、苍蝇等，也食用浆果、无花果、Coccinia palmata果实，以及Tecoma capensis和Erythrina的花朵，会吸食Aloe和Erythrina的花蜜。在树冠层和树枝末端觅食，高度在森林地面以上5至20米。加入混合物种群，尤其在干季。","breeding":"繁殖期在不同地区有所变化，一般为独巢，伴侣关系可维持数年。巢呈倒置壶状，入口位于下方，隧道长度通常不超过30厘米，使用坚韧材料如藤蔓和攀援植物的卷须构建，外观粗糙干燥，悬挂在2.5至15米高处的树枝或藤蔓尖端。每窝产卵2至4枚，蛋壳颜色多样，孵化期估计为15至17天，雏鸟期约22天。","identification":"与其他森林栖息的织雀相比，灰背织雀背部无绿色调，腹部无赤褐色调，通过这些特征可以区分。","protection":"IUCN：LC（无危）","distribution":"分布在安哥拉、布隆迪、喀麦隆、刚果共和国、刚果民主共和国、赤道几内亚、斯威士兰、加蓬、肯尼亚、马拉维、莫桑比克、尼日利亚、卢旺达、索马里、南非、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。"},{"name":"金背织雀","english_name":"Preuss's Weaver","scientific_name":"Ploceus preussi","overview":"金背织雀（英文名：Preuss's Weaver，学名：Ploceus preussi），是雀形目织雀科织雀属的鸟类。拥有醒目的金栗色冠部和黄色背部，延伸至尾上覆羽。在非洲热带地区广泛分布，主要栖息于几内亚至加纳，喀麦隆至加蓬，刚果民主共和国东部的原始和次生森林。","appearance":"雄鸟头部前额和冠部至眼睛为橙褐色，后冠和颈背橙褐色，具黑色细长羽毛突出；背部和肩部为金色，部分中央羽毛黑色，臀部黄色，翼上覆羽和尾部黑色；面部、颊、耳羽、喉部黑色；胸部金色，中央有一橙褐色斑块，腹部、胁部、大腿和尾下覆羽为金色。雌鸟相似，但前额黑色，冠部橙褐色至黄色，胸部缺少橙褐色斑块。幼鸟头部橄榄绿色，嘴淡棕色。","call":"通常沉默，但已记录到尖锐的“chwep”叫声。","habits":"主要以昆虫为食，包括其卵和幼虫，也吃草蜢、毛虫、蜘蛛和其他树皮上的节肢动物。偶尔会在10米以下的高度觅食。在树干和树皮上觅食，甚至在死树上，也会在长满附生植物的树枝上觅食。通常成对出现，最多四只个体可能代表家庭群。在利比里亚与共存，在喀麦隆与黄顶织雀共存；在刚果盆地，与金冠啄木鸟、暗色山雀t、细嘴绿鹎、Western Black-headed Oriole和灰颏绿食蜜鸟等混群。","breeding":"繁殖季节在利比里亚为11月，喀麦隆为8月，刚果民主共和国为3月、6月、8月和12月。一夫一妻制。单独筑巢。已知唯一的一个巢为球形，入口位于下方，主要由灰色Usnea苔藓编织，用棕榈叶条固定，安全地固定在离地面11米高的小树枝上。雏鸟由两性共同喂养。","identification":"与黄顶织雀区别在于后者具有较暗的下背部和臀部，且不会沿树枝和树干攀爬；褐顶织雀有深色的冠部，偏好山区。","protection":"IUCN：LC（无危）；分布零散，局部常见，但森林栖息地在其范围内被分割和减少。","distribution":"分布在喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、加纳、几内亚、利比里亚和塞拉利昂。"},{"name":"黄顶织雀","english_name":"Yellow-capped Weaver","scientific_name":"Ploceus dorsomaculatus","overview":"黄顶织雀（英文名：Yellow-capped Weaver，学名：Ploceus dorsomaculatus），是雀形目织雀科织雀属的鸟类。分布于非洲中部，包括喀麦隆、中非共和国、加蓬、刚果和刚果民主共和国东部。其显著特征为雄鸟拥有的金色冠羽和背部，而下背及尾部为黑色。","appearance":"雄性黄顶织雀具有独特的金色头部和上背部，下背部与尾部呈现黑色，形成鲜明对比。雌鸟在面罩和前额至头顶中部为黑色。幼鸟整体上呈深色。成年鸟体长约14厘米。","call":"大部分时间保持沉默，其叫声记录尚不明确。","habits":"栖息于原始森林及次生林的中层和树冠，尤其偏爱亚高山森林。常以成对或小群体的形式出现，亦会加入多种鸟类混群。生活方式较为隐蔽。","breeding":"关于其繁殖行为的具体信息未详，一般织雀科鸟类会建造复杂巢穴，推测黄顶织雀也有相似的繁殖习性。","identification":"与金背织雀相近，但后者下背和臀部为黄色而非黑色，且在树枝和树干上爬行的方式类似啄木鸟。","protection":"IUCN：LC（无危）","distribution":"分布于两块相隔较远的区域：喀麦隆南部、加蓬北部、刚果西北部和中非共和国西南部；以及刚果民主共和国东部（高海拔边缘地区）。","other":"关于其生态习性的详细研究尚待进行，尤其是叫声和繁殖行为。"},{"name":"绿头金织雀","english_name":"Olive-headed Weaver","scientific_name":"Ploceus olivaceiceps","overview":"绿头金织雀（英文名：Olive-headed Weaver，学名：Ploceus olivaceiceps），是雀形目织雀科织雀属的鸟类。分布于非洲的坦桑尼亚、赞比亚东部、马拉维和莫桑比克。其自然生境为亚热带或热带干燥森林。","appearance":"绿头金织雀拥有灰橄榄色的头部和背部，下体呈金色黄色。成熟的雄鸟头部金色更鲜艳，胸部有更广泛的锈色斑块。幼鸟颜色较淡，与成鸟有明显区别。","call":"不常鸣叫，偶尔会发出一系列柔和高音的嗡嗡声，类似‘tzee-twa-twa’。","habits":"栖息于成熟的Miombo林地，偏好‘Old Man’s Beard’Usnea苔藓丰富的环境。绿头金织雀以单个或成对出现，有时加入混合物种群中秘密觅食昆虫，像山雀或攀雀一样沿着树枝爬行寻找食物，不集群筑巢。","breeding":"繁殖生态信息未详述。","identification":"与同属其他种类相比，绿头金织雀的灰橄榄色头部和金色下体是辨识关键。幼鸟的颜色较淡，易于区分。","protection":"IUCN：NT（近危）。绿头金织雀受到栖息地丧失的威胁。","distribution":"繁殖区域包括坦桑尼亚北部、西部和南部，赞比亚东部，马拉维中部和南部，莫桑比克西北部和南部。"},{"name":"坦桑织雀","english_name":"Usambara Weaver","scientific_name":"Ploceus nicolli","overview":"坦桑织雀（英文名：Usambara Weaver，学名：Ploceus nicolli），是雀形目织雀科织雀属的鸟类。独特的织雀科鸟类，分布于坦桑尼亚的东非山脉，如乌萨马拉山、乌卢古鲁山和乌德宗瓦山等地。其最显著的特征是深色上部羽毛、橙色胸前饰带和黄色腹部。","appearance":"雄鸟具有黄色额斑，而雌鸟则缺乏这一特征。体型中等，羽毛色彩鲜明，上体呈深色，胸前有醒目的橙色饰带，腹部黄色。雄鸟和雌鸟在外形上有细微差别，雄鸟的额头有一块黄色斑点。","call":"鸣叫声包括不寻常的‘seet-swit’叫声，以及带有独特滚动节奏的‘radio static’歌曲，这在织雀中颇为罕见。","habits":"生活在高海拔的山地森林中，常见于成对出现，经常加入混合物种的鸟群。行动类似啄木鸟，沿树枝攀爬。它们主要栖息于山地森林的上层。","breeding":"具体繁殖细节未详述，但通常织雀科鸟类会编织复杂巢穴。","identification":"与林织雀相似，但通过橙色胸部可以轻松区分。","protection":"IUCN：NT（近危）。全球数量估计少于2500只，且处于下降趋势。面临森林破碎化和持续的生境破坏威胁。","distribution":"仅分布于坦桑尼亚的东部山脉，包括乌萨马拉山、乌卢古鲁山和乌德宗瓦山，以及可能的鲁贝霍山脉北部。在乌德宗瓦山脉国家公园和乌萨马拉山脉的东西部森林保护区中有所发现。","other":"有效保护剩余生境和扩大现有森林保护区对于坦桑织雀的生存至关重要。"},{"name":"褐顶织雀","english_name":"Brown-capped Weaver","scientific_name":"Ploceus insignis","overview":"褐顶织雀（英文名：Brown-capped Weaver，学名：Ploceus insignis），是雀形目织雀科织雀属的鸟类。独特的黑黄相间颜色的织雀，这种鸟类的显著特征是雄鸟的棕色顶冠和雌鸟的黑色顶冠，两性均具有背部的黄色斑块。主要分布在非洲的山地森林中，通常成对或小群体活动，常加入混种觅食群。褐顶织雀在树干上像啄木鸟一样爬行觅食。","appearance":"雄性褐顶织雀拥有独特的棕色顶冠，而雌鸟则呈现黑色顶冠。两性均在背部有黄色斑块，这一特征在织雀中较为罕见。体型适中，羽毛色彩鲜明，雄鸟与雌鸟的顶冠颜色差异明显，雌雄幼鸟的具体羽毛变化及大小信息未详述。","call":"褐顶织雀不常鸣叫，但其发出的叫声符合织雀的一般特征，包括\"chit\"音符和类似无线电噪音的\"sizzling\"歌声。","habits":"褐顶织雀栖息于山地森林环境，活动范围覆盖较大的树干，它们以类似啄木鸟的方式爬行觅食。它们通常成对或形成小群体，也会加入混合物种的觅食群。具体的迁徙模式、飞行特点、活动范围、食物来源和天敌信息未详述。","breeding":"关于褐顶织雀的繁殖信息，包括繁殖期、求偶行为、筑巢、交配、产卵、孵化和育雏过程的具体细节未提供。","identification":"与金背织雀和黄顶织雀相比，雄性褐顶织雀可以通过其棕色顶冠加以区分，而雌鸟则以其全黑的头部与之区别。","protection":"IUCN状态未提供。","distribution":"分布于非洲东部的尼日利亚（Obudu和Mambilla高原）、喀麦隆西南部和比奥科岛；南苏丹南部的Imatong山脉和Dongatona山脉，刚果民主共和国东部，卢旺达西部，布隆迪西部，乌干达西南部和东部，肯尼亚西部，坦桑尼亚北部和西部；安哥拉西部的Gabela（库安扎省南部）；在加蓬东北部和刚果西南部有过一次记录。","other":"褐顶织雀在非洲特定区域的分布和生态习性显示出其独特性和研究价值。"},{"name":"斑翅织雀","english_name":"Bar-winged Weaver","scientific_name":"Ploceus angolensis","overview":"斑翅织雀（英文名：Bar-winged Weaver，学名：Ploceus angolensis），是雀形目织雀科织雀属的鸟类。具有暗褐色上体，黄色背部和臀部，显眼的白色翼带，以及柠檬色腹侧的淡色下体。幼鸟外观与成鸟相似，但具有淡橄榄灰色冠羽和苍白的喙。该物种分布于非洲安哥拉、刚果民主共和国南部和赞比亚。","appearance":"斑翅织雀是一种体型小、嘴细长的鸟类，体长约13厘米。雄鸟头部前额、顶冠和颈背呈黑褐色，延伸至喙侧面；肩部和背部黑褐，中央有黄色羽尖，臀部黄色；上翼和尾部深棕色，飞羽具白色边缘，大覆羽有宽白尖，小覆羽有窄白尖，形成明显的翼带；下体白色，腹部带有黄色调。雌鸟与雄鸟相似，但肩羽尖端更白，下体黄色彩调较少。幼鸟的冠羽呈暗橄榄灰，颊部和狭窄的眉纹为白色，上颌绿色，下颌粉红色。","call":"斑翅织雀的叫声通常由一系列高音的吱吱声、嗡嗡声和啾啾声组成，有时会发出类似‘tyoo-vo-vo-vo’或更高音的‘tree-zi-zee-zi-zee-zi’声音。","habits":"斑翅织雀栖息于成熟常绿（Cryptosepalum）森林和湿润的Miombo（Brachystegia）林地，特别是‘老人须’Usnea苔藓丰富的区域。它们以昆虫为食，如螳螂、甲虫和摇蚊幼虫，通过像啄木鸟一样沿树枝搜寻的方式觅食。","breeding":"斑翅织雀是独居单配偶的繁殖者。巢穴为近似球形，具有一条30-210毫米长的入口管，从一侧垂下。一窝通常产2-3枚卵，卵壳为蓝绿色，带有较深的斑点和云状标记，主要集中在卵的较厚端。","identification":"斑翅织雀与其他种类相比，其独特的黑色头部、黄色背部、白色翼带和柠檬色腹部是辨识要点。","protection":"IUCN：LC（无危）","distribution":"斑翅织雀主要分布于非洲安哥拉、刚果民主共和国南部和赞比亚，生活在受保护区域。"},{"name":"圣多美织雀","english_name":"Sao Tome Weaver","scientific_name":"Ploceus sanctithomae","overview":"圣多美织雀（英文名：Sao Tome Weaver，学名：Ploceus sanctithomae），是雀形目织雀科织雀属的鸟类。雄鸟具橄榄褐色背部和橙色脸及上胸，而雌鸟整体呈淡褐色。常以对或小至大群出现，活跃于树冠层，觅食行为类似䴓类。","appearance":"雄性圣多美织雀头部为肉桂橙色，黑色冠形成明显的帽状，肩部和背部变为深巧克力棕色，翼上覆羽带有白色边缘形成翼带。雌鸟颜色较暗淡，上部偏棕，下部灰白带橙色晕染，喙部灰粉。幼鸟类似雌鸟，但额部、冠部和颈背皆为暗褐色。","call":"鸣唱开始缓慢，以清晰的音符开头，随后加速至嘈杂的连音，常见叫声为尖锐的\"chwet\"。","habits":"栖息于树上，常以群体形式活动，有时成对或家庭群出现。它们在树的不同层次上觅食，会上下移动，移除苔藓，探查缝隙和枯叶，偶尔倒挂，捕食飞行中的昆虫。","breeding":"未提供具体繁殖信息。","identification":"圣多美岛上的其他织雀种类缺乏明显的翼带。","protection":"IUCN：LC（无危）","distribution":"仅分布于圣多美岛（几内亚湾南部）。"},{"name":"黄腿织雀","english_name":"Yellow-legged Weaver","scientific_name":"Ploceus flavipes","overview":"黄腿织雀（英文名：Yellow-legged Weaver，学名：Ploceus flavipes），是雀形目织雀科织雀属的鸟类。其显著特征在于黄色的腿部，主要分布在非洲的刚果民主共和国，尤其在伊图里森林的东北部。","appearance":"黄腿织雀具有独特的黄色腿部，这是其最显著的外部特征之一。关于其羽毛颜色、大小和变化的详细描述未能获取到具体信息。","habits":"黄腿织雀生活在亚热带或热带的湿润低地森林中，对其栖息地的选择显示出一定的特异性。然而，具体的生活习性，如觅食方式、食物偏好和活动范围等细节尚不清楚。","identification":"黄腿织雀通过其特有的黄色腿部与其他织雀物种相区分，但具体的辨识要点和亚种间的差异信息未能获取。","protection":"IUCN：VU（易危）。黄腿织雀属于分布范围受限的物种，仅存在于刚果东部低地森林生态系统中。由于持续的战争和森林砍伐，其全球分布范围极小，且种群数量因栖息地的破坏和碎片化而减少。已知的标本数量不足十只，最近的一次记录是在1959年；1990年和1994年在奥卡皮野生动物保护区有两次目击记录。","distribution":"黄腿织雀的分布局限于非洲的刚果民主共和国，特别是在伊图里森林的东北部，以及奥卡皮野生动物保护区。"},{"name":"鲁武织巢鸟","english_name":"Ruvu Weaver","scientific_name":"Ploceus holoxanthus","overview":"鲁武织巢鸟（英文名：Ruvu Weaver，学名：Ploceus holoxanthus），是雀形目织雀科织雀属的鸟类。特有于坦桑尼亚东部。繁殖雄鸟色彩鲜艳，通体亮黄色，面部橙红色，有深棕色眼睛。雌鸟较为暗淡，背部条纹呈褐色，腹部淡色，上喙暗灰下喙浅黄橙色。其分布范围以鲁武河为中心，与非洲金织雀相似，但可通过眼色和喙色辨别。","appearance":"雄性鲁武织巢鸟身长约12厘米，明亮的黄色体羽，背部略带橄榄绿，脸部、喉部呈栗橙色，翅膀主羽亮黄色，翼羽轴轻黄色，尾羽黄色。雌鸟前额、头顶和颈背黄色至棕黄色，眉纹淡黄白色，背部淡棕色，羽干中心深色，腹部灰白，耳羽边缘橄榄色，两胁和尾下覆羽淡黄棕色。喙部颜色独特，上喙暗色，下喙浅黄橙色。","habits":"鲁武织巢鸟栖息于湿地，广泛活动于周边的草原和林地。它们的饮食可能包括种子和昆虫。关于迁徙和飞行特点的具体信息尚不明确。","identification":"与非洲金织雀的区别在于鲁武织巢鸟雄鸟的深棕色眼睛，而非洲金织雀雄鸟全年有红棕色眼睛。雌性鲁武织巢鸟的两色喙与非洲金织雀雌鸟的角质喙形成对比。","protection":"IUCN：NT（近危）","distribution":"主要分布在坦桑尼亚东部，沿鲁武河、瓦米河和鲁菲吉河流域，特别是在莫罗戈罗附近已知有多个群落。","other":"鲁武织巢鸟曾被误认为非洲金织雀的一个变种，直到2021年通过形态学分析才被确认为独立物种。"},{"name":"绿枕织雀","english_name":"Olive-naped Weaver","scientific_name":"Ploceus brachypterus","overview":"绿枕织雀（英文名：Olive-naped Weaver，学名：Ploceus brachypterus），是雀形目织雀科织雀属的鸟类。分布于西非从塞内加尔和冈比亚至喀麦隆西部的地区。该物种拥有独特的橄榄绿色背部和枕部，雄鸟和雌鸟色彩鲜明，雄鸟具有黑色喉咙和脸部周围肉桂棕色的色调，而雌鸟则以黄色眉纹和较长的眼纹为特征。","appearance":"绿枕织雀是一种中等体型的鸟类，头部呈深金色，雄鸟有黑色眼线和橄榄绿色的枕部与黑色的喉咙。雌鸟则展现出明显的黄色眉纹，较长的眼纹，且无黑色的喉部。上体颜色为橄榄绿色至金橄榄色，下体和翼下覆羽呈鲜亮的黄色。雄鸟的额头和冠部带有金色光泽，面部和耳罩呈现出橙红色调。雌鸟的额头、冠部、枕部和上体为橄榄绿色到金橄榄色，黄色眉纹显著，眼脸黑色，耳罩和胸带黄色。雄鸟的下体为鲜亮的黄色。","call":"绿枕织雀的鸣叫声为典型的织雀类声音，包括“chet”音符和类似电台静电的歌曲。","habits":"绿枕织雀栖息于林地、灌木丛、湿润的草原、林间小路森林、森林边缘和海岸灌木丛，以及种植园、半常绿森林边缘和红树林中。通常单独或成对出现，适应性强，能迅速占领合适的生境。分布高度可达1,650米。","identification":"绿枕织雀在西非大部分地区独特，很难混淆，但需与同样背绿色的黄腹织雀进行比较。","protection":"IUCN：LC（无危）","distribution":"绿枕织雀广泛分布在西非，自塞内加尔和冈比亚延伸至喀麦隆西部，包括各种生境，如林地、灌木丛、种植园、红树林和半常绿森林边缘。","other":"绿枕织雀的分类历史复杂，曾被认为是黑颈织雀的一个亚种，但分子研究显示两者遗传上非常相似。"},{"name":"栗黑织雀","english_name":"Chestnut-and-black Weaver","scientific_name":"Ploceus castaneofuscus","overview":"栗黑织雀（英文名：Chestnut-and-black Weaver，学名：Ploceus castaneofuscus），是雀形目织雀科织雀属的鸟类。分布在从塞拉利昂到尼日利亚南部。曾被认为是大黑织雀的一个亚种，后因雄鸟显著的栗黑色羽毛而被确认为独立物种。","appearance":"成年雄性栗黑织雀的羽毛独特，主体为黑色，上体、腹部和尾下覆羽呈丰富的栗褐色。雌鸟则为橄榄褐色，腹部颜色较浅，臀部带有赤褐色，翅膀边缘呈淡黄色，下体为淡黄白色，侧腹有赤褐色晕染。幼鸟的特征尚未详述，但可能与成年雌鸟相似。","call":"鸣叫与Vieillot's黑织雀类似，包括短促的tyup、jup、pik和zeet声，穿插着快速、细薄且略带刮擦感的chattering音符，以及一些口哨式的音调，例如weeyoo、woo和wee-weeyoo。","habits":"栗黑织雀栖息于森林边缘、村庄、高草丛生的草原、沼泽地带，以及围绕池塘和湿地的环境，通常不高于海拔800米。它们可能保持居民状态，但在觅食时会远离繁殖群落。食物主要包括昆虫，如蚱蜢、飞蚁、白蚁、毛虫、蝴蝶、螳螂，以及种子、果实、浆果和花蜜。","breeding":"繁殖期在冈比亚为1月，在几内亚为2月，在利比里亚为2月至4月和8月至11月，在加纳为12月至8月，在多哥为2月和9月至10月，在尼日利亚为5月至8月。雄鸟领地可能包含多达五个雌鸟，形成群居繁殖模式。巢由雄鸟以棕榈叶或草条编织，呈椭圆形，内部由雌鸟铺垫草籽头。巢位于水面上方1至2米处，或树上6至8米高的位置。","identification":"雄性栗黑织雀的栗黑色羽毛是与其他织雀属物种区分的关键。雌鸟可能与其它雌鸟织雀混淆，但通过与独特雄鸟的关联可以识别。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部，自塞拉利昂至尼日利亚南部。","other":"栗黑织雀与人类居住区密切相关，由于森林砍伐，其分布范围在某些区域可能正在扩大。它是本地市场用于传统医药的常见物种之一，尤其在贝宁和尼日利亚，用于祝福仪式。"},{"name":"朱顶精织雀","english_name":"Red-crowned Malimbe","scientific_name":"Malimbus coronatus","overview":"朱顶精织雀（英文名：Red-crowned Malimbe，学名：Malimbus coronatus），是雀形目织雀科精织雀属的森林鸟类。其特征在于雄鸟成鸟头顶具有一块不易察觉的红色斑块，而雌鸟全身呈光泽黑色，幼鸟则为哑光黑色头部带栗色。该鸟种稀少且分布零散。","appearance":"雄鸟成鸟除头顶有一红色椭圆形斑块外，其余部分与雌鸟相似，全身呈现光泽的黑色。雌鸟成鸟通体黑色，光泽感明显。幼鸟则呈现出哑光黑的体色，头部带有栗色。雄鸟的红色斑块并不总是容易观察到。","call":"鸣叫声复杂，包括类似织雀的叽叽喳喳声“che-chur-chet”，以及电嗡声“dzrrrrrrr”和高音下滑的“teooot-teoot”音符。","habits":"偏好高大的原始森林和次生低地、沼泽森林的树冠层，常以成对出现。其栖息地通常位于喀麦隆至刚果民主共和国东部的热带雨林。","identification":"雌性朱顶精织雀难以与黑喉精织雀区分开，除非雄鸟个体同时出现，因为两者极为相似。","distribution":"分布于非洲中部，具体包括喀麦隆、中非共和国东南部、刚果共和国北部、刚果民主共和国东部及赤道几内亚和加蓬。"},{"name":"黑喉精织雀","english_name":"Cassin's Malimbe","scientific_name":"Malimbus cassini","appearance":"雌鸟通体黑色，而雄鸟的特征尤为醒目，其胸部至颈背延伸出鲜艳的红色，直至头顶，围绕着黑色的喉咙和面部。这种红黑相间的色彩组合使得黑喉精织雀在其栖息范围内独一无二。","call":"其鸣唱是一系列机械般的哨声和叽喳声，叫声中包含长音的沙哑声和尖锐的‘check！’音符。","habits":"通常以小群体或混群形式出现，有时会与其他精织雀种类一同活动。它们偏爱沼泽森林、棕榈树及靠近水边的环境。","breeding":"关于其繁殖行为的具体信息未在现有资料中详述。","identification":"红颈圈、黑色喉咙和腹部的独特组合让黑喉精织雀易于识别，特别是在其分布范围内。","protection":"IUCN状态未知，需进一步确认。","distribution":"分布于非洲中部，包括喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬等地，沿大河东至伊托姆韦；加纳的报告现已认为有误。","other":"无"},{"name":"金胸精织雀","english_name":"Rachel's Malimbe","scientific_name":"Malimbus racheliae","overview":"金胸精织雀（英文名：Rachel's Malimbe，学名：Malimbus racheliae），是雀形目织雀科精织雀属的美丽鸟类。主要分布于非洲中南部地区的低地原始森林及其边缘地带，特别是在围绕几内亚湾附近的低地森林中。金胸精织雀以金黄色胸部和橙色头部为显著特征。","appearance":"雄鸟拥有橙红色的额头和头顶，逐渐过渡为黄色的颈背；上体、翅膀和尾巴全黑；脸颊、耳羽、下巴和喉咙黑色；胸部中央有一大块双叶状橙色斑，边缘渐变为黄色；腹部、两侧和大腿黑色，下尾羽覆羽黄色；深红色眼睛；黑色喙；灰蓝色腿脚。雌鸟头部和上体全黑；胸部橙色斑块大小及橙黄比例个体间差异大；下尾羽覆羽淡黄色。幼鸟头部顶部、侧面及整个上体黑色；下巴、喉咙和胸部橙色；腹部、两侧和大腿黑色；下尾羽覆羽淡褐色；棕色眼睛；上颌棕色，下颌几乎白色；棕色腿脚。","call":"发出短暂而机械的吱吱声，其歌声则是一系列较长的音符，融合了干燥的嘶哑声，类似于其他织雀和精织雀的歌曲。","habits":"金胸精织雀通常在小群体或混合物种群中活动，高悬于地面之上。它们偏好在低地森林中活动，有时会与其他种类的精织雀混群。特别喜爱在musanga树（又名软木树或伞树）中活动。","breeding":"筑巢由三到四只鸟共同完成，其中仅有一只为雌鸟，她在筑巢中扮演主导角色。巢筑好后，参与筑巢的一只雄鸟会驱赶其他雄鸟。剩下的雌雄双方共同承担孵化蛋的责任。","identification":"与其他精织雀种类相比，金胸精织雀可通过其黄色的下尾羽覆羽和橙色胸部边缘的黄色来识别。","protection":"IUCN：LC（无危）","distribution":"分布于尼日利亚东南部、喀麦隆西部和西南部、赤道几内亚以及加蓬北部中部。","other":"该鸟种得名于John Cassin的女儿Rachel Cassin Davis（1844-1922年），她是一位著名的鸟类学家的女儿。"},{"name":"保氏精织雀","english_name":"Gola Malimbe","scientific_name":"Malimbus ballmanni","overview":"保氏精织雀（英文名：Gola Malimbe，学名：Malimbus ballmanni），是雀形目织雀科精织雀属的鸟类。引人注目的黑黄相间的精织雀，雄鸟拥有橙黄色颈背和金黄色胸带及腹斑，雌鸟全身几乎黑色，仅胸部有模糊的淡黄色新月形斑纹。该物种是上几内亚森林的特有种，分布于塞拉利昂东部至利比里亚再到科特迪瓦。","appearance":"雄性保氏精织雀身长17厘米，具有醒目的橙黄色颈背，亮金色的胸部新月形图案和金黄色腹斑。雌鸟整体黑色，胸部有不明显的淡黄色新月形斑纹。幼鸟与成鸟相似，但颜色较为暗淡，黄色部分延伸至喉咙。","call":"雄鸟的鸣唱包含一系列杂乱、嘁嘁喳喳的声音，随后是一段喘息声，持续时间约三秒，类似于黑头织雀的鸣叫。雌鸟的鸣唱类似，但结尾缺少喘息声。","habits":"保氏精织雀通常单独或小群出现在低层林冠，离地面高度在8至22米之间，以昆虫为食。它们会加入混合物种的鸟群中。有两个繁殖季节，一个小的繁殖季在7月至8月的短暂干季，主繁殖季在10月至11月。","breeding":"繁殖季节分为两个时段，一次在7月至8月的短暂中间干季，另一次在10月至11月。","identification":"与其他malimbe属物种相比，保氏精织雀的黑羽上有黄色而非红色的装饰。幼鸟可以通过其较淡的色彩和黄色喉部识别。","protection":"IUCN：NT（近危）","distribution":"分布于非洲西部，具体包括塞拉利昂东部至利比里亚至科特迪瓦。在塞拉利昂的戈拉森林和邻近的利比里亚西部，以及利比里亚东部至科特迪瓦西部，最近在几内亚东南部的Diecke森林保护区也有发现。","other":"该物种以德国地球科学家Peter Ballmann命名，他曾收集鸟类标本，包括此物种的早期标本之一。"},{"name":"红臀精织雀","english_name":"Red-vented Malimbe","scientific_name":"Malimbus scutatus","overview":"红臀精织雀（英文名：Red-vented Malimbe，学名：Malimbus scutatus），是雀形目织雀科精织雀属的鸟类。以独特的红臀部斑块而著称。雄鸟面部黑色，顶冠、颈及胸部呈红色；雌鸟仅胸部显红色。常见于非洲西部的森林中，多成对出现。","appearance":"红臀精织雀的雄鸟面部漆黑，头冠、颈部与胸部鲜红夺目，雌鸟仅胸部保留红色。其最显著的特征是臀部的红色斑块，这一特征在同类中独树一帜。","call":"其叫声包括清脆的‘tchuk’声以及类似蝉鸣的‘zee-zee-zee’连续音。","habits":"红臀精织雀常栖息于中层林冠至树冠的地带，偏好高大的原始森林、次生低地森林、农林交错区、种植园及村落附近的树木丛。它们有时会加入混合鸟群，偶尔与其他malimbe种类一同活动，觅食方式类似于山雀，从叶片和细枝上寻找食物。","breeding":"关于红臀精织雀的繁殖信息未在现有资料中详细记载。","identification":"红臀精织雀与其它malimbe种类相比，最大的区别在于其臀部的红色斑块，这是辨识该物种的关键特征。","protection":"IUCN：LC（无危）","distribution":"红臀精织雀分布于非洲西部，具体国家包括贝宁、喀麦隆、科特迪瓦、加纳、几内亚、利比里亚、尼日利亚、塞拉利昂和多哥。其自然栖息地主要是亚热带或热带沼泽。","other":"红臀精织雀在分类学历史上曾有系统学变动，但具体细节未详。"},{"name":"尼日利亚精织雀","english_name":"Ibadan Malimbe","scientific_name":"Malimbus ibadanensis","overview":"尼日利亚精织雀（英文名：Ibadan Malimbe，学名：Malimbus ibadanensis），是雀形目织雀科精织雀属的鸟类。仅分布于尼日利亚西南部，包括以它命名的城市伊巴丹（位于奥约州）。1951年首次被发现时曾较为常见，但由于森林砍伐，数量急剧下降。","appearance":"成鸟长约20厘米。雄鸟个体全身黑色，头部和胸部鲜红色；雌鸟个体的红色部分较小。","habits":"栖息于森林和林地环境，包括部分退化区域，常以成对或小群体形式觅食，有时会与红头精织雀一同活动。","identification":"与红头精织雀相比，尼日利亚精织雀的雄鸟头部和胸部颜色更为鲜艳。","protection":"IUCN：EN（濒危）","distribution":"非洲：尼日利亚西南部，包括伊巴丹周边地区及伊冯森林保护区。"},{"name":"蓝嘴精织雀","english_name":"Blue-billed Malimbe","scientific_name":"Malimbus nitens","appearance":"雄鸟几乎全身黑色，胸部有深红色斑块，红斑大小因个体而异，有时延伸至喉咙甚至下巴，下体烟黑色，缺乏光泽。雌鸟类似雄鸟，但红色胸斑通常较小。幼鸟上体颜色较淡，下体炭黑色，头部颜色从黑色到棕色不等，散布着红色羽毛，胸斑暗红或黑色带红羽，最年轻个体的下巴和喉咙羽毛边缘呈橙棕色。虹膜棕色，喙蓝灰色，腿蓝灰至深灰色。","call":"鸣唱包含哨音和机械音，伴有刺耳声，叫声包括短促的‘rhewp’声。具体鸣唱为‘chisisisi-wer chi-wurrr chilly-wer’重复，求偶时雄鸟向雌鸟展示弓身动作，发出‘wookitiki wookitiki wheeze’声。领土防卫时雄鸟单独或遇其他雄鸟后会唱‘wo wewo wewowe weee we we’。","habits":"栖息于低地森林，尤其是低地沼泽和靠近水源的区域。在林下层活动，形成小群体或参与混合物种群。偏好在低地森林和沼泽地带，尤其在棕榈树附近和水边。活动范围广泛，从塞内加尔至安哥拉北部。","breeding":"繁殖季节在塞内加尔为6月至7月，利比里亚为11月至3月，科特迪瓦为6月至3月，加纳为6月至7月和9月至10月，多哥为4月和7月，尼日利亚为2月至11月（主要为4月至7月），喀麦隆为5月至6月和9月至10月，刚果共和国为12月至3月。在刚果民主共和国除4月和8月外全年繁殖，在乌干达为11月和3月，在安哥拉为2月至4月。一夫一妻制。筑巢由雄鸟单独完成，巢球状，入口管宽，常以45度角悬挂，外观类似洪水残骸，内部以精细的棕榈叶碎片或马尾松苔藓铺垫，悬挂在离地面0.4至3米高的棕榈叶片或灌木丛中，接近矮鳄鱼巢穴，可能为保护之故。","identification":"与其他malimbe种类的区别在于全黑上体、红喉斑和黑色腹部的组合。鸣叫和行为特征也是辨识要点。","protection":"IUCN：LC（无危）","distribution":"分布于西非至东非，从塞内加尔和冈比亚至利比里亚，东至乌干达和刚果民主共和国东部，南至安哥拉北部。具体国家包括安哥拉、贝宁、布基纳法索、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、冈比亚、加纳、几内亚、几内亚比绍、利比里亚、马里、尼日尔、尼日利亚、塞内加尔、塞拉利昂、南苏丹、多哥和乌干达。"},{"name":"红头精织雀","english_name":"Red-headed Malimbe","scientific_name":"Malimbus rubricollis","overview":"红头精织雀（英文名：Red-headed Malimbe，学名：Malimbus rubricollis），是雀形目织雀科精织雀属的鸟类。显著特征为雄鸟头部至颈背呈现鲜艳的红色，雌鸟头顶和颈背有一块鲜红斑块，全身其余部分黑色。广泛分布于非洲热带雨林区域，包括西非几内亚、塞拉利昂、利比里亚至尼日利亚南部，中非加蓬、刚果等地。","appearance":"红头精织雀体长约18厘米，体重40至55克。雄鸟额头、冠部和颈背鲜红，冠羽硬挺呈刺状，红色延伸至耳羽后方，形成半圈颈环；面颊和耳羽黑色，余下羽毛全黑。雌鸟整体黑色，仅后冠和颈背有红色斑块。幼鸟较暗淡，额部和冠部为暗红褐色，后冠和颈背橙色，面颊和耳羽淡棕色。","call":"鸣叫声包括逐渐加速的哨音，最终转为嘶嘶声，如“whetdoteew-dzrsrsrrrr”。","habits":"栖息于低地原始森林和次生林，偏好森林边缘和开阔地带，有时出现在咖啡园、可可园及农田周边的小片森林。主要以昆虫为食，如蚂蚁、甲虫、蚱蜢、毛虫等，也会吃小型软体动物、蜘蛛，以及果实和浆果。通常在树冠层活动，高度在15至45米间，偶尔下降至25米以下。","breeding":"繁殖期在不同地区有所差异，如塞拉利昂为7月，尼日利亚为11月至4月，刚果民主共和国的伊图里地区为5月和10月。一夫一妻制，单独筑巢或形成小规模巢群。巢呈倒置壶状，入口宽短约25厘米，常由藤蔓、草叶和寄生兰花根须构成，悬挂在树枝下方，离地面6至45米高。","identification":"与同属其他种类相比，红头精织雀最显著的区别在于雄鸟的红色头部和颈环，雌鸟的红色后冠斑块。","protection":"IUCN：LC（无危）","distribution":"分布于西非几内亚、塞拉利昂、利比里亚至尼日利亚南部，中非加蓬、刚果、安哥拉，刚果民主共和国，南苏丹西部，乌干达南部，肯尼亚西部和坦桑尼亚西北部。","other":"在尼日利亚的传统医药市场中，曾有少量红头精织雀被出售用于传统药物。"},{"name":"红腹精织雀","english_name":"Red-bellied Malimbe","scientific_name":"Malimbus erythrogaster","overview":"红腹精织雀（英文名：Red-bellied Malimbe，学名：Malimbus erythrogaster），是雀形目织雀科精织雀属的鸟类。主要分布在非洲低地森林中，从尼日利亚东南部延伸至刚果和东部至乌干达以及刚果民主共和国东部。其最显著的特征是红腹部和黑背部，面部黑色，头部和颈部红色，形成独特的项圈外观。","appearance":"红腹精织雀拥有鲜明的色彩对比，大部分体羽红色，背部黑色，头部的红色冠和颈部使其具有醒目的项圈状外观。雄鸟的喉部黑色，而雌鸟喉部红色，整体上雌鸟较雄鸟颜色暗淡。体型适中，具体尺寸需参照详细资料。","call":"红腹精织雀的鸣唱和叫声由一系列干燥、机械的音符组成，这些音符连贯成复杂的短语，带有沙哑的声音。","habits":"这种鸟通常生活在小群体中，或与其他物种混群，它们在低地森林的较高处活动，探查枯叶和枯枝。它们的栖息地跨越了多个非洲国家，包括喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬、尼日利亚、南苏丹和乌干达。","breeding":"关于红腹精织雀的繁殖习性，目前文献记载有限，需要更多研究来深入了解其繁殖行为和生态需求。","identification":"红腹精织雀与其他malimbe物种的区别在于其完全红色的腹部。雌雄两性在颜色上有明显差异，雄鸟具有黑色喉部，而雌鸟喉部为红色。","protection":"IUCN：LC（无危）","distribution":"红腹精织雀分布于非洲的低地森林，具体包括尼日利亚东南部、喀麦隆西南部和南部、中非共和国西南部、赤道几内亚、加蓬、刚果北部和西南部、刚果民主共和国东北部和东部，以及乌干达西部的Semliki谷Bwamba森林。历史上也有记录显示曾在南苏丹Bengangai森林出现过。"},{"name":"冠精织雀","english_name":"Crested Malimbe","scientific_name":"Malimbus malimbicus","overview":"冠精织雀（英文名：Crested Malimbe，学名：Malimbus malimbicus），是雀形目织雀科精织雀属的鸟类。包括安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、象牙海岸、赤道几内亚、加蓬、加纳、几内亚、利比里亚、马里、尼日利亚、塞拉利昂、多哥和乌干达。","appearance":"成年雄性冠精织雀具有长约17厘米的身体，重约30至40克。其头部主要是红色，顶部有一束尖锐的羽毛形成的小红冠，眼睛周围有黑色面罩。上体和翅膀、尾巴以及下体下半部呈现暗淡的炭黑色光泽。雌鸟的外观与雄鸟相似，但缺乏尖锐的冠羽，胸部的红色面积较小，且黑带更窄。幼鸟起初额头黑色，头顶、颈背和耳覆羽呈暗红褐色，无红胸区，喉部为黑色混合红色，全身上下暗橄榄棕色。成鸟前的过渡阶段，头部和胸部的羽毛混杂着红色和黑色，下体可能为深橄榄棕色。","call":"冠精织雀的歌声被描述为各种啾啾声和嘶嘶声的混合，有时会连续唱同一主题2到3秒然后转换，已记录的最长歌曲持续了37秒。接触叫声是一种刺耳的‘scree scree scree’。","habits":"冠精织雀主要以蜘蛛、蚱蜢、甲虫、蝉、毛虫和昆虫卵为食，也会吃油棕果实。它们在树干和树枝上觅食，高度从5米到25米不等，偶尔也会飞扑捕捉空中昆虫。通常成对出现在森林下层或中层，有时会加入多种物种组成的群队，如鹎科、旧大陆鵙科、鸫科、太阳鸟科、其他织雀科物种和啄木鸟科。","breeding":"繁殖季节在不同地区有所不同，如几内亚的四月、利比里亚的九月至十一月、象牙海岸的四月至五月和九月、尼日利亚的二月、喀麦隆的八月至十一月等。它们是单配偶制，虽然多个巢可能由同一对建造。雄鸟追求雌鸟，唱歌展示巢穴邀请。巢形似倒置的壶，带有短入口隧道，主要由2至3毫米直径的纤维编织，包括棕榈叶条、叶柄和藤蔓碎片，悬挂于棕榈树上，离地面高度5至22米。一窝产1至2枚白色或绿白色的蛋，带有赭石色、灰色和棕色斑点，平均大小为22.8 x 15.8毫米，仅由雌鸟孵化。","identification":"冠精织雀的独特之处在于雄鸟和雌鸟都有红色的下巴，喉咙下方的红色仅限于喉部，以及黑色的腹股沟。与其他malimbe种类的区别在于其独特的红头和黑色面罩。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲西部和中部的热带湿润低地森林，具体包括安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、象牙海岸、赤道几内亚、加蓬、加纳、几内亚、利比里亚、马里、尼日利亚、塞拉利昂、多哥和乌干达。"},{"name":"红头编织雀","english_name":"Red-headed Weaver","scientific_name":"Anaplectes rubriceps","overview":"红头编织雀（英文名：Red-headed Weaver，学名：Anaplectes rubriceps），是雀形目织雀科红头编织雀属的鸟类。广泛分布于非洲的广阔地带，自塞内加尔至埃塞俄比亚，向南至莫桑比克等地。其显著特征为雄鸟拥有醒目的红色头部，而雌鸟和非繁殖期雄鸟的上体呈灰或褐色调，腹部颜色较浅。该鸟种常栖息于阔叶林、灌木丛、金合欢树林及湿润的草原环境。","appearance":"红头编织雀体长12至15厘米，体重约22克。繁殖期雄鸟具有黑色眼罩，红头、橙红色翼缘及灰白腹部，雌鸟及非繁殖期雄鸟上体灰或橄榄色，下体偏白。喙橙红或橙色，腿脚粉色至暗棕色。非繁殖期雄鸟和雌鸟头部及颈侧呈灰褐色，腹部灰白或橄榄白色，喙橙色或粉橙色。","call":"其叫声为高音、类似昆虫的吱吱声，融入典型的织雀叫声与歌声中。","habits":"红头编织雀栖息于多种树丛生境，如金合欢树林、布雷基斯特吉亚树林，也会出现在花园、灌木丛及湿润的草原。它们常加入混种群落，以昆虫为主食，偶尔摄取植物种子和果实，如金合欢种子、Premna果及寄生植物的果实。鸟儿单独或成对搜寻食物，有时会倒挂觅食。","breeding":"繁殖期从12月至翌年3月不等，具体时间依地理位置而异。雄鸟单独筑巢，巢呈壶状，入口长15至20厘米，由柔韧的枝条、叶柄及藤蔓构成。每窝产卵2至4枚，通常为3枚，淡蓝色或蓝绿色，孵化期及雏鸟期未详。","identification":"与红嘴雀的区别在于后者体型较小，背部有斑纹，且常成大群活动。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的广泛区域，北至塞内加尔，东至埃塞俄比亚，南至莫桑比克，博茨瓦纳北部及东部，津巴布韦，南非东北部等地。在乌干达，自1970年代以来分布区有所扩大。","other":"红头编织雀巢穴有时会被迪德里克杜鹃寄生，巢穴也可能被其他鸟类如环喉雀所占据。"},{"name":"红编织雀","english_name":"Red Weaver","scientific_name":"Anaplectes jubaensis","overview":"红编织雀（英文名：Red Weaver，学名：Anaplectes jubaensis），是雀形目织雀科红头编织雀属的鸟类。曾被认为是红头编织雀的亚种，后因其独特的羽毛特征而被区分为独立物种。雄鸟头部和身体几乎全为鲜艳的红色，雌鸟的外观与红头编织雀雌鸟相似，整体呈现灰褐色。该鸟种分布于非洲索马里南部和肯尼亚东北部，主要栖息于沿海湿润灌木丛和低海拔林地。","appearance":"成年雄性红编织雀拥有几乎全红的头部和身体，翅膀和尾巴为黑褐色，边缘泛红，肩胛羽边缘形成V字型黑色线条，对比鲜明。雌鸟头部、颈部、背部、肩胛和上尾覆羽呈灰褐色，翼羽边缘带红色，下体白色，混杂橄榄色或灰黄色。雄鸟非繁殖季节羽毛特征尚未有明确记载。橙色或橙粉色喙，红棕色虹膜，腿和脚粉棕色。","habits":"主要栖息于沿海湿润灌木丛和林地，特别是在溪流附近。活动范围和迁徙情况不明，但预计为留鸟。饮食以昆虫为主，也可能摄入少量果实和花蜜。","breeding":"繁殖生物学信息极少，已知在小规模群体中筑巢，具体繁殖时间未知，但在索马里5月末观察到筑巢活动，肯尼亚有报告在9月筑巢。","identification":"雄性红编织雀全身鲜红，与橙巧织雀和红嘴火雀有明显区别，后者具有黑色喙、面部、腹部和翅膀。雌鸟和非繁殖期雄鸟可通过橙红色喙与其它织雀相区别。","protection":"IUCN：LC（无危）；尽管总体范围估计为70,200平方公里，但由于栖息地退化和丧失，种群数量被认为正在下降。","distribution":"主要分布在非洲索马里南部，沿朱巴河中下游至肯尼亚东北部（拉穆县）。","other":"由于索马里的政治局势，对该物种生态学和需求的理解改善工作主要集中在肯尼亚的小片区域内。"},{"name":"绯红奎利亚雀","english_name":"Cardinal Quelea","scientific_name":"Quelea cardinalis","overview":"绯红奎利亚雀（英文名：Cardinal Quelea，学名：Quelea cardinalis），是雀形目织雀科奎利亚雀属的鸟类。雌鸟和非繁殖季雄鸟则呈现褐色条纹外观，具黄色眉纹。主要分布在非洲东部及中东部的草丛与灌木草原环境。","appearance":"雄鸟在繁殖季节头部至喉部呈鲜艳红色，胸部红色程度各异，颈部和背部为淡棕色带暗色条纹，臀部淡棕色条纹较少，上翼和尾部深棕色，初级飞羽边缘带有窄黄边。腹部和尾下覆羽白色，两胁和大腿肉桂色。眼睛棕色，喙黑色，腿棕色。非繁殖季雄鸟及雌鸟额头、头顶和颈背淡棕色带暗色条纹，侧面头部肉桂棕色，明显黄色眉纹，浅黄色下颏和喉部，色彩延伸至胸部，两胁有条纹；喙暗棕色。幼鸟上体深棕色带宽阔淡色边缘，黄色眉纹，白色喉部和下体，胸部、两胁和大腿淡色洗染，喙棕色。","call":"鸣唱是一系列由尖锐音符引入的嗡嗡声或嘶嘶声，以鼻音哨声结束，'tsap tsap tsap tsaptsaptsap zee-zee-zee-zee dzidzidzidzidzi nyeeeaaan'。联系叫声柔和的'zeet'。","habits":"栖息于高草丛和树木茂盛的草原，通常位于干燥地带，海拔400-3000米间，常见于800-2000米，山区偶尔高达3000米，但在赞比亚多低于900米。群居性，可达上千只的大群。主要食物为草籽，如Panicum和Setaria属，观察到取食Leonotis nepetifolia的花蜜，也食用昆虫，尤其是毛虫，以及喂给幼鸟的反刍种子。地面觅食。","breeding":"繁殖期具体信息未知，但繁殖雄鸟的记录表明其为领地性繁殖者。雄鸟繁殖羽色鲜艳，雌鸟和非繁殖季雄鸟外观相似。","identification":"繁殖雄鸟与繁殖雄性红头奎利亚雀相似，但红色分布于颈部较少而胸部更多，呈现出更整洁的‘兜帽’外观。","protection":"IUCN状态未知。","distribution":"分布于南苏丹南部、刚果民主共和国东北部、乌干达、肯尼亚西部、卢旺达、坦桑尼亚西北部和北部、赞比亚东部，马拉维中部罕见。繁殖期间亦偶见于埃塞俄比亚南部。","other":"与红头奎利亚雀形成亲缘关系紧密的分支，与红嘴奎利亚雀有近亲关系。"},{"name":"红头奎利亚雀","english_name":"Red-headed Quelea","scientific_name":"Quelea erythrops","overview":"红头奎利亚雀（英文名：Red-headed Quelea，学名：Quelea erythrops），是雀形目织雀科奎利亚雀属的鸟类。与黑色喉部条纹相映衬，红色延伸至胸部。广泛分布于非洲，从塞内加尔和冈比亚直至埃塞俄比亚，南至南非东部。","appearance":"成年雄鸟在繁殖季节头部呈暗红色，喉部带有黑色条纹，红色略微延伸至胸部，背部淡棕色，有深色中央条纹，尾巴和上翼棕色，边缘微黄；腹部、大腿和尾下覆羽呈灰白色。非繁殖期雄鸟和雌鸟外观相似，头部、顶部和颈背淡棕色，有深色条纹，宽黄色眉纹；下巴和喉咙白色，带黄色调，胸部淡黄色，无条纹。雌鸟和幼鸟与非繁殖期雄鸟相似，但羽毛边缘较宽，下体呈淡黄色。","call":"雄鸟的叫声为重复的沙哑声，群聚时发出叽叽喳喳的声音，以及尖锐的‘tyap’接触叫声。","habits":"栖息于高草丛生的环境，常靠近水源，亦可见于农业区，包括稻田。在肯尼亚，海拔低于1400米的高降雨量区域；在埃塞俄比亚，海拔低于1500米；在南非，主要沿海岸分布，最高可达1600米。迁徙模式随地区而异，形成明显的繁殖区和非繁殖区。","breeding":"繁殖季节主要在西非为6月至10月，圣多美岛为11月至2月；苏丹和刚果盆地为7月至8月，南刚果为1月至3月，乌干达为4月，坦桑尼亚为4月至5月；安哥拉、赞比亚和马拉维为1月至4月；南非通常为12月至1月，但在津巴布韦3月初也有记录。雄鸟可能同时建造多达三个巢穴。巢由雄鸟构建，是一个紧密编织的穹顶状结构，侧入口较大，有时上方有小平台，悬挂于地面约1.5米或水面上，位于草丛或芦苇茎之间。","identification":"繁殖期雄性红头奎利亚雀与红嘴奎利亚雀相似，但前者颈后红色更多，胸部红色较少，形成更整洁的‘兜帽’外观。","protection":"IUCN：LC（无危）","distribution":"分布于西非的塞内加尔、冈比亚、几内亚比绍和马里（尼日尔河泛滥平原）东至尼日利亚、喀麦隆、中非共和国、刚果民主共和国西部和东北部、南苏丹西南部、埃塞俄比亚和肯尼亚，以及圣多美、加蓬、刚果西南部沿刚果河和乌班吉河内陆，安哥拉西北部、赞比亚、马拉维、莫桑比克东南部和南非东部海岸（夸祖鲁纳塔尔省）。偶尔出现在纳米比亚东北部和博茨瓦纳北部（卡普里维地带）以及赞比西河津巴布韦一侧。","other":"被认为是害鸟，在某些地区被视为害虫。"},{"name":"红嘴奎利亚雀","english_name":"Red-billed Quelea","scientific_name":"Quelea quelea","overview":"红嘴奎利亚雀（英文名：Red-billed Quelea，学名：Quelea quelea），是雀形目织雀科奎利亚雀属的鸟类。小型的、约12厘米长、重15至26克的迁徙性织雀科鸟类，原生于非洲撒哈拉沙漠以南地区。以集群生活方式著名，数量庞大，有时被称为‘羽翼蝗虫’。该物种主要栖息于干燥的灌木草原和农业区，避免森林、沙漠和寒冷高海拔地区。","appearance":"红嘴奎利亚雀具有短尾，背部斑驳，喙呈黄色或红色，眼环和腿同样显色。繁殖期雄鸟头部可出现黑色面罩，周围可能带有玫瑰色、米色或肉桂色的洗刷，但也有白色面罩的情况。非繁殖期，红嘴奎利亚雀上体条纹，下体淡色，喙转为粉色或暗红色。雌鸟和非繁殖期雄鸟的外观相似，但在繁殖季节雌鸟的喙和眼环会变成黄色或橙色。幼鸟头部灰色，脸颊白色，翼覆羽和飞羽有宽大的淡褐色边缘。","call":"飞行群体会发出独特的翼拍声，到达栖息地或巢址时，鸟群会持续移动并发出嘈杂声约半小时，之后才安静下来。叫声包括雄鸟短促的鸣唱，开始时为一些叽喳声，随后是颤音。","habits":"主要栖息于热带和亚热带的季节性半干旱气候区，如萨赫勒地区，偏好干燥的灌木草原，包括农业地带，以草籽和谷物为食。依赖水源，每日需饮水。以大群形式迁徙，以寻找适宜的繁殖和食物资源。","breeding":"在低地灌木丛中繁殖，选择有刺植被的区域，通常在雨季开始后的4至9周筑巢。巢由雄鸟建造，呈小椭圆形或球形，有侧入口，用新鲜的绿色草条编织。繁殖周期短，雌雄一夫一妻制，每窝产卵1至5枚，孵化期为10至12天，幼鸟在巢中喂养10至11天后离巢。","identification":"与红头织雀有显著区别，后者体型更大，常单独生活在林地中，背部无条纹。不同亚种间主要通过雄鸟繁殖季节的头部颜色和条纹差异辨识。","protection":"IUCN：LC（无危）","distribution":"分布于非洲撒哈拉沙漠以南的大部分地区，从塞内加尔到坦桑尼亚，再到莫桑比克和南非。在尼日利亚、乍得、苏丹、埃塞俄比亚、肯尼亚、安哥拉、赞比亚、博茨瓦纳、津巴布韦、莫桑比克和南非均有记录。","other":"红嘴奎利亚雀被认为是世界上数量最多的野生鸟类之一，其庞大的数量使其成为非洲作物的主要害鸟。尽管采取了多种控制措施，如喷洒农药和投掷火弹，但对其种群数量的控制收效甚微。"},{"name":"红织雀","english_name":"Red Fody","scientific_name":"Foudia madagascariensis","overview":"红织雀（英文名：Red Fody，学名：Foudia madagascariensis），是雀形目织雀科艳织雀属的鸟类。体型较小，原生于马达加斯加，现已引入印度洋多个岛屿。其分布范围虽有限，但在所在区域内常见。","appearance":"红织雀体长约13厘米，体重介于13至20克之间。繁殖季节的雄鸟呈鲜艳的猩红色，眼周有黑色条纹，翅膀和尾巴为暗色，上翼、肩羽和覆羽边缘随磨损逐渐变淡，整体显得更加深邃。雌鸟和非繁殖季节的雄鸟上部橄榄棕色，头部和颈背有模糊的中央条纹，背部和肩部有深色斑纹，臀部无斑纹且颜色较浅；下部灰橄榄色，胸部更偏向棕或橄榄色，腹部颜色更浅，下尾羽覆羽为淡白色；喙角质色，上喙有时较暗和灰色，下喙颜色较浅；腿肉褐色。幼鸟外观类似雌鸟，但在换羽前呈现较为土黄色的外观，具有宽阔的土黄色羽毛边缘。","call":"发出高音的颤音歌曲，'trrr tree tree'，可能包含短促、嘶哑的短语。雄鸟在求偶期间会发出响亮的'seer'叫声，而雌鸟通过'tsip'叫声请求交配。","habits":"红织雀栖息于开阔地带，包括自然草原、耕作区、城镇和森林中的空旷地带，但不会出现在完整的森林内部（除过渡地带），在罗德里格斯岛被观察到在森林中觅食。在马达加斯加海拔可达2400米；在科摩罗群岛，主要分布于海拔1000米以下，偶尔在大科摩罗岛可达2000米。常形成离散的小群，幼鸟会跨越森林区域分散。主要以种子为食，也会食用花蜜和节肢动物，如甲虫、毛虫、蛾子和蜘蛛。","breeding":"繁殖季节在马达加斯加为9月至次年5月；在毛里求斯为11月至次年4月；在留尼汪为10月至次年5月（高峰期为2月至4月）；在科摩罗群岛为10月至次年5月；在塞舌尔群岛为9月至次年4月（高峰期为12月）；在查戈斯群岛为11月至12月；在圣赫勒拿岛为10月至次年2月。一夫一妻制。雄鸟保卫约1200平方米的领地，通过从显眼的栖木唱歌来宣告领土。巢由草条编织而成，呈椭圆形，侧面有入口，靠近顶部有一个突出的门廊，有时延伸成短隧道，观察显示雌鸟可能参与筑巢过程；在毛里求斯，巢顶使用苔藓，巢体使用草和莎草构建，而雌鸟在孵化期间并不衬垫巢穴。巢通常位于芦苇、高草、灌木或树的顶端附近，或在棕榈叶的中肋上。一窝产2至4枚蛋，平均大小为18 x 12.8毫米，孵化期为11至14天，由雌鸟独自孵化；雏鸟由两性共同喂养，主要通过反哺，育雏期为15至16天。","identification":"红织雀与林织雀的区别在于，繁殖季节的雄性红织雀背部和腹部为红色，而林织雀的相应部位为橙色。雌鸟和非繁殖季节的雄鸟与萨卡织雀的辨别要点在于体型较小、喙较小且面部标记不同。","protection":"IUCN：LC（无危）","distribution":"原产地为马达加斯加；已广泛引入（可能是自然引入）该地区的其他地方，包括科摩罗群岛、塞舌尔群岛和马斯卡林群岛。","other":"红织雀与毛里求斯织雀和罗德里格斯织雀在资源竞争上有所影响，尤其是在各自岛屿上的影响不同。"},{"name":"马岛红头织雀","english_name":"Comoro Fody","scientific_name":"Foudia eminentissima","overview":"马岛红头织雀（英文名：Comoro Fody，学名：Foudia eminentissima），是雀形目织雀科艳织雀属的鸟类。又名:马岛红头织雀雀，此鸟种特有于科摩罗群岛，尤其在西部三岛的湿润森林及其边缘地带，以及马约特岛的干燥低地灌丛中可见。繁殖期雄鸟头部呈鲜艳的红色，雌鸟和非繁殖期雄鸟则较为暗淡。与红织雀相比，本物种体型略大，色彩更深，喙稍长且微弯。","appearance":"雄鸟繁殖期马岛红头织雀的额头、头顶、颈背、脸颊、耳羽、喉部和胸部为鲜亮的红色；眼纹黑色并向后延伸；背部黑色，带有橄榄灰色边缘；下腰和尾上覆羽红色；上翼和尾部深橄榄绿色，飞羽和尾羽有黄色边缘；两胁和大腿灰白色，腹部和尾下覆羽白色带淡黄褐色调，中央腹羽尖端红色；虹膜棕色；喙黑色；腿色从暗棕至肉粉色。雌鸟和非繁殖期雄鸟头部至背部为暗淡的橄榄绿，有较暗的中央条纹，臀部纯橄榄绿；翅膀和尾部深橄榄绿，飞羽和尾羽有狭窄的黄色边缘；眉纹淡黄色，向后延伸；脸颊和耳羽淡黄；喉至尾下覆羽淡白，两胁和大腿灰白色；虹膜棕色；喙角质色，上颌较浅；腿色从暗棕至肉粉色。幼鸟外观类似雌鸟。不同岛屿的亚种主要在大小和雄鸟繁殖期羽毛细节上有差异。","call":"马岛红头织雀发出高而清脆的音符，通常以长串的形式作为鸣唱。","habits":"栖息于森林地带，选择的生境在不同岛屿间有所变化。在马约特岛上，它们不再出现在完整的常绿森林中，而是居住在农田、城镇花园、干燥海岸森林、灌木丛、老椰子林和红树林边缘。海拔高度从海平面至300米以上。它们是留鸟，分布零散，遗传分化的小群体相距不过30公里，表明其迁徙范围有限。","breeding":"繁殖期为9月至次年4月，实行一夫一妻制并具有领地意识。筑巢为球形结构，侧面有入口，通常建有遮蔽入口的门廊，有时巢材中含有大量苔藓。每窝产蛋约3枚，蛋壳颜色为淡蓝绿色，偶尔有少量黑斑，尺寸约为19.8×15.2毫米。","identification":"与红织雀相比，马岛红头织雀更大，颜色更深，喙更长且微曲。雌鸟和非繁殖期雄鸟与红织雀非常相似，但马岛红头织雀体型更大，颜色更深，更绿，喙较长且稍弯曲。","protection":"IUCN：NT（近危）","distribution":"分布于非洲的科摩罗群岛，包括西部三岛及马约特岛。","other":"曾被认为是阿岛织雀的亚种，现已独立为一物种。"},{"name":"阿岛织雀","english_name":"Aldabra Fody","scientific_name":"Foudia aldabrana","overview":"阿岛织雀（英文名：Aldabra Fody，学名：Foudia aldabrana），是雀形目织雀科艳织雀属的鸟类。又名:马岛红头织雀雀，属于塞舌尔群岛的一部分。","appearance":"雄性阿岛织雀在繁殖期间头部、颈部橙红色，背部和身体黄色，侧翼和胁部橄榄灰色，腹部硫磺黄色，尾羽橙色。雌鸟和非繁殖期雄鸟颜色较暗淡。所有个体均具有黄色调，比近缘物种更黄，尤其在腹部。喙长且厚重，用于竞争食物。","call":"阿岛织雀的鸣声包括高音金属质感的‘two-eet’、‘twee’或‘tee’声，间杂较低沉、更短促的音符。有多种鸣唱序列，包含各种音调，有时被描述为‘tsee-oo tsee-oo fsssssss looklooklooklooklook’。雄鸟发出鼻音‘fizzing’声，与领地防卫有关。","habits":"阿岛织雀广泛分布于阿尔达布拉岛，包括主岛和环礁小岛，偏好灌木丛、椰子树林和卡苏里纳树丛。它们是杂食性，以昆虫、种子、果实、花蜜为主食，偶尔食用花朵和其他物质。主要在卡苏里纳林中觅食，通过在树叶和树干上觅食、探查和翻动树皮来寻找食物。","breeding":"繁殖期为11月底至次年4月中旬，尤其集中在12月至1月，通常随雨季开始或之后不久开始。雄鸟保卫约650平方米的领地，双方共同筑巢，雌鸟可能承担大部分工作。巢由干燥藤蔓、草、棕榈叶、卡苏里纳针叶编织，内部铺垫细草茎，悬挂于地面1至17米处，平均高度13.5米。一窝产卵2至4枚，浅蓝色，孵化期13至16天，雌鸟单独孵卵，双亲共同喂养幼鸟，雄鸟在三日后开始参与喂食，育雏期15至18天。巢穴和蛋受到黑鼠和非洲白颈鸦的严重捕食。","identification":"繁殖期雄性阿岛织雀的黄色腹部使其容易与红织雀区分开。雌鸟和非繁殖期雄鸟的羽毛与红织雀非常相似，但可通过更强的黄色色调，特别是在下体和头部，来谨慎区分。","protection":"IUCN：EN（濒危）","distribution":"阿岛织雀分布于塞舌尔西南部的阿尔达布拉环礁，包括主岛及其附近的小岛。","other":"阿岛织雀面临干旱加剧和外来及本土捕食者的威胁，尤其是黑鼠和非洲白颈鸦，这些因素严重影响了繁殖成功率。"},{"name":"林织雀","english_name":"Forest Fody","scientific_name":"Foudia omissa","overview":"林织雀（英文名：Forest Fody，学名：Foudia omissa），是雀形目织雀科艳织雀属的鸟类。为马达加斯加特有种。繁殖期雄鸟具有醒目的红头罩，而非繁殖期和雌鸟则颜色较为暗淡。该物种广泛分布在马达加斯加东部，从北部至南部，亦可见于西南部的一些特定地区。","appearance":"林织雀雄鸟在繁殖季节头部呈红色，与非繁殖期和雌鸟的暗淡色彩形成鲜明对比。雌鸟和非繁殖期雄鸟颜色较暗，带有绿色调，且喙较大。雄鸟在繁殖季节的红头罩和腹部是其显著特征之一，但褪羽期间的雄鸟可能与红织雀相似。","call":"林织雀发出高亢、清脆的鸣叫，通常以一系列连续的音符组成歌曲。","habits":"林织雀主要栖息于低地雨林及海拔高达2,000米的湿润和半湿润山地森林中。它们有时会成群活动，群体中可能包含其他种类的鸟类。","breeding":"林织雀的繁殖习性与红织雀有所不同，具体细节尚需进一步研究。","identification":"林织雀与红织雀非常相似，但林织雀的雌鸟和非繁殖期雄鸟颜色更暗，带绿色调，且喙较大。此外，林织雀的雄鸟在繁殖期缺乏红背和红腹，这是与红织雀的明显区别。","protection":"IUCN：LC（无危）","distribution":"林织雀分布于马达加斯加东部，从北部的Montagne d'Ambre和Tsaratanana向南至Tolagnaro，同时在岛西南部的Isalo和Analavelona等地也有少量种群。","other":"林织雀与红织雀的杂交现象常见，这进一步增加了识别上的复杂性。"},{"name":"毛里求斯织雀","english_name":"Mauritius Fody","scientific_name":"Foudia rubra","overview":"毛里求斯织雀（英文名：Mauritius Fody，学名：Foudia rubra），是雀形目织雀科艳织雀属的鸟类。原生于毛里求斯岛，分布于西南部的残存森林和周边地区。其显著特征为红头红胸的繁殖期雄鸟，雌鸟和非繁殖期雄鸟呈暗绿色，体型小，约14厘米长。","appearance":"繁殖期雄性毛里求斯织雀头部、颈部、胸部为红色至橙红色，黑色眼罩，背部橄榄灰带暗纹，尾羽暗橄榄灰，边缘灰白形成翼斑，腹部橄榄绿。雌鸟和非繁殖期雄鸟上体暗橄榄绿，翼和尾暗橄榄灰，下体较浅橄榄绿，喉部泛黄，腿棕色，喙在非繁殖期为暗棕色。","call":"鸣声为一系列双音节音符，通常以嗡嗡声结束。飞行叫声尖锐。","habits":"毛里求斯织雀主要栖息于原生森林，亦可见于被外来植物侵入的退化森林，如日本杉（Cryptomeria）林。以昆虫为主食，如蚱蜢、甲虫幼虫、毛虫及蜘蛛，也会食用外来灌木的浆果和特有种植物果实，定期吸食花蜜，具有适应吸食的刷状舌尖。","breeding":"繁殖季节为10月至翌年2月，一夫一妻制。巢由草、苔藓、地衣或小枝构成，位于树上2至9米高处，入口侧向，可能有门廊。每窝产2-3枚淡蓝色蛋，平均尺寸19-2×13-9毫米，仅雌鸟孵化，孵化期14天，雏鸟由两性共同喂养，离巢期18天。巢穴成功率低，主要因天敌破坏。","identification":"与红织雀相比，毛里求斯织雀缺乏背部和腹部的红色，喙更长、更细且略弯。雌鸟和非繁殖期雄鸟比红织雀颜色更深，更绿，与家麻雀雌鸟相似，但喙更细。","protection":"IUCN：EN（濒危）","distribution":"主要分布在毛里求斯岛，已被引入邻近的Île aux Aigrettes岛。","other":"自1990年代以来，通过控制天敌数量和建立保护区，种群数量趋于稳定，甚至在主岛上有所扩大。"},{"name":"塞舌尔织雀","english_name":"Seychelles Fody","scientific_name":"Foudia sechellarum","overview":"塞舌尔织雀（英文名：Seychelles Fody，学名：Foudia sechellarum），是雀形目织雀科艳织雀属的鸟类。小型黄色调。原生于塞舌尔群岛的库辛岛、库西内岛、弗雷加特岛，并已引入阿莱德岛等地。其自然栖息地为林地，但也适应了椰子种植园和花园等环境。","appearance":"繁殖期的雄性塞舌尔织雀面部呈黄色，而雌鸟则不具备这一特征。整体羽毛为暗淡的橄榄色，喙部黑色。该鸟体长约12.5厘米（5英寸）。雌鸟和幼鸟与红织雀的雌鸟和幼鸟相似，但上体条纹较少，可借此区分。","call":"其叫声包含高音的银铃声和较低沉的‘vet’声，有时会连续发出一系列声音。","habits":"塞舌尔织雀主要以昆虫和其他小节肢动物为食，同时也会食用果实、花蜜和种子。它们被观察到会吃海鸟如白燕鸥的蛋。食谱中还包括虫子、甲虫、蚂蚁和蜘蛛。在库辛岛，该鸟有明确的繁殖季节，介于5月至9月间，之后会换羽。而在其他一些岛屿上，似乎全年都在繁殖。它们与同属物种红织雀共享塞舌尔群岛的栖息地。","breeding":"IUCN 最近将该鸟的保护状态从‘濒危’调整为‘近危’，这得益于塞舌尔自然保护区成功实施的保护措施。目前估计塞舌尔织雀的数量约为3500只。通过将鸟迁移到无天敌的岛屿，有助于它们数量的增长；新引入至阿莱德岛的塞舌尔织雀在最初的十三个月里成功尝试了三次繁殖。","identification":"与红织雀相比，塞舌尔织雀上体颜色更暗，且喙部更长、更细、略微弯曲。","protection":"IUCN：NT（近危）","distribution":"繁殖区域与非繁殖区域均为库辛岛、库西内岛、弗雷加特岛和阿莱德岛（塞舌尔群岛东北部内陆岛屿）。"},{"name":"罗岛织雀","english_name":"Rodrigues Fody","scientific_name":"Foudia flavicans","appearance":"雄鸟繁殖期个体体长约12厘米，体重13至17克，头部和颈背呈金色，背部橄榄棕色带深色条纹，翅膀和尾巴为棕色，翼羽边缘有黄色至米色。雌鸟和非繁殖期雄鸟颜色较暗，上体橄榄棕色，下体淡白色略带黄晕。喙黑色，腿褐色。幼鸟似雌鸟，但喉部带有黄色，喙呈角质色。","call":"叫声为尖锐的‘chup’声，歌曲由悦耳的音符组成，以颤音或嗡嗡声结束。雄鸟和雌鸟都会歌唱，雌鸟的歌谣较短。","habits":"栖息于残存的自然森林和密集的异域树木与灌木丛中。主要以昆虫、蜘蛛、果实和种子为食，频繁地吸食花蜜，适应了刷状舌尖。通常成对或家庭群活动，有时加入混种群。","breeding":"可能全年繁殖，巢为侧入口的椭圆形，由草编织，位于树梢1.5至4.5米处，通常在南洋杉树上。一窝产3枚淡蓝色蛋，雌鸟单独孵化，孵化期13至16天，雏鸟喂养期约14天。1999年调查发现超过300对鸟占据领地，总人口超过900只。","identification":"雄鸟繁殖期色彩鲜艳，易于识别。雌鸟和非繁殖期雄鸟与红织雀相似，但体型较小，喙更细。与家麻雀雌鸟区别在于喙更薄。","protection":"IUCN：NT（近危）","distribution":"分布局限于罗德里格斯岛，位于东马斯卡林群岛。","other":"1968年后，因飓风影响和栖息地破坏，数量急剧减少，至1999年通过再植林项目，尤其是非本土树种，其种群数量已恢复至超过900只。"},{"name":"短尾织雀","english_name":"Bob-tailed Weaver","scientific_name":"Brachycope anomala","overview":"短尾织雀（英文名：Bob-tailed Weaver，学名：Brachycope anomala），是雀形目织雀科短尾织雀属的鸟类。体型较小的鸟类，以短而粗的尾巴著称。在喀麦隆东南部、中非共和国南部至刚果和刚果民主共和国的森林地带中广泛分布。","appearance":"成年雄鸟在繁殖季节具有黄色的额头和冠羽，黑色的眼纹、脸颊、耳羽、下颚和喉部；背部和尾部呈深棕色，边缘稍淡；胸部黄色，侧腹、腹部和尾下覆羽呈淡黄色，逐渐变白接近肛门处。非繁殖期雄鸟、雌鸟和幼鸟整体呈淡褐色，上部羽毛边缘呈黑色，短尾明显。雌鸟与非繁殖期雄鸟相似，但喙为黑色。幼鸟与雌鸟类似，但虹膜为暗灰色，喙呈粉色，脚爪为浅棕色。","call":"其叫声简单，常发出尖锐的“jit”声，歌唱时带有几声清脆的颤音。","habits":"通常在森林中靠近大河流的开阔地带生活，以小群或成对出现。在刚果盆地的森林中，种群分散。","breeding":"相关信息未提及。","identification":"非繁殖期雄鸟和雌鸟可能与许多其他小型暗色鸟类混淆，但短尾是其独特标志。","protection":"IUCN状态未提及。","distribution":"分布在喀麦隆东南部（桑加河支流）、刚果（刚果河和乌班吉河流域）、中非共和国南部（乌班吉河）、刚果民主共和国（刚果河、乌班吉河、乌埃勒河和阿里乌米河，以及博马的老记录）。近期在安哥拉西北部（卢因加河）有记录。","other":"相关信息未提及。"},{"name":"黄顶巧织雀","english_name":"Yellow-crowned Bishop","scientific_name":"Euplectes afer","overview":"黄顶巧织雀（英文名：Yellow-crowned Bishop，学名：Euplectes afer），是雀形目织雀科巧织雀属的鸟类。以其鲜明的黄色和黑色繁殖期羽毛而著称。分布于非洲撒哈拉以南的众多国家，已引入至伊比利亚半岛、牙买加和波多黎各等地。该鸟种高度雌雄异型，繁殖季节时雄鸟呈现醒目的金黄色头部和黑色身体，而雌鸟和非繁殖期雄鸟则呈淡褐色。","appearance":"黄顶巧织雀体型小巧，约9.5至10.5厘米长，重约15克。繁殖期雄鸟具有独特的金色头顶、前额和后冠，颈部后方有一黑色宽带，脸颊、喉部、胸部和腹部为黑色，肩部有黄色斑块，背部和臀部黄色，翅膀和尾巴为棕色。雌鸟及非繁殖期雄鸟的上体为淡褐色，有较深的条纹，下体偏白色，胸侧和胁部有细小的暗色条纹。","call":"发出高音、嘶哑、嗡嗡声，类似昆虫的叫声：'zzzzzz, zzit, zzit, zzzz'，在求偶时还会发出特殊的'zzeeet zzzeeet zzzeeet'颤音，最后以'rik-rik-rik'的敲击声结束。","habits":"偏好开阔的草地、湿地、泛滥平原和季节性水浸地带，常出现在小麦和高粱田以及湿地边缘的杂草丛中。群居，非繁殖季节可能与其它种类混群。以草籽为主食，也会摄取昆虫。","breeding":"繁殖期主要集中在7月至10月，从西非到苏丹西部，刚果民主共和国东北部，埃塞俄比亚10月，刚果民主共和国南部和安哥拉1月至4月。雄鸟建立领地，建造侧面开口的球形巢，吸引雌鸟。每巢产2至4枚白色带暗斑的蛋，仅由雌鸟孵化，孵化期12至14天，雏鸟在11至13天后离巢。","identification":"与黄色巧织雀相比，黄顶巧织雀较小，且没有黄色的头顶。非繁殖期雄鸟和雌鸟与南部红巧织雀相似，但后者下体为浅黄色而非白色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部、中部、东部和南部，包括但不限于安哥拉、贝宁、博茨瓦纳、布基纳法索、喀麦隆、中非共和国、乍得、刚果共和国、刚果民主共和国、科特迪瓦、埃塞俄比亚、加蓬、冈比亚、加纳、几内亚、几内亚比绍、肯尼亚、莱索托、利比里亚、马里、毛里塔尼亚、莫桑比克、纳米比亚、尼日尔、尼日利亚、塞内加尔、塞拉利昂、南非、苏丹、坦桑尼亚、多哥、乌干达、赞比亚和津巴布韦。","other":"在加利福尼亚南部曾有逃脱的雄鸟个体记录，但未知是否仍在该区域。"},{"name":"火额巧织雀","english_name":"Fire-fronted Bishop","scientific_name":"Euplectes diadematus","overview":"火额巧织雀（英文名：Fire-fronted Bishop，学名：Euplectes diadematus），是雀形目织雀科巧织雀属的鸟类。繁殖季节中的雄鸟以其醒目的黑黄相间的羽毛和独特的红色额斑而美丽非凡，雌鸟和非繁殖季节的雄鸟则呈褐色带条纹。主要分布于非洲的索马里中部至肯尼亚至坦桑尼亚东北部。","appearance":"成年雄鸟在繁殖季节拥有大型的红色额斑，中央带有黑色，头部其余部分为黑色，背部呈黄黑相间，下背至尾上覆羽为黄色；尾羽深灰棕色，飞羽边缘淡黄色；腹部黑色，大腿白色，腹下部和尾下覆羽黄色。非繁殖季节的雄鸟和雌鸟类似，呈棕色，羽毛中心有暗色条纹，翅膀和尾巴棕色，翼羽边缘淡黄色。雌鸟外观与非繁殖季节的雄鸟相似。雏鸟特征未详述。","call":"鸣唱为高音调的啾啾声。","habits":"栖息于海拔1000米以下的开阔草地和耕作区，也会出现在灌木丛生的沿海沙丘、稻田和临时洪水区域。该物种具有游荡或迁徙特性，其活动与降雨相关。以草籽为主食，如Sporobolus和Echinochloa的种子，也吃白蚁和蜘蛛。成小群觅食，有时会与其他织雀科鸟类混群或共栖。","breeding":"在索马里繁殖期为8月至9月，肯尼亚则为5月至6月，雨后亦可见繁殖活动。可能为一雄多雌制，领地性，单独或集群筑巢，每群最多十二个雄鸟。雄鸟在展示时上下跳跃，抖动羽毛，拍打翅膀。巢为圆筒状，入口位于顶部下方的小门廊下，用草茎和叶片松散编织，距地面不超过0.5米。雌鸟参与筑巢，孵化期间继续用更柔软的草料铺垫巢内。每次产卵2-5枚，蛋壳呈淡蓝色，带有黑色斑点，平均尺寸为16.5 x 12.5毫米（肯尼亚数据）。孵化由雌鸟承担，孵化期10-12天，雏鸟期11-12天。","identification":"非繁殖季节的雄鸟和雌鸟与其他主教鸟非常相似，但体型较小，翼羽边缘黄色更为明显。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的中部索马里、肯尼亚南部与坦桑尼亚东北部，随降雨模式迁徙。"},{"name":"黑巧织雀","english_name":"Black Bishop","scientific_name":"Euplectes gierowii","overview":"黑巧织雀（英文名：Black Bishop，学名：Euplectes gierowii），是雀形目织雀科巧织雀属的鸟类。大型巧织雀属鸟类，分布于非洲撒哈拉以南的中东部、东部和东南部。繁殖季节时，雄鸟呈现醒目的红色与黑色对比，而雌鸟和非繁殖期雄鸟则为褐色带条纹。该物种包括三种亚种。","appearance":"黑巧织雀体长14至16厘米，雄鸟在繁殖季节拥有黑色的翅膀、尾巴、胸部、脸颊和前额，颈、头背和胸带橙红或鲜红，下尾覆羽淡黄色带黑色条纹，上背部颜色随亚种而异，从黄色到橙黄色。雌鸟整体暗色，面部两侧和下尾覆羽有大胆斑点，胸部有暗色斑点，翼衬黑色。非繁殖期雄鸟背部、翅膀和臀部黑色，面侧和胸部淡黄褐色，幼鸟类似雌鸟但胸部斑点较小。","call":"其叫声包含一系列低沉的啾啾声，包括'zhe-zee zee-zee zee-zhe SEE-ZHEE'、'zee-zee-zee zee-zee'和'hishaah hishaah SHAAAAAAH'，以及'tsee-tseet-tseet-tseet'。","habits":"黑巧织雀主要栖息于草甸、灌木丛和湿地环境，分布于安哥拉、喀麦隆、中非共和国、刚果、刚果民主共和国、埃塞俄比亚、肯尼亚、南苏丹、坦桑尼亚和乌干达。它们有时会形成小群，尤其在繁殖期，雄鸟会保卫领地。","breeding":"黑巧织雀可能实行一夫多妻制，雄鸟在繁殖季节保卫领土。","identification":"繁殖期雄鸟与黑翅巧织雀通过体型较大、黑色臀部和黑色冠部相区分。雌鸟和非繁殖期雄鸟与其他巧织雀和寡妇鸟相似，但可以通过整体深色、背部和胸部重条纹及大型体型初步识别。","protection":"IUCN状态未知。","distribution":"黑巧织雀在非洲中东部、东部和东南部繁殖，具体国家包括安哥拉、喀麦隆、中非共和国、刚果、刚果民主共和国、埃塞俄比亚、肯尼亚、南苏丹、坦桑尼亚和乌干达。","other":"黑巧织雀属于雀形目织雀科，曾被归入Groteiplectes属，与火额巧织雀、黑翅巧织雀、橙巧织雀、红巧织雀、黑臀巧织雀和红领巧织雀形成一个分子系统发育谱系。"},{"name":"黑臀巧织雀","english_name":"Zanzibar Red Bishop","scientific_name":"Euplectes nigroventris","overview":"黑臀巧织雀（英文名：Zanzibar Red Bishop，学名：Euplectes nigroventris），是雀形目织雀科巧织雀属的鸟类。繁殖季节的雄鸟外观极为引人注目，全身黑色下部与橙红色上部形成鲜明对比。雌鸟和非繁殖期雄鸟呈褐色，具条纹。该物种广泛分布于非洲沿海地区，自肯尼亚东南部至坦桑尼亚南部，直至莫桑比克中东部。","appearance":"繁殖期雄鸟的额头、头顶和颈背为红色，肩部鲜亮的赤褐色，其余上部包括尾羽覆羽为红色；翅膀灰褐带淡色边缘，尾巴灰褐，大腿部分呈现橙黄色至棕色，腹部黑色。非繁殖期雄鸟和雌鸟羽毛相似，上部至尾羽覆羽为褐色，带深褐色中央条纹，下体淡白色，胸中部带有淡黄色斑块，大腿淡黄色。幼鸟类似雌鸟，但上部羽毛边缘更宽、颜色更浅。","call":"其鸣唱柔和沙沙声中穿插着尖锐的鼻音“zhhhnn”或“djeeeeen”。接触叫声为“tsip”，受惊时发出尖锐的“drrt”。","habits":"栖息于沿海草甸和农田区域，海拔低于1000米。主要以种子为食，包括Echinochloa haploclada和Panicum maximum的种子，也食用稻谷和高粱。昆虫是雏鸟的食物之一。小群活动，常与其他巧织雀属和Quelea种类混群。","breeding":"繁殖期在肯尼亚为5月至10月，坦桑尼亚全年可见繁殖记录。雄鸟一夫多妻制，每只雄鸟最多可拥有五位配偶。巢由雄鸟建造，为薄壁椭圆形结构，侧面入口，用草条制成，内部由雌鸟用Panicum maximum等草籽头衬垫，形成覆盖入口的门廊。巢置于草地、芦苇或灌木中，离地面1至1.5米。每窝产卵2至3枚，平均2.4枚，卵色淡蓝，偶见稀疏的棕色斑点，平均尺寸16.5x12.5毫米。仅雌鸟孵卵，孵化期12天；雏鸟仅由雌鸟喂养，巢期13至16天。","identification":"繁殖期雄鸟的全黑下部与橙红上部是显著特征。非繁殖期雄鸟和雌鸟与其他巧织雀属物种相似，但体型较小，且缺乏火冠巧织雀等种翼羽明显的黄色边缘。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的肯尼亚东南部至坦桑尼亚南部，直至莫桑比克中东部，包括Zanzibar和Pemba等离岸岛屿。"},{"name":"黑翅巧织雀","english_name":"Black-winged Red Bishop","scientific_name":"Euplectes hordeaceus","overview":"黑翅巧织雀（英文名：Black-winged Red Bishop，学名：Euplectes hordeaceus），是雀形目织雀科巧织雀属的鸟类。曾被称为火冠巧织雀，常驻非洲热带地区的鸟类，分布自塞内加尔至苏丹，南至安哥拉、坦桑尼亚、津巴布韦和莫桑比克。这常见的编织雀，栖息于各种开阔地带，尤其偏好高草丛生的环境，通常靠近水源。其编织的球形巢穴位于高草之中，每次产卵2至4枚。","appearance":"成年雄性黑翅巧织雀在繁殖季节拥有醒目的外表，头部、颈部和胸部呈橙红至深红色，背部为红棕色，臀部和上尾覆羽为橙红至红色；翅膀和尾巴黑色，翼覆羽、次级飞羽、三级飞羽和尾羽有浅黄至白色的边缘，但随着羽毛磨损可能消失；脸颊、耳羽、下巴和喉咙黑色；胸腹部橙红至红色，腹部黑色，下侧腹、大腿、肛周和下尾覆羽白色或带有橙色至肉桂色。雌鸟和非繁殖季雄鸟呈褐色，有暗褐色中央羽毛条纹，翼和尾为褐色，边缘较淡。雄鸟非繁殖季保留黑色翅膀和尾部，但翼覆羽有宽阔的淡色边缘，上体为棕色，有黑色中央羽毛条纹，下体白色至淡棕色。","call":"黑翅巧织雀的鸣唱分为三部分，包含咔嗒声和嘶嘶声，如“chussaka-tsipa-tsipa-tsipa-zzzzzzh-tututututu”。站立的雄鸟在领地内发出多种叫声，其中一些较为悦耳的声音仅在近距离可闻，如“seep-seep-seep-zzzzzzray-titi-zzzzzzray-titi-zzzzzzray sisisisi”。雄鸟向返回的雌鸟发出啾啾声；雌鸟以柔和、高音的叫声请求交配；受到惊吓时发出尖锐的“chak”声。","habits":"黑翅巧织雀主要栖息于高草丛生的地带，包括稀树草原和耕作区，森林国家的空旷地带，以及废弃耕作区过度生长的区域，海拔高度可达2000米。它们经常出现在比其他红羽织雀更湿润的环境中。这些织雀以草籽为主食，尤其是Panicum maximum、Hyparrhenia、Pennisetum和Rottboellia的种子，也吃稻谷和嫩玉米。昆虫也是它们的食物之一，包括白蚁翅膀、毛虫等。它们在草丛中觅食，也常常在地上觅食，会从栖木上捕捉飞行中的昆虫。通常成对或小群活动，加入混合群落与北部红织雀和白顶织雀共处。","breeding":"繁殖期在不同地区有所差异，一般在雨季开始时。雄鸟保卫400至1200平方米的领地，容忍同域的红巧织雀、金背巧织雀和黄巧织雀，但对红领巧织雀表现攻击性。雄鸟在领地内显眼地展示，羽毛蓬松，持续鸣叫；接近雌鸟时，雄鸟可能缓慢扇动翅膀或在雌鸟前振动翅膀。巢由雄鸟建造，为椭圆形，侧面有大入口，由草条编织而成，支撑在高草或其他植被的垂直茎上，高度0.8至3.0米，内部由雌鸟用细草衬垫。每窝产卵2至4枚，蛋壳呈淡蓝绿色，平均尺寸为18.5 x 13.8毫米。孵化由雌鸟单独完成，孵化期为12至14天；幼鸟仅由雌鸟喂养，留巢期为11至13天，不利条件下可长达16天。巢可能被白眉金鹃寄生，雄鸟也会遭到白眉鸦鹃的骚扰。","identification":"繁殖季雄性黑翅巧织雀通过其橙红色的头部和胸部，黑色的翅膀和腹部，以及棕色的尾巴来识别。非繁殖季雄鸟通过黑色翅膀与橙巧织雀区分。雌鸟与同类相似，但体型更大、颜色更淡。","protection":"IUCN：LC（无危）","distribution":"分布于西非、中非、东非和东南非，包括塞内加尔至苏丹，南至安哥拉、坦桑尼亚、津巴布韦和莫桑比克。具体包括毛里塔尼亚南部、冈比亚、塞内加尔北部和西南部、马里中部和南部、几内亚比绍、几内亚、塞拉利昂、利比里亚、象牙海岸东部至尼日尔西南部、尼日利亚中部、喀麦隆、中非共和国、乍得南部、苏丹西南部、南苏丹和埃塞俄比亚西部，间断分布至加蓬、刚果、刚果民主共和国（除中部森林区）、乌干达、肯尼亚西部和东南部、卢旺达西部、布隆迪西部、坦桑尼亚大部分地区（包括桑给巴尔和奔巴岛）、安哥拉北部和西部、赞比亚、马拉维、津巴布韦北部和东部、莫桑比克中部。此外，在圣多美也有分布，可能是人为引入。"},{"name":"红巧织雀","english_name":"Southern Red Bishop","scientific_name":"Euplectes orix","overview":"红巧织雀（英文名：Southern Red Bishop，学名：Euplectes orix），是雀形目织雀科巧织雀属的细小鸟类。又名: 红寡妇雀。显著特征为繁殖期雄鸟的鲜亮红黑相间羽毛，额头至面颊为黑色，头部其余部分为红色。广泛分布于赤道以南的非洲湿地及草原，从刚果民主共和国南部至莫桑比克，延伸至安哥拉、赞比亚、博茨瓦纳等地。","appearance":"体长约10-11厘米，喙圆而厚实。繁殖期雄鸟头部除黑色的额头、面颊和喉部外，其余部位为红色，背部、翅膀和尾部为红至橙红色，下胸部、腹部为黑色。非繁殖期雄鸟和雌鸟羽毛呈棕色，下体颜色较淡，有条纹。雌鸟体型略小于雄鸟。","call":"发出各种清脆的鸣叫声和鼻音的接触声，雄鸟拥有嗡嗡的歌唱。","habits":"栖息于靠近水源的高草地和农田附近，如沼泽、芦苇丛和糖蔗田。在非繁殖季节，分散至相邻的灌木丛和干燥的草原。日常觅食时段为早晨和傍晚，以种子和节肢动物为主食，常与多种鸟类混群活动。","breeding":"繁殖季为4月至6月，雄鸟建造多个巢穴吸引雌鸟，实行多妻制。巢穴位于芦苇丛中，由雄鸟搭建，雌鸟则负责内部装饰。每窝产卵2-4枚，仅雌鸟孵化，孵化期约12-13天，雏鸟由雌鸟喂养，11-15天后离巢。","identification":"红巧织雀与橙巧织雀的主要区别在于繁殖期雄鸟的头部黑色范围不同，红巧织雀仅额头黑色，橙巧织雀头顶黑色面积更大，且尾上覆羽较长。雌鸟和非繁殖期雄鸟相似，难以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南部非洲，自刚果民主共和国南部、肯尼亚西南部至莫桑比克，包括安哥拉、赞比亚西部、博茨瓦纳北部、纳米比亚、南非等地。"},{"name":"橙巧织雀","english_name":"Northern Red Bishop","scientific_name":"Euplectes franciscanus","overview":"橙巧织雀（英文名：Northern Red Bishop，学名：Euplectes franciscanus），是雀形目织雀科巧织雀属的鸟类。繁殖期尾上覆羽几乎遮住整个尾部，头顶黑色部分较大，区别于红巧织雀。广泛分布于非洲赤道以北地区。","appearance":"橙巧织雀是一种小型鸟，约11厘米长，体重介于12至22克之间。繁殖季节的雄鸟具有鲜明的对比色：头部、喉部、胸部为红色至红棕色，背部、尾上覆羽鲜亮的红色，而前额、脸颊和耳羽为黑色，尾部棕色被红色尾上覆羽遮掩。翅膀呈棕色，边缘较浅。雌鸟和非繁殖季节的雄鸟羽毛为淡褐色和白色相间，具暗色中央条纹，与歌雀类似。幼鸟与雌鸟相似，但在换羽前有更宽的淡色羽缘。","call":"鸣唱由细薄的尖叫声组成，随后是粗糙的‘zee-zee-zee’哼声和嘶嘶声。飞行时发出咔哒声，接触呼叫为高音的‘tsip’，警报时发出尖锐的‘chak’。","habits":"栖息于高大的开放草地、作物田和季节性泛滥区，偏好在季节性泛滥区筑巢。高度群居，非繁殖季节形成大群，与金丝雀和蜡嘴雀等种子食用者共处。主要以小草籽和昆虫为食，尤其偏爱小米，也吃其他农作物如高粱、甘蔗和玉米。在海拔600至1800米的地方可见，但也能在低地和沿海地带发现。","breeding":"繁殖期从8月至11月在冈比亚和塞内加尔，5月至10月在马里和象牙海岸，7月至9月在加纳，6月至7月在多哥，7月至11月在贝宁，6月至10月在布基纳法索和尼日利亚。一雄多雌制，雄鸟建立领地，通过展示飞行吸引雌鸟。巢由雄鸟建造，为球状结构，侧入口，内衬草花头，放置于地面1至2米高处，通常由垂直的草茎支撑。每窝产卵2至4枚，平均大小为17.3 x 12.8毫米。仅雌鸟孵卵，孵化期13至14天；雏鸟仅由雌鸟喂养，育雏期14至16天。","identification":"与黑翼巧织雀的区别在于体型较小，喙较短，与黄冠巧织雀的区别在于颜色更偏向黄色，胸部条纹较少。雄鸟的连续红色下巴是区分于红巧织雀的明显特征。","protection":"IUCN：LC（无危）","distribution":"分布于西非、中非、东非，具体包括毛里塔尼亚南部、塞内加尔、几内亚比绍、几内亚、马里南部、塞拉利昂北部、利比里亚北部、布基纳法索、象牙海岸北部、加纳（内陆为主，沿海局部）、多哥、贝宁、尼日西南部、尼日利亚（主要在大河以北）、乍得南部、喀麦隆北部、中非共和国北部、苏丹（尤其是尼罗河及其支流）、南苏丹、埃塞俄比亚西部和东北部、厄立特里亚西部、索马里西北部和南部、刚果民主共和国东北部、乌干达北部、肯尼亚西部（巴林戈湖和博戈里亚湖）。在西印度群岛有引进种群，包括波多黎各、马提尼克、瓜德罗普、古巴、牙买加和圣克罗伊岛（美属维尔京群岛）。在美国加州洛杉矶附近也有引进的种群。","other":"橙巧织雀在一些地区被视为害鸟，据报道会损害农作物，如索马里的作物。在西印度群岛的引进种群在甘蔗作物的草地边缘繁殖。"},{"name":"金背巧织雀","english_name":"Golden-backed Bishop","scientific_name":"Euplectes aureus","overview":"金背巧织雀（英文名：Golden-backed Bishop，学名：Euplectes aureus），是雀形目织雀科巧织雀属的鸟类。非繁殖季节雄鸟和雌鸟则呈现褐色条纹，面部带有黄色调。该物种主要分布在安哥拉西部及圣多美岛，为安哥拉特有种，但在圣多美有人工引入记录。","appearance":"金背巧织雀体长约12厘米，体重约25克，具有短尾和大喙。繁殖季节的雄鸟头部、胸部、腹部为黑色，上体呈金橙色，尾羽基部灰色，翅膀和尾部呈棕黑色，边缘带淡黄色。雌鸟和非繁殖季节雄鸟头顶部及上体为红棕色，带深色中央条纹，翼部和尾部为棕色，边缘红棕色，脸部有黄色斑纹，下巴至喉咙白色到淡黄色，腹部、大腿和尾下覆羽白色。","call":"其鸣唱为一系列强调的嗡嗡声。","habits":"金背巧织雀常见于草地、过耕地带和开阔的稀树草原。它们通常以小群出现，有时与其他种类混群。饮食包括种子和昆虫。","breeding":"关于繁殖行为的详细信息较少，但已知繁殖期雄鸟的外观显著改变。","identification":"繁殖季节的雄鸟特征明显，非繁殖季节雄鸟和雌鸟较难区分，但体型较小，喙更粗壮，面部黄色更多。","protection":"IUCN状态未知。","distribution":"金背巧织雀分布于安哥拉沿海地区（从罗安达到本戈南部至本格拉，以及刚果东北极点），圣多美岛也有记录。","other":"该物种可能在两个分布区之一被人为引入。"},{"name":"黄巧织雀","english_name":"Yellow Bishop","scientific_name":"Euplectes capensis","overview":"黄巧织雀（英文名：Yellow Bishop，学名：Euplectes capensis），是雀形目织雀科巧织雀属的鸟类。亦被称为Cape bishop、Cape widow或yellow-rumped widow。广泛分布于非洲的中部、东部和南部。","appearance":"黄巧织雀体长约15厘米，体型健壮。繁殖季节的雄鸟全身黑色，除亮黄色的下背、臀部和肩部斑块，翼羽边缘呈棕色。其特征为短小的黑色厚锥形喙，相对较短的尾巴，以及短暂的冠羽。非繁殖季节，黑色羽毛被重纹的淡褐色取代，喙色变淡，但黄色的肩部和臀部仍然可见，与雌鸟的外观形成对比，雌鸟为重纹的棕色，缺乏明显的色彩对比。幼鸟和雌鸟在野外难以辨认，与几种其他主教鸟和寡妇鸟的幼鸟及雌鸟以及一些雀科鸟类相似。","call":"叫声包括连续的‘zeet zeet zeet’声，以及雄鸟飞行时发出的尖锐‘zzzzzt’声。喀麦隆西南部孤立亚种phoenicomerus的鸣声截然不同，以干燥的颤音开始，随后是‘swit-err，swit-err’声。","habits":"黄巧织雀栖息于较湿润的植被区域，如南非的fynbos（灌木丛）、潮湿的草地和蕨类植物覆盖的山谷，海拔从海平面到埃塞俄比亚高原。它们通常以种子、谷物和部分昆虫为食。","breeding":"繁殖期在不同地区有所差异，如喀麦隆为11月，埃塞俄比亚为7月至10月，在刚果民主共和国的繁殖时间从7月至11月不等。繁殖行为为一雄多雌制，每只雄鸟可与三至四只雌鸟配对。繁殖时通常单独或成对出现，但从不形成真正的群体。在东非，它们的巢穴可能与黑翅巧织雀和黑臀巧织雀的巢穴紧密关联。雄鸟在‘蜂鸣飞行’展示中向进入领地的雌鸟炫耀，翅膀拍打与歌声交替，同时发出翼震声。巢穴由雄鸟编织，呈穹顶状，侧面有入口，由草条构成，内部由雌鸟用草籽装饰。巢穴位于地面以上0.5至1.5米的草丛或小灌木中，巢内有时会发现羊绒等异物。一窝产卵2至4枚，卵的颜色和斑点模式多样，平均尺寸为21.3×15毫米。孵卵由雌鸟承担，持续13至16天，幼鸟主要通过反刍喂养，出壳后的巢居期为16至20天。","identification":"繁殖季节的雄鸟与雌鸟及幼鸟在外观上存在明显差异，主要通过黄色的肩部和臀部斑块识别。与其他主教鸟和寡妇鸟的雌鸟及幼鸟的区别在于这些部位的黄色。在非繁殖季节，雄鸟的黄色肩部和臀部是区分其与雌鸟的关键特征。","protection":"IUCN：LC（无危）","distribution":"非洲中部、东部和南部，包括但不限于安哥拉、博茨瓦纳、布隆迪、喀麦隆、刚果民主共和国、赤道几内亚、斯威士兰、埃塞俄比亚、肯尼亚、莱索托、马拉维、莫桑比克、尼日利亚、卢旺达、南非、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。","other":"最大记录寿命超过9年，在一项为期17年的研究中估计的年死亡率为54%。"},{"name":"扇尾巧织雀","english_name":"Fan-tailed Widowbird","scientific_name":"Euplectes axillaris","overview":"扇尾巧织雀（英文名：Fan-tailed Widowbird，学名：Euplectes axillaris），是雀形目织雀科巧织雀属的鸟类。主要栖息于非洲热带和亚热带的草甸与沼泽地带。其最显著的特征是雄鸟的宽大红肩，在繁殖季节尤为明显。","appearance":"雄性扇尾巧织雀在繁殖季全身黑色，仅肩部呈鲜艳的红色，而非繁殖季则转为条纹状的棕色。雌鸟则保持棕色条纹，肩部带有小片红褐色。成年雄鸟体重26-32克，雌鸟20-25克，身长15厘米左右。雄鸟尾羽呈扇形，繁殖期更显延长。","call":"鸣声由高音的刮擦音和嘶嘶声组成，飞行时发出连贯的'吱吱'声，报警时声音更为尖锐。","habits":"常群居于湿地、草地、农耕地，偏好高草丛生的环境，海拔多在1500米以下，偶尔可达2000米以上。以草籽、谷物、昆虫为食，如白蚁和毛虫。","breeding":"繁殖期广泛，自八月至次年三月不等，依地理位置而异。雄鸟通过展示鲜艳的红肩吸引雌鸟，雌鸟单独筑巢孵卵，通常产2-3枚蛋，孵化期12-14天，雏鸟由雌鸟独自喂养。","identification":"雄性扇尾巧织雀以其独特的红肩和扇形尾羽易于识别，雌鸟则需通过肩部的红褐色斑点与同类区分。","protection":"IUCN：LC（无危）","distribution":"分布于安哥拉至津巴布韦的非洲中部、东部和东南部国家。"},{"name":"黄肩巧织雀","english_name":"Yellow-mantled Widowbird","scientific_name":"Euplectes macroura","overview":"黄肩巧织雀（英文名：Yellow-mantled Widowbird，学名：Euplectes macroura），是雀形目织雀科巧织雀属的鸟类。这一引人注目的鸟种以其独特的黑黄相间羽毛和长尾闻名，雄鸟在繁殖季节展现出耀眼的金色肩羽。广泛分布于非洲的西部、中部、东部和东南部，包括从安哥拉到津巴布韦在内的多个国家。","appearance":"雄性黄肩巧织雀在繁殖季节长达19厘米，非繁殖季节则缩短至14厘米左右，体重约22至29克。其特征性的黑色羽毛覆盖大部分身体，拥有显著的金色肩部羽毛，尾部异常延长，平均长度可达10.7厘米。非繁殖期雄鸟的尾羽变短，呈褐色。雌鸟和非繁殖期雄鸟则呈现斑驳的棕色外观，带有黄色边缘的翼羽和淡色腹部。雌鸟与非繁殖期雄鸟相似，但翼羽为棕色，边缘较浅，下体颜色更淡。","call":"黄肩巧织雀的鸣唱是一系列尖锐的‘zhet’音节，雄鸟在领地展示飞行时会发出高亢的颤音，交替着嘶嘶声的呼唤。此外，飞行中的雄鸟也会发出哨音。","habits":"黄肩巧织雀栖息于湿润的草地和沼泽地带，包括树木和灌木丛生的环境，也会出现在废弃农田的稻田和茂密草丛中。它们的活动高度从低海拔至1700米不等，适应多种气候条件。以种子为主食，特别是莎草科植物的种子，同时也会捕食昆虫，如白蚁及其翅膀。在非繁殖季节，它们会加入织雀科的混合群落。","breeding":"繁殖期在不同地区有所差异，通常在雨季期间。黄肩巧织雀实行一夫多妻制，每只雄鸟可能吸引多达五只雌鸟。雄鸟通过追逐飞行和展示尾羽吸引雌鸟，而巢穴则由雄鸟编织框架，雌鸟负责内部的干草装饰。巢穴一般位于地面以上15至60厘米处的草丛中，孵化期约为12至14天，仅由雌鸟承担。雏鸟由雌鸟独自喂养，直到15天后离巢。","identification":"黄肩巧织雀的雄鸟与雌鸟在繁殖季节的明显差异在于雄鸟的长尾和金色肩羽。与其他织雀科鸟类相比，黄肩巧织雀的金色肩羽是识别的关键特征。亚种macrocerus的雄鸟在繁殖期具有持续黑色的肩部，而非金色。","protection":"IUCN：LC（无危）","distribution":"黄肩巧织雀广泛分布于非洲的西部、中部、东部和东南部地区，具体国家包括但不限于安哥拉、贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果民主共和国、科特迪瓦、加蓬、冈比亚、加纳、几内亚、几内亚比绍、利比里亚、马拉维、马里、莫桑比克、尼日尔、尼日利亚、塞内加尔、塞拉利昂、苏丹、坦桑尼亚、多哥、赞比亚和津巴布韦。","other":"黄肩巧织雀的亚种macrocerus在埃塞俄比亚、肯尼亚西部和乌干达有分布，其雄鸟在繁殖期的肩部始终为黑色，尾部更长。"},{"name":"沼泽巧织雀","english_name":"Marsh Widowbird","scientific_name":"Euplectes hartlaubi","overview":"沼泽巧织雀（英文名：Marsh Widowbird，学名：Euplectes hartlaubi），是雀形目织雀科巧织雀属的鸟类。首次由José Vicente Barbosa du Bocage于1878年描述。该鸟种主要分布在非洲中部，包括安哥拉、喀麦隆、刚果共和国、刚果民主共和国、加蓬、肯尼亚、尼日利亚、坦桑尼亚、乌干达和赞比亚。","appearance":"繁殖季节的雄性沼泽巧织雀主要为黑色，拥有长长的尾巴，其肩部颜色随地理位置而异，北部地区的雄鸟肩部主要呈橙色，而南部地区的雄鸟肩部则为黄橙相间。雌鸟和非繁殖期的雄鸟则呈现条纹状的褐色外观，不过雄鸟的肩部色彩仍然鲜艳。","call":"沼泽巧织雀的叫声包括低沉的嘶哑声、啾啾声以及类似煮沸水的嘶嘶声。","habits":"繁殖季节，沼泽巧织雀栖息于沼泽环境，而非繁殖季节则利用多种开阔生境。","identification":"北方繁殖的雄性沼泽巧织雀与扇尾巧织雀相似，但尾部长。雌鸟可能与其他几种鸟类混淆，但通常通过与橙色肩部雄鸟的关联得以识别。","protection":"IUCN状态未知。","distribution":"沼泽巧织雀的分布集中在非洲中部，具体国家包括安哥拉、喀麦隆、刚果共和国、刚果民主共和国、加蓬、肯尼亚、尼日利亚、坦桑尼亚、乌干达和赞比亚。"},{"name":"淡黄肩织雀","english_name":"Montane Widowbird","scientific_name":"Euplectes psammacromius","overview":"淡黄肩织雀（英文名：Montane Widowbird，学名：Euplectes psammacromius），是雀形目织雀科巧织雀属的鸟类。东部非洲特有种。成年雄鸟在繁殖季节呈现几乎全黑的羽毛，搭配极长的尾巴，肩部有显眼的黄色斑块；雌鸟和非繁殖季节的雄鸟则以斑驳的褐色为主，雄鸟保留着色彩鲜艳的肩部斑纹。","appearance":"繁殖期雄性淡黄肩织雀全长约15厘米（含尾部），尾羽特别长，平均可达24.7厘米，整个身体几乎全黑，肩部的次要飞羽呈鲜黄色，中间和主要飞羽基部以及初级飞羽基部为淡肉桂色。雌鸟和非繁殖期雄鸟羽毛上有暗褐色条纹，上体颜色较浅，喉部及下体呈淡褐色，带有微弱条纹。雌鸟整体较为素淡，上体条纹不明显，下体呈哑光白色，翅膀为棕色，仅隐约可见黄色边缘，喙呈粉红色。","call":"鸣唱为一系列复杂音符组成的高音调歌曲，还报告有哨音和咔嗒声的叫声。","habits":"生活在海拔1800至3000米的山地短密草地，常见于靠近溪流地带。据报道，非繁殖季节会形成大群。食物以草籽和昆虫为主，具体细节尚待公布。","breeding":"繁殖期在坦桑尼亚为五月，在赞比亚为一月，在马拉维为十月至十一月。雄鸟有领地性，进行空中飞行展示。巢为圆顶形，侧面入口，由细草松散编织而成，通常离地面不超过20厘米。每窝产2枚蛋，蛋壳呈淡橄榄绿色，密集地布满极细小的棕色斑点和条纹。","identification":"雄性淡黄肩织雀与沼泽寡妇鸟的区别在于其更宽广的淡肉桂色肩部斑块。雌鸟可能与几种其他物种混淆，但通常通过与淡肉桂色肩部的雄鸟的关联而被识别。","protection":"IUCN：LC（无危）。分布范围有限，但在其狭小的分布区内局部常见。在马拉维-赞比亚的尼亚卡国家公园和坦桑尼亚乌祖翁加瓦山脉及龙格韦山的保护区中出现。","distribution":"分布于东非，主要见于坦桑尼亚西南部高地、赞比亚东北部和马拉维北部的尼亚卡高原，海拔1800至3000米之间。","other":"淡黄肩织雀是坦桑尼亚-马拉维山区特有物种，为东非蒙特地区的特有种。"},{"name":"白翅巧织雀","english_name":"White-winged Widowbird","scientific_name":"Euplectes albonotatus","overview":"白翅巧织雀（英文名：White-winged Widowbird，学名：Euplectes albonotatus），是雀形目织雀科巧织雀属的鸟类。体长约14厘米，重20–27克。雄鸟繁殖羽黑色，具醒目的白色翼斑与淡蓝喙，肩羽在非洲东北部为栗色、其余地区为金黄色；雌鸟及非繁殖羽体羽淡褐纵纹，腹部白色。分布于撒哈拉以南非洲的草原、灌丛、沼泽及农耕区，海拔2000米以下，多为留鸟，具局部游荡。以草籽为主，兼食昆虫与花蜜，繁殖期因地而异，一夫多妻，雄鸟筑椭圆形侧口草巢于近地面草丛，雌鸟孵卵并育雏。","appearance":"雄鸟繁殖羽通体黑色，初级飞羽基部白色，次级飞羽基白，外侧大覆羽白色，形成显眼的白色翼斑；肩羽（小覆羽）金黄色， northeast Africa 种群为栗色；尾羽延长平均8.5厘米，末端圆；虹膜褐色，喙淡蓝灰，腿黑褐。非繁殖羽雄鸟头至上背棕褐具黑纵纹，尾缩短平均5.3厘米，羽缘色浅；具黄白色眉纹及喙基黄斑，喉白，胸腹棕白相间。雌鸟与非繁殖雄鸟相似，但下体更白，飞羽无白斑，小覆羽褐具黄缘，上喙褐、下喙粉褐。幼鸟似雌鸟，下体带黄或浅黄色；雄鸟在第二次换羽后约13个月获得成鸟翼斑。亚种eques雄鸟肩羽肉桂褐，asymmetrurus雄鸟尾更长平均13厘米。","call":"鸣唱由栖枝或飞行中发出，呈“squee-squi-squeeze twirr zem-zem-zem tsisisisisisi”的连串滑音；飞行时发出清脆的“chip”叫声。","habits":"栖息于相对干燥地区的高草灌丛、沼泽边缘及农田杂草带，海拔通常低于2000米。多为留鸟，有局部游荡；苏丹达尔富尔地区干季缺如，肯尼亚察沃等地为季节性繁殖访客。主食多种草籽（如Brachiaria、Chloris、Hyparrhenia、Pennisetum、Setaria等），亦食栽培小米；南非记录取食芦荟花蜜。兼食昆虫，包括有翅白蚁及甲虫，地面拾取或空中飞捕。非繁殖期与其他织布鸟及红头奎利亚雀混成大群活动。","breeding":"繁殖期随地区变化：苏丹9–10月，埃塞俄比亚6月，卢旺达及南刚果2–4月，肯尼亚3–6月为主，坦桑尼亚12–3月，安哥拉、赞比亚、马拉维1–4月，津巴布韦、博茨瓦纳12–4月，南非10–4月。一夫多妻，一雄可配4雌。雄鸟占地600–1900平方米，于高栖处鸣唱并做缓慢蝶状飞行炫耀。巢由雄鸟编织，椭圆形侧口，以干湿草茎构成骨架，内衬细草（如鼠尾粟），常具前檐，距地不足1.5米；旧巢可被橙颊梅花雀利用。每窝2–4枚卵，平均2.6枚，卵淡青绿密被橄榄绿点，平均18.5×13.6毫米；仅雌鸟孵卵12–15天，雏鸟由雌鸟回吐育雏11–14天，36天独立。巢偶尔被杜鹃寄生，津巴布韦一项研究中2%巢受影响，14/21巢被捕食者（包括人类及多乳鼠）破坏。环志个体最久记录7年。","identification":"本种以黑白翼斑与金黄色（或肉桂色）肩羽组合区别于同属其他巧织雀；尾长适中，远短于长尾巧织雀。非繁殖羽及雌鸟凭翼无白斑与雄鸟区分，且腹部白色无纵纹。亚种间差异：eques肩羽肉桂褐而非金黄，asymmetrurus雄鸟尾显著更长。","protection":"IUCN: LC（无危）。分布区内普遍常见，南非克鲁格国家公园估计1.6万只，莫桑比克中南部超3万只；曾引入南大西洋圣赫勒拿岛及澳大利亚新南威尔士，均已灭绝。","distribution":"繁殖区域：非洲中南部及东南部。指名亚种albonotatus分布于南坦桑尼亚、赞比亚、马拉维、纳米比亚东北部、博茨瓦纳北部及东部、津巴布韦、莫桑比克、斯威士兰及南非东部；eques亚种见于中非共和国、南苏丹、南埃塞俄比亚、刚果民主共和国西部、卢旺达西部、布隆迪西部、乌干达西部及南部、肯尼亚至南坦桑尼亚；asymmetrurus亚种分布于圣多美岛、加蓬西部、刚果南部、安哥拉及刚果民主共和国西部。非繁殖区域：局部游荡，苏丹达尔富尔干季缺如。","other":"文献记录与橙巧织雀在圈养下杂交；eques与指名亚种在坦桑尼亚南部存在杂交，但在布隆迪与西坦桑尼亚可能隔离。曾提出sassii亚种（坦噶尼喀湖西北岸）现归入eques亚种。"},{"name":"红领巧织雀","english_name":"Red-collared Widowbird","scientific_name":"Euplectes ardens","overview":"红领巧织雀（英文名：Red-collared Widowbird，学名：Euplectes ardens），是雀形目织雀科巧织雀属的鸟类。繁殖季节，雄鸟以醒目的黑色羽毛与鲜艳的红色颈环著称，非繁殖季节则呈褐色。雌鸟和非繁殖雄鸟外观相似，具淡色眉纹和腹部，缺乏长尾。广泛分布于非洲西部和南部的开阔草原和灌木丛地带。","appearance":"雄鸟约25-30厘米，雌鸟12-13厘米；雄鸟体重15.6-25.5克，雌鸟13.1-21.5克。繁殖季节，雄鸟全身黑色，仅喉部有一狭窄的镰刀形红色颈环，背部至尾羽覆羽有浅棕色至白色边缘。雌鸟和非繁殖雄鸟上体暗纹，下体淡色，有黄色眉纹，无长尾，下体黄色至黄白色，腹部白色，翼缘有淡色边。雄鸟尾长平均22.8厘米，外侧尾羽最长。","call":"发出尖锐的嘶嘶声颤音，如chisisisisi-chisisisisi-chisisisisi，可持续或短促爆发，伴有多样性的嘶嘶声和咔哒声叫声。","habits":"栖息于各种远离水源的环境，包括开放或有灌木的草地、高草丛、灌木丛和耕作区，常在森林地带的开阔地。非繁殖季节有局部移动，性比在南非的栖息地随季节变化。以多种草籽为主食，包括Sorghum、Panicum maximum等，也吃小浆果和昆虫，如甲虫、蚂蚁、毛虫和白蚁。通常在地上觅食，也会在空中捕捉白蚁。","breeding":"繁殖期因地区而异，一般从十月到次年五月。雄鸟建立1000-15000平方米的大领地，内含3-22个巢结构，常在斜坡上。雄鸟通过展开尾羽进行求偶展示。雌鸟筑巢，巢由细长的草编织而成，内衬草穗，巢高1-3.5米。每窝产卵2-4枚，孵化期12-15天，仅由雌鸟承担。幼鸟喂养期14-17天，由雌鸟单独喂养。","identification":"与红颈巧织雀有显著区别，后者羽色更红，尾长较短。红领巧织雀雄鸟的红颈环是识别关键，但在不同个体中红颈环颜色和宽度有变异。","protection":"IUCN：LC（无危）","distribution":"分布于塞拉利昂至乌干达，苏丹西南部，坦桑尼亚西北部，南至南非东部。在肯尼亚东南部罕见，广泛存在于东非和南非。","other":"曾与红颈巧织雀视为同种，现确认为独立物种。"},{"name":"长尾巧织雀","english_name":"Long-tailed Widowbird","scientific_name":"Euplectes progne","overview":"长尾巧织雀（英文名：Long-tailed Widowbird，学名：Euplectes progne），是雀形目织雀科巧织雀属的鸟类。这种中等体型的鸟类在其栖息地极为常见，以其独特的长尾和黑橙相间的羽色著称。繁殖期雄鸟几乎全身黑色，翅膀有红白相间的亮点，尾部异常延长；雌鸟和非繁殖期雄鸟则以褐色条纹为主。分布于非洲东部至中南部地区。","appearance":"雄鸟繁殖期体长可达50–71厘米，其中尾部长约41厘米；非繁殖期雄鸟和雌鸟体长约15厘米。繁殖期雄鸟几乎全黑，尾部极长，翅膀有橙红色肩饰，边缘有淡色边框。非繁殖期雄鸟保留黑色飞羽和橙红色肩饰，但尾部缩短，上体有暗色中央条纹，下体呈白色至淡黄色，带有中央条纹。雌鸟全年保持褐色条纹外观，翼覆羽有微弱的色彩边缘。幼鸟似雌鸟，亚成年雄鸟似非繁殖期雄鸟，但翼覆羽仅有窄橙棕色边缘。","call":"飞行中的鸣唱为高音且重复的‘twi-twi-twi-twi-zizizizi’声，以及从栖木发出的嘶嘶‘weezle weezle’歌。反应时会发出一连串的劈啪叫声，接触叫声为‘zik’，警戒时为更强烈的‘tseek tseek’声。","habits":"栖息于草甸，偏好短草区，常在海拔1800至2800米的肯尼亚和南非。群居，尤其在非繁殖期。主食为草籽，如Setaria sphacelata等，也吃小麦种子和Senecio juniperinus的果实。还摄食蜘蛛、甲虫、蚜虫等多种节肢动物。地面觅食，也会捕食空中飞虫。与同属其他物种形成混合群。","breeding":"繁殖期在肯尼亚为11月至1月，南非为10月至6月。一雄多雌制，每雄可拥有最多五个雌鸟。雄鸟通过展示其长尾和翼上的肩饰吸引雌鸟，雌鸟则选择长尾雄鸟。巢由雌鸟单独建造，呈圆顶状，入口侧向，位于雄鸟领地内的矮草丛中，离地不足50厘米。每巢产卵2-3枚，孵化期12-14天，仅雌鸟孵卵，雏鸟期约17天。","identification":"雄鸟繁殖期的长尾和红白肩饰使其极易辨认。雌鸟和非繁殖期雄鸟与同属其他物种类似，但可通过其特有的翼部图案和长尾雄鸟的存在来区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部至中南部，包括肯尼亚高地、安哥拉、刚果民主共和国南部、赞比亚、博茨瓦纳、南非、斯威士兰和莱索托。在南非沿海草地和中部高地亦有分布。","other":"长尾巧织雀的研究揭示了雌鸟选择理论，即雌鸟偏好长尾雄鸟，这与自然选择原理相悖，但有利于性选择进化。"},{"name":"杰氏巧织雀","english_name":"Jackson's Widowbird","scientific_name":"Euplectes jacksoni","overview":"杰氏巧织雀（英文名：Jackson's Widowbird，学名：Euplectes jacksoni），是雀形目织雀科巧织雀属的中等体型的暗色巧织雀。分布于非洲东部，主要在肯尼亚西部和中部至坦桑尼亚北部的高原地带。","appearance":"繁殖期的雄性杰氏巧织雀具有显著特征，长而向下弯曲的尾巴和红棕色的肩部，使其在同类中独一无二。非繁殖期的雄鸟会失去其长长的尾巴，羽毛变得斑驳且呈褐色，但仍保留着肩部的独特图案。雌鸟全年保持褐色并带有条纹。雄鸟的肩部图案是识别的重要特征。","call":"杰氏巧织雀的主要叫声是一种干涩的“zrit”声。","habits":"杰氏巧织雀栖息于海拔较高的草原，偶尔也会出现在农田和其他开阔生境。它们通常群居，特别是在非繁殖季节。繁殖期间，雄鸟会进行一种奇特的空中跳跃展示。","breeding":"具体繁殖细节未详述，但基于其生态习性，繁殖期可能涉及复杂的求偶展示和巢筑活动。","identification":"雌性杰氏巧织雀在非繁殖季节可能会与其他物种混淆，但通常与雄鸟个体共同出现，后者可以通过肩部图案进行识别。非繁殖期的雄鸟可能与扇尾巧织雀的非繁殖期雄鸟相混淆，但肩部的橙色斑块更小且位置受限。","protection":"IUCN：NT（近危）","distribution":"杰氏巧织雀的分布区域集中在非洲东部的肯尼亚西部和中部至坦桑尼亚北部的高原地带。","other":"杰氏巧织雀面临的威胁主要是栖息地的丧失。"},{"name":"红颈巧织雀","english_name":"Red-cowled Widowbird","scientific_name":"Euplectes laticauda","overview":"红颈巧织雀（英文名：Red-cowled Widowbird，学名：Euplectes laticauda），是雀形目织雀科巧织雀属的鸟类。这种小型巧织雀以东非的草甸和灌木林地为家，以其长长的尾巴和鲜艳的红色领圈闻名，是东非草原上的独特风景。在繁殖季节展现出令人瞩目的性征，雄鸟具有醒目的黑色身躯，配上深红的领圈和冠羽，尾部长达20厘米，雌鸟和非繁殖季节的雄鸟则以暗色条纹的上体和淡色下体为主，胸部有淡褐色带纹，黄色的眼眉和脸庞，缺乏长尾。","appearance":"雄性红颈巧织雀在繁殖季节呈现为纯黑色，头部和颈部带有深红色的领圈和冠羽，尾羽长达20厘米，尾羽中央的羽毛向下弯曲。雌鸟和非繁殖季节的雄鸟上体呈暗色条纹，下体颜色较浅，胸部有一道淡褐色的带纹，眼眉和脸部为黄色，没有长长的尾羽。喙、虹膜和腿为棕色，嘴的上颌颜色较淡。雌鸟和未成年雄鸟的背部条纹为深棕色，翅膀边缘呈淡色，下体有一条明显的淡褐色带纹，腹部白色，尾下覆羽为白色中心带棕色。","habits":"红颈巧织雀栖息于中高海拔的开阔草地、灌木丛、稀树草原和农田地带。它们可能会形成群体，通常与其他种子食鸟混群。在繁殖季节过后，它们会进行局部迁移。它们主要以种子为食，偶尔也会进食昆虫。","breeding":"繁殖期在埃塞俄比亚为8月至10月，肯尼亚为4月至7月和12月至次年1月，坦桑尼亚（阿鲁沙国家公园）为1月至5月。红颈巧织雀实行一夫多妻制，雄鸟拥有两到三个配偶。雄鸟通过展示飞行吸引雌鸟，巢穴由雌鸟建造，位于地面不到1米处，由细长的草编织而成，形状近似椭圆。每窝产2-3枚蛋，偶尔可达4枚，蛋壳灰绿色，布满灰棕、灰褐和紫褐色斑点。孵化期为13-14天，仅由雌鸟承担。雏鸟由雌鸟单独喂养，约16天后离巢。","identification":"繁殖季节的雄性红颈巧织雀与其他种类的巧织雀相比，具有独特的红领圈和较短的尾羽。非繁殖季节的雄鸟和雌鸟可以通过缺乏红色翼斑、淡褐色胸部带纹（条纹较轻）以及黄色眼眉和脸部来识别。","protection":"IUCN：LC（无危）","distribution":"红颈巧织雀分布于东非的苏丹、厄立特里亚、埃塞俄比亚至肯尼亚中部和坦桑尼亚北部。它们常见于中高海拔的草甸和灌木林地。","other":"红颈巧织雀曾被认为是红领巧织雀的同种，后因显著的羽毛差异和雄鸟繁殖期尾羽长度的不同而被区分为独立物种。"},{"name":"啄花雀","english_name":"Woodhouse's Antpecker","scientific_name":"Parmoptila woodhousei","overview":"啄花雀（英文名：Woodhouse's Antpecker，学名：Parmoptila woodhousei），是雀形目梅花雀科啄花雀属的鸟类。此鸟以美国探险家Samuel Washington Woodhouse的名字命名，主要特征为雄鸟个体拥有鲜红色的前额和喉部，棕色的上半身，以及斑驳的暗棕色和白色条纹覆盖的胸至腹部。分布于非洲中西部的热带湿润森林，高度介于700至1800米之间。","appearance":"雄性啄花雀的额头为红褐色，带有更亮的红色条纹，冠羽和背部呈棕色，有暗棕色的斑点和淡色的羽轴条纹。上翼和尾巴为棕色。脸部和喉部无斑点，呈红褐色，下体为白色，带有鳞状棕色图案，尾下覆羽有断续的棕色条纹。雌鸟相似，但前额棕色（如同冠羽），羽毛缺乏红色尖端。幼鸟上半身更均匀的棕色，仅有少数淡色羽轴条纹，下半身为淡棕色，侧腹模糊地条纹更深的棕色。","call":"鸣叫包括柔和的哨声“ptiee”音符和重复的高音下降哨声。","habits":"啄花雀主要在森林的低层植被和地面觅食蚂蚁，通常单独或小群活动，有时会与蚁群或混种鸟群一起。它们的栖息地为中西部非洲的热带湿润森林。","identification":"雄性啄花雀的红褐色额头和喉部，以及其特有的叫声，帮助区分于其他种类。","protection":"IUCN：LC（无危）","distribution":"非洲中西部，包括安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬、尼日利亚、坦桑尼亚和乌干达。在乌干达，可以在Budongo中央森林保护区的Nature Reserve N15（Nyakafunjo Block 15）观察到。"},{"name":"红额啄花雀","english_name":"Red-fronted Antpecker","scientific_name":"Parmoptila rubrifrons","overview":"红额啄花雀（英文名：Red-fronted Antpecker，学名：Parmoptila rubrifrons），是雀形目梅花雀科啄花雀属的鸟类。自塞拉利昂至加纳，常见于热带低地湿润森林中。红额啄花雀因头部独特的红色标记而得名，雄鸟与雌鸟的外观差异显著。","appearance":"红额啄花雀体长约11厘米，体重介于8至10.5克之间。雄鸟具有醒目的红色前额和头顶，上体呈暗橄榄色，翼和尾部为棕色，下面部分为锈色胸腹。面部带有深色斑纹和白色条纹，下巴呈淡黄色。雌鸟上体颜色较暗，面部有细小白点，喉咙和下体为淡白色，带有黑色斑点，侧面形成不规则的条纹。幼鸟的上体类似雌鸟，下体均匀呈赤褐色。","call":"红额啄花雀发出高音下滑的“peeeeee”叫声。","habits":"通常在初级和沼泽森林的下层和中层活动，靠近水源。以昆虫为食，尤其是蚂蚁，偶尔也会吃小种子。成对或家庭群在混合物种群中觅食，常在较低的高度，一般低于5米。会在蚁巢旁停留长达一分钟，从茎上捕食昆虫。","breeding":"筑巢发生在10月至11月，4月发现雌鸟有卵巢蛋，9月到翌年4月观察到处于繁殖状态的个体，象牙海岸在12月、1月和6月有幼鸟出现。巢穴由植被构成，放置于离地面2.5至3.5米高的沼泽或水淹地带的次生林树上，有时仅由雄鸟建造，耗时约8天。","identification":"雄性红额啄花雀以其红色前额和头顶、暗橄榄色上体、锈色胸腹以及独特的面部条纹与白点相区别。雌鸟上体暗淡，有细小白点，下体有黑色斑点形成的不规则条纹。与雨林红额啄花雀的区别在于分布区域和外观上的细微差异。","protection":"IUCN：NT（近危）","distribution":"分布于非洲西部，从塞拉利昂至加纳，包括几内亚、利比里亚、科特迪瓦和加纳。","other":"红额啄花雀的分布区已呈现碎片化，数量因持续的森林砍伐和伐木而显著减少。该物种在多个保护区中得到保护，包括塞拉利昂的Gola森林、科特迪瓦的Taï森林国家公园以及加纳的Kakum和Ankasa国家公园和Subri河及Tano Offin森林保护区。"},{"name":"雨林红额啄花雀","english_name":"Jameson's Antpecker","scientific_name":"Parmoptila jamesoni","overview":"雨林红额啄花雀（英文名：Jameson's Antpecker，学名：Parmoptila jamesoni），是雀形目梅花雀科啄花雀属的鸟类。现通常被视为独立物种。","appearance":"体型小，喙细长，腿呈淡棕色。雄鸟额头鲜红，上半身暗灰橄榄褐色，脸及下体锈赤色；雌鸟面颊至喉咙土黄色，胸至尾下覆羽淡黄，羽毛边缘呈橄榄褐，形成鳞状斑纹。幼鸟似雌鸟，但脸部棕色。","call":"发出高音下滑的“whseet”叫声。","habits":"在原始森林、次生林和河岸森林的低层和中层活动，常靠近水源。以昆虫为主食，偏好蚂蚁。","breeding":"具体繁殖细节未知。","identification":"雄鸟头部的红色特征明显区分于雌鸟和其他近似种。","protection":"IUCN：LC（无危）","distribution":"分布于刚果民主共和国、乌干达西部（阿尔伯丁裂谷）和坦桑尼亚极西北部（Minziro森林）。","other":"以詹姆斯·斯利戈·詹姆斯命名，鉴于其在非洲的暴力行为，有提议更改该物种的通用名。"},{"name":"白胸黑雀","english_name":"White-breasted Nigrita","scientific_name":"Nigrita fusconotus","overview":"白胸黑雀（英文名：White-breasted Nigrita，学名：Nigrita fusconotus），是雀形目梅花雀科黑雀属的小型鸟类。具有独特的外观，黑色的帽子和尾巴与棕色背部形成鲜明对比，白色腹部十分醒目。广泛分布在非洲热带雨林区域，全球活动范围达到2,700,000平方千米。","appearance":"体长约10至11.5厘米，体重7至11克。头部顶部和侧面为光泽的黑色，上体呈棕色，臀部、尾上覆羽和尾巴为黑色，翅膀的羽毛也是黑色；下巴和喉咙白色，胸部到尾下覆羽呈灰白色。眼睛虹膜深棕色至暗红色，眼环淡蓝色至灰色，喙黑色，腿深灰色。雌雄相似。幼鸟外观像成年个体但颜色较暗淡，头部棕色无光泽，臀部和尾巴暗棕色而非黑色，下体有灰色调。","call":"发出一系列上下起伏的哀婉哨声，另有一种独特叫声，是一连串高音调的音符逐渐下降。","habits":"栖息于低地和中海拔的原始森林、次生林、森林边缘和空地、棕榈树、可可种植园，甚至在比奥科岛的苔藓森林。通常成对或小群体出现在树冠层，以昆虫为主食，包括异翅目的虫子、毛虫，也吃果实如无花果、大戟科植物以及油棕果肉。偶尔食用种子和花蜜。通常在树冠层30米以上活动，从细枝上啄食昆虫，在树冠层的花朵和芽中觅食。常与其他物种混合群聚。","breeding":"繁殖季节主要在1月至4月的西非，11月在比奥科岛，6月在喀麦隆处于繁殖状态；1月、6月至9月以及11月在刚果民主共和国，3月和8月至9月在安哥拉处于繁殖状态。在乌干达，7月发现巢穴，4月至5月和11月至12月处于繁殖状态，在肯尼亚9月筑巢。巢为侧入口的空心结构，由各种材料构成，放置于离地面6至10米高的棕榈叶或细树枝附近。每窝产卵3至6枚。","identification":"与某些蜡嘴雀类似，但缺乏红色羽毛，可通过这些特征区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的西部和中部，包括安哥拉、贝宁、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、加纳、几内亚、肯尼亚、利比里亚、马里、尼日利亚、卢旺达、塞拉利昂、坦桑尼亚和乌干达。"},{"name":"栗胸黑雀","english_name":"Chestnut-breasted Nigrita","scientific_name":"Nigrita bicolor","overview":"栗胸黑雀（英文名：Chestnut-breasted Nigrita，学名：Nigrita bicolor），是雀形目梅花雀科黑雀属的鸟类。常见于非洲。其分布区域广阔，覆盖约3,000,000平方公里，栖息于亚热带或热带的低地森林、红树林及灌木丛。该物种在全球范围内被评价为无危状态。","appearance":"雄性栗胸黑雀体长约11至12厘米，体重约8.6至11.7克。上体及翼、尾呈暗钢灰色，额部、头部侧面、喉部和下体为深红栗色。雌鸟类似雄鸟，但下体颜色略淡。幼鸟上体灰褐色，颊部和喉部淡灰，下体肉桂色，尾下覆羽最亮。brunnescens亚种比指名亚种更暗淡，上体呈钢褐色；saturatior亚种与前者相似，但下体颜色更深，色泽更丰富。","call":"其歌声多变，包含响亮悦耳的哨音，有时伴有嘈杂的叽喳声。在利比里亚，海岸与内陆的歌声存在方言差异。叫声包括清脆的'chi-chi-hooeee'和拟声的'kitty come here'。","habits":"栗胸黑雀栖息于低地森林近地面处，沿溪流活动，也出现在树冠层。以昆虫为主食，包括毛虫和飞蚁，也食用油棕榈的油壳和果肉、无花果、种子、花蜜和树蛙卵团。单个或成对、小群觅食，常与灰冠黑雀一起在树冠层活动，加入混种群。旱季时，个体集中在油棕榈果实附近，维持彼此间的距离和等级。","breeding":"相关信息未提供。","identification":"与其他黑雀种类共存，通过其深红栗色的下体结合小巧体型加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部和中部，包括安哥拉、贝宁、喀麦隆、中非共和国、刚果共和国、刚果民主共和国等地。","other":"相关信息未提供。"},{"name":"淡额黑雀","english_name":"Pale-fronted Nigrita","scientific_name":"Nigrita luteifrons","overview":"淡额黑雀（英文名：Pale-fronted Nigrita，学名：Nigrita luteifrons），是雀形目梅花雀科黑雀属的鸟类。分布于非洲中部热带雨林，活动范围覆盖2,500,000平方千米。此物种被IUCN评为无危等级。","appearance":"雄鸟成鸟上部灰色，腹部黑色，具深灰翅膀与非常淡的白色前额；雌鸟全身灰色，脸侧至颈部黑色，面部有黑色面罩，同样拥有淡白色前额。两性皆有淡粉色至灰褐色腿。幼鸟面部与上身均匀灰色，翅膀稍暗，下身棕色，眼睛颜色浅淡。","call":"叫声包括柔和的“tew”音和四个下降的哨声“twe-tee-tee-tee”。歌唱为一系列更长的下降哨声。","habits":"生活在森林边缘和农场，常以小群或混群出现，与同属其他物种共存。偏好非洲热带雨林环境。","breeding":"具体繁殖信息未提及。","identification":"与灰冠黑雀区别在于后者翼上有斑点，而淡额黑雀翼上无斑点，且具有明显淡色前额。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，包括安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、加纳、利比里亚、尼日利亚、塞拉利昂、多哥和乌干达。","other":"亚种alexanderi的前额、头顶和颈背呈黄色，虹膜黑色，与指名亚种有区别。"},{"name":"灰冠黑雀","english_name":"Grey-headed Nigrita","scientific_name":"Nigrita canicapillus","overview":"灰冠黑雀（英文名：Grey-headed Nigrita，学名：Nigrita canicapillus），是雀形目梅花雀科黑雀属的鸟类。广泛分布于非洲西部和中部的热带雨林中。以黑色头部带有白色边线和灰色冠部为显著特征。","appearance":"体长13至14厘米，体重17至21克。成鸟头部前额和侧面黑色，边缘白色，灰色的冠至背部，臀部和上尾覆羽淡灰色，尾巴黑色。上翼黑色，每个翼覆羽尖端有圆形白色斑点，三级飞羽尖端白色；脸部、喉咙和整个下体黑色。虹膜奶油色到橙红色，眼圈灰色；喙黑色；腿深灰色。幼鸟暗灰色，翅膀和尾巴黑褐色，翼覆羽和三级飞羽上有不明显的白色斑点，虹膜淡灰色。不同亚种在颜色和斑点上有细微差异。","call":"发出清晰而哀婉的三音节哨声，'hooeee, hooeeee, hoo'，有时伴有柔和的气泡声和刺耳的喋喋不休声，全年皆可听到。","habits":"栖息于热带雨林、画廊森林及其边缘地带。主要以小昆虫、蚂蚁、白蚁、昆虫幼虫、果实、种子为食，偶尔摄取花蜜。在最大树木的树冠层25米处觅食，也常在较低层次活动。单独或成对、家庭群觅食，参与混合物种的鸟群活动。","breeding":"筑巢季节多变，从2月到10月不等，取决于具体地点。筑巢材料多样，包括草茎、叶片、草根、纤维、苔藓和新鲜草头。每窝产3至6枚蛋，孵化期12至13天。雏鸟有灰色白色的绒毛，喙内侧有黄色白色乳突，腭部有五个黑斑，舌下有黑色新月形标记。","identification":"与苍白额黑雀类似，但体型更大，额头更多黑色。东方和中央非洲的个体通过翼上的白色斑点进一步区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部和中部的热带雨林，包括安哥拉、贝宁、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、冈比亚、加纳、肯尼亚、尼日利亚、苏丹、坦桑尼亚、多哥、乌干达和赞比亚。"},{"name":"小绿背织雀","english_name":"Shelley's Oliveback","scientific_name":"Nesocharis shelleyi","overview":"小绿背织雀（英文名：Shelley's Oliveback，学名：Nesocharis shelleyi），是雀形目梅花雀科绿背织雀属的鸟类。特有于非洲中西部。仅见于喀麦隆、赤道几内亚和尼日利亚的高地森林、森林边缘及农田，具有黑色头部、黄色绿色背部、灰色腹部，以及独特的蓝色厚喙。","appearance":"小绿背织雀体长约8厘米，体重7至9克。雄鸟具有黑色头部和喉咙，灰色颈环，耳羽后方有垂直白色条纹，橄榄色上体，臀部泛金黄色，黑色尾巴，橄榄黄色边缘的黑色翅膀，橄榄色胸部，灰色腹部和尾下覆羽。雌鸟脸部后方白色条纹减少或缺失，胸部和颈部、腹部同为灰色。幼鸟外观似雌鸟，但色彩较暗淡，灰色部分带褐色调。亚种bansoensis与指名亚种相似，但下体颜色更深。","call":"发出高音调的‘siew’声，觅食时伴有低音颤鸣；其歌曲由一系列重复的4至8个不同的、高音调的嗡鸣颤音组成，频率在5至8千赫兹之间。","habits":"栖息于海拔1200米以上的山地森林和可可种植园，主要在喀麦隆1550至2100米间，而在比奥科岛则在50米以上高度。以小型昆虫和种子为食，活跃于林下至树冠层，单个或成对觅食，有时会倒挂觅食，通常形成8至10只的小群。","breeding":"繁殖季节在尼日利亚为1月，在喀麦隆为12月至3月。雄鸟在展示时，嘴中衔着一缕草，沿树枝跳跃，身体左右转动，每隔几秒发出吱吱的颤音。已知两次繁殖尝试中，一次使用了北双领花蜜鸟的旧巢，另一次使用了黑腹山织雀的旧巢，巢内铺有植物绒毛。每次产卵3枚，其余繁殖信息未知。","identification":"与其他绿背织雀属物种相比，小绿背织雀具有更紧凑的体型、短而粗的尾巴和蓝色的厚喙。其黑色头部、橄榄绿色背部、灰色腹部和黑色尾端是辨识的关键特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲喀麦隆山脉生态区，包括喀麦隆、赤道几内亚和尼日利亚的高地森林。在喀麦隆大多位于1550至2100米海拔，比奥科岛则在更高海拔。","other":"尽管在某些地方较为罕见，但由于容易被忽视，其实际数量可能比预想的要多。"},{"name":"白领绿背织雀","english_name":"White-collared Oliveback","scientific_name":"Nesocharis ansorgei","overview":"白领绿背织雀（英文名：White-collared Oliveback，学名：Nesocharis ansorgei），是雀形目梅花雀科绿背织雀属的小型鸟类。分布于非洲的布隆迪、刚果民主共和国、卢旺达、坦桑尼亚和乌干达，具有特征性的狭窄灰白色颈圈。全球活动范围约94,000平方千米，被IUCN评为无危（Least Concern）。","appearance":"体型微小，长约10厘米，体重8-9.5克。雄鸟头部和喉部黑色，颈后灰色，具有一条细窄的白色颈圈延伸至耳羽后方至喉咙下方；背部橄榄绿色，尾羽黑褐色；上翼黑褐，羽缘橄榄黄；胸部橄榄色，腹部至尾下覆羽灰色。雌鸟面部后方的白线减少或缺失，整个下体包括胸部均为灰色。幼鸟特征未详述。","call":"叫声为轻柔的‘tssep’声，歌声是一串颤音，以两个清晰滑音哨声开始，类似小绿背织雀的叫声。","habits":"栖息于稠密湿润的生境，包括森林边缘、灌丛和耕作区，常结成小群活动。具体栖息地、迁徙、飞行特点、活动范围、觅食方式等细节未详。","breeding":"关于繁殖行为的详细信息未提供。","identification":"与灰头绿背织雀相比，体型更小，头部黑色。辨识要点包括狭窄的灰白色颈圈。","protection":"IUCN：LC（无危）","distribution":"分布于刚果民主共和国东部和乌干达西部至坦桑尼亚西北部的阿尔伯丁裂谷区域，最近记录显示在刚果西南部和安哥拉西北部也有分布。","other":"该物种可能因未被充分注意而显得较为罕见，但在某些局部地区相对常见，出现在多个保护区。"},{"name":"灰头绿背织雀","english_name":"Grey-headed Oliveback","scientific_name":"Delacourella capistrata","overview":"灰头绿背织雀（英文名：Grey-headed Oliveback，学名：Delacourella capistrata），是雀形目梅花雀科 Delacourella 属的鸟类。常见的梅花雀科（Estrildidae）小型雀鸟，分布于非洲中部和西部。该鸟以独特的橄榄色背部和灰色头部著称，活动范围广泛，约800,000平方公里。在贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果民主共和国、科特迪瓦、冈比亚、加纳、几内亚、几内亚比绍、马里、尼日利亚、塞拉利昂、苏丹、多哥和乌干达均有分布。","appearance":"灰头绿背织雀体长约14厘米，体重介于10.8至13.2克之间。头顶、颈背及大部分下体呈灰色，上体和尾巴橄榄色至金橄榄色，上翼灰褐色，边缘略带黄橄榄色。前额、眼圈和脸颊白色，从下巴到喉咙有一黑色项圈延伸至颈部两侧。两胁黄色，虹膜深棕色至暗红色，眼圈深灰色，喙黑色，腿深灰色。雌雄外观相似，幼鸟较成鸟颜色更深，面部斑块为灰色，两胁橄榄色至淡褐色，喙灰色，基部和尖端暗色。","call":"发出高音的‘tsssp’叫声，鸣唱为一系列哨声，开始时音调下降，随后音符变短，音调逐渐降低，‘chwee-chwee-chwee-chwi’。","habits":"栖息于草地湿润的灌木丛、靠近水源的灌木丛和河流边的树林，活动范围包括树冠至地面。以野生无花果（Ficus）、其他果实、草籽以及小昆虫、蚂蚁和毛虫为食，也会捕食蜗牛。单独或成对觅食，善于飞越树叶间，从树冠向下至地面觅食。","breeding":"在托哥的筑巢活动发生在7月至8月，尼日利亚为6月至7月，刚果民主共和国（乌埃勒）为7月至10月，乌干达为5月至6月。巢由干燥的杂草和草茎编织而成，侧面入口，悬挂着下垂的管口，通常位于灌木或树木分叉处离地约2.5米的位置。每窝产卵3至5枚，孵化期15至16天；雏鸟皮肤黑色，头部和背部覆盖灰色绒羽，上喙带有弯曲的白色弧线和下方的白色球状物，下喙有两个白色球状物（白色肿胀后方有黑色背景），腭部淡粉色至淡黄色，带有五个大黑点，舌粉红色，带有暗色条纹和灰色尖端；雏鸟期21至22天。","identification":"与其它绿背织雀种类相比，灰头绿背织雀具有白色的面颊和黑色的项圈，这些特征帮助区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲，从塞内加尔和冈比亚至几内亚，东至南苏丹南部，乌干达西部和刚果民主共和国东北部。"},{"name":"红嘴斑腹雀","english_name":"Red-billed Pytilia","scientific_name":"Pytilia lineata","overview":"红嘴斑腹雀（英文名：Red-billed Pytilia，学名：Pytilia lineata），是雀形目梅花雀科斑腹雀属的小型鸟类。其最显著的特点是拥有红色的翅膀、尾巴和喙，身体大部分呈灰色，分布于埃塞俄比亚的特定地区。","appearance":"红嘴斑腹雀体长约12.5至13厘米，体重介于11至16.8克之间。雄鸟具有灰色头部和背部，臀部及上尾覆羽为红色，中央尾羽亦为红色，其余尾羽为深棕色带红色边缘；翅膀灰色，翼上的覆羽和主翼羽、次级飞羽边缘为红色；喉咙灰白色，腹部有灰色和白色的条纹，从胸部到腹部灰色条纹逐渐变宽，白色条纹在下尾覆羽处最宽；眼睛暗褐色至红色，眼环灰色；喙红色；腿粉色。与红翅斑腹雀的区别在于红嘴斑腹雀的喙为红色而非黑色。雌鸟灰色部位带有褐色色调，腹部颜色较淡，白色条纹比灰色条纹更宽。幼鸟主要为棕灰色，臀部和尾巴为红褐色，翅膀为棕灰色带红褐色边缘，腹部为灰色，有条纹痕迹，眼睛暗褐色，喙灰色或棕色，逐渐变为粉红色然后转为红色。","call":"红嘴斑腹雀的报警声和飞行叫声为“chwick”。其歌声由几个尖锐的吱吱声后跟一连串急促的咔嚓声组成，发音为'titititititititit'。","habits":"红嘴斑腹雀栖息于开阔的林地草原和灌木丛，以及Combretum-Terminalia林地，海拔高度在750至1800米之间。它们通常是居民鸟，偶尔会进行局部移动，有时出现在平常未见它们的地方。关于饮食和觅食的信息有限，已知在圈养环境下，它们以小种子和昆虫为食。","breeding":"繁殖记录显示，红嘴斑腹雀的筑巢活动发生在五月。求偶时，雄鸟会在雌鸟周围跳跃，喙中衔着草或羽毛，并在栖息处上下点头。目前没有更多关于繁殖的详细信息。","identification":"红嘴斑腹雀与绿翅斑腹雀和橙翅斑腹雀的分布区域重叠，但可通过其红色的翅膀轻松区分。雌鸟和幼鸟在羽毛颜色上较雄鸟更淡，且带有褐色色调。","protection":"IUCN：LC（无危）。红嘴斑腹雀在全球范围内并不受到威胁，在其分布区的西部和埃塞俄比亚中部高地较为常见至丰富，已确认约30个地点有其存在，一天内最多观察到26只个体；在西北部较为罕见。历史上曾在苏丹东部出现，靠近埃塞俄比亚边境有多个旧记录，但自1910年后再无记录。","distribution":"红嘴斑腹雀主要分布在非洲的埃塞俄比亚，具体包括北部和中部埃塞俄比亚，以及一些历史记录中的苏丹极东南部。","other":"红嘴斑腹雀曾被认为与红翼斑腹雀为同一物种，后被划分为独立种类。"},{"name":"红翅斑腹雀","english_name":"Red-winged Pytilia","scientific_name":"Pytilia phoenicoptera","overview":"红翅斑腹雀（英文名：Red-winged Pytilia，学名：Pytilia phoenicoptera），是雀形目梅花雀科斑腹雀属的鸟类。这独特而美丽的蜡嘴雀科成员，以其深红色的翅膀和臀部闻名。分布于非洲西部和中部的湿润阔叶林地、草原和灌木丛。雌鸟颜色较灰淡，常见于小群或成对活动，与其它鸟类混群。曾与红嘴斑腹雀归为一类，现已分离。","appearance":"雄性红翅斑腹雀长12.5至13厘米，体重13.7至16.1克。头部和上体灰色，臀部和尾羽上覆羽红色，中央尾羽带红色，其余尾羽深棕色，翼上覆羽和主翼羽边缘红色；喉部灰白色，下体有灰白相间的条纹，白色条纹在尾下覆羽处最宽。雌鸟上体略带褐色，下体比雄鸟更淡，白色条纹比灰色条纹宽。幼鸟上体棕灰色，臀部和尾巴带红色，翼羽棕灰色带锈色边缘，下体灰色，有条纹痕迹。","call":"发出上升的哨音和双音节的叽叽声，还有‘spink’的音调。其鸣唱结合了高音哨声和低沉的哼鸣声。","habits":"栖息于大树林和灌木丛生的干燥林地，靠近村庄和火烧迹地。主要以小型草籽和白蚁为食，常在地面觅食，通过探查地面和树上的白蚁通道捕食白蚁。通常单独或成对活动，偶尔与其他种子食鸟混群。","breeding":"繁殖季节在冈比亚为8月和9月，在尼日利亚为9月至2月。雄鸟在求偶时会跳跃环绕雌鸟，叼着草或羽毛，也会在栖木上上下跳动。巢为侧入口的球形，由草茎和草籽头构成，内衬少量羽毛和干草叶片，位于离地2米内的灌木中。每窝产卵3至4枚，孵化期14天。雏鸟皮肤头部暗灰色，身体粉色，随年龄增长变黑，孵化后19至21天离巢。","identification":"与绿翅斑腹雀和红脸斑腹雀类似，但可通过其红色翅膀加以区分。红嘴斑腹雀的喙为黑色，而非红色。","protection":"IUCN：LC（无危）","distribution":"分布于贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果民主共和国、科特迪瓦、埃塞俄比亚、冈比亚、加纳、几内亚、几内亚比绍、马里、尼日尔、尼日利亚、塞内加尔、塞拉利昂、苏丹、多哥和乌干达。","other":"在野外，红翅斑腹雀的巢穴可能被长尾维达雀寄生。在圈养条件下，成年鸟能抚育宽尾维达雀的雏鸟。"},{"name":"黄翅斑腹雀","english_name":"Yellow-winged Pytilia","scientific_name":"Pytilia hypogrammica","overview":"黄翅斑腹雀（英文名：Yellow-winged Pytilia，学名：Pytilia hypogrammica），是雀形目梅花雀科斑腹雀属的鸟类。非洲梅花雀科的雀鸟，以独特的黄色翅膀和红臀部著称。雄鸟具有红色面部，雌鸟头部灰色。分布于几内亚至利比里亚，东至乍得南部和中非共和国西部，常见于湿润的阔叶林、河岸森林边缘和沿海灌木丛。","appearance":"体长约12.5厘米，体重约14.3-15克。雄鸟面部、耳羽至喉部鲜红，冠至背部灰色，臀部和尾上覆羽红色；中央尾羽带红，其余尾羽暗褐色，翼上覆羽和外侧飞羽镶金黄色边；下体橄榄灰，有细黑白色条纹。雌鸟头部至胸部灰褐色，下体较雄鸟淡，条纹均匀。幼鸟上体棕灰，臀部和尾部带红，翼具锈色边缘，下体灰，有条纹痕迹。","call":"报警叫声从1kHz上升至2.4kHz，伴随高音下降；接触叫声类似'seee'，类似橙翅斑腹雀的叫声；还有嗡嗡的哨声，调制速率40峰/秒。","habits":"栖息于成熟的几内亚森林、沿河森林边缘、沿海灌木丛和废弃耕地。以小草籽为主食，也吃昆虫，主要是白蚁和蚂蚁。通常单独或成对活动，偶尔加入小群，与其它小型种子食鸟混群。","breeding":"繁殖季节为10月至次年1月。雄鸟向雌鸟鞠躬，尾巴朝向雌鸟，发出叫声。巢呈松散覆盖球状，入口位于一侧，筑于灌木或树上，离地面0.5-4米。每窝产3-4枚卵，孵化期12-14天，雏鸟期20-22天。","identification":"与其他Pytilia属鸟类相比，通过黄色翅膀和红臀部容易区分。","protection":"IUCN：LC（无危）；在部分区域较为罕见。","distribution":"分布于西非几内亚至利比里亚，向东延伸至乍得南部和中非共和国西部，主要分布在湿润森林地带。"},{"name":"橙翅斑腹雀","english_name":"Orange-winged Pytilia","scientific_name":"Pytilia afra","overview":"橙翅斑腹雀（英文名：Orange-winged Pytilia，学名：Pytilia afra），是雀形目梅花雀科斑腹雀属的鸟类。拥有独特的橄榄绿色细条纹腹部，黄色翼缘和红色尾部标记，分布广泛，IUCN 将其评估为无危级别。最初由德国自然学家Johann Friedrich Gmelin于1789年描述。","appearance":"体长约11厘米，体重约14-15克。雄鸟具有红色的前额至耳羽、下巴和上喉部，头部其余部分灰色，背部呈金色橄榄色，翅膀上的大型覆羽边缘为金色橙色，初级飞羽黑色带橙边，臀部红色，尾巴中央羽毛暗棕色带红色外缘。雌鸟的头部灰绿色，没有红色，背部和翅膀颜色较暗淡，下体有更宽的条纹。幼鸟似雌鸟，但色彩更暗淡。","call":"报警或兴奋时发出短促的叫声，持续0.04秒，声音能量峰值在3千赫兹，带有4.5千赫兹的泛音。联系叫声为上升音调和随后较长的下降音调结合在一起，'seeee'，大部分能量集中在4千赫兹。此外还有'peeping tyooyu'声，音调比红翅斑腹雀和黄翅斑腹雀更低。特有的嘶哑哨声持续1秒，快速调制每秒36-40次，音高保持在3.4千赫兹，元素在短语中降低音高。","habits":"栖息于开放的树林和灌木地带，高草草原，纠结的灌丛，耕作区，一般海拔低于1800米。主要以小草籽和白蚁为食，通常在地面觅食。常以家庭群体或小型群居，非繁殖季节有时会形成较大群落。","breeding":"繁殖季节在坦桑尼亚为4月至6月，在赞比亚和津巴布韦为1月至5月，在马拉维为3月至7月，在津巴布韦为2月至4月。求偶时，雄鸟持羽毛在喙中，跳跃并展示尾巴，筑巢为侧入口的球状，由草制成，内衬少量羽毛，位于灌丛中离地2-2.5米处。每窝产卵3-5枚，孵化期12-14天，雏鸟期21天。","identification":"与绿翅斑腹雀(P. chloroptera)相比，发现于更湿润的生境，下体条纹更细，翼缘黄色，雄鸟面部红色图案不同。","protection":"IUCN：LC（无危）","distribution":"分布于非洲南部，从南苏丹南部和埃塞俄比亚南部至南非东北部，向西至刚果南部和安哥拉西部。具体国家包括：安哥拉、博茨瓦纳、布隆迪、刚果共和国、刚果民主共和国、埃塞俄比亚、肯尼亚、马拉维、莫桑比克、卢旺达、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。","other":"橙翅斑腹雀可能被捕捉作为笼鸟。"},{"name":"绿翅斑腹雀","english_name":"Green-winged Pytilia","scientific_name":"Pytilia melba","overview":"绿翅斑腹雀（英文名：Green-winged Pytilia，学名：Pytilia melba），是雀形目梅花雀科斑腹雀属的鸟类。广泛分布于撒哈拉以南非洲，尤其在西部、中部、东部和南部较为常见。其最显著的外部特征是雄鸟的红色额头，以及橄榄绿色的背部和翅膀。雌鸟头部呈灰色，与雄鸟明显不同。","appearance":"绿翅斑腹雀体长约12.5厘米，平均寿命6年。雄鸟具有独特的红色额头和喉咙，上体为黄色绿色，臀部和尾覆羽为红色，尾羽中央一对为红色，其余为暗褐色。雌鸟缺乏雄鸟的红色特征，头部为灰色，胸部无亮带，斑纹不明显。幼鸟羽毛较淡，腹部和尾覆羽为橙色，喙黑色，虹膜深棕色。喙比其他小型梅花雀强健，用于啄开白蚁穴。","habits":"绿翅斑腹雀栖息于干燥的荆棘草原、干燥林地和耕作区，以小草籽、白蚁和伪蝎为食。它们通常在地上寻找食物，受到惊扰时会飞入树上。绿翅斑腹雀常成对或小群活动，有时加入混合物种的鸟群。","breeding":"绿翅斑腹雀的繁殖期不详，但孵化期约为12天，幼鸟在21天后羽毛长成。它们倾向于在矮灌木丛中筑巢，偶尔在盒子或箱子中筑巢。巢材主要是干草，偶尔辅以羽毛。每对绿翅斑腹雀在夏季大约筑巢2至3次，幼鸟能够独立进食后，需与亲鸟分离，以便亲鸟再次繁殖。","identification":"绿翅斑腹雀与橙翅斑腹雀的区别在于后者翼羽边缘有诊断性的金黄色，而绿翅斑腹雀的翼羽边缘为绿色。不同亚种间可通过腹部横纹的差异进行辨识。","protection":"IUCN：LC（无危）","distribution":"绿翅斑腹雀遍布非洲大陆的西部、中部、东部和南部，具体包括西非至东非的广大地区，以及南非。"},{"name":"红头环喉雀","english_name":"Red-headed Finch","scientific_name":"Amadina erythrocephala","overview":"红头环喉雀（英文名：Red-headed Finch，学名：Amadina erythrocephala），是雀形目梅花雀科环喉雀属的鸟类。广泛分布于非洲的梅花雀科鸟类，其全球分布面积约为1,600,000平方公里，常见于安哥拉、博茨瓦纳、莱索托、纳米比亚、南非和津巴布韦等地。","appearance":"体长12-13厘米，体重17.5-30克。雄鸟头部至颈背、脸颊和喉咙呈红色，眼周有宽阔的淡灰色区域；颈后和肩部为无斑点的灰色，其余上体灰褐色，臀部和上尾覆羽有细黑亚端斑和淡色尖端；尾羽微呈梯形，深棕色，外侧尾羽尖端白色并有白色边缘；上翼浅灰色，有淡色和黑色斑点与条纹；下体白色至棕黄色，两侧有栗色斑块，羽毛中央白色，末端黑色，形成明显的横斑和鳞状图案；下尾覆羽白色；虹膜深棕色，眼圈淡灰色；喙粗壮，淡角质色，繁殖季节略带粉色；腿淡粉色。雌鸟较雄鸟暗淡，头部灰褐色，常带有锈橙色尖端，上体更偏棕色，下体淡黄色，上腹缺乏栗色斑块，斑纹不如雄鸟鲜明。","call":"叫声为类似麻雀的干涩‘shep’声，飞行时发出‘zree-zree’声；报警声为尖锐的‘tek’。雄鸟的歌声为重复的柔和颤音或嗡嗡声。","habits":"以草籽和昆虫（包括白蚁）为食，群居，常在小群体中觅食；干旱期间数百只成群出现在水坑旁。","breeding":"资料不足。","identification":"雌性环喉雀与较大的雌鸟Cut-throat相似，但可通过头部条纹（而非纯色）和缺乏白色尖端的外侧尾羽来区分。","protection":"IUCN：LC（无危）","distribution":"分布于西南安哥拉（从西南Bengo向南）、纳米比亚、博茨瓦纳、南非南部津巴布韦和低地莱索托。","other":"该物种与环喉雀是Amadina属的唯二成员。"},{"name":"环喉雀","english_name":"Cut-throat Finch","scientific_name":"Amadina fasciata","overview":"环喉雀（英文名：Cut-throat Finch，学名：Amadina fasciata），是雀形目梅花雀科环喉雀属的鸟类。分布广泛，遍及非洲大陆，尤其在萨赫勒地区、东非和南部非洲可见其踪迹。雄鸟具有显著的红色喉带，雌鸟和幼鸟则无此特征。","appearance":"环喉雀体型小巧，体长11-12厘米，体重介于15-32克。雄鸟成鸟具沙褐色体羽，布满黑色条纹，头部淡黄褐色，眼上方至喉部有一鲜明红色半月形带，上下缘分别由白色带环绕；胸部淡黄色，中央腹部呈栗色，下胸至两胁有淡黄色羽毛，边缘黑色形成鳞状图案，尾巴棕色，外侧有白色斑点。雌鸟色彩较淡，头及上体沙色，细小条纹，缺乏红色喉带及栗色腹部。幼鸟雄鸟有红色喉带，但色泽稍暗，上体及下体颜色较淡，条纹不明显；雌鸟幼鸟条纹更加模糊，脸及喉部仅有少量暗色标记。","habits":"环喉雀栖息于半干旱开阔草地林地、干燥灌木丛、金合欢（Acacia）稀树草原、摩帕奈（Colophospermum mopane）林地、海菲纳（Hyphaene）棕榈稀树草原及农田和村落边缘的灌木丛，通常活动于海拔1500米以下。以草籽为主食，地面觅食，也会捕食白蚁（Isoptera）和其他昆虫。成群或成对觅食，非繁殖季节加入混合群与其他雀科及织雀科鸟类共同活动。","breeding":"环喉雀利用其他鸟类建造的巢穴，每窝产3至6枚白色蛋，孵化期约12-13天，雏鸟21-27天离巢，但继续受父母喂养约三周。","identification":"环喉雀雄鸟特有的红色喉带是与其他种类的重要辨识特征，尤其是与红头环喉雀雌鸟的区别在于后者头部无条纹，外侧尾羽尖端白色。","protection":"IUCN：LC（无危）","distribution":"非洲西部、中部、东部，包括津巴布韦、科特迪瓦、赞比亚、埃塞俄比亚等国家。全球活动范围约3,350,000平方公里。"},{"name":"绿背斑雀","english_name":"Green Twinspot","scientific_name":"Mandingoa nitidula","overview":"绿背斑雀（英文名：Green Twinspot，学名：Mandingoa nitidula），是雀形目梅花雀科绿背斑雀属的鸟类。广泛分布于撒哈拉以南的非洲低地湿润森林。其最显著的特征是雄鸟的红脸和雌鸟的橄榄绿色脸，以及腹部的两块亮白斑点。","appearance":"绿背斑雀是一种体型小而健壮的蜡嘴雀，体羽深绿色，腹部有明亮的白色双斑。雄鸟面部红色，雌鸟则呈橄榄黄色，喙色较暗近黑。雌雄异型明显，雄鸟鲜艳，雌鸟较为低调。","call":"该鸟具有独特的叫声，是一种短暂而高音的颤音，常在飞行中发出。歌声复杂，由多种不同的叫声混合组成，但在野外较少听到。","habits":"绿背斑雀偏好居住在森林及其周边地带，尤其喜欢密集的灌木丛和开阔地带的草丛中。它们的活动范围广泛，迁徙模式随季节变化而调整，善于飞行，以草籽为主要食物来源。","breeding":"繁殖季节在不同地区有所不同，通常在9月至翌年5月之间。求偶时，雄鸟会携带筑巢材料，上下摆动，吸引雌鸟。巢为大型的草茎球状结构，置于3至15米高的浓密树叶中。每窝产卵3至6枚，孵化期为12至14天，幼鸟由双亲共同喂养，离巢时间为21至23天。","identification":"与绿翅斑雀相似，但体型更小，更倾向于森林环境而非草原。与绿翅斑雀相比，不具备红色尾巴。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部、中部、东部和东南部，具体包括利比里亚、加蓬、赞比亚、马拉维、津巴布韦和南非的夸祖鲁-纳塔尔省等地。"},{"name":"红脸朱翅雀","english_name":"Red-faced Crimsonwing","scientific_name":"Cryptospiza reichenovii","overview":"红脸朱翅雀（英文名：Red-faced Crimsonwing，学名：Cryptospiza reichenovii），是雀形目梅花雀科朱翅雀属的鸟类。这种非洲常见的梅花雀以其红色主调的羽毛和雄鸟眼周的红色斑块而著称。其全球分布范围约390,000平方千米，遍及安哥拉、布隆迪、喀麦隆、刚果民主共和国、马拉维、莫桑比克、尼日尔、尼日利亚、卢旺达、坦桑尼亚、乌干达、赞比亚和津巴布韦。","appearance":"红脸朱翅雀体型小巧，背部鲜红，翅膀和尾巴呈黑色，下体颜色较为暗淡，偏向橄榄色。雄鸟和雌鸟外观相似，不过雄鸟脸部有醒目的红色斑点，而雌鸟则有淡黄色的脸部斑纹。它们的眼睛周围都带有红色特征。","call":"鸣叫时发出尖锐的‘tsit’声。","habits":"这种鸟儿喜欢栖息在中海拔的山地森林中，尤其是湿润地带，如溪流边的浓密林区，也会出现在林缘和开阔的林间空地。它们通常成对或小群活动，显得相当隐蔽。","identification":"与绿背朱翅雀在大小和整体色彩上相似，但红脸朱翅雀色泽更为淡雅，且脸部具有红色或黄色标记。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的中西部、中部和东南部，具体国家包括但不限于安哥拉、布隆迪、喀麦隆、刚果民主共和国、马拉维、莫桑比克、尼日尔、尼日利亚、卢旺达、坦桑尼亚、乌干达、赞比亚和津巴布韦。","other":"系统学历史上，红脸朱翅雀的分类有过调整，但目前被广泛接受为独立物种。"},{"name":"绿背朱翅雀","english_name":"Abyssinian Crimsonwing","scientific_name":"Cryptospiza salvadorii","overview":"绿背朱翅雀（英文名：Abyssinian Crimsonwing，学名：Cryptospiza salvadorii），是雀形目梅花雀科朱翅雀属的鸟类。其分布于非洲中东部，主要在东非地区，常见于山地森林环境。","appearance":"绿背朱翅雀体型小巧，约10至11厘米长，重10.9至14克。头部和上背部呈灰橄榄色，其余上部羽毛、尾羽深红，翼部和背部尤为鲜艳。下体灰色橄榄，雄鸟两侧带红色斑点。雌鸟色彩较淡，上部偏棕色，下体浅橄榄色，幼鸟羽色更暗，仅部分区域显红。嘴黑，眼及腿深褐色。","call":"绿背朱翅雀的叫声为柔和的‘tsip-tsip’声，受惊时发出。其歌喉含蓄，重复叫声，伴以轻柔旋律，但较少听见。","habits":"绿背朱翅雀栖息于山地森林，尤其偏好潮湿环境，如溪流边的浓密植被。它们在林缘或开阔地带活动，通常保持在低矮灌木丛中，有时可见于竹林、灌丛或沿水道的茂密植被中。它是一种警觉性强、难以接近的鸟，常在感受到威胁时迅速隐蔽。主要以草籽为食，也会食用其他小型种子，如Setaria spp、Impatiens spp和Laportea spp等，偶尔可能捕食昆虫。","breeding":"绿背朱翅雀在埃塞俄比亚的繁殖行为记录显示，其繁殖期在4月至8月间；在乌干达，Bwindi地区3月和Mount Elgon地区6月及11月观察到繁殖活动，所有已知繁殖行为发生在雨季后的干燥月份。","identification":"绿背朱翅雀与红脸朱翅雀在体型和整体色彩上相似，但前者颜色更深，面部无红色或黄色。雄鸟侧翼的红色斑点是辨识要点。","protection":"IUCN：LC（无危）","distribution":"绿背朱翅雀主要分布在非洲东部的肯尼亚、埃塞俄比亚等地，栖息于海拔1500至300米的山地森林。","other":"物种名和别名Salvadori's crimsonwing是为了纪念意大利鸟类学家Count Adelardo Tommaso Salvadori Paleotti，即Tommaso Salvadori。"},{"name":"暗腹朱翅雀","english_name":"Dusky Crimsonwing","scientific_name":"Cryptospiza jacksoni","overview":"暗腹朱翅雀（英文名：Dusky Crimsonwing，学名：Cryptospiza jacksoni），是雀形目梅花雀科朱翅雀属的鸟类。常见于刚果民主共和国东部、乌干达西部、卢旺达和布隆迪的阿尔伯丁裂谷山区森林中。其全球分布面积约78,000平方公里。物种命名以英国探险家Frederick John Jackson的名字纪念。","appearance":"暗腹朱翅雀体型较小，全身深色，背部和面部呈红色，翅膀与尾巴黑色，腹部呈深灰色。雄鸟与雌鸟相似，但雄鸟脸部的红色更为显著。幼鸟脸部无红色斑块。","call":"发出尖锐的‘tsit’声。","habits":"栖息于阿尔伯丁裂谷的山地森林，包括林缘和林间空地。通常成对或小群体活动，较为隐蔽。","breeding":"关于其繁殖行为的具体信息尚待补充。","identification":"与乌双斑雀大小和整体颜色相近，但暗腹朱翅雀脸部有红色，而侧翼无红色。","protection":"IUCN状态未知，具体保护级别需查询最新数据。","distribution":"分布于刚果民主共和国东部、乌干达西部、卢旺达和布隆迪的阿尔伯丁裂谷山区。","other":"暗腹朱翅雀是其属下的唯一物种，没有亚种分化。"},{"name":"谢氏朱翅雀","english_name":"Shelley's Crimsonwing","scientific_name":"Cryptospiza shelleyi","overview":"谢氏朱翅雀（英文名：Shelley's Crimsonwing，学名：Cryptospiza shelleyi），是雀形目梅花雀科朱翅雀属的鸟类。分布于刚果民主共和国东部、乌干达西部、卢旺达和布隆迪的阿尔伯丁裂谷山区。其鲜艳的红色外观和稀有性使其成为研究和保护的重点。","appearance":"谢氏朱翅雀约13厘米长，雄鸟具有醒目的红色头冠、面部和背部，黑色翅膀和尾巴形成鲜明对比，橄榄黄色下体带有暖色调侧面和腹部。雌鸟较为暗淡，头部橄榄色，肩部和臀部带红色。两性均具有鲜红的喙。","call":"其鸣叫声尖锐而高亢，通常发出tit tit tit的叫声，伴随上升和下降的高音tu tutu ti ti ti系列。","habits":"栖息于湿润的封闭林冠森林，常位于水边的山谷底部，也出现在森林边缘的低矮次生植被、森林空地、以大型草本植物、竹丛为主的开阔地以及上层森林和山地草原生态过渡区。","identification":"与其他朱翅雀属鸟类相比，谢氏朱翅雀的红色羽毛和高音鸣叫是其显著特征，有助于野外辨识。","protection":"IUCN：EN（濒危）","distribution":"主要分布在刚果民主共和国东部的伊东贝山脉、卡胡齐-比埃加国家公园、基伍湖西岸山脉，卢旺达的纽恩威森林、吉什瓦蒂、马库瓦和穆库拉森林，布隆迪的布里里森林，乌干达的鲁文佐里山脉和宾迪不可穿透森林，以及维龙加山脉，跨越刚果民主共和国、乌干达和卢旺达边境。","other":"谢氏朱翅雀面临的主要威胁是森林丧失和退化，尤其是为了农业和木材开采导致的森林破坏。尽管在一些保护区如维龙加国家公园、纽恩威森林保护区和乌干达的鲁文佐里山脉国家公园和宾迪不可穿透国家公园存在，但针对朱翅雀的专项调查未能在宾迪不可穿透森林国家公园和马哈因加大猩猩国家公园发现其踪迹。"},{"name":"黑腹裂籽雀","english_name":"Black-bellied Seedcracker","scientific_name":"Pyrenestes ostrinus","overview":"黑腹裂籽雀（英文名：Black-bellied Seedcracker，学名：Pyrenestes ostrinus），是雀形目梅花雀科裂籽雀属的鸟类。主要分布在非洲中西部，包括科特迪瓦至南苏丹、肯尼亚西部和南部至赞比亚和安哥拉北部。体长约15厘米，重约22.2克，上体和腹部呈黑色，头部、胸部及尾部显现出鲜艳的红色。拥有厚实的黑色喙，眼周有白色的环状羽毛，使其在野外容易识别。","appearance":"黑腹裂籽雀的外观特征鲜明，雄鸟头部、颈部至胸部和两侧呈现出鲜艳的深红色，上身及下身覆盖着炭黑色的羽毛，尾羽基部和边缘为红色，其余部分为暗褐色。眼睛周围有白色的“眼睑”。雌鸟红色部分仅限于头部、喉咙、臀部至尾部，颈侧、胸侧和上侧的羽毛尖端颜色可变，其余部分为黄褐色，翅膀为黑褐色，覆羽边缘为黄褐色。幼鸟类似雌鸟，但头部颜色为黄褐色而非红色，尾羽上覆羽和尾羽为赤褐色，喙在离巢两个月后达到成年大小。","call":"其叫声包括低沉的'peenk'声，报警声为'terr'。雄鸟有多达七种不同的歌曲主题，每首歌都由甜美的哨音、咯咯声、尖锐的音符、颤音和嘶嘶声的颤音组成，如'pep-tiddly-et, o-tslee-tslee'或'dee-oh-la-dee-day'。雌鸟的歌声较少发出。","habits":"栖息于热带雨林中的水道、封闭的林地、湿润的常绿森林边缘、河岸森林、棕榈草原，以及潮湿的荒废农田，如木薯地。常见于低地和丘陵地带，海拔高度在700至1400米之间。不同喙型的个体适应不同的生境和生态位，小喙和大喙个体在同一区域内共存，而大喙个体还出现在森林和草原过渡区。","breeding":"繁殖季节在8月至11月（主要为9月至10月）和4月至5月，以及在刚果民主共和国的雨季期间，12月至7月在伊东布韦，7月至12月在乌埃勒；在乌干达为2月、4月至7月和11月，在赞比亚为2月至3月。筑巢由双方共同完成，巢穴为大型球状，侧面入口，由干燥的藤蔓和竹子叶片条、草、干叶、蕨类植物、树皮碎片和攀援植物松散地编织在一起，内部铺以少量草尖，位于地面以上1至9米的树、灌木或竹丛中。","identification":"与蓝蜡嘴雀的区别在于全蓝色的喙。黑腹裂籽雀的喙形状和大小在个体间有显著差异，分为小喙、大喙和超大喙三种形态，这三种形态的喙主要用于处理不同硬度的种子，是区分它们的重要特征。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中西部，具体包括科特迪瓦、加纳、多哥、贝宁、南苏丹、尼日利亚、赤道几内亚、西非和南部喀麦隆、中非共和国、乍得西南部、加蓬、刚果民主共和国、刚果共和国、乌干达、肯尼亚西部、安哥拉、赞比亚和坦桑尼亚西南部。","other":"黑腹裂籽雀具有三种喙的形态变异，这与它们的饮食偏好有关。小喙个体倾向于食用较软的Scleria goossensii种子，大喙个体则能够处理更硬的Scleria verrucosa种子，而超大喙个体则能开壳坚硬的Scleria racemosa种子。"},{"name":"赤红裂籽雀","english_name":"Crimson Seedcracker","scientific_name":"Pyrenestes sanguineus","overview":"赤红裂籽雀（英文名：Crimson Seedcracker，学名：Pyrenestes sanguineus），是雀形目梅花雀科裂籽雀属的鸟类。梅花雀科裂籽雀属的鸟类，主要分布在非洲西部，包括冈比亚至科特迪瓦一带。其显著特征为拥有厚重的喙，全身大部分呈棕色，头部、颈部、胸部及两侧呈现鲜艳的红色，尾羽中央及外侧边缘亦为红色，其余部分为棕色。该鸟种在繁殖季节眼环肿胀明显。","appearance":"成年赤红裂籽雀体型饱满，长度约14至15厘米，体重介于16.9至26.6克之间。雄鸟头部、颈部向下延伸至胸部和两侧均为鲜亮的红色，上覆羽、中央尾羽和侧尾羽边缘红色，其余羽毛棕色，下覆羽为深棕色；雌鸟仅头部、喉咙和从臀部到尾巴有红色，其余羽毛更偏棕黄色。幼鸟色泽较淡，头部和喉咙为棕黄色而非红色，长上覆羽呈赤褐色。","call":"鸣叫特征包括在觅食期间发出柔和空洞的‘tsut…tsut’声，求偶歌声悠长而多变，如‘titi-tsee-chiweeta-toy-ti-tseea’或音调逐渐升高至第四声（最响亮）后渐弱的‘tee-ti-ti-teee, ti, tee’。","habits":"赤红裂籽雀居住在淡水沼泽森林、潮汐溪流附近的灌木丛、稻田旁的灌木丛、被伐林中的池塘以及开阔森林中的湿莎草丛中。它们常在地面或近地面处觅食，主要以莎草和稻谷种子为食，有时会成对或小群体活动，偶尔与蓝嘴雀等物种共同觅食。","breeding":"繁殖期在9月，幼鸟在3月和7月可见。在冈比亚，巢建于6月至8月、10月和11月，9月有离巢的幼鸟。巢呈球状，侧入口，由干蕨叶、死叶或枯芦苇堆砌，内衬软草穗，位于水面或地面以上1至3米，藏于密林藤蔓之下。每窝产卵3至4枚，双亲共同孵卵，孵化期16天。雏鸟皮肤暗黑红色，孵化后24天离巢，离巢后10天独立。","identification":"雄性黑腹裂籽雀与赤红裂籽雀的区别在于前者背部和腹部为黑色而非棕色；雌鸟和幼鸟几乎相同，但在象牙海岸东部有重叠分布。此外，赤红裂籽雀的雄鸟头部红色区域更大，延伸至两侧。","protection":"IUCN：LC（无危）","distribution":"分布于冈比亚、塞内加尔南部、几内亚比绍、几内亚、塞拉利昂、利比里亚和科特迪瓦，主要栖息在非洲西部的淡水沼泽森林、潮汐溪流、稻田附近的灌木丛等环境。","other":"赤红裂籽雀在冈比亚较为罕见，可能受到河岸沼泽森林丧失的影响，而在利比里亚等地，由于适度的伐木和小规模森林损失，该物种似乎受益。"},{"name":"小裂籽雀","english_name":"Lesser Seedcracker","scientific_name":"Pyrenestes minor","overview":"小裂籽雀（英文名：Lesser Seedcracker，学名：Pyrenestes minor），是雀形目梅花雀科裂籽雀属的鸟类。色彩鲜艳、体形圆润的梅花雀科蜡嘴雀，分布于坦桑尼亚南部至津巴布韦东部和莫桑比克中部。在潮湿的生境中栖息，包括山地森林边缘、沿溪地带和偶尔的芦苇床。这种鸟种较为稀少，害羞且不显眼，生活在亚热带或热带的湿润低地林、旱林、季节性湿润草原和河流附近。","appearance":"雄性小裂籽雀头部、背部到后冠部及后耳羽覆至胸上部呈鲜亮的深红色，上体和下胸部至腹部、尾下覆羽呈棕色，上尾覆羽、中央尾羽和侧尾羽边缘为红色，其余尾羽为棕色；翅膀深棕色，翼盖具红褐色边缘；虹膜深红棕色，眼圈颜色从深红到浅灰，仅近距离可见淡白“眼睑”。雌鸟相似，但头部红色区域限于额至眼后方及下巴。幼鸟全身呈淡棕色，头部微带红褐色，上尾覆羽和尾巴有暗红色斑迹，喙黑色。","call":"鸣叫包括清脆的‘tzeet’声和连续爆炸性的‘chat-chat-chat’或‘qap’声，还有柔和的咕噜声和‘chop’声。雄鸟在巢边发出咔嗒声警报。歌曲为柔和的颤音。","habits":"小裂籽雀栖息于山地森林边缘的茂密植被、沿溪的高草丛、村庄附近的次生林、河岸森林边缘、芦苇床和山坡上的蕨类灌木丛，海拔范围从100米至900米（坦桑尼亚）、500米至1700米（马拉维）和高达1800米（津巴布韦东部）。它们主要是居民，但在津巴布韦的Rusitu-Haroni地区可能是部分迁徙，主要在夏季出现。它们以低水平和地面觅食，通常成对活动，主要食物为草籽，包括森林竹状草Olyra latifolia的大硬籽。","breeding":"繁殖季节为1月和5月，在马拉维，12月底和3月开始筑巢；在津巴布韦和沿海莫桑比克为12月至3月，3月至5月。巢为覆盖式的椭圆形结构，有时带有入口隧道，由草条、香蕉叶和芦苇制成，偶尔置于蕨类垫上，外部可能有一层干叶和草，未衬里，放置在1.5至3米或更高的地面或水面之上。每窝产卵3枚；双亲共同孵卵，孵化期为13至15天；雏鸟期为20至23天。","identification":"小裂籽雀与黑腹裂籽雀可能混淆，但两者分布范围并不重叠。","protection":"IUCN：LC（无危）","distribution":"分布于坦桑尼亚中部至津巴布韦东部和莫桑比克中部，包括南部坦桑尼亚（从乌兹翁加瓦山脉和乌卢古鲁山脚起）、马拉维、北部和中部莫桑比克以及津巴布韦东部。"},{"name":"灰颊蓝嘴雀","english_name":"Grant's Bluebill","scientific_name":"Spermophaga poliogenys","overview":"灰颊蓝嘴雀（英文名：Grant's Bluebill，学名：Spermophaga poliogenys），是雀形目梅花雀科蓝嘴雀属的鸟类。分布于刚果、刚果民主共和国东部和乌干达西部的亚热带或热带湿润低地森林中。全球活动范围约354,000平方千米，该物种被IUCN评为无危。其显著特征为大而圆的头部，黑色和红色的森林蜡嘴，拥有蓝色和红色的喙。","appearance":"雄鸟具有红色前额延伸至头顶中部，眼睛周围似黑框眼镜般环绕，而雌鸟腹部有白色斑点，仅喉部和臀部呈红色。幼鸟类似雌鸟，但缺乏斑点和喉部红色。雄性红头蓝嘴雀与灰颊蓝嘴雀相似，但红色延伸到颈背，眼睛似乎有乳白色边缘；雄性黑腹裂籽雀喙为蓝黑色。","call":"其鸣唱为一系列哀伤的下降音符，共7-8个，表现为‘deeeee-deee-deee-deee-dee-doo-dee-doo’。","habits":"灰颊蓝嘴雀是稀有且隐秘的居民，栖息于刚果盆地低地的原始森林和沼泽森林的灌木层，海拔高达1400米。","breeding":"关于灰颊蓝嘴雀的繁殖信息有限，需更多研究以了解其繁殖习性。","identification":"雄鸟个体与红头蓝嘴雀和黑腹裂籽雀在外观上有细微差别，主要通过红色分布范围和眼周颜色辨别。","protection":"IUCN：LC（无危）","distribution":"分布于非洲刚果、刚果民主共和国东部至乌干达西部，具体在极东南喀麦隆（Lobéké）、刚果北部（Nouabalé-Ndoki国家公园）、刚果民主共和国以及乌干达西部（Semliki森林）。"},{"name":"红胸蓝嘴雀","english_name":"Western Bluebill","scientific_name":"Spermophaga haematina","overview":"红胸蓝嘴雀（英文名：Western Bluebill，学名：Spermophaga haematina），是雀形目梅花雀科蓝嘴雀属的鸟类。以及从下巴到胸部的鲜红色羽毛，雌鸟的喙同样为蓝色，但红尖较小，面部颜色为黑色、洗过的红色或深红色。该鸟广泛分布在几内亚、加蓬、科特迪瓦等地，栖息于亚热带或热带的湿润低地林和湿润疏灌丛。","appearance":"雄性红胸蓝嘴雀具有光泽的黑色头部和上部，翅膀和尾巴为黑色，下巴至胸部和侧翼为鲜红色，下胸部、腹部和臀下覆羽为黑色。雌鸟头部前额和面部为暗紫色，上体和翅膀为深褐色，尾上覆羽为红色，尾巴为深褐色或黑色。雌雄均具有灰白色眼环，雄鸟的更为明显且肿胀。幼鸟似雌鸟，但上体覆羽和侧翼为红棕色，下体为烟灰色，胸部侧边带有红色色调。","call":"鸣叫包括高音哨声“psiu”。歌唱包括一系列清晰哨音，音调变化，开始时为连续的点击声，随后是长而纯净的上升和下降音符。","habits":"生活在森林下层、空地边缘、画廊森林、伐木道路、林场种植地以及冈比亚残留的森林灌丛和干燥的沿海棕榈林，通常靠近水源。以浆果、草籽、稻谷、油棕果皮为主食，也会食用昆虫如白蚁和蚜虫以及蜘蛛。使用喙的锋利边缘切割坚硬的食物，通过扭转而非压碎的方式去除壳。","breeding":"繁殖季节在冈比亚为8月至12月，筑巢发生在6月和9月至11月；在尼日利亚为8月至10月；在加蓬，筑巢时间为12月至1月，幼鸟离巢时间为3月至4月。筑巢为大型球状结构，侧入口，由苔藓、蕨类、干叶和草构成，有时衬有草或羽毛，隐藏在1至2米高的浓密灌木中。","identification":"雄性红胸蓝嘴雀的独特特征在于其黑色头部，这是该物种中唯一雄鸟具有这一特征的蓝嘴雀。雌鸟和雄鸟在喙的颜色上有细微差别，以及面部色彩的差异。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部和中部，包括安哥拉、贝宁、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、冈比亚、加纳、几内亚、几内亚比绍、利比里亚、马里、尼日利亚、塞内加尔、塞拉利昂、多哥。","other":"在次生森林中的密度超过每平方公里25对，在砍伐森林中沿路密度更高，成熟森林内部密度仅每平方公里3对。在加蓬东北部非常丰富，每2至3公顷就有1对。"},{"name":"红头蓝嘴雀","english_name":"Red-headed Bluebill","scientific_name":"Spermophaga ruficapilla","overview":"红头蓝嘴雀（英文名：Red-headed Bluebill，学名：Spermophaga ruficapilla），是雀形目梅花雀科蓝嘴雀属的常见鸟类。分布广泛，主要在非洲中部至中东部地区，包括安哥拉、中非共和国、苏丹南部、肯尼亚、坦桑尼亚、刚果民主共和国、布隆迪、卢旺达和乌干达。该鸟种活动范围广阔，约覆盖563,000平方千米，体重平均为22.1克，被评估为无危状态。","appearance":"红头蓝嘴雀拥有醒目的外观，最显著的特征是其硕大且锥形的蓝色喙部，头部全为红色。雄鸟腹部呈黑色，而雌鸟腹部则带有斑点。两者均展现着独特的红头蓝喙的色彩组合。","call":"该鸟的鸣叫包括轻微的‘schpit’声和罕见听到的哨声歌曲。","habits":"红头蓝嘴雀偏好生活在雨林、林带森林、灌木丛以及次生环境中，通常以成对或小群体的方式活动于茂密的下层植被中，偶尔也会出现在道路和路径上。","breeding":"关于红头蓝嘴雀的繁殖行为和生长周期的具体信息尚未详细记录。","identification":"红头蓝嘴雀与灰颊蓝嘴雀的区别在于其全红的头部。雄鸟个体与黑腹裂籽雀的雄鸟相似，但可通过黑色尾巴和红蓝相间的喙部而非纯蓝色喙部来区分。","protection":"IUCN：LC（无危）","distribution":"红头蓝嘴雀主要分布在非洲的中部和中东部，包括但不限于安哥拉、中非共和国、苏丹南部、肯尼亚、坦桑尼亚、刚果民主共和国、布隆迪、卢旺达和乌干达。","other":"系统学历史和其他重要信息未详述。"},{"name":"褐双点雀","english_name":"Brown Twinspot","scientific_name":"Clytospiza monteiri","overview":"褐双点雀（英文名：Brown Twinspot，学名：Clytospiza monteiri），是雀形目梅花雀科褐双点雀属的鸟类。非洲次撒哈拉地区常见的小型鸣禽。该物种以其独特的灰色头罩、红色臀部和带有白色双斑点的红褐色胸腹而著称。分布于尼日利亚东南部、喀麦隆、南苏丹南部、肯尼亚西部、加蓬、安哥拉、刚果民主共和国中部以及乌干达等地。","appearance":"褐双点雀拥有鲜明的外观特征，雄鸟具有红色中央喉纹，而雌鸟则呈白色。它们的背部呈棕色，腹部和胸部覆盖着独特的白色双斑点，这一特征在同属鸟类中极为罕见。体型小巧，平均体重约14.9克。","call":"褐双点雀的叫声是一声尖锐的‘veet’，其歌声则是一种多变的、高音的啾啾声。","habits":"褐双点雀栖息于植被茂密的地带，包括湿润的灌木丛、过度生长的农田和森林边缘。它们通常成对或小群体活动，偏好在亚热带或热带的湿润疏灌丛、干燥的稀树草原和耕地上生存。","identification":"与朱背双斑雀相似，但可通过棕色背部和胸部的双斑点来区分。此外，雄鸟的红色喉纹也是辨识的重要特征。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的尼日利亚东南部和喀麦隆至南苏丹南部和肯尼亚西部，以及从加蓬延伸到安哥拉西部和刚果民主共和国中部的地区。","other":"褐双点雀是其属中的唯一成员，与火雀属（Lagonosticta）的火雀关系密切。"},{"name":"玫胸斑雀","english_name":"Pink-throated Twinspot","scientific_name":"Hypargos margaritatus","overview":"玫胸斑雀（英文名：Pink-throated Twinspot，学名：Hypargos margaritatus），是雀形目梅花雀科斑雀属的小型鸟类。食用种子。以粉色喉咙和圆润的体型为显著特征，分布于非洲东南部的莫桑比克南部、南非东北部及斯威士兰。全球活动范围约160,000平方千米。","appearance":"雄性玫胸斑雀头部至背部呈棕色，臀部和上尾覆羽呈暗淡的粉红，尾巴深棕色带粉色边缘，翅膀棕色；脸部、颈部两侧至胸部上方为粉红色，下胸至尾下覆羽黑色，两侧胸部和腹部带有大块的粉白色斑点。雌鸟颜色较灰，下腹部和尾下覆羽呈浅灰色，两侧胸部和腹部黑色带粉白色大斑点。虹膜深褐色，眼环淡粉色蓝，喙蓝灰色，腿灰色。幼鸟全身下部灰白，喙黑色。","call":"近距交流声为柔和上升的“seesee”或“sisi”；远距离叫声或警报声为短促的“zirr”或“rrrrreeee”或长而高的“tseeeerrr”。鸣唱为颤音结尾带嗡嗡声的乐句。","habits":"栖息于干燥的灌木林和密林，沙质森林，棕榈灌丛，河流森林边缘的荆棘覆盖，以及密集的荆棘灌丛。通常成对或小家庭群活动，偶尔与其他蜡嘴雀混群。主要在地面觅食，以小草籽和昆虫为食。居民种类，不迁徙。","breeding":"在南非夸祖鲁-纳塔尔省，繁殖期为1月。巢穴为侧入口的卵形结构，由叶脉、叶片、花朵和蜘蛛网构成，内部铺有植物纤维或羽毛，隐藏于接近地面的浓密植被和落叶层中。每窝产3-5枚蛋，孵化期12-14天；雏鸟皮肤粉红，头部有灰色绒毛，喙部有白色乳头状突起，口内部分几天后变为蓝绿色，出飞后转蓝；出飞期20-21天。在南非可能遭受双斑维达雀的寄生。","identification":"与相似的朱胸斑雀的区别在于，后者雄鸟喉部为酒红色，雌鸟喉部为橙粉色，且两者的冠部均为灰色而非棕色。","protection":"IUCN：LC（无危）。在南非因范围小被列为近危。在莫桑比克估计数量超过80,000只，每年多达2000只被出口用于笼鸟贸易。","distribution":"分布于莫桑比克南部（R Save以南）、南非东北部（东林波波至北夸祖鲁-纳塔尔）和斯威士兰东部。","other":"在南非的大型保护区中常见。"},{"name":"朱胸斑雀","english_name":"Red-throated Twinspot","scientific_name":"Hypargos niveoguttatus","overview":"朱胸斑雀（英文名：Red-throated Twinspot，学名：Hypargos niveoguttatus），是雀形目梅花雀科斑雀属的鸟类。广泛分布于撒哈拉沙漠以南非洲的常见鸟类，全球分布面积估计约为2,000,000平方公里，可见于安哥拉、布隆迪、刚果民主共和国、肯尼亚、马拉维、莫桑比克、纳米比亚、卢旺达、索马里、南非、坦桑尼亚、赞比亚和津巴布韦。","appearance":"这是一种体型较小、结实的暗色蜡嘴雀，最显著的特点是黑色腹部上的两枚明亮的白色“双点”。雄鸟头部呈现红色，冠部为灰色，而雌鸟胸部橙色，头部呈棕色。","call":"其独特的叫声为短促高音的颤鸣，极少听到的歌声则由多种不同的叫声类型复杂混合而成。","habits":"朱胸斑雀偏好茂密的生境，包括森林边缘、开阔地和灌木丛，性格较为害羞，不易察觉。它们在东部和东南部非洲的热带区域活跃。","identification":"与粉喉斑雀相似，但可通过雄鸟的灰色冠部和雌鸟的橙色胸部加以区分。","protection":"IUCN：LC（无危）","distribution":"朱胸斑雀主要分布于撒哈拉沙漠以南的非洲东部和东南部，包括但不限于安哥拉、布隆迪、刚果民主共和国、肯尼亚、马拉维、莫桑比克、纳米比亚、卢旺达、索马里、南非、坦桑尼亚、赞比亚和津巴布韦。"},{"name":"朱背双斑雀","english_name":"Dybowski's Twinspot","scientific_name":"Euschistospiza dybowskii","overview":"朱背双斑雀（英文名：Dybowski's Twinspot，学名：Euschistospiza dybowskii），是雀形目梅花雀科双斑雀属的鸟类。分布于非洲几内亚至科特迪瓦，尼日利亚中部至乌干达西部。以独特的暗色外观和腹部醒目的白色‘双斑’而著称，全球活动范围约450,000平方千米，纪念法国植物学家Jean Dybowski的名字。朱背双斑雀的保护状态被评估为无危。","appearance":"雄性朱背双斑雀头部至颈部呈深灰色，上体包括臀部和尾羽覆片为鲜亮的红色，尾羽为黑褐色边缘带灰红，翅膀为棕黑色，下胸至尾下覆羽黑色，两胁带有白色斑点。虹膜深褐至红棕色，眼圈粉红。雌鸟颜色较淡，下体更灰，腹面和两胁灰色，尾下覆羽烟灰色。幼鸟上体暗褐灰色，臀部和尾羽覆片红灰色。","call":"发出清脆的‘kek’声作为近距离接触的叫声，远距离时发出金属质感的‘tsit’音，兴奋或警戒时会连串高声鸣叫。其歌声为一系列响亮、丰富的气泡般颤音、嘟噜声和哨音，含有一些长笛般的音符。","habits":"栖息于林地中的草地、花岗岩山脚的灌木丛、杂草丛生的耕地和草质的高原。常以小群或成对出现，觅食小型草籽和昆虫，常在地面觅食，尤其在收获季节的‘饥饿稻’（Digitaria exilis）农田中，以及厕所和垃圾堆周围的年度草丛中。","breeding":"在塞拉利昂的9月、喀麦隆的3月，刚果东部的9月至10月以及苏丹的10月繁殖。雄鸟在地面或枝头展示求偶行为，嘴中叼着茎或羽毛，跳跃并向上抬着头，上下跳动，有时左右摆动头部，同时歌唱。巢由干燥的草和植物纤维松散构建，内衬羽毛，位于地面或高达3米的蕨类植物或灌木中，通常产4至6枚蛋，孵化期13至14天，雏鸟期18至20天，双亲共同喂养，31天后独立。","identification":"最相似于褐双点雀，但可以通过其红色背部和仅限于腹部的双斑进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于塞内加尔东南部、几内亚比绍东部、马里南部、几内亚、塞拉利昂、科特迪瓦西部、尼日利亚中部与东部、喀麦隆北部、中非共和国、刚果民主共和国东北部、南苏丹南部和乌干达西北部。"},{"name":"乌双斑雀","english_name":"Dusky Twinspot","scientific_name":"Euschistospiza cinereovinacea","overview":"乌双斑雀（英文名：Dusky Twinspot，学名：Euschistospiza cinereovinacea），是雀形目梅花雀科双斑雀属的小型鸟类，分布于安哥拉、布隆迪、乌干达、卢旺达和刚果民主共和国。其独特的小而淡的腹部‘双斑’和飞行中显眼的红色臀部使其在同类中脱颖而出。全球活动范围约133,000平方千米，保护状态被评为无危。","appearance":"乌双斑雀体长约11.5厘米，体重9至14克。成年雄鸟的头部至背部呈暗灰色，臀部和上尾覆羽鲜红，尾巴黑褐色，翅膀灰褐；腹部和下尾覆羽黑色，胸腹两侧及腹部有细小的双白点；眼睛深棕色或红褐色，眼圈粉色、灰色或浅蓝色；喙及腿黑色。雌鸟与雄鸟相似，但颈背较淡，下体更黑。幼鸟上体呈灰褐色，下臀和上尾覆羽灰红，喉咙和下体灰褐，两胁带红色但无白色斑点，眼圈灰白，虹膜棕色。","call":"发出近距联系声“tsyip-tsyip”，远距联系声和警报声“tsvilip”。求偶期间的鸣唱由一系列较为平淡的音符组成。","habits":"栖息于茂密的草丛和灌木丛中，如安哥拉的miombo（Brachystegia）林地、山地森林边缘的长草地带、河流边的森林、草地山沟以及溪流旁的高草丛中。在刚果民主共和国的Itombwe地区，栖息高度为1300至2000米；在乌干达的Kigezi，高度为1800至2300米。以草籽和小昆虫为食，通常在地面觅食，成对或单独活动。","breeding":"繁殖季节在安哥拉为7月至8月。求偶时，雄鸟会衔着茎或羽毛在嘴中，于地面展示，围绕雌鸟跳跃，尾羽展开接触地面并歌唱。在圈养环境中，巢为侧面入口的球状，由枝条和芦苇制成。一窝产3枚卵；孵化期13天；雏鸟口裂缘有两个大白色肿块，基部淡蓝，嘴内黑色，角落有黄色垫片，位于白色肿块之间，软腭有五个黑点；育雏期21天。","identification":"与暗腹朱翅雀大小和总体颜色相似，但乌双斑雀两侧和腹部有红色，面部无红色。亚种graueri比指名亚种下方更暗。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲中部，包括安哥拉、布隆迪、乌干达、卢旺达和刚果民主共和国。在安哥拉，从Cuanza Sul和S Malanje S至Huíla较为常见；在刚果民主共和国少见；在乌干达稀缺，卢旺达和布隆迪则为不常见。","other":"在安哥拉高地发现了一种模仿乌双斑雀的暗紫维达雀种群。"},{"name":"黑腹火雀","english_name":"Black-bellied Firefinch","scientific_name":"Lagonosticta rara","overview":"黑腹火雀（英文名：Black-bellied Firefinch，学名：Lagonosticta rara），是雀形目梅花雀科火雀属的鸟类。常见的梅花雀科火雀属鸟类，广泛分布于非洲西部、中部和东部，其活动范围广阔，覆盖了约2,300,000平方千米。","appearance":"雄性黑腹火雀主要呈现粉红色至红色，而雌鸟则拥有棕色背部，灰色头部，及淡粉色腹部。两性共有的特征包括深色喙，喙基部呈粉色，显著的黑色腹部，以及缺乏白色斑点的下体。这些特征在视觉上构成了该物种的独特标识。","call":"黑腹火雀的鸣唱由一系列低沉的哨声组成，叫声则包括‘chet’音符和短促的颤音，这些声音特征有助于野外辨识。","habits":"黑腹火雀栖息于森林边缘、茂密的灌木丛、丰茂的草原和灌木地带。它们通常以成对或小群体的形式活动，有时会与其他蜡嘴雀混群。黑腹火雀的生存环境多样，包括过耕的农田和丛林边缘。","breeding":"关于黑腹火雀的繁殖习性的具体信息未在现有资料中详述，但基于同类物种的行为模式，可推测它们可能在特定季节进行繁殖，筑巢、交配、产卵并孵化。","identification":"黑腹火雀与其他火雀属物种的区别在于其下体缺乏白色斑点，雄鸟更可通过全红头部进一步区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的多个区域，包括贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果民主共和国、科特迪瓦、加纳、几内亚、肯尼亚、利比里亚、尼日利亚、塞内加尔、塞拉利昂、南苏丹、多哥和乌干达。"},{"name":"斑胸火雀","english_name":"Bar-breasted Firefinch","scientific_name":"Lagonosticta rufopicta","overview":"斑胸火雀（英文名：Bar-breasted Firefinch，学名：Lagonosticta rufopicta），是雀形目梅花雀科火雀属的小型鸟类，常见于中非，拥有2,900,000平方千米的全球活动范围。以头部和胸部的红色及胸部特有的白色条纹为显著特征。","appearance":"斑胸火雀体长约11厘米，上体呈哑光棕色，下体为红色，喙部亦为红色，尾巴下方有淡色而非黑色的斑纹。头部、背部呈灰褐色，与深红色的臀部和尾羽上覆羽形成对比。尾羽较背部更深的棕色，靠近基部有不同程度的红色。下体除鲜红的胸部外，其余部分为黄灰色。雌雄相似，但幼鸟色泽较为暗淡，红色仅限于臀部和尾羽上覆羽。","call":"常见的叫声为低沉的“chip”声，而其歌声则是快速的颤音鸣唱。","habits":"斑胸火雀广泛栖息于各种开阔地带，包括阔叶林地、灌木丛、草原、农田和灌木丛，通常成对或小群活动。它偏好在草地、灌木、金合欢树草原和森林空地，也会出现在居住区附近和潮湿的农田中。在非繁殖季节，会形成较大的群体，并加入混合种类的鸟群。主要以地面的小种子为食，尤其是草籽和小米。","breeding":"相关信息未提供。","identification":"斑胸火雀与红嘴火雀的区别在于头部较深的棕色标记和胸部两侧的条纹。此外，与其他火雀的不同之处在于其尾巴下方的颜色为淡色而非黑色。","protection":"IUCN：LC（无危）","distribution":"斑胸火雀分布在非洲西部至中部，具体国家包括贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果民主共和国、科特迪瓦、埃塞俄比亚、冈比亚、加纳、几内亚、几内亚比绍、肯尼亚、利比里亚、马里、尼日尔、尼日利亚、卢旺达、塞内加尔、塞拉利昂、苏丹、坦桑尼亚、多哥和乌干达。","other":"斑胸火雀与棕火雀（Lagnosticta nitidula）构成超种概念，曾被认为可能是同一物种。目前认可两个亚种。"},{"name":"褐背火雀","english_name":"Brown Firefinch","scientific_name":"Lagonosticta nitidula","overview":"褐背火雀（英文名：Brown Firefinch，学名：Lagonosticta nitidula），是雀形目梅花雀科火雀属的鸟类。广泛分布于南部非洲，包括安哥拉、刚果民主共和国、坦桑尼亚、纳米比亚、博茨瓦纳和津巴布韦。全球活动范围约1,300,000平方千米，被IUCN评为无危物种。","appearance":"成年褐背火雀体长约9至10厘米，体重约10至11克。雄鸟上体呈棕至灰棕色，头部、颈背、臀部和尾羽上覆羽较灰色，飞羽深棕色，尾羽深灰至黑色，眉纹、眼周及面侧呈紫红至绯红色，下颏和喉部紫红色，上胸部分紫红至绯红，点缀以小白点或条纹，腹部灰至淡灰黄色，尾下覆羽淡灰黄色；虹膜暗褐至红褐色，眼圈淡蓝；喙紫红色，上下缘黑色；腿色酒红或棕灰色。雌鸟外观与雄鸟相似，但眼圈蓝灰，羽色通常略淡。幼鸟头、上体及喉至胸部深灰，腹部暖灰棕色，喙黑色，带有小白角质突起，眼圈灰色，虹膜深褐，腿黑至深灰；成鸟喙色约在离巢10至11周后成熟。","call":"褐背火雀的鸣叫包括类似斑胸火雀的多种叫声，接触叫声为1至2个短促的'kewp'音节；受惊或被打扰时发出急促的叽喳声，每秒12至18个音节，'trrrittit trrittrit'（这种声音未在斑胸火雀中听到）。其歌声是一系列高音金属质感的音符和低音鼻音，常以下降的哨音结尾，与斑胸火雀的歌曲相同。","habits":"褐背火雀主要以小草籽为食，也会捕食小型昆虫。它们在地上觅食，偏好潮湿的土地，用喙散播表面的食物。通常成对或小群活动，经常与其它种子食性的物种混群。","identification":"褐背火雀是所有火雀中颜色最暗淡的，是唯一没有红色或粉红色臀部的种类。雄鸟的脸部有大面积的红色斑块，而雌鸟仅有一点红色。与斑胸火雀相比，它们的鸣叫和歌声有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，具体包括安哥拉、刚果民主共和国中部和坦桑尼亚西南部至纳米比亚东北部，博茨瓦纳北部和津巴布韦西北部。"},{"name":"红嘴火雀","english_name":"Red-billed Firefinch","scientific_name":"Lagonosticta senegala","overview":"红嘴火雀（英文名：Red-billed Firefinch，学名：Lagonosticta senegala），是雀形目梅花雀科火雀属的鸟类。主要分布在撒哈拉以南非洲，覆盖广泛区域，包括西部、中东部、东部和南部非洲。全球活动范围约为10,000,000平方公里。该物种曾被引入埃及，但已在那里绝灭。","appearance":"红嘴火雀体长约10厘米，重7至12克。雄鸟成鸟头部至胸部呈鲜红色，冠部和颈背带褐色，侧胸有小白色斑点；上体呈红染的褐色，臀部和尾上覆羽红色，尾羽黑色，边缘红色；翅覆羽具变化的红色边缘，飞羽褐色；腹部淡褐色，下尾覆羽淡灰到灰褐色，有时有淡色边缘；虹膜深棕色，眼圈黄色（非繁殖季节绿色）；喙浅红色或粉色，上下缘和内切割缘黑色；腿灰棕色。雌鸟上体褐色，面颊亮红，脸颊淡棕色至淡粉色，喉部灰白，下体淡灰褐色，侧胸和胁有细小白色斑点。幼鸟似雌鸟，但面颊灰色，下体无斑点，喙黑色，眼圈灰色，腿粉灰。","call":"发出旋律般的“swee-tee-eeer”歌声和喷吐似的“prrrrrt”叫声。接触叫声为长笛般的哨声“pea”，常升高音调；警报叫声尖锐“chick”；巢穴叫声为连续的“wiswiswis”，吸引配偶入巢；乞食叫声为不规则交替的“wis”和“we”音符，前者发展成警报叫声，后者变成接触叫声。歌唱为尖锐叫声后跟哨声的接触叫声，哨声重复或音调和长度变化。","habits":"栖息于开阔的草木林地，伴生有金合欢（Acacia）荆棘丛，近开阔地的灌木丛，次生植被和靠近垃圾堆的区域，环绕农耕区和城镇乡村；低地，局部到高地1000至2200米。成对或小群活动，常与其他梅花雀科鸟类混群。以小草籽（直径1至2毫米）为主食，如一年生的Echinochloa和Setaria草籽，以及埃塞俄比亚种植的tef（Eragrostis tef），同时食用玉米（Zea mays）和木薯（Manihot）等农作物。在地面觅食，常在露天厕所区的裸露地面吃草籽。","breeding":"繁殖季节为7月至4月（主要10月至12月）在塞内加尔，全年除干季高峰（主要5月至10月）在尼日利亚，3月至4月和9月至12月在埃塞俄比亚；肯尼亚全年（主要3月至6月雨季），赞比亚1月至9月（主要1月至4月），马拉维全年（主要3月至5月），津巴布韦峰值12月至3月，南非北部（前德兰士瓦）12月至4月，东部（夸祖鲁-纳塔尔）1月至3月。繁殖对通常分散；有时数对在草屋顶。雄鸟持羽毛向雌鸟展示，飞翔时翅膀发出响声，站立竖直，头向后仰，羽毛挥动，向上跳跃，最后深鞠躬。巢为松散的草球，侧入口，置于灌木或树上，茅草屋顶或地面。每窝3至5枚蛋；孵化期自最后一枚蛋起11至12天；雏鸟皮肤出生时粉红，灰色绒毛，喙缝有两对白色乳突，由一条窄蓝色带隔开（至离巢时转黑），腭黄色，通常三点（有时五点），喉部粉红，舌黄色无斑，下口线粉红，末端黑色，标记在较老雏鸟中横跨，后部形成舌下新月（成年黑色腭点扩大并在成鸟中融合成黑色口线）；离巢期18至19天；离巢后双亲再喂养10天。巢被靛蓝维达雀寄生，其成年雄鸟模仿宿主歌声和叫声，幼鸟模仿宿主雏鸟口腔颜色和模式。最早繁殖年龄为4个月。","identification":"与褐背火雀的区别在于后者具有褐色臀部。与斑胸火雀相似，但后者冠部褐色（而非红色）。","protection":"IUCN：LC（无危）","distribution":"主要分布在撒哈拉以南非洲，包括西部、中东部、东部和南部。具体国家和地区包括塞内加尔、尼日利亚、赞比亚、埃塞俄比亚、肯尼亚、马拉维、津巴布韦和南非等地。曾在埃及引入，现已绝灭。"},{"name":"岩火雀","english_name":"Rock Firefinch","scientific_name":"Lagonosticta sanguinodorsalis","overview":"岩火雀（英文名：Rock Firefinch，学名：Lagonosticta sanguinodorsalis），是雀形目梅花雀科火雀属的小型鸟类。分布于尼日利亚的乔斯高原及邻近的喀麦隆西北部。雄鸟拥有鲜艳的红色背部和脸部，雌鸟则呈现较淡的红褐色背部。该物种于1998年被发现，全球活动范围约为29,000平方千米。岩火雀的保护状态目前被评估为无危。","appearance":"岩火雀性别二型性明显，雄鸟具有明亮的红色背部和深红色的脸部、喉咙、胸部及腹部，而雌鸟则展现红褐色背部、灰褐色脸部及灰红色的喉咙、胸部和腹部。其共同特征包括蓝灰色的喙，棕色的上翼覆羽，深红色的臀部和上尾覆羽，以及带有白色斑点的暗灰色侧腹和下翼覆羽。翅膀呈暗红褐色，尾巴为黑色，边缘带红色。幼鸟相比成鸟颜色更淡，头部和冠部呈灰褐色，全身羽毛颜色较为暗淡。","call":"岩火雀的叫声包括柔和的“teew”哨音，下降的颤音，“tep”音符，以及“pit-pit-pit”的叫声。","habits":"岩火雀偏好在灌木草原中的孤山和岩石地带筑巢，它们对栖息地有高度的忠诚度，通常全年返回同一地区。在旱季，它们会前往画廊森林获取水源，因此此时的家园范围较大。岩火雀以种子为主食，倾向于成对觅食于植被较多、地面裸露较少的地方。","breeding":"岩火雀为一夫一妻制，终生保持伴侣关系。繁殖季节开始于雨季末期，平均每次产卵3枚。巢穴遭受掠食者的袭击率约为50%，若首次繁殖失败，它们会尝试第二次繁殖。雌雄双方共同参与孵化，而夜间仅由雌鸟照料巢穴，因为只有雌鸟具有帮助保温的孵卵斑。孵化期平均为14天，雏鸟在孵化几天后离巢。","identification":"岩火雀与灰顶火雀相似，但喙色更为双色，整体色彩更鲜亮，两性背部均呈更红色调。与黑腹火雀的区别在于腹下部黑色覆盖面积较小，雄鸟的头部顶部有灰色斑块。岩火雀的初级飞羽较宽，尖端并不狭窄。","protection":"IUCN：LC（无危）","distribution":"岩火雀主要分布于尼日利亚北部的乔斯高原，以及喀麦隆西北部，包括乔斯高原、卡戈罗、潘尚乌、曼达拉山等地。","other":"岩火雀面临来自人类活动的威胁，如森林砍伐和农田扩张，这导致其栖息地破坏和碎片化。"},{"name":"赖氏火雀","english_name":"Chad Firefinch","scientific_name":"Lagonosticta umbrinodorsalis","overview":"赖氏火雀（英文名：Chad Firefinch，学名：Lagonosticta umbrinodorsalis），是雀形目梅花雀科火雀属的小型鸟类，体长约10至11厘米，分布于中部非洲的狭小区域内，主要见于乍得西南部和喀麦隆北部。曾一度被认为是红腹火雀的亚种，现广泛认同其为独立物种，以纪念德国鸟类学家安东·赖兴诺。","appearance":"雄鸟主要为亮丽的粉红色，上体颜色较深，头部顶部和颈部为灰色，腹部下方为黑色。雌鸟与雄鸟相似，但色彩略显暗淡，整体偏棕黄色。幼鸟上体棕色，下体米黄色，臀部具有鲜艳的粉红色。喙部粗壮，呈圆锥形，颜色为灰色，腿和脚亦为灰色。","call":"赖氏火雀的叫声包括柔和的‘teew’哨音、‘tep’音符以及连串的‘pit-pit-pit’叫声。其鸣唱由一系列相同音调的哨音组成。","habits":"栖息于干燥、岩石较多的环境，常伴有草丛和灌木。通常成对或小群活动，偏好在干旱草原地带，高草覆盖的岩石斜坡。它们在地面觅食，以种子为主食。","breeding":"繁殖行为发生在雨季，赖氏火雀会成对地在地面上寻找食物。","identification":"与红腹火雀相比，赖氏火雀的头部顶部和颈部为灰色，而后者缺乏这一特征。与岩火雀的区别在于，后者仅在头部顶部有灰色，且下颌基部有淡灰色斑块。","protection":"IUCN：LC（无危）","distribution":"赖氏火雀分布于非洲的东苏丹草原生态区，主要集中在乍得西南部和喀麦隆北部。"},{"name":"马里火雀","english_name":"Mali Firefinch","scientific_name":"Lagonosticta virata","overview":"马里火雀（英文名：Mali Firefinch，学名：Lagonosticta virata），是雀形目梅花雀科火雀属的鸟类。这种小型火雀以红褐色为主色调，头部上方呈灰棕色，背部和翅膀上覆羽为灰褐色，臀部和尾羽上方为红色，尾巴黑色，尾羽边缘红色。主要分布于西非的塞内加尔东部和马里南部的干燥岩石地带，常被视作马里的象征。","appearance":"成年马里火雀长约10-11厘米，体重约8.5-10.9克。雄鸟具有灰棕色的冠羽，背部灰褐色，臀部和尾羽上方红色，尾羽黑色，边缘红色。翅膀灰褐色，初级飞羽宽大。面部和下颌至腹部深粉红色，胸部两侧和上腹有小圆斑点，腹部中央灰色，下腹部和尾下覆羽黑色。雌鸟类似，但颜色略淡，下腹部和尾下覆羽为烟灰色。幼鸟冠羽至背部和翅膀覆羽灰褐色，臀部和尾羽上方红色，尾巴黑色，边缘红色，耳羽和下侧浅灰棕色。","call":"马里火雀的叫声包括短促的干涩颤音、高音的“veet”声和较长、低音的“feeeu”声。其安静的鸣唱由低音颤音与高音哀鸣和哨声混合而成。","habits":"生活在干燥的岩石山坡、草地和灌木丛中，通常成对或小群活动。主要以地面的小型草籽为食，有时在小群体中觅食。","breeding":"繁殖期记录在7月至12月间。筑巢为接近地面的灌木或蕨类植物中的草制空心球状巢，带有大的侧面入口。每窝产3-4枚卵，孵化期大约11-13天。雏鸟皮肤暗灰色至紫黑色，绒毛淡灰色，喙角灰粉色，带有蓝白小乳突。雏鸟期19天，孵化后32天即可独立。","identification":"与灰顶火雀极为相似，但整体较暗淡，前额更多红色，肩部白色斑点较少。与红嘴火雀和斑胸火雀的区别在于尾巴下方的黑色。","protection":"IUCN：LC（无危）","distribution":"分布于塞内加尔东部和马里南部，主要集中在上尼日尔河谷次级区域。"},{"name":"灰顶火雀","english_name":"African Firefinch","scientific_name":"Lagonosticta rubricata","overview":"灰顶火雀（英文名：African Firefinch，学名：Lagonosticta rubricata），是雀形目梅花雀科火雀属的鸟类。直译: 非洲火雀，广泛分布于非洲各地的鸟类。其分布区域覆盖了非洲的西部、中部、东南部和南部，全球分布面积估计达到540万平方公里。这种鸟以它独特的蓝灰色喙和尾巴下方的黑色标记而闻名。","appearance":"成年雄性灰顶火雀身长10至11厘米，体重约8.6至11.7克。头部的冠部和颈部呈铅灰色，背部橄榄棕色，翼覆羽亦如此，有时带有灰色调。臀部、上尾覆羽和外侧尾羽为深红色，其余尾羽黑色，基部有红色边缘。下体从颏到腹部为深红色，胸侧和胁部有小白斑点，腹中部灰黑，肛周及下尾羽黑色。喙短尖，黑色带灰，下颌基部粉红。雌鸟色彩较淡，幼鸟缺乏红色下体。五种亚种在羽色上有细微差异。","call":"鸣叫包括上升的颤音\"trrrrrrrr-t\"和响亮清脆的\"tui-tui-tui-tui\"，通常后跟\"wink-wink-wink\"，报警声为类似欧亚鹪鹩的尖锐敲击声。歌曲由随机重复的各种清脆音符组成，穿插着吱吱哨声、颤音和鸣叫。","habits":"灰顶火雀偏好湿润、植被茂密的生境，如森林边缘的蕨类植物、含金合欢树的灌木丛、草丛下的荆棘，以及河流边的浓密植被。常见于近道路或小径的安静地带，也能在花园和乡村附近发现。它们主要以种子为食，辅以昆虫，通常在地上觅食，通过翻找土壤寻找食物。","breeding":"繁殖期在南部非洲为11月至翌年6月，高峰在1月至4月，北部地区则较晚。雄鸟筑巢，呈圆筒状，侧面入口，由干枯的长草茎构成，内衬柔软的草穗或羽毛。巢藏于高草丛、蕨类植物或树桩旁的草丛中。每窝产2至5枚卵，双亲共同孵卵约12天。雏鸟由双方喂养2至3周直至离巢，之后再被喂养10天，此时完全独立。暗蓝靛鸲是其寄生者。","identification":"灰顶火雀与红嘴火雀、条胸火雀的区别在于其尾巴下方的黑色标记。某些亚种可能与詹姆斯火雀极为相似，但总体上颜色更深，更少粉红。亚种间在羽色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部、中部、东南部和南部，从塞内加尔向东至埃塞俄比亚，然后向南至刚果民主共和国南部和坦桑尼亚，经莫桑比克至南非东开普省。","other":"灰顶火雀有五个亚种，其中L. r. landanae亚种因喙色不同而有时被视为独立物种。"},{"name":"淡嘴火雀","english_name":"Landana Firefinch","scientific_name":"Lagonosticta landanae","overview":"淡嘴火雀（英文名：Landana Firefinch，学名：Lagonosticta landanae），是雀形目梅花雀科火雀属的小型鸟类，常见于非洲中部，分布区域广泛，从塞内加尔至埃塞俄比亚，南至南非的东开普省。该鸟以独特的蓝色灰喙和鲜艳的红色羽毛著称，雌雄颜色有所不同，雄鸟更为鲜亮。其全球活动范围约为100,000平方千米，主要分布在安哥拉、刚果共和国、刚果民主共和国等地。","appearance":"淡嘴火雀体长10-11厘米，体重8.6-11.7克。雄鸟头部灰色，颈侧至背部棕色，臀部和尾上覆羽鲜红，尾羽基部红色，其余黑色，翼羽深棕色。面部、喉部、胸部和上腹部鲜红，两胁红色带白色斑点，腹部中央灰黑色，下尾覆羽黑色；虹膜褐色，眼圈粉红；喙蓝灰色，下颌基部粉色；腿灰色。雌鸟色彩较暗淡，偏棕粉色，腹侧常无或仅有少量斑点。幼鸟类似雌鸟，但更偏黄褐色，腹部和下尾覆羽深锈色，无斑点，外侧初级飞羽宽，喙黑至蓝灰色，眼圈灰至粉红色，虹膜深褐色。","call":"发出哀怨的吹哨声“feeeeeee”，近距离无方向展示时，两性会发出柔和的挤压声“whit”；警报声为快速连续的“pitpitpitpit”，每秒10-20声，有时延长为干燥的咔哒声或爆炸性的叽叽声；受惊时发出单个“pit”。雄鸟的歌声包括各种清澈的颤音，速度和音调各异：细而快的“srrrrrrrrrr”，纯净的“hee-hee-hee-hee-hee-hee”哨音，略带嗡嗡声的“zee-zee-zee-zee...”，中音的颤音更加悦耳，如“hee-wee-wee-wee-wee...”，一系列短促的“too-too-too”哨音，或略微刺耳的“chew-chew-chew”，或类似咔哒的“chichichichichichi”。歌曲可能包含高音甜美的哨音，音调起伏不定。","habits":"栖息于茂密的植被中，如高草丛、灌木丛、河流森林边缘、常绿和落叶森林边缘、山地蕨类植物、丘陵林地、被忽视的耕作区。海拔高度从苏丹的低地到2400米，埃塞俄比亚的1230-2500米；肯尼亚高地主要是1500-2000米，年降水量超过500毫米；赞比亚和马拉维的Nyika高原、津巴布韦东部的悬崖地带以及南非的沿海和悬崖地带，湿度较高的低地到2200米和2500米。居民种，可能在苏丹有海拔迁移。","breeding":"繁殖记录显示在加纳沿海地区为6-7月；尼日利亚北部7月，东部8-10月；喀麦隆10-11月；乌干达7-9月，肯尼亚3-7月，坦桑尼亚阿鲁沙1月，伊林加和米库米国家公园6-7月；刚果南部2-5月，赞比亚1-5月，马拉维11-5月，津巴布韦和南非11-4月。求偶时，雄鸟口中衔着大羽毛或草茎，飞向栖息处，采取直立姿势，向上伸展，腹部羽毛微膨，头部和颈部羽毛光滑，尾巴稍微朝向雌鸟倾斜，后仰头部，指向雌鸟，突然向上跳跃，上下弹跳；重复展示，呼叫和歌唱，然后向雌鸟鞠躬；当一对在地面时，雄鸟展开尾巴，围绕雌鸟转圈；求偶展示结束时，它丢弃羽毛，向她移动，她蹲下并颤抖尾巴，两者交配。巢是一个松散构造的球状物，侧面有入口孔（通常被叶子或枯草覆盖），由草茎和叶子制成，经常使用棕色和腐烂的材料，内部衬有细小的种子草或羽毛，位于灌木或灌木的叉中，靠近地面在刷子堆中，剑草的丛中，树基部的碎片下，弯曲的干茎或玉米田中的叶子下，或在低矮的草本植物中，被高草遮蔽或暴露在荆棘灌木或稀疏叶化的灌木中。一窝产3-6枚卵；孵化期12-14天；雏鸟皮肤黑色至灰黑色，腹部紫黑色，绒毛浅灰色，喙部有一对圆形白色乳头，底部蓝色，一个在嘴角上方，一个在下方，乳头间的肿胀呈淡紫色，颚部淡黄色，带有五个黑色斑点形成环状，中间两个斑点较小，舌头粉红色带黑色条纹，下嘴淡粉色带黑色新月形；巢中时期21天。在南非和东非，混合的雏鸟和模仿的歌声表明巢穴受到暗紫维达雀的寄生；在西非，根据歌声模仿，受到喀麦隆维达雀的寄生。","identification":"与同属其他种类相比，淡嘴火雀的喙色为独特蓝灰色至紫罗兰色，上部灰蓝至紫罗兰色，下部紫至红，且其冠部和颈侧的颜色、下体的红色部分以及翅膀和尾巴的色彩深度存在差异。亚种之间在羽毛色泽上有细微差别，如landanae亚种的羽毛颜色接近haematocephala亚种，但喙色有明显区别。","protection":"IUCN：LC（无危）","distribution":"淡嘴火雀的分布区域跨越撒哈拉以南非洲的多个国家，从西部的塞内加尔向东延伸至埃塞俄比亚，再向南至刚果民主共和国和坦桑尼亚，最南端可达南非的东开普省。具体分布包括安哥拉、刚果共和国、刚果民主共和国等地。在苏丹低地至2400米，埃塞俄比亚1230-2500米，肯尼亚高地主要是1500-2000米，赞比亚和马拉维的Nyika高原、津巴布韦东部的悬崖地带以及南非的沿海和悬崖地带，湿度较高的低地到2200米和2500米。","other":"淡嘴火雀有时被视为独立物种，称为淡嘴火雀或苍白喙火雀，主要依据是其喙色的独特性，但其羽毛颜色与haematocephala亚种非常相似。"},{"name":"红腹火雀","english_name":"Jameson's Firefinch","scientific_name":"Lagonosticta rhodopareia","overview":"红腹火雀（英文名：Jameson's Firefinch，学名：Lagonosticta rhodopareia），是雀形目梅花雀科火雀属的鸟类。广泛分布于撒哈拉以南非洲，活动范围约2,600,000平方公里。得名于James Sligo Jameson。该鸟种在东非至中南部非洲均有分布，被IUCN评为无危等级。","appearance":"雄鸟成鸟前额至背部呈棕色微带粉红，臀部和尾上覆羽红色，尾羽黑色，外侧基部半红；翼上覆羽具鲜红色边缘；面部、喉部和胸部深红色，腹部和尾下覆羽暗黑。雌鸟颜色较淡，上身淡棕色，头部偏灰，下体温暖橙红色，腹部偏棕，尾下覆羽黑。幼鸟上身褐色，臀部红色，下体单一淡黄色，喙黑色。不同亚种在颜色上有细微差异。","call":"叫声主要包括变调的颤音，旋律般的哨声含上升音符，如'wee-weepweepwee...'；还有干燥的接触音，重复的单音或双音颤音，如't'we twe'和'簇胸吸蜜鸟, twi...'。报警声为快速的嗡嗡声，雌鸟的远距离呼叫为长'feeew'，巢穴呼叫为快速重复的'tititi'。","habits":"栖息于半干旱的金合欢灌木丛、草地灌丛、玉米田、河流森林边缘的干燥地带以及岩石山坡，主要生活在海拔1200米以下的低地。以小草籽和昆虫为食，包括白蚁。在Zambia的Lochinvar国家公园，主要依赖一年生草本植物Echinochloa、Setaria、Urochloa和Panicum的种子。在繁殖季节和之后，可能进行局部移动，最远可达4公里。","breeding":"繁殖期在雨季晚期，如肯尼亚的7月，赞比亚的1月至5月，马拉维的2月至8月，津巴布韦全年皆可繁殖，主要集中在12月至5月，南非北部的12月至4月。雄鸟求偶时会展示高举的身体和头部，梳理胸部和头部羽毛，携带羽毛或草条，发出点击声并唱歌。巢为侧面入口的草球状，置于地面以上0.1-0.3米，通常在草丛中或灌木丛中的草生长处。每窝产卵3-5枚，孵化期12-13天，雏鸟皮肤黑粉色，孵化后16-19天离巢，离巢后14天独立。","identification":"与红嘴火雀和斑胸火雀的区别在于尾下覆羽黑色，与灰顶火雀某些亚种相似，但整体更淡更粉红。","protection":"IUCN：LC（无危）","distribution":"分布于安哥拉、博茨瓦纳、乍得、刚果民主共和国、厄立特里亚、埃塞俄比亚、肯尼亚、马拉维、马里、莫桑比克、纳米比亚、南非、苏丹、斯威士兰、坦桑尼亚、乌干达、赞比亚和津巴布韦。","other":"在Zambia的Lochinvar国家公园，1972-1973年密度为40/km²，但随着高草覆盖减少、牛群踩踏和不可口草本增加，数量到1997年显著下降。"},{"name":"黑脸火雀","english_name":"Black-faced Firefinch","scientific_name":"Lagonosticta larvata","overview":"黑脸火雀（英文名：Black-faced Firefinch，学名：Lagonosticta larvata），是雀形目梅花雀科火雀属的鸟类。广泛分布于非洲大陆，活动范围广阔，覆盖2,100,000平方千米。其别称包括酒红火雀，后者原被视为独立物种，但根据1993年Dowsett和Forbes-Watson的研究，现被归入黑脸火雀种下。黑脸火雀在非洲的多个国家均有分布，包括贝宁、布基纳法索、喀麦隆等。","appearance":"雄性黑脸火雀具有显著的黑色脸部，其下体颜色从灰色到粉色再到玫瑰红色，随地理位置而异。雌鸟则主要呈灰棕色，下体带红色调，尾巴下方为淡色。幼鸟似雌鸟，但缺乏粉红色泽，背部为浅红色，下体较淡且无斑点，喙为黑色。成年雄鸟的头部和背部为暗灰褐色，胸腹部颜色从酒红到暗灰不等，具白色小斑点。雌鸟头部和背部暗灰棕色，喉部灰白，下体颜色逐渐变为土黄色。","call":"黑脸火雀的常见叫声为柔和的重复哨音，警报声为快速上升的尖锐音符序列，每秒约8至14个音符，常以断续的喋喋不休声呈现。其歌曲由2至4个凄凉的哨音组成，频率在3至5kHz之间，有时上升，有时下降后再上升，持续时间0.3至0.4秒。","habits":"黑脸火雀栖息于有树木的草地、Combretum-Terminalia林地、竹林、岩石脊上的矮灌木丛等地，偏好靠近水源的环境。它们通常在比同类更茂密的林区活动，单个或成对觅食，有时会加入其他蜡嘴雀群。食物主要包括直径1至2毫米的小型草籽和白蚁，偏爱在火烧过的地点觅食。","breeding":"繁殖记录显示，黑脸火雀在象牙海岸一月、多哥七月、尼日利亚北部七月至十月、刚果东北部七月后、埃塞俄比亚十一月和乌干达六月进行繁殖。雄鸟在求偶时会在地面跳跃围绕雌鸟，有时口中叼着羽毛，发出轻柔的鸣叫或歌曲，展示黑色喉咙，上下点头并向雌鸟鞠躬。巢穴由细草构成，内部铺垫柔软的草茎、草穗和羽毛，建在高草丛中或离地不超过1米的灌木丛中。每窝产卵3至4枚，孵化期为11至12天，雏鸟喂养期为17至19天，离巢后仍由父母喂养8至14天。","identification":"黑脸火雀雌雄差异明显，雄鸟具有独特的黑色面部和变色的下体，而雌鸟为灰棕色，下体有红色调。与同属其他火雀相比，黑脸火雀可通过其苍白的尾巴下方和深色喙来识别。","protection":"IUCN：LC（无危）","distribution":"分布于东苏丹、东南苏丹和西埃塞俄比亚，从马里南部至苏丹西南部和南苏丹西部及南部，刚果东北部（Uele）、乌干达西部和北部。还见于塞内加尔、冈比亚、几内亚比绍东部至几内亚北部和马里西部（至Mandinga山脉）。在非洲的多个国家中均有分布，包括贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果民主共和国、科特迪瓦、埃塞俄比亚、冈比亚、加纳、几内亚比绍、马里、尼日尔、尼日利亚、塞内加尔、塞拉利昂、苏丹、多哥和乌干达。","other":"黑脸火雀是某些种类Indigobird寄生繁殖的目标，寄生幼鸟模仿宿主巢穴雏鸟的口部颜色和图案。"},{"name":"蓝饰雀","english_name":"Blue Waxbill","scientific_name":"Uraeginthus angolensis","overview":"蓝饰雀（英文名：Blue Waxbill，学名：Uraeginthus angolensis），是雀形目梅花雀科蓝饰雀属的鸟类。广泛分布在南部非洲的常见物种，亦是颇受欢迎的笼鸟。该鸟种长约12至13厘米，重约6.3到13克，以其独特的粉蓝色脸庞、胸部、臀部和两翼而闻名。","appearance":"蓝饰雀雄鸟拥有灰褐色的冠至背部和上翅，尾羽宽大，臀部、上尾覆羽和长尖尾呈蓝色；脸部、喉咙、胸部至两侧呈现淡天蓝色至浅青色，腹部中心至肛周和下尾覆羽为淡黄白色。雌鸟相似，但蓝色较淡，仅限于脸部、下巴至胸部中央。幼鸟类似雌鸟，但胸部的蓝色更淡且范围更小，年轻雄鸟比雌鸟有更多的蓝色，两者喙均为黑色。成年雄鸟的喙为淡灰色至淡紫蓝色，边缘和尖端黑色；腿为灰粉色。","call":"蓝饰雀的叫声包括近距接触声，轻柔的'swip swip'；远距接触声和飞行叫声为1至3个响亮、嘶哑、高音调（6-7千赫兹）上升的哨声，'chee-chee-chee'；警报声为快速的喋喋不休（每秒18-20个音符）。其歌声由一系列短促的模糊哨声和嘶哑刺耳的音符组成，具有地区性和个体差异。","habits":"蓝饰雀栖息于金合欢木（Acacia）林地和灌木丛、茂密的草地、耕作地以及靠近常水的农村住宅和花园。它们主要以小型草籽为食，也吃一些昆虫和蜘蛛。通常成对或家庭群活动，有时会形成较大群体，经常与其它梅花雀科鸟类混群。","breeding":"繁殖季节一般在2月至5月期间，筑巢期从雨季开始后两个月左右，草籽成熟且白蚁丰富时。巢为侧面入口的球状，由草头和茎构成，内部铺垫细草或羽毛，建于1至4米高的荆棘丛或树中。每次产卵通常3至5枚，孵化期13至14天，雏鸟皮肤呈淡粉色，带有淡黄褐色至灰色绒毛，喙缘有轻微肿胀，孵化后17至19天离巢。","identification":"雄性红颊蓝饰雀具有明显的红色脸颊斑和粉色喙，但已记录到杂交种。蓝饰雀与红颊蓝饰雀的歌声相似。","protection":"IUCN：LC（无危）","distribution":"分布于南部非洲，从安哥拉、刚果到肯尼亚和坦桑尼亚，南至南非北部。在圣多美岛可能被引入。","other":"蓝饰雀在某些地区密度很高，例如在南非尼尔河泛滥平原的开放金合欢-二叉刺槐灌木丛中，密度约为每公顷0.25至0.75对。"},{"name":"红颊蓝饰雀","english_name":"Red-cheeked Cordon-bleu","scientific_name":"Uraeginthus bengalus","overview":"红颊蓝饰雀（英文名：Red-cheeked Cordon-bleu，学名：Uraeginthus bengalus），是雀形目梅花雀科蓝饰雀属的鸟类。小型梅花雀科蓝饰雀属的鸟类。分布广泛于非洲中部、西部和东部的干燥地带。其特征为雄鸟个体拥有独特的红颊斑，而全身则呈淡褐色上部与蓝色下部的鲜明对比。雌鸟较为黯淡，缺乏红颊斑。全球活动范围约770万平方公里。","appearance":"红颊蓝饰雀体型小巧，长度约12.5厘米，平均重量为9.9克。雄鸟的上部为浅至中等的褐色，翅膀尖端有窄边，臀部、尾羽覆盖处及长而尖锐的尾巴为蓝色。最显著的特点是双颊上的红色斑块，其余脸部至胸部及两侧为淡绿松石色到明亮的钴蓝色。雌鸟相似，但蓝色更淡，红颊斑缺失，仅限于胸部中央和上侧腹部。幼鸟像雌鸟，但胸部蓝色较淡，雄鸟幼鸟侧面有蓝色痕迹，而雌鸟幼鸟则没有。随着成长，3-4个月内可获得成年羽毛。","call":"红颊蓝饰雀的联络叫声为尖锐上升的哨音，通常被描述为“tsee-tsee”。其歌声更为复杂，由一系列高音符组成，最后一个音符较长、较低且带沙哑声，节奏感强但略显慵懒。","habits":"红颊蓝饰雀常见于干燥的荆棘灌木丛、灌木草原、萨赫勒和几内亚的森林地带，也常出现在村落周围种植着小米和木薯的地区，海拔高度从海平面至罕见的2300米。它们主要以小草籽为食，也会摄食白蚁和蛾类幼虫。通常成对或小群体活动，有时与其它梅花雀科鸟类混群。它们在地面觅食，活跃于耕作区、灌木边缘和草地林地。","breeding":"繁殖期多在雨季后期至旱季早期，如塞内加尔的9月至12月，冈比亚的4月至1月（主要集中在7月至10月和5月至7月至9月），尼日利亚的7月至10月雨季，埃塞俄比亚的4月至12月，赞比亚的12月至4月，刚果东北部（乌埃莱）的8月至11月。雄鸟求偶时面对雌鸟，头部抬起，用喙夹住羽毛尖端，上下摇晃头部，随后靠近雌鸟，展示尾部。巢呈球状，入口位于侧面，由细草茎和头构成，有时外层覆盖根或黄色干草碎片，内部衬以羽毛或软草，位于1至4米高的树或灌木中。每窝产卵3至5枚，孵化期为13至14天，幼鸟皮肤粉红，带有长而淡黄色至灰色的绒毛，喙裂处有蓝点，孵化后16至19天离巢。","identification":"雌鸟与蓝饰雀雌鸟极难区分，红颊蓝饰雀雌鸟脸颊上棕色区域更广泛，但最安全的识别方式是与红颊蓝饰雀雄鸟的关联。不同亚种间颜色深浅有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部、中部和东部，包括塞内加尔、冈比亚、毛里塔尼亚南部、马里南部、尼日尔南部、乍得南部、苏丹南部、埃塞俄比亚、索马里西北和西南部、刚果民主共和国南部、安哥拉东部、赞比亚北部和西部、坦桑尼亚南部、莫桑比克北部。也已引入夏威夷群岛的夏威夷岛和欧胡岛。","other":"红颊蓝饰雀在圈养中非常受欢迎，但需注意其对低温的敏感性，尤其是在繁殖季节，雄鸟间会变得极具攻击性。"},{"name":"蓝顶蓝饰雀","english_name":"Blue-capped Cordon-bleu","scientific_name":"Uraeginthus cyanocephalus","overview":"蓝顶蓝饰雀（英文名：Blue-capped Cordon-bleu，学名：Uraeginthus cyanocephalus），是雀形目梅花雀科蓝饰雀属的鸟类。小巧精致的梅花雀科鸟类，以蓝色头部和鲜艳的色彩而闻名。分布于东非地区，包括南苏丹南部、埃塞俄比亚南部、索马里南部、肯尼亚和坦桑尼亚。该鸟种在适宜条件下能适应圈养环境，但繁殖较为困难。","appearance":"蓝顶蓝饰雀体型纤细，尾巴修长，体长13至13.5厘米，体重介于8.5至10.8克之间。雄鸟的头部至上胸和两颊呈现亮丽的天蓝色，背部和翅膀上覆羽为淡褐色，尾羽和臀部蓝色，腹部和下覆羽颜色较浅，从灰白色到浅黄褐色不等。雌鸟的冠部颜色从蓝灰色到棕色，下额至眼上方及上胸和两侧蓝，其余下体部分呈淡黄褐色，腹部至肛门部位白色。幼鸟外观类似雌鸟，脸部颜色较浅，胸部和两侧颜色更淡。","call":"蓝顶蓝饰雀的常见鸣声为高音的‘tzee-tzee’，接触叫声为尖锐的‘tseee’，报警声为快速连续的‘tchek’，巢穴附近发出高音的‘chee-chee-chee’，歌声包括一系列短长哨音和杂乱音符，通常以低音开始，高音结束。","habits":"栖息于干旱和半干旱的金合欢树灌木丛中，主要分布在年降雨量250至1000毫米的地区，海拔高度可达1300米。以小种子和昆虫为主食，特别偏好白蚁。通常成对或小群体活动。","breeding":"繁殖季节在索马里为5月至6月，在肯尼亚雨季至旱季初期，在坦桑尼亚则从11月至次年6月。筑巢材料为精细草茎，内部铺垫柔软的草花头或羽毛，巢置于荆棘树或金合欢树中，有时在电杆上，靠近活跃的黄蜂巢。每窝产卵4至6枚，孵化期13至14天，雏鸟期17至19天。","identification":"雌性蓝顶蓝饰雀与蓝饰雀和红颊蓝饰雀在重叠分布区容易混淆，但可通过其更鲜艳的粉红色喙进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部，从南苏丹南部、埃塞俄比亚南部和索马里南部延伸至坦桑尼亚中部，局部区域在苏丹、埃塞俄比亚和索马里的分布更为集中。","other":"蓝顶蓝饰雀在圈养条件下的表现良好，但在繁殖方面具有挑战性。"},{"name":"紫耳蓝饰雀","english_name":"Violet-eared Waxbill","scientific_name":"Granatina granatina","overview":"紫耳蓝饰雀（英文名：Violet-eared Waxbill，学名：Granatina granatina），是雀形目梅花雀科 Granatina 属的鸟类。梅花雀科蓝饰雀属的鸟类。分布于非洲南部，包括安哥拉南部、纳米比亚、博茨瓦纳、津巴布韦、莫桑比克南部和南非北部。其最显著的特征为雄鸟的深蓝色额头、胸腹部的鲜艳栗色以及雌鸟奶油色的下体。该鸟种广泛见于干旱的荆棘灌木草原和较干的林地。","appearance":"紫耳蓝饰雀体长约14厘米，重量介于9.5到13.9克之间。雄鸟头部至眉区深蓝色，头顶丰富栗色渐变为背部的淡红褐色，臀部和尾上覆羽深蓝色，长尾羽黑色，多数尾羽基部三分之二边缘淡蓝色，翼羽棕色；脸侧至喉咙呈紫色，眼先棕黑色，下巴至喉咙中央黑色，其余喉咙和下体丰富栗色，下腹至尾下覆羽棕黑色至黑色；虹膜红橙色至红棕色，宽眼环橙红色；喙红色；腿灰褐色至暗灰色。雌鸟前额和眉区淡蓝色，头顶红褐至棕色，背灰棕色，臀部至尾淡蓝色，脸颊、耳羽和脸侧紫色，眼先暗灰色，下巴和喉咙淡黄白色，胸部深肉桂色，腹部和两胁更浅，下腹至尾下覆羽淡奶油色；虹膜棕色至红棕色，眼环淡橙红色。幼鸟类似雌鸟，但臀部和尾部蓝色较淡，头部无蓝色，喙红黑色，眼环黑灰色，虹膜棕色；独立前额头出现蓝色，眼先黑色，脸颊紫色。","call":"紫耳蓝饰雀的联系叫声为“tsek”，兴奋或威胁声为“chay chay chay”。巢边呼唤由雄鸟发出，以吸引雌鸟，每秒8个柔和音调，系列内音调变化。鸣唱开始于尖锐的‘chay chay’颤音，随后是悠扬的哨音，如‘tiu-woo-wee’或‘chick-weeoo-weeyi’，并以嗡嗡声和模糊的哨音结束。","habits":"紫耳蓝饰雀栖息于干旱的荆棘灌木草原和较干的林地，常在地面或灌木较低层觅食，常与其他雀鸟一同活动。它们主要以小草籽、Portulaca olearacea的种子、小型树木果实、龙舌兰属植物的花蜜为食，也吃昆虫如白蚁、小毛虫、蚂蚁和甲虫。","breeding":"繁殖期从雨季几周后持续到旱季，在博茨瓦纳为12月至7月（主要2月至4月），在赞比亚为12月至4月，津巴布韦为10月至5月（多数记录1月至3月），南非北部为12月至5月。求偶时，雄鸟口含草或羽毛，展示面部和两胁的羽毛，向雌鸟鞠躬点头，亮出色彩斑斓的脸部斑块。巢为松散构造的球形，侧面入口，由干草茎制成，内衬羽毛，置于荆棘丛中离地0.5米至3米处。","identification":"紫耳蓝饰雀与黑颊梅花雀相似，但后者具有红色臀部、暗色面罩和条纹翅膀。紫耳蓝饰雀与紫蓝饰雀的区别在于无紫色脸颊，且分布范围不重叠。","protection":"IUCN：LC（无危）","distribution":"紫耳蓝饰雀分布于非洲南部，具体包括安哥拉南部、纳米比亚、博茨瓦纳、津巴布韦、莫桑比克南部和南非北部。","other":"紫耳蓝饰雀的巢可能被箭尾维达雀寄生，其雏鸟模仿紫耳蓝饰雀雏鸟的嘴部图案和颜色。"},{"name":"紫蓝饰雀","english_name":"Purple Grenadier","scientific_name":"Granatina ianthinogaster","overview":"紫蓝饰雀（英文名：Purple Grenadier，学名：Granatina ianthinogaster），是雀形目梅花雀科 Granatina 属的鸟类。分布于东非地区，从南苏丹、埃塞俄比亚和索马里延伸至坦桑尼亚中部。其最显著的特征是雄鸟的深蓝色尾巴和红色喙，以及腹部的紫色羽毛。雌鸟则主要呈肉桂色，带有银蓝色眼斑。","appearance":"紫蓝饰雀体长约13-14厘米，体重12-17.4克。雄鸟具有肉桂色面颊，眼周至喙下方呈钴蓝至紫蓝色，头部至颈部和喉部肉桂色，背部和上翼呈暗褐色，臀部和尾上覆羽紫蓝色，尾部黑色，基部有蓝色边缘。上胸和胸部两侧肉桂色，胸部至腹部及尾下覆羽紫蓝色，胸部中央有肉桂至栗色斑块。虹膜橙红色，眼环橙红色，喙红色，有时顶部稍显暗灰色，腿灰棕色至深灰色。雌鸟头部至颈部和喉部浅肉桂色，背部和翅膀棕色，臀部和尾上覆羽深蓝色，下体浅肉桂色，有白色斑点和条纹，尾下覆羽较淡。幼鸟类似雌鸟，但整体呈棕肉桂色，臀部和尾上覆羽蓝色，无斑点或条纹，喙红棕色。","call":"紫蓝饰雀发出高音的\"wis\"或\"wis-wis\"声，通常在接近配偶或独立幼鸟时发出。接触颤音约每秒10个音符，每个音符下降，通常由短而快、音调更高的颤音引入。警报声为短促尖锐的\"tsek\"，有时连续发出。兴奋或威胁时发出响亮的刺耳声\"chay-chay-chay\"，追逐另一雄鸟时发出。巢穴呼唤，由雄鸟吸引雌鸟至巢穴，一系列接触音或柔和音符伴随接触颤音。雄鸟长时间与配偶分离后，早晨或傍晚发出高音、薄薄的上升哨声，混合短柔音，以长甜美的上滑哨声结束。雌鸟的歌声与雄鸟的颤音歌相似。","habits":"紫蓝饰雀栖息于干燥地区和半干旱的荆棘灌木林，以及有金合欢树丛和灌木丛的地带，河流沿岸的森林也在其栖息范围内，海拔从近海平面至1600米。它们通常是定居的，以小草籽和白蚁为食，在地面和灌木丛中觅食，成对或小群体活动，有时单独行动，常显得相当隐蔽。","breeding":"繁殖期记录在埃塞俄比亚和索马里的3月至7月，以及11月，在索马里则在雨季期间。求偶时，雄鸟会衔着草茎或羽毛，上下跳动靠近雌鸟，伸长脖子，头向一侧弯曲。巢为松散构建的球形，侧面有入口，有时有喷口，用细草制成，内衬羽毛，放置于低矮灌木的分叉处或高草下的灌木中。每窝产3-5枚蛋，孵化期13-14天。雏鸟皮肤呈紫黑色，有灰色或淡黄色绒毛，喙裂处有蓝色肿胀，嘴张开时可见两侧各有两个蓝色肿胀，口腔表面黑色，上颚中心灰白色，后部橙色渐变为白色和淡蓝色，其余部分和口腔内部黑色，舌白色，近根部有黑色条纹，舌后变黑，边缘白色，下颌内侧黑色。雏鸟期18-19天，离开巢穴1-2天后失去出生绒毛，8-9天后能自行进食，喙基部转粉色，眼周围开始长出蓝色或白色羽毛，24-35天后喙转粉色。年轻个体在面部羽毛长全后形成配偶关系，雄鸟在离巢后2个月开始唱歌。","identification":"紫蓝饰雀雄鸟与雌鸟的辨识在于雄鸟更加鲜艳，拥有紫蓝色的腹部和肉桂色的头部，而雌鸟主要为肉桂棕色，下体有白色斑点和条纹。与其他相似物种的辨识需依据颜色模式、体型大小和行为习性。","protection":"IUCN：LC（无危）","distribution":"紫蓝饰雀分布于非洲东部，从南苏丹东南部、埃塞俄比亚东部和南部、索马里、乌干达东北部、肯尼亚、坦桑尼亚北部和中部。主要栖息于亚热带或热带的（低地）干燥疏灌丛。"},{"name":"黄腹梅花雀","english_name":"Yellow-bellied Waxbill","scientific_name":"Coccopygia quartinia","overview":"黄腹梅花雀（英文名：Yellow-bellied Waxbill，学名：Coccopygia quartinia），是雀形目梅花雀科黄腹梅花雀属的鸟类。别称: 东非梅花雀，小型、色彩艳丽的梅花雀。其最显著的特征是拥有黑色和红色的双色喙，灰色头部，黄色腹部，橄榄绿色背部，黑色尾巴和醒目的红色臀部。广泛分布在东非的亚热带和热带地区。","appearance":"黄腹梅花雀体长约9-10厘米，体重6-8克。头部为灰色，背部呈橄榄绿色，下腹部和尾部为红色，尾巴黑色。喙上部黑色，下部红色，虹膜为深红色到深棕色，脚爪黑色。雌雄同色，但雌鸟略显暗淡，幼鸟与雌鸟相似，但更灰暗，臀部呈红褐色。","call":"鸣叫声为清脆的“swee”，通常在飞行中发出。","habits":"栖息于中高海拔的茂密灌木丛、花园、农田、草地和森林边缘。常见于道路边缘的草地上觅食，通常以小群体形式活动。以小草籽为主食，也会捕捉飞行中的小昆虫。","breeding":"繁殖季节在东非为3月、6月和8月至10月，在肯尼亚随区域性降雨变化。筑巢于灌木或小树的浓密树叶中，高度1-5米，巢为细长覆盖结构，侧边有入口。每窝产卵3-6枚，孵化期13-14天，雏鸟孵化后21-22天离巢。","identification":"与同属物种相比，黄腹梅花雀可通过其独特的双色喙和鲜艳的红色臀部来辨识。","protection":"IUCN：LC（无危）","distribution":"分布于东非中部和东南部，包括埃塞俄比亚、肯尼亚、马拉维和津巴布韦等地。在埃塞俄比亚、肯尼亚、马拉维和津巴布韦的特定海拔范围内，从低至400米至高达3000米。"},{"name":"黑颊黄腹梅花雀","english_name":"Swee Waxbill","scientific_name":"Coccopygia melanotis","overview":"黑颊黄腹梅花雀（英文名：Swee Waxbill，学名：Coccopygia melanotis），是雀形目梅花雀科黄腹梅花雀属的鸟类。分布于非洲南部，包括津巴布韦、南非、斯威士兰、莱索托以及莫桑比克西南部。该鸟以其鲜艳的色彩和柔和的鸣叫声而闻名。","appearance":"这种小鸟体长9-10厘米，重约5.7-7.5克。雄鸟具有灰色头部和颈部，橄榄绿色背部和翅膀，鲜红的臀部和上尾覆羽，黑色尾巴。脸部和喉咙为黑色，胸前有一条白色带延伸到耳羽下方。雌鸟相似，但脸部呈灰色，下巴和喉咙变为白色。幼鸟比雌鸟更暗淡，呈棕色灰色，喉部无白色，喙全黑。","call":"其鸣叫声为柔和的哨音“see-see”或“swee-swee”，报警声为尖锐的“teerrrr”；高音尖锐的“tsweee”。歌声为柔和穿透的“teeeeeeeit”和“tuuuuuueeet”，或“sii-sii-soo-sii”。","habits":"黑颊黄腹梅花雀栖息于开阔的草地、灌木草丛、沿海灌木林、农场附近和房屋周围，海拔从海平面至1800米。它们通常居住在同一区域，可能进行一些高度迁移。主要以小草籽和小昆虫为食，偶尔也会食用蜘蛛、蚜虫、白蚁、粉虫和小型蛾子。","breeding":"筑巢活动在津巴布韦始于7月，在南非北部从11月至2月，中部从11月至4月，东部从11月至1月，南部从10月至5月。雄鸟会向雌鸟展示求偶行为，包括跳跃和歌唱。巢由干燥的草构成，带有侧面入口和短管，内衬草穗和羽毛，建在离地面2米高的灌木或藤蔓中。每窝产4-5枚卵，孵化期为12-13天；幼鸟孵化后，孵化期间为19-22天。","identification":"与黄腹梅花雀相比，黑颊黄腹梅花雀的腹部颜色更偏向黄褐色，雄鸟缺乏黑色喉咙，且二者分布范围并不重叠。","protection":"IUCN：LC（无危）","distribution":"分布于津巴布韦中南部和莫桑比克西南部至南非南部。在莫桑比克，仅限于勒邦博山脉（与斯威士兰接壤），数量稀少，估计不超过500只。在南非南部似乎正在扩展其分布范围。"},{"name":"安哥拉梅花雀","english_name":"Angola Waxbill","scientific_name":"Coccopygia bocagei","overview":"安哥拉梅花雀（英文名：Angola Waxbill，学名：Coccopygia bocagei），是雀形目梅花雀科黄腹梅花雀属的鸟类。脸部呈淡灰黄色，下巴和喉咙白色。","appearance":"体长9-10厘米，雄鸟具有灰色的冠和颈背，橄榄绿的背部和上翼，头部至背部有细致的暗灰色条纹，臀部和上尾覆羽红色，尾部黑色。脸部和喉咙黑色，一条白色带从脸颊后方延伸至喉咙下方；上胸灰色，下胸至腹部鲜亮黄色，两胁黄灰色并有暗灰色条纹，下尾羽覆羽淡黄色；深红棕色虹膜；上喙黑色，下喙红色；腿黑色。雌鸟缺失黑色部分，脸部淡灰黄色，下巴和喉咙白色。幼鸟似雌鸟，但更偏灰色，喙全黑。","call":"鸣叫特征尚未详细描述，但可能发出类似近缘种Swee和Yellow-bellied Waxbills的哀怨‘swee-swee’和‘seeet’声。","habits":"常以成对或小群形式出现在森林和灌木丛附近的开阔地带，以草籽为食。","identification":"在分布区域内无相似物种重叠。","protection":"IUCN：LC（无危）","distribution":"非洲：安哥拉。具体分布于该国西部。","other":"某些分类学者认为它与Swee蜡嘴雀是同一物种。"},{"name":"淡蓝梅花雀","english_name":"Lavender Waxbill","scientific_name":"Glaucestrilda caerulescens","overview":"淡蓝梅花雀（英文名：Lavender Waxbill，学名：Glaucestrilda caerulescens），是雀形目梅花雀科 Glaucestrilda 属的鸟类。小型的梅花雀科鸟类，以银灰色的外观和淡紫色的喙著称。分布于非洲西部，从塞内加尔到中非共和国北部，同时在夏威夷岛也有引入种群。栖息于干燥的稀树草原、耕地、亚热带或热带的（低地）干燥疏灌丛和牧草地。","appearance":"淡蓝梅花雀体长约10厘米，体重介于8至15.1克之间。雄鸟通体呈珍珠灰，上身与下身颜色相近，具有一条黑色的眼纹，红色的臀部和上尾覆羽，尾羽中央一对为深红色，其余为暗灰色带红边；腹部和两胁为烟灰色，偶尔可见白色斑点；虹膜深棕色，眼圈黑色；喙为粉灰色，尖端、上下棱和切割边缘为黑色；腿黑色。雌鸟与雄鸟相似，但下腹和两胁颜色更深。幼鸟比雌鸟更淡，无黑眼纹，臀部、尾羽和下尾覆羽红色较浅，两胁无白色斑点。","call":"其叫声高亢、清脆，音调不变，常发出一连串‘see-see-squee-see’的叫声；雌鸟的联系叫声为‘tseeht-tseet’，雄鸟的叫声为‘seet-tyoo’，第二声开始音调最高。","habits":"淡蓝梅花雀栖息于灌木丛和灌木边缘，延伸至林地，偏好在较为开阔的土地上的茂密地带、岩石山坡以及耕作边缘。它们的食物主要包括小草籽、小果实、花朵（花粉和花蜜）以及一些昆虫。通常成对或小群体觅食，也会加入其他梅花雀科鸟类组成的混合群。","identification":"淡蓝梅花雀可通过其独特的银灰色外观、淡紫色的喙和红色的臀部来识别，与同属其他物种相比，这些特征明显。在不同亚种间，主要差异体现在羽毛颜色的深浅和红色部分的鲜艳程度。","protection":"IUCN：LC（无危）","distribution":"非洲分布从塞内加尔和冈比亚至几内亚和东部至中非共和国北部。在夏威夷岛有人工引入的种群。"},{"name":"黑尾梅花雀","english_name":"Grey Waxbill","scientific_name":"Glaucestrilda perreini","overview":"黑尾梅花雀（英文名：Grey Waxbill，学名：Glaucestrilda perreini），是雀形目梅花雀科 Glaucestrilda 属的鸟类。常见的梅花雀，广泛分布于非洲南部的湿润地带。该鸟种以灰白相间的羽毛、黑色尾巴和醒目的红色臀部为显著特征，常见于中西部、中部及东南部非洲，包括津巴布韦、加蓬、安哥拉、南非等地。其全球分布面积估计约671,000平方公里。","appearance":"成年黑尾梅花雀体型小巧，体长约10.5至11厘米，重量在6.1至9克之间。雄鸟标本种（incana）以上下身珍珠灰色为主，眼周有黑色条纹，红色臀部和上尾覆羽，尾巴黑色；腹部和两胁呈烟灰色，下尾覆羽黑色。眼睛深棕色，眼圈黑色；喙蓝灰色，尖端和切割边缘更黑；腿色从暗蓝灰到黑色。雌鸟相似于雄鸟，但下腹和两胁颜色更深。幼鸟比雌鸟淡，无黑色眼纹。incana亚种比标本种略小且色泽更浅，臀部红色更鲜亮。","call":"黑尾梅花雀的联系叫声是一声尖锐的“pseeu pseeu”哨音，频率约4.5kHz，音调先升后降，持续时间约0.3秒；雄鸟的叫声则为哀怨的长音“fweeeee”，频率约3.6kHz，开始和结束音量较轻，持续时间约0.8秒，有时会随后跟短音。","habits":"偏好开放的林地环境，有分散的树木和草地，常出现在低地和中海拔常绿森林边缘、Cryptosepalum森林、竹林、密生河岸森林、次生植被和灌木丛，以及岩石附近的轻型Miombo（Brachystegia）林。它们通常定居，不迁徙。食物包括小型草籽、荨麻属种子、昆虫、花蜜和marula果实。觅食时，它们会用脚固定草头，或在地面拾取掉落的种子。","breeding":"繁殖季节一般在雨季后期，如刚果南部的1月和4月、赞比亚的12月至5月、马拉维的2月和4月、津巴布韦的1月至4月以及南非东部的10月至2月。求偶时，雄鸟会衔着长草茎在空中飞舞，筑巢高度在1.5至5米间，常用细长的草茎和开花头制成，偶尔会利用织布鸟旧巢。一窝产卵2至5枚，孵化期12天，雏鸟皮肤初期粉红或棕粉色，头部和背部有稀疏绒毛，3至4天后皮肤变灰，离巢期为18至21天。","identification":"与纽氏梅花雀非常相似，但黑尾梅花雀的灰色更深，喙全黑，大腿部为灰色。","protection":"IUCN：LC（无危）","distribution":"黑尾梅花雀分布于非洲中西部、中部和东南部，具体包括刚果民主共和国、刚果、加蓬、安哥拉、南非、斯威士兰、马拉维、坦桑尼亚、赞比亚、津巴布韦及莫桑比克。在低地至约1900米的高度范围内都有发现，具体海拔范围在各国有所不同，如赞比亚950至1950米，马拉维60至1900米，津巴布韦至700米。"},{"name":"纽氏梅花雀","english_name":"Cinderella Waxbill","scientific_name":"Glaucestrilda thomensis","overview":"纽氏梅花雀（英文名：Cinderella Waxbill，学名：Glaucestrilda thomensis），是雀形目梅花雀科 Glaucestrilda 属的鸟类。近危的梅花雀科鸟类。分布于非洲的安哥拉西部与纳米比亚西北部，活动范围约95,400平方千米。纽氏梅花雀体型小巧，平均体重约为7.0克，偏好干燥的稀树草原与亚热带或热带的（低地）干燥疏灌丛。","appearance":"雄性纽氏梅花雀全身呈淡珍珠灰色，头顶至背部有黑色条纹穿过眼区，红色臀部和上尾覆羽，尾巴黑色；腹部为烟灰色（有时带有红色），两胁至肛门处红色，下尾覆羽黑色。雌鸟较雄鸟略显灰淡，下腹及两胁深灰色。幼鸟类似雌鸟，但缺乏黑色眼纹和红色两胁，喙全黑。","call":"纽氏梅花雀的鸣叫包括尖锐的‘brrrt, brrrt’接触叫声，以及更强烈的警戒声；梳理羽毛和社交时发出柔和且变化多端的‘swee-swee-swee’声，以及远距离可闻（超过100米）的‘hu-wee’声。雄鸟的歌唱为一连串的长音哨声，‘see-eh, see-eh, sueee’。","habits":"纽氏梅花雀以小草籽和其他小种子、花部或花蜜、昆虫（如白蚁和产蜜介壳虫）为食。它们通过攀爬茎干或悬挂在枝头来摘取草籽。它们在灌木和树冠层觅食，也会在空中捕捉刚飞出的白蚁。纽氏梅花雀通常成对或小群活动，偶尔加入混合物种的群体。","breeding":"筑巢活动在11月末至12月期间，首场雨后开始，在纳米比亚。野外巢穴未被描述，但在圈养环境中，它们会建造由草和椰子纤维构成的大球状巢，带有一个长而狭窄的向下倾斜的入口管，有时顶部还会有‘公鸟巢’。每窝产3-4枚蛋，孵化期12-14天，雏鸟期17-21天。没有其他繁殖信息。","identification":"纽氏梅花雀与黑尾蜡嘴雀非常相似，但后者偏好较湿润的生境，且颜色更暗。纽氏梅花雀的灰度更浅，喙上有粉色。","protection":"IUCN：LC（无危）。局部常见，在纳米比亚较为罕见，总数量可能不足2000只。全球种群因栖息地丧失和退化而被认为正在减少。在纳米比亚，Epupa瀑布的Cunene河上拟建的水坝项目可能威胁到其生存。","distribution":"纽氏梅花雀分布在非洲的安哥拉西部（W Angola）和纳米比亚西北部（nw Namibia）。在安哥拉，它们生活在Acacia和Colophospermum mopane林地的河岸植被中；在纳米比亚，它们仅限于mopane林地和河岸森林，靠近水源。","other":"纽氏梅花雀的分布范围在重新绘制后比先前估计的更大，因此在2014年被BirdLife International从近危状态下调。"},{"name":"灰颊梅花雀","english_name":"Anambra Waxbill","scientific_name":"Estrilda poliopareia","appearance":"雄鸟的前额至颈背呈灰褐色，上体为暗淡的橄榄黄色，有微弱的条纹，臀部和尾羽覆羽为纯红色，尾巴深棕色，部分尾羽基部有红色边缘；眼下方为浅褐色，喉部白色，胸部浅黄色，腹部至尾下覆羽为黄色，两胁更深更棕色；虹膜乳白色，眼圈黑色；喙较厚，鲜亮的橙红色；腿为灰棕色。雌鸟体色略淡。幼鸟特征未描述。","call":"发出鼻音的'nyert'声，常与其他个体合唱。","habits":"栖息于高草丛和莎草科植物的沙质河岸、沼泽和河口的沙滩，也见于开放落叶林内或边缘的长草丛中，以及木薯种植园，靠近人类居住地。可能在严重雨季洪水后进行短距离移动，但在某些地区，至少在2001年10月底的观察表明，这种鸟类可能是定居的。以莎草和草类的小种子、象草种子和花朵为食，攀爬并附着在草茎上取食种子头。以小群体或大群（约30只）觅食，有时与橙颊梅花雀混群。","breeding":"推测在10月至11月洪水消退后繁殖；4月末观察到携带筑巢材料的个体，6月观察到雌鸟体内有大型发育中的卵黄。无其他繁殖信息。","identification":"与外观相似的橙颊梅花雀区别在于后者总是有橙色面颊斑（幼鸟颜色较暗淡）。","protection":"IUCN：NT（近危）","distribution":"分布于贝宁南部（下乌埃梅河）和尼日利亚南部（奥尼查、福卡多斯、努恩河、尼日尔三角洲、巴达格里）。","other":"自1980年以来，尽管进行了大量针对性的搜索，记录极少。2010年在贝宁东南部下乌埃梅泛滥平原发现了新种群。"}];
